if (!function_exists('admin_is_ajax_request')) {
    function admin_is_ajax_request()
    {
        $requested_with = strtolower((string) ($_SERVER['HTTP_X_REQUESTED_WITH'] ?? ''));
        if ($requested_with === 'xmlhttprequest') {
            return true;
        }

        $sec_fetch_mode = strtolower((string) ($_SERVER['HTTP_SEC_FETCH_MODE'] ?? ''));
        if ($sec_fetch_mode !== '' && $sec_fetch_mode !== 'navigate') {
            return true;
        }

        $sec_fetch_dest = strtolower((string) ($_SERVER['HTTP_SEC_FETCH_DEST'] ?? ''));
        if ($sec_fetch_dest !== '' && $sec_fetch_dest !== 'document') {
            return true;
        }

        $accept = strtolower((string) ($_SERVER['HTTP_ACCEPT'] ?? ''));
        if (strpos($accept, 'application/json') !== false) {
            return true;
        }

        $has_ajax_action = isset($_POST['ajax_action']) || isset($_GET['ajax_action']);
        if ($has_ajax_action && strtoupper((string) ($_SERVER['REQUEST_METHOD'] ?? 'GET')) === 'POST') {
            return $accept === '' || strpos($accept, 'text/html') === false;
        }

        return false;
    }
}

if (!function_exists('admin_redirect_to')) {
    function admin_redirect_to($location)
    {
        if (!headers_sent()) {
            header('Location: ' . $location);
        }
        exit;
    }
}

