if (!function_exists('admin_safe_return_url')) {
    function admin_safe_return_url($fallback = 'admin_attendance.php?page=dashboard')
    {
        $host = (string) ($_SERVER['HTTP_HOST'] ?? '');
        $candidates = [
            (string) ($_SERVER['HTTP_REFERER'] ?? ''),
            (string) ($_SERVER['REQUEST_URI'] ?? ''),
        ];

        foreach ($candidates as $candidate) {
            $candidate = trim($candidate);
            if ($candidate === '' || strpos($candidate, "\n") !== false || strpos($candidate, "\r") !== false) {
                continue;
            }

            $parts = @parse_url($candidate);
            if ($parts === false) {
                continue;
            }

            $candidate_host = (string) ($parts['host'] ?? '');
            if ($candidate_host !== '' && isset($parts['port'])) {
                $candidate_host .= ':' . $parts['port'];
            }
            if ($candidate_host !== '' && $host !== '' && strcasecmp($candidate_host, $host) !== 0) {
                continue;
            }

            $path = (string) ($parts['path'] ?? '');
            if ($path === '') {
                continue;
            }

            $query = '';
            if (isset($parts['query'])) {
                parse_str((string) $parts['query'], $query_params);
                unset($query_params['ajax_action']);
                $query_string = http_build_query($query_params);
                $query = $query_string !== '' ? '?' . $query_string : '';
            }

            return $path . $query;
        }

        return $fallback;
    }
}

if (!function_exists('admin_is_php_function_disabled')) {
    function admin_is_php_function_disabled($functionName)
    {
        $functionName = strtolower(trim((string) $functionName));
        if ($functionName === '') {
            return false;
        }

        $disabled = array_filter(array_map('trim', explode(',', (string) ini_get('disable_functions'))));
        foreach ($disabled as $item) {
            if (strtolower($item) === $functionName) {
                return true;
            }
        }

        return false;
    }
}

if (!function_exists('admin_ffmpeg_status')) {
    function admin_ffmpeg_status()
    {
        static $cached = null;
        if (is_array($cached)) {
            return $cached;
        }

        $base = function_exists('resolve_ffmpeg_binary_status')
            ? resolve_ffmpeg_binary_status()
            : [
                'configured_path' => trim((string) (getenv('FFMPEG_BINARY') ?: '')),
                'resolved_path' => '',
                'env_present' => false,
                'exists' => false,
                'executable' => false,
                'is_directory' => false,
                'shell_available' => function_exists('shell_exec') && !admin_is_php_function_disabled('shell_exec'),
                'status' => 'error',
                'message' => 'មិនទាន់កំណត់ FFMPEG_BINARY នៅក្នុង .env ទេ។',
            ];

        $status = [
            'path' => (string) ($base['configured_path'] ?? ''),
            'resolved_path' => (string) ($base['resolved_path'] ?? ''),
            'env_present' => !empty($base['env_present']),
            'exists' => !empty($base['exists']),
            'executable' => !empty($base['executable']),
            'is_directory' => !empty($base['is_directory']),
            'wrong_platform_binary' => !empty($base['wrong_platform_binary']),
            'shell_available' => !empty($base['shell_available']),
            'version' => '',
            'status' => (string) ($base['status'] ?? 'error'),
            'message' => '',
        ];

        if (!$status['env_present']) {
            $status['message'] = 'មិនទាន់កំណត់ FFMPEG_BINARY នៅក្នុង .env ទេ។';
            $cached = $status;
            return $cached;
        }

        if (!$status['exists']) {
            $status['message'] = $status['is_directory']
                ? 'path ដែលបានកំណត់ជាថតមួយ ប៉ុន្តែរកមិនឃើញ file `ffmpeg` ខាងក្នុងទេ។'
                : 'រកមិនឃើញ file FFmpeg តាម path ដែលបានកំណត់ក្នុង .env ទេ។';
            $cached = $status;
            return $cached;
        }

        if ($status['wrong_platform_binary']) {
            $status['status'] = 'error';
            $status['message'] = 'អ្នកបាន upload `ffmpeg.exe` ដែលជាសម្រាប់ Windows ប៉ុន្តែ server នេះជា Linux/cPanel។ សូមប្តូរទៅ Linux ffmpeg binary វិញ។';
            $cached = $status;
            return $cached;
        }

        if ($status['is_directory'] && $status['resolved_path'] === '') {
            $status['status'] = 'error';
            $status['message'] = 'path ដែលបានកំណត់ជាថតមួយ ប៉ុន្តែមិនទាន់ចង្អុលដល់ file `ffmpeg` ពិតប្រាកដទេ។';
            $cached = $status;
            return $cached;
        }

        if (!$status['executable']) {
            $status['status'] = 'warning';
            $status['message'] = 'រកឃើញ FFmpeg ហើយ ប៉ុន្តែមិនទាន់មាន permission execute នៅលើ server ទេ។';
            $cached = $status;
            return $cached;
        }

        if (!$status['shell_available']) {
            $status['status'] = 'warning';
            $status['message'] = 'រកឃើញ FFmpeg ហើយ ប៉ុន្តែ server បិទ shell_exec ដូច្នេះមិនអាច verify version បានទេ។';
            $cached = $status;
            return $cached;
        }

        $binaryToCheck = $status['resolved_path'] !== '' ? $status['resolved_path'] : $status['path'];
        $output = @shell_exec(escapeshellarg($binaryToCheck) . ' -version 2>&1');
        $firstLine = is_string($output) ? trim((string) strtok(str_replace(["\r\n", "\r"], "\n", $output), "\n")) : '';
        $status['version'] = $firstLine;

        if ($firstLine !== '' && stripos($firstLine, 'ffmpeg version') === 0) {
            $status['status'] = 'ok';
            $status['message'] = $status['is_directory']
                ? 'FFmpeg ត្រូវបានរកឃើញពី folder ដែលបានកំណត់ ហើយ auto-resolve ទៅ binary បានជោគជ័យ។'
                : 'FFmpeg រួចរាល់សម្រាប់ auto-compress និង audio summarization ហើយ។';
        } elseif ($firstLine !== '') {
            $status['status'] = 'warning';
            $status['message'] = 'FFmpeg path ត្រូវបានអានបាន ប៉ុន្តែ version output មិនត្រឹមត្រូវទេ។ សូមពិនិត្យថា path ចង្អុលទៅ file `ffmpeg` មែន។';
        } else {
            $status['status'] = 'warning';
            $status['message'] = 'រកឃើញ FFmpeg ហើយ ប៉ុន្តែមិនអាច verify ការរត់ binary បានពេញលេញទេ។';
        }

        $cached = $status;
        return $cached;
    }
}

