if (!function_exists('get_setting')) {
    function get_setting($mysqli, ...$args)
    {
        static $settings_cache = [];

        $admin_id = 'SYSTEM_WIDE';
        $key = '';
        $default = '';

        if (count($args) >= 3) {
            $admin_id = $args[0];
            $key = $args[1];
            $default = $args[2];
        } elseif (count($args) == 2) {
            $key = $args[0];
            $default = $args[1];
        } elseif (count($args) == 1) {
            $key = $args[0];
        }

        if (empty($key))
            return $default;

        $cache_key = "{$admin_id}_{$key}";
        if (isset($settings_cache[$cache_key]))
            return $settings_cache[$cache_key];

        // Priority 1: Check admin-specific setting
        $sql = "SELECT setting_value FROM app_settings WHERE admin_id = ? AND setting_key = ? LIMIT 1";
        if ($stmt = $mysqli->prepare($sql)) {
            $stmt->bind_param("ss", $admin_id, $key);
            $stmt->execute();
            $res = $stmt->get_result();
            if ($row = $res->fetch_assoc()) {
                $settings_cache[$cache_key] = $row['setting_value'];
                $stmt->close();
                return $row['setting_value'];
            }
            $stmt->close();
        }

        // Priority 2: Fallback to SYSTEM_WIDE if it wasn't already checked
        if ($admin_id !== 'SYSTEM_WIDE') {
            $sql = "SELECT setting_value FROM app_settings WHERE admin_id = 'SYSTEM_WIDE' AND setting_key = ? LIMIT 1";
            if ($stmt = $mysqli->prepare($sql)) {
                $stmt->bind_param("s", $key);
                $stmt->execute();
                $res = $stmt->get_result();
                if ($row = $res->fetch_assoc()) {
                    $settings_cache[$cache_key] = $row['setting_value'];
                    $stmt->close();
                    return $row['setting_value'];
                }
                $stmt->close();
            }
        }

        $settings_cache[$cache_key] = $default;
        return $default;
    }
}

if (!function_exists('update_system_setting')) {
    /**
     * Helper function to save a system-wide setting.
     * @param mysqli $mysqli
     * @param string $key
     * @param string $value
     * @return bool
     */
    function update_system_setting($mysqli, ...$args)
    {
        $admin_id = 'SYSTEM_WIDE';
        $key = '';
        $value = '';

        if (count($args) >= 3) {
            $admin_id = $args[0];
            $key = $args[1];
            $value = $args[2];
        } else {
            $key = $args[0];
            $value = $args[1];
        }

        if (empty($key))
            return false;

        $sql = "INSERT INTO app_settings (admin_id, setting_key, setting_value) VALUES (?, ?, ?)
                ON DUPLICATE KEY UPDATE setting_value = VALUES(setting_value)";
        if ($stmt = $mysqli->prepare($sql)) {
            $stmt->bind_param("sss", $admin_id, $key, $value);
            $ok = $stmt->execute();
            $stmt->close();
            return $ok;
        }
        return false;
    }
}
