if (!function_exists('normalize_workspace_order_pages')) {
    function normalize_workspace_order_pages(array $ordered_pages, array $allowed_pages = [])
    {
        $normalized = [];
        foreach ($ordered_pages as $page_key) {
            $page_key = trim((string) $page_key);
            if ($page_key === '') {
                continue;
            }
            if (!empty($allowed_pages) && !in_array($page_key, $allowed_pages, true)) {
                continue;
            }
            if (isset($normalized[$page_key])) {
                continue;
            }
            $normalized[$page_key] = true;
        }
        return array_keys($normalized);
    }
}
if (!function_exists('save_workspace_card_order')) {
    function save_workspace_card_order($mysqli, $admin_id, array $ordered_pages, array $allowed_pages = [])
    {
        $admin_id = trim((string) $admin_id);
        if ($admin_id === '') {
            $admin_id = 'SYSTEM_WIDE';
        }

        $ordered_pages = normalize_workspace_order_pages($ordered_pages, $allowed_pages);

        $started_tx = false;
        try {
            if (method_exists($mysqli, 'begin_transaction')) {
                $mysqli->begin_transaction();
                $started_tx = true;
            } else {
                $mysqli->autocommit(false);
                $started_tx = true;
            }

            if (!($delete_stmt = $mysqli->prepare("DELETE FROM workspace_card_orders WHERE admin_id = ?"))) {
                throw new RuntimeException('Cannot prepare workspace order delete statement.');
            }
            $delete_stmt->bind_param("s", $admin_id);
            if (!$delete_stmt->execute()) {
                $delete_stmt->close();
                throw new RuntimeException('Cannot clear previous workspace order.');
            }
            $delete_stmt->close();

            if (!empty($ordered_pages)) {
                if (!($insert_stmt = $mysqli->prepare("INSERT INTO workspace_card_orders (admin_id, page_key, sort_order) VALUES (?, ?, ?)"))) {
                    throw new RuntimeException('Cannot prepare workspace order insert statement.');
                }

                foreach ($ordered_pages as $idx => $page_key) {
                    $sort_order = (int) $idx;
                    $insert_stmt->bind_param("ssi", $admin_id, $page_key, $sort_order);
                    if (!$insert_stmt->execute()) {
                        $insert_stmt->close();
                        throw new RuntimeException('Cannot insert workspace order row.');
                    }
                }
                $insert_stmt->close();
            }

            // Mirror to legacy app_settings key for compatibility/fallback.
            if (!update_setting($mysqli, $admin_id, 'workspace_card_order', json_encode($ordered_pages, JSON_UNESCAPED_UNICODE))) {
                throw new RuntimeException('Cannot mirror workspace order to app_settings.');
            }

            if ($started_tx) {
                $mysqli->commit();
            }
            return true;
        } catch (Throwable $e) {
            if ($started_tx) {
                try {
                    $mysqli->rollback();
                } catch (Throwable $ignore) {
                }
            }
            error_log('[workspace_card_order.save] ' . $e->getMessage() . ' admin_id=' . $admin_id);
            return false;
        } finally {
            try {
                $mysqli->autocommit(true);
            } catch (Throwable $ignore) {
            }
        }
    }
}
if (!function_exists('get_workspace_card_order')) {
    function get_workspace_card_order($mysqli, $admin_id, array $allowed_pages = [])
    {
        $admin_id = trim((string) $admin_id);
        if ($admin_id === '') {
            $admin_id = 'SYSTEM_WIDE';
        }

        $ordered_pages = [];
        if ($stmt = $mysqli->prepare("SELECT page_key FROM workspace_card_orders WHERE admin_id = ? ORDER BY sort_order ASC, updated_at ASC")) {
            $stmt->bind_param("s", $admin_id);
            if ($stmt->execute()) {
                $res = $stmt->get_result();
                while ($row = $res->fetch_assoc()) {
                    $ordered_pages[] = (string) ($row['page_key'] ?? '');
                }
            }
            $stmt->close();
        }

        $ordered_pages = normalize_workspace_order_pages($ordered_pages, $allowed_pages);
        if (!empty($ordered_pages)) {
            return $ordered_pages;
        }

        // Legacy fallback from app_settings. If found, migrate it to the dedicated table.
        $legacy_raw = get_setting($mysqli, $admin_id, 'workspace_card_order', '[]');
        $legacy_decoded = json_decode((string) $legacy_raw, true);
        if (!is_array($legacy_decoded)) {
            $legacy_decoded = [];
        }
        $legacy_decoded = normalize_workspace_order_pages($legacy_decoded, $allowed_pages);
        if (!empty($legacy_decoded)) {
            save_workspace_card_order($mysqli, $admin_id, $legacy_decoded, $allowed_pages);
        }

        return $legacy_decoded;
    }
}
