if (!function_exists('isSidebarHidden')) {
    function isSidebarHidden($mysqli, $pageKey, $actionKey = null, $admin_id = null)
    {
        global $admin_pages_list;

        $pageKey = trim((string) $pageKey);
        $actionKey = ($actionKey === null) ? null : trim((string) $actionKey);
        $admin_id = ($admin_id === null) ? null : trim((string) $admin_id);

        // Backward-compat: many call sites use legacy signature
        // isSidebarHidden($mysqli, $admin_id, $page_key, $action_key).
        $known_pages = array_keys($admin_pages_list ?? []);
        $known_pages[] = 'dashboard';
        $known_pages[] = 'homes';
        $known_pages[] = 'stock';
        $known_pages = array_values(array_unique($known_pages));

        $looks_like_page = in_array($pageKey, $known_pages, true);
        $action_looks_like_page = ($actionKey !== null && in_array($actionKey, $known_pages, true));
        if (!$looks_like_page && $action_looks_like_page) {
            $legacy_admin = $pageKey;
            $pageKey = $actionKey;
            $actionKey = ($admin_id !== null && $admin_id !== '') ? $admin_id : null;
            $admin_id = $legacy_admin;
        }

        static $cache = [];
        $cacheKey = 'sidebar_hidden_items_' . (($admin_id !== null && $admin_id !== '') ? $admin_id : 'SYSTEM_WIDE');
        if (!isset($cache[$cacheKey])) {
            if ($admin_id !== null && $admin_id !== '') {
                $json = get_setting($mysqli, $admin_id, 'sidebar_hidden_items', get_setting($mysqli, 'sidebar_hidden_items', '[]'));
            } else {
                $json = get_setting($mysqli, 'sidebar_hidden_items', '[]');
            }
            $cache[$cacheKey] = json_decode($json, true) ?: [];
        }

        $hidden = $cache[$cacheKey];
        if ($actionKey !== null && $actionKey !== '') {
            $fullKey = $pageKey . ':' . $actionKey;
            return in_array($fullKey, $hidden, true);
        }
        return in_array($pageKey, $hidden, true);
    }
}

if (!function_exists('get_app_scan_setting')) {
    if (!function_exists('is_system_wide_app_scan_key')) {
        function is_system_wide_app_scan_key($key)
        {
            static $global_keys = ['app_latest_version', 'app_latest_build', 'app_apk_url', 'app_update_message', 'app_force_update'];
            return in_array((string) $key, $global_keys, true);
        }
    }

    function get_app_scan_setting($mysqli, ...$args)
    {
        static $app_settings_cache = [];

        $admin_id = null;
        $key = '';
        $default = '';

        // Signature detection: (mysqli, key, default) or (mysqli, admin_id, key, default)
        if (count($args) >= 3) {
            $admin_id = $args[0];
            $key = $args[1];
            $default = $args[2];
        } elseif (count($args) == 2) {
            $key = $args[0];
            $default = $args[1];
        } elseif (count($args) == 1) {
            $key = $args[0];
        }

        if (empty($key))
            return $default;

        if (isset($_POST['ajax_action']) && $_POST['ajax_action'] === 'save_app_scan_settings') {
            $app_settings_cache = [];
        }

        if (is_system_wide_app_scan_key($key)) {
            $admin_id = 'SYSTEM_WIDE';
        }

        $resolved_admin_id = (!empty($admin_id)) ? (string) $admin_id : 'SYSTEM_WIDE';
        $cache_key = $resolved_admin_id . '::' . $key;
        if (isset($app_settings_cache[$cache_key]))
            return $app_settings_cache[$cache_key];

        $sql = "SELECT setting_value FROM app_scan_settings 
                WHERE setting_key = ? 
                AND (admin_id = ? OR admin_id = 'SYSTEM_WIDE') 
                ORDER BY (admin_id = ?) DESC LIMIT 1";
        if ($stmt = $mysqli->prepare($sql)) {
            $stmt->bind_param("sss", $key, $resolved_admin_id, $resolved_admin_id);
            $stmt->execute();
            $res = $stmt->get_result();
            if ($row = $res->fetch_assoc()) {
                $val = $row['setting_value'];
                $app_settings_cache[$cache_key] = $val;
                $stmt->close();
                return $val;
            }
            $stmt->close();
        }
        return $default;
    }
}

if (!function_exists('update_app_scan_setting')) {
    function update_app_scan_setting($mysqli, ...$args)
    {
        global $current_admin_id;
        $admin_id = null;
        $key = '';
        $value = '';

        if (count($args) >= 3) {
            $admin_id = $args[0];
            $key = $args[1];
            $value = $args[2];
        } else {
            $key = $args[0];
            $value = $args[1];
            $admin_id = $current_admin_id;
        }

        if (empty($admin_id))
            $admin_id = 'SYSTEM_WIDE';
        if (empty($key))
            return false;
        if (is_system_wide_app_scan_key($key)) {
            $admin_id = 'SYSTEM_WIDE';
        }

        $sql = "INSERT INTO app_scan_settings (admin_id, setting_key, setting_value) VALUES (?, ?, ?)
                ON DUPLICATE KEY UPDATE setting_value = VALUES(setting_value)";
        if ($stmt = $mysqli->prepare($sql)) {
            $stmt->bind_param("sss", $admin_id, $key, $value);
            $ok = $stmt->execute();
            $stmt->close();
            return $ok;
        }
        return false;
    }
}

if (!function_exists('ensure_payroll_biometric_records_table')) {
    function ensure_payroll_biometric_records_table($mysqli)
    {
        $mysqli->query("CREATE TABLE IF NOT EXISTS payroll_biometric_records (
            id INT AUTO_INCREMENT PRIMARY KEY,
            employee_id VARCHAR(64) NOT NULL,
            employee_name VARCHAR(255) DEFAULT NULL,
            purpose VARCHAR(50) NOT NULL DEFAULT 'payroll',
            verification_count INT NOT NULL DEFAULT 1,
            first_verified_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
            last_verified_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
            last_platform VARCHAR(80) DEFAULT NULL,
            last_auth_method VARCHAR(80) DEFAULT NULL,
            last_ip_address VARCHAR(45) DEFAULT NULL,
            last_user_agent VARCHAR(255) DEFAULT NULL,
            UNIQUE KEY uniq_emp_purpose (employee_id, purpose),
            KEY idx_last_verified (last_verified_at)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");
    }
}

if (!function_exists('fetch_payroll_biometric_records')) {
    function fetch_payroll_biometric_records($mysqli, $limit = 100)
    {
        ensure_payroll_biometric_records_table($mysqli);
        $limit = max(1, min(500, (int) $limit));
        $records = [];
        $sql = "SELECT b.id, b.employee_id,
                       COALESCE(NULLIF(b.employee_name, ''), u.name, b.employee_id) AS employee_name,
                       u.department, u.position,
                       b.verification_count, b.first_verified_at, b.last_verified_at,
                       DATE_FORMAT(b.first_verified_at, '%d/%m/%Y %h:%i %p') AS first_verified_at_formatted,
                       DATE_FORMAT(b.last_verified_at, '%d/%m/%Y %h:%i %p') AS last_verified_at_formatted,
                       b.last_platform, b.last_auth_method, b.last_ip_address
                FROM payroll_biometric_records b
                LEFT JOIN users u ON b.employee_id = u.employee_id
                WHERE b.purpose = 'payroll'
                ORDER BY b.last_verified_at DESC
                LIMIT $limit";
        if ($result = $mysqli->query($sql)) {
            while ($row = $result->fetch_assoc()) {
                $records[] = $row;
            }
            $result->close();
        }
        return $records;
    }
}


if (!function_exists('initialize_sidebar_settings')) {
    /**
     * Function to populate sidebar settings for a specific admin if their settings are empty.
     * @param mysqli $mysqli Database connection
     */
    function initialize_sidebar_settings($mysqli, $admin_id = null)
    {
        global $admin_pages_list;

        // 1. ពិនិត្យ និងបង្កើត Main Menu
        $check_sql = "SELECT COUNT(*) as count FROM sidebar_settings";
        $res = $mysqli->query($check_sql);
        $count = $res ? $res->fetch_assoc()['count'] : 0;

        if ($count == 0) {
            $default_menu = [
                'homes' => ['text' => 'ទំព័រដើម', 'icon' => 'fa-solid fa-house', 'order' => 10],
                'users' => ['text' => 'គ្រប់គ្រងអ្នកប្រើប្រាស់', 'icon' => 'fa-solid fa-users', 'order' => 20],
                'reports' => ['text' => 'របាយការណ៍វត្តមាន', 'icon' => 'fa-solid fa-chart-simple', 'order' => 30],
                'requests' => ['text' => 'គ្រប់គ្រងសំណើរ', 'icon' => 'fa-solid fa-file-signature', 'order' => 40],
                'notifications' => ['text' => 'ការជូនដំណឹង', 'icon' => 'fa-solid fa-bell', 'order' => 45],
                'locations' => ['text' => 'គ្រប់គ្រងទីតាំង/QR', 'icon' => 'fa-solid fa-map-location-dot', 'order' => 50],
                'categories' => ['text' => 'គ្រប់គ្រងប្រភេទ', 'icon' => 'fa-solid fa-folder-open', 'order' => 60],
                'tokens' => ['text' => 'គ្រប់គ្រង Token & Session', 'icon' => 'fa-solid fa-key', 'order' => 70],
                'settings' => ['text' => 'ការកំណត់', 'icon' => 'fa-solid fa-cogs', 'order' => 80]
            ];

            $sql = "INSERT IGNORE INTO sidebar_settings (menu_key, menu_text, icon_class, menu_order) VALUES (?, ?, ?, ?)";
            if ($stmt = $mysqli->prepare($sql)) {
                foreach ($default_menu as $key => $details) {
                    $stmt->bind_param("sssi", $key, $details['text'], $details['icon'], $details['order']);
                    $stmt->execute();
                }
                $stmt->close();
            }
        }

        // Ensure any new pages added to $admin_pages_list are present.
        try {
            $existing = [];
            if ($sel = $mysqli->prepare("SELECT menu_key FROM sidebar_settings")) {
                $sel->execute();
                $res = $sel->get_result();
                while ($r = $res->fetch_assoc()) {
                    $existing[] = $r['menu_key'];
                }
                $sel->close();
            }

            $ins = $mysqli->prepare("INSERT IGNORE INTO sidebar_settings (menu_key, menu_text, icon_class, menu_order) VALUES (?, ?, ?, ?)");
            if ($ins) {
                foreach ($admin_pages_list as $key => $actions) {
                    if (in_array($key, $existing, true)) {
                        continue;
                    }
                    $menu_text = ucfirst(str_replace('_', ' ', $key));
                    $icon = 'fa-solid fa-folder';
                    $order = 9999; // put new items at end by default
                    $ins->bind_param("sssi", $key, $menu_text, $icon, $order);
                    $ins->execute();
                }
                $ins->close();
            }
        } catch (Exception $e) {
            // Non-fatal
        }

        // 2. ពិនិត្យ និងបង្កើត Submenu
        $check_submenu_sql = "SELECT COUNT(*) as count FROM submenu_settings";
        $stmt_check_submenu = $mysqli->prepare($check_submenu_sql);
        $stmt_check_submenu->execute();
        $submenu_result = $stmt_check_submenu->get_result();
        $submenu_count = $submenu_result ? $submenu_result->fetch_assoc()['count'] : 0;
        $stmt_check_submenu->close();

        if ($submenu_count == 0) {
            $submenu_sql = "INSERT IGNORE INTO submenu_settings (menu_key, action_key, submenu_text) VALUES (?, ?, ?)";
            if ($stmt_submenu = $mysqli->prepare($submenu_sql)) {
                foreach ($admin_pages_list as $menu_key => $actions) {
                    if (count($actions) <= 1 && isset($actions[$menu_key]))
                        continue;
                    foreach ($actions as $action_key => $action_text) {
                        $stmt_submenu->bind_param("sss", $menu_key, $action_key, $action_text);
                        $stmt_submenu->execute();
                    }
                }
                $stmt_submenu->close();
            }
        }
    }
}

// These variables will be defined after successful login or before login page display.
$panel_title = 'Admin Panel'; // Default value
$panel_logo_path = '';
$show_title_with_logo = true;
$footer_text = '';

