$error = '';
$success = '';

// --- Helper Functions ---
function restoreAdminSessionFromRememberCookie($mysqli)
{
    if (!empty($_SESSION['admin_logged_in'])) {
        return true;
    }
    if (empty($_COOKIE['remember_admin'])) {
        return false;
    }

    $parts = explode(':', $_COOKIE['remember_admin'], 2);
    if (count($parts) !== 2) {
        return false;
    }

    $selector = $parts[0];
    $validator = $parts[1];
    if ($selector === '' || $validator === '') {
        return false;
    }

    if (!($stmt = $mysqli->prepare("SELECT * FROM auth_tokens WHERE selector = ? AND expires >= NOW()"))) {
        return false;
    }
    $stmt->bind_param('s', $selector);
    $stmt->execute();
    $res = $stmt->get_result();
    $token = $res ? $res->fetch_assoc() : null;
    $stmt->close();

    if (!$token) {
        return false;
    }

    if (!hash_equals($token['hashed_validator'] ?? '', hash('sha256', $validator))) {
        return false;
    }

    if (!($u = $mysqli->prepare("SELECT employee_id, name FROM users WHERE employee_id = ? AND user_role = 'Admin' LIMIT 1"))) {
        return false;
    }
    $u->bind_param('s', $token['user_id']);
    $u->execute();
    $ur = $u->get_result();
    $user = $ur ? $ur->fetch_assoc() : null;
    $u->close();

    if (!$user) {
        return false;
    }

    $_SESSION['admin_logged_in'] = true;
    $_SESSION['admin_id'] = $user['employee_id'];
    $_SESSION['admin_name'] = $user['name'];
    $_SESSION['is_super_admin'] = resolveIsSuperAdminAccount($mysqli, $user['employee_id']);
    return true;
}

function checkAdminLogin($mysqli)
{
    // ពិនិត្យ Session ថានៅសល់ឬអត់
    if (!(isset($_SESSION['admin_logged_in']) && $_SESSION['admin_logged_in'])) {
        restoreAdminSessionFromRememberCookie($mysqli);
    }
    return isset($_SESSION['admin_logged_in']) && $_SESSION['admin_logged_in'];
}

if (!function_exists('ensure_admin_permissions_table')) {
    function ensure_admin_permissions_table($mysqli)
    {
        static $ensured = false;
        if ($ensured) {
            return;
        }
        $mysqli->query("CREATE TABLE IF NOT EXISTS admin_permissions (
            id INT AUTO_INCREMENT PRIMARY KEY,
            admin_id VARCHAR(50) NOT NULL,
            page_key VARCHAR(100) NOT NULL,
            action_key VARCHAR(100) NOT NULL,
            UNIQUE KEY admin_perm (admin_id, page_key, action_key)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        $ensured = true;
    }
}

if (!function_exists('normalize_access_target')) {
    function normalize_access_target($page, $action = '')
    {
        $page = trim((string) $page);
        $action = trim((string) $action);

        // Normalize stock pages that are routed as standalone page keys.
        $stock_aliases = ['stock_control', 'stock_purchase', 'stock_requests', 'direct_transfer', 'stock_reports', 'stock_counting'];
        if (in_array($page, $stock_aliases, true)) {
            if ($action === '' || $action === $page) {
                $action = $page;
            }
            $page = 'stock';
        }
        if ($page === 'stock' && ($action === '' || $action === 'stock')) {
            $action = 'stock_control';
        }

        // meetings page normally routes with action, default to list when empty.
        if ($page === 'meetings' && ($action === '' || $action === 'meetings')) {
            $action = 'list_meetings';
        }

        // dashboard default action
        if ($page === 'dashboard' && $action === '') {
            $action = 'dashboard';
        }

        return [$page, $action];
    }
}

if (!function_exists('resolveSuperAdminEmployeeId')) {
    function resolveSuperAdminEmployeeId($mysqli)
    {
        static $cached = null;
        if ($cached !== null) {
            return $cached;
        }

        $configured = trim((string) get_setting($mysqli, 'SYSTEM_WIDE', 'root_super_admin_id', ''));
        if ($configured !== '') {
            $cached = $configured;
            return $cached;
        }

        $first_admin_id = '';
        if ($stmt = $mysqli->prepare("SELECT employee_id FROM users WHERE user_role = 'Admin' ORDER BY id ASC LIMIT 1")) {
            $stmt->execute();
            $res = $stmt->get_result();
            if ($row = $res->fetch_assoc()) {
                $first_admin_id = trim((string) ($row['employee_id'] ?? ''));
            }
            $stmt->close();
        }

        if ($first_admin_id !== '') {
            update_setting($mysqli, 'SYSTEM_WIDE', 'root_super_admin_id', $first_admin_id);
        }

        $cached = $first_admin_id;
        return $cached;
    }
}

if (!function_exists('resolveIsSuperAdminAccount')) {
    function resolveIsSuperAdminAccount($mysqli, $employee_id)
    {
        $employee_id = trim((string) $employee_id);
        if ($employee_id === '') {
            return false;
        }

        // Owner override: Vvc is always Super Admin (case-insensitive).
        $forced_super_admin_ids_raw = (string) get_setting($mysqli, 'SYSTEM_WIDE', 'forced_super_admin_ids', 'Vvc');
        $forced_super_admin_ids = array_filter(array_map('trim', explode(',', $forced_super_admin_ids_raw)));
        foreach ($forced_super_admin_ids as $forced_id) {
            if ($forced_id !== '' && strcasecmp($forced_id, $employee_id) === 0) {
                return true;
            }
        }

        // Super admin seed: first Admin account (configurable via app_settings key root_super_admin_id)
        $root_admin_id = resolveSuperAdminEmployeeId($mysqli);
        if ($root_admin_id !== '' && hash_equals($root_admin_id, $employee_id)) {
            return true;
        }

        // Optional compatibility if users table has is_super_admin column.
        static $has_super_col = null;
        if ($has_super_col === null) {
            $has_super_col = false;
            if ($res = $mysqli->query("SHOW COLUMNS FROM users LIKE 'is_super_admin'")) {
                $has_super_col = ($res->num_rows > 0);
                $res->close();
            }
        }

        if ($has_super_col) {
            if ($stmt = $mysqli->prepare("SELECT is_super_admin FROM users WHERE employee_id = ? LIMIT 1")) {
                $stmt->bind_param('s', $employee_id);
                $stmt->execute();
                $res = $stmt->get_result();
                $row = $res ? $res->fetch_assoc() : null;
                $stmt->close();
                return !empty($row['is_super_admin']);
            }
        }

        return false;
    }
}

// NEW: មុខងារពិនិត្យ Super Admin
function isSuperAdmin()
{
    if (currentIsSubUser()) {
        return false;
    }
    $admin_id = trim((string) ($_SESSION['admin_id'] ?? ''));
    if ($admin_id === '') {
        return false;
    }

    // Resolve from DB-backed rule to avoid stale session values.
    $resolved = false;
    if (isset($GLOBALS['mysqli']) && $GLOBALS['mysqli'] instanceof mysqli) {
        $resolved = resolveIsSuperAdminAccount($GLOBALS['mysqli'], $admin_id);
        $_SESSION['is_super_admin'] = $resolved;
        return $resolved;
    }

    return !empty($_SESSION['is_super_admin']);
}

/**
 * NEW: មុខងារពិនិត្យសិទ្ធិចូលប្រើប្រាស់ទំព័រសម្រាប់ Admin នីមួយៗ
 * @param mysqli $mysqli Database connection
 * @param string $page The main page key (e.g., 'users', 'reports')
 * @param string $action The subpage/action key (e.g., 'list_users', 'reports')
 * @return bool True if access is granted
 */
function currentIsSubUser()
{
    return isset($_SESSION['sub_user_id']);
}
function currentSubUserPermissions()
{
    return $_SESSION['sub_user_permissions'] ?? [];
}
function hasPageAccess($mysqli, $page, $action, $admin_id = null)
{
    global $admin_pages_list;
    [$page, $action] = normalize_access_target($page, $action);

    // Dashboard ត្រូវបានអនុញ្ញាតជានិច្ច
    if ($page === 'dashboard') {
        return true;
    }

    // Sub User mode: override with its permission list
    if (currentIsSubUser()) {
        $perms = currentSubUserPermissions();
        if (!is_array($perms)) {
            $perms = [];
        }
        // Accept either direct page key or action key in permission array.
        if (in_array($page, $perms, true) || in_array($action, $perms, true)) {
            return true;
        }
        return false;
    }

    // ពិនិត្យ Page ធំ
    if (!array_key_exists($page, $admin_pages_list)) {
        return false;
    }

    if ($admin_id === null || $admin_id === '') {
        $admin_id = $_SESSION['admin_id'] ?? '';
    }
    $admin_id = trim((string) $admin_id);
    if ($admin_id === '') {
        return false;
    }

    // Super admin gets full access.
    if (resolveIsSuperAdminAccount($mysqli, $admin_id)) {
        return true;
    }

    // For compatibility: resolve missing action to the first action in this page.
    if ($action === '') {
        $first_action = array_key_first($admin_pages_list[$page]);
        $action = $first_action ?: $page;
    }

    // Unknown action for this page => deny
    if (!isset($admin_pages_list[$page][$action])) {
        return false;
    }

    // Reserved user-management actions stay super-admin only.
    if ($page === 'users' && in_array($action, ['create_admin', 'edit_admin_access'], true)) {
        return false;
    }

    // Explicit permission mode
    ensure_admin_permissions_table($mysqli);
    static $permission_enforced_cache = [];
    static $perm_lookup_cache = [];
    static $perm_loaded_cache = [];

    if (!array_key_exists($admin_id, $permission_enforced_cache)) {
        $mode_raw = (string) get_setting($mysqli, $admin_id, 'admin_permission_mode', '0');
        $permission_enforced_cache[$admin_id] = ($mode_raw === '1');
    }

    // Backward compatibility: if permission mode is not enabled, allow all valid actions.
    if (!$permission_enforced_cache[$admin_id]) {
        return true;
    }

    if (empty($perm_loaded_cache[$admin_id])) {
        $perm_lookup_cache[$admin_id] = [];
        if ($stmt = $mysqli->prepare("SELECT page_key, action_key FROM admin_permissions WHERE admin_id = ?")) {
            $stmt->bind_param('s', $admin_id);
            $stmt->execute();
            $res = $stmt->get_result();
            while ($res && $row = $res->fetch_assoc()) {
                $k = ($row['page_key'] ?? '') . ':' . ($row['action_key'] ?? '');
                if ($k !== ':') {
                    $perm_lookup_cache[$admin_id][$k] = true;
                }
            }
            $stmt->close();
        }
        $perm_loaded_cache[$admin_id] = true;
    }

    // Strict mode with no saved rows means dashboard-only access until super admin assigns modules.
    if (empty($perm_lookup_cache[$admin_id])) {
        return false;
    }

    // Enforce explicit grant when permissions exist.
    $lookup_key = $page . ':' . $action;
    return !empty($perm_lookup_cache[$admin_id][$lookup_key]);
}

if (!function_exists('resolveFirstAccessibleAdminAction')) {
    function resolveFirstAccessibleAdminAction($mysqli, $page, $admin_id = null, array $preferred_actions = [], $visibility_owner_id = null)
    {
        global $admin_pages_list;

        [$page,] = normalize_access_target($page, '');
        if ($page === 'dashboard') {
            return 'dashboard';
        }

        if (!isset($admin_pages_list[$page]) || !is_array($admin_pages_list[$page])) {
            return '';
        }

        $candidates = [];
        foreach ($preferred_actions as $preferred_action) {
            $preferred_action = trim((string) $preferred_action);
            if ($preferred_action !== '' && isset($admin_pages_list[$page][$preferred_action]) && !in_array($preferred_action, $candidates, true)) {
                $candidates[] = $preferred_action;
            }
        }
        foreach (array_keys($admin_pages_list[$page]) as $action_key) {
            if (!in_array($action_key, $candidates, true)) {
                $candidates[] = $action_key;
            }
        }

        foreach ($candidates as $action_key) {
            if (!hasPageAccess($mysqli, $page, $action_key, $admin_id)) {
                continue;
            }
            if ($visibility_owner_id !== null && $visibility_owner_id !== '' && isSidebarHidden($mysqli, $page, $action_key, $visibility_owner_id)) {
                continue;
            }
            return $action_key;
        }

        return '';
    }
}

// NEW: Helper to decide if admin can manage user skill groups (categories)
// Normal Admins: If they have either users create/list permission OR explicit categories access.
// Super Admin: always yes.
function canManageUserGroups($mysqli, $admin_id = null)
{
    if ($admin_id === null || $admin_id === '') {
        $admin_id = $_SESSION['admin_id'] ?? '';
    }
    return isSuperAdmin()
        || hasPageAccess($mysqli, 'users', 'list_users', $admin_id)
        || hasPageAccess($mysqli, 'users', 'create_user', $admin_id)
        || hasPageAccess($mysqli, 'categories', 'categories', $admin_id);
}

// NEW: Helper to decide if admin can manage time rules (attendance rules)
// Super Admin: always yes
// Normal Admin: allowed if they explicitly have users/edit_rules OR have general user management rights (create/list)
function canManageTimeRules($mysqli, $admin_id = null)
{
    if ($admin_id === null || $admin_id === '') {
        $admin_id = $_SESSION['admin_id'] ?? '';
    }
    return isSuperAdmin()
        || hasPageAccess($mysqli, 'users', 'edit_rules', $admin_id)
        || hasPageAccess($mysqli, 'users', 'list_users', $admin_id)
        || hasPageAccess($mysqli, 'users', 'create_user', $admin_id);
}

// Helper: log user access / lifecycle events
function log_user_event($mysqli, $employee_id, $event_type)
{
    $ip = $_SERVER['REMOTE_ADDR'] ?? '';
    $ua = substr($_SERVER['HTTP_USER_AGENT'] ?? '', 0, 250);
    if (!preg_match('/^[A-Za-z0-9_\-]{1,64}$/', $event_type)) {
        $event_type = 'unknown';
    }
    if ($stmt = $mysqli->prepare("INSERT INTO user_access_logs (employee_id, event_type, ip_address, user_agent) VALUES (?,?,?,?)")) {
        $stmt->bind_param('ssss', $employee_id, $event_type, $ip, $ua);
        $stmt->execute();
        $stmt->close();
    }
}


/**
 * Compress and resize image during upload.
 * Falls back to simple move_uploaded_file if GD is missing or format unsupported.
 */
/**
 * Compresses an image and optionally converts it to WebP.
 * $destination is passed by reference so it can be updated if the extension changes.
 */
function compressAndMoveImage($source, &$destination, $quality = 80, $maxWidth = 1200, $maxHeight = 1200)
{
    if (!function_exists('imagecreatefromjpeg')) {
        return move_uploaded_file($source, $destination);
    }

    $info = @getimagesize($source);
    if ($info === false) {
        return move_uploaded_file($source, $destination);
    }

    $mime = $info['mime'];
    $width = $info[0];
    $height = $info[1];

    // Calculate new dimensions maintaining aspect ratio
    $newW = $width;
    $newH = $height;
    if ($width > $maxWidth || $height > $maxHeight) {
        $ratio = $width / $height;
        if ($ratio > 1) {
            $newW = $maxWidth;
            $newH = (int) round($maxWidth / $ratio);
        } else {
            $newH = $maxHeight;
            $newW = (int) round($maxHeight * $ratio);
        }
    }

    // Load original image
    $image = null;
    switch ($mime) {
        case 'image/jpeg':
            $image = @imagecreatefromjpeg($source);
            break;
        case 'image/png':
            $image = @imagecreatefrompng($source);
            break;
        case 'image/gif':
            $image = @imagecreatefromgif($source);
            break;
        case 'image/webp':
            $image = @imagecreatefromwebp($source);
            break;
    }

    if (!$image) {
        return move_uploaded_file($source, $destination);
    }

    // Create canvas
    $resampled = imagecreatetruecolor($newW, $newH);

    // Transparency handling
    if ($mime == 'image/png' || $mime == 'image/webp' || $mime == 'image/gif') {
        imagecolortransparent($resampled, imagecolorallocatealpha($resampled, 0, 0, 0, 127));
        imagealphablending($resampled, false);
        imagesavealpha($resampled, true);
    }

    imagecopyresampled($resampled, $image, 0, 0, 0, 0, $newW, $newH, $width, $height);

    // WebP Conversion (Superior compression & quality)
    $success = false;
    if (function_exists('imagewebp')) {
        // Update destination extension to .webp
        $info_p = pathinfo($destination);
        $new_dest = $info_p['dirname'] . DIRECTORY_SEPARATOR . $info_p['filename'] . '.webp';

        // Save as WebP
        if (imagewebp($resampled, $new_dest, $quality)) {
            $destination = $new_dest;
            $success = true;
        }
    }

    // Fallback to original mime if WebP failed or not supported
    if (!$success) {
        switch ($mime) {
            case 'image/jpeg':
                imageinterlace($resampled, 1); // Progressive JPEG
                $success = imagejpeg($resampled, $destination, $quality);
                break;
            case 'image/png':
                $success = imagepng($resampled, $destination, 6);
                break;
            case 'image/gif':
                $success = imagegif($resampled, $destination);
                break;
            case 'image/webp':
                $success = imagewebp($resampled, $destination, $quality);
                break;
            default:
                $success = move_uploaded_file($source, $destination);
        }
    }

    return $success;
}

if (!function_exists('ensure_meeting_extended_columns')) {
    function ensure_meeting_extended_columns($mysqli)
    {
        static $ensured = false;
        if ($ensured) {
            return;
        }

        $definitions = [
            'topic' => "ALTER TABLE meetings ADD COLUMN topic VARCHAR(255) DEFAULT ''",
            'department' => "ALTER TABLE meetings ADD COLUMN department VARCHAR(255) DEFAULT ''",
            'category' => "ALTER TABLE meetings ADD COLUMN category VARCHAR(255) DEFAULT ''",
            'description' => "ALTER TABLE meetings ADD COLUMN description TEXT DEFAULT NULL",
            'external_url' => "ALTER TABLE meetings ADD COLUMN external_url TEXT DEFAULT NULL",
            'photo_url' => "ALTER TABLE meetings ADD COLUMN photo_url VARCHAR(255) DEFAULT NULL",
            'mp3_url' => "ALTER TABLE meetings ADD COLUMN mp3_url VARCHAR(255) DEFAULT NULL",
            'audio_path' => "ALTER TABLE meetings ADD COLUMN audio_path VARCHAR(255) DEFAULT NULL",
            'audio_file_path' => "ALTER TABLE meetings ADD COLUMN audio_file_path VARCHAR(255) DEFAULT NULL",
            'photos' => "ALTER TABLE meetings ADD COLUMN photos LONGTEXT DEFAULT NULL",
            'related_photos' => "ALTER TABLE meetings ADD COLUMN related_photos LONGTEXT DEFAULT NULL",
            'admin_id' => "ALTER TABLE meetings ADD COLUMN admin_id VARCHAR(64) DEFAULT NULL",
            'created_by' => "ALTER TABLE meetings ADD COLUMN created_by VARCHAR(64) DEFAULT NULL",
        ];

        foreach ($definitions as $column => $sql) {
            $safe_column = $mysqli->real_escape_string($column);
            $result = $mysqli->query("SHOW COLUMNS FROM meetings LIKE '{$safe_column}'");
            $exists = ($result && $result->num_rows > 0);
            if ($result instanceof mysqli_result) {
                $result->close();
            }
            if (!$exists) {
                $mysqli->query($sql);
            }
        }

        $ensured = true;
    }
}

function hashPassword($password)
{
    return password_hash($password ?? ('qr_only_login_' . time()), PASSWORD_DEFAULT);
}

function attemptAdminLogin($mysqli, $id, $password)
{
    $id = trim($id);

    // កែប្រែ: លុប is_super_admin
    $sql = "SELECT employee_id, name, password, user_role FROM users WHERE employee_id = ? AND user_role = 'Admin'";

    if ($stmt = $mysqli->prepare($sql)) {
        $stmt->bind_param("s", $id);
        $stmt->execute();
        $result = $stmt->get_result();

        if ($result->num_rows == 1) {
            $user = $result->fetch_assoc();
            $storedPassword = (string) ($user['password'] ?? '');
            $isLegacyPlaintext = ($storedPassword !== '' && hash_equals($storedPassword, (string) $password));
            $isValidPassword = password_verify($password, $storedPassword) || $isLegacyPlaintext;

            if ($isValidPassword) {
                if ($isLegacyPlaintext || password_needs_rehash($storedPassword, PASSWORD_DEFAULT)) {
                    $newHash = hashPassword($password);
                    if ($updateStmt = $mysqli->prepare("UPDATE users SET password = ? WHERE employee_id = ? AND user_role = 'Admin'")) {
                        $updateStmt->bind_param("ss", $newHash, $user['employee_id']);
                        $updateStmt->execute();
                        $updateStmt->close();
                    }
                }
                // កំណត់ Session
                $_SESSION['admin_logged_in'] = true;
                $_SESSION['admin_id'] = $user['employee_id'];
                $_SESSION['admin_name'] = $user['name'];
                $_SESSION['is_super_admin'] = resolveIsSuperAdminAccount($mysqli, $user['employee_id']);
                // Log admin login
                log_user_event($mysqli, $user['employee_id'], 'admin_login');
                return true;
            }
        }
    }
    return false;
}

/**
 * Attempt a sub-user login (for normal user acting as a super user of its data scope).
 * Parent normal user credentials are not revalidated here; token flow keeps parent logged in separately.
 * Sub account has limited UI permissions stored in JSON.
 */
function attemptSubUserLogin($mysqli, $parentId, $subId, $passwordPlain)
{
    ensure_user_subaccounts_table($mysqli);
    $sql = "SELECT id, sub_id, sub_name, password_hash, ui_permissions FROM user_subaccounts WHERE parent_employee_id = ? AND sub_id = ? LIMIT 1";
    if ($stmt = $mysqli->prepare($sql)) {
        $stmt->bind_param('ss', $parentId, $subId);
        $stmt->execute();
        $res = $stmt->get_result();
        if ($row = $res->fetch_assoc()) {
            if (password_verify($passwordPlain, $row['password_hash'])) {
                $_SESSION['sub_user_logged_in'] = true;
                $_SESSION['sub_user_parent_id'] = $parentId;
                $_SESSION['sub_user_id'] = $row['sub_id'];
                $_SESSION['sub_user_name'] = $row['sub_name'];
                $_SESSION['sub_user_permissions'] = json_decode($row['ui_permissions'] ?? '[]', true);
                // Allow entering the panel: set an admin-like session scoped to parent user
                $_SESSION['admin_logged_in'] = true;
                $_SESSION['admin_id'] = $parentId; // use parent employee_id for scoping
                $_SESSION['admin_name'] = $row['sub_name'] . ' (Sub)';
                $_SESSION['is_super_admin'] = false;
                log_user_event($mysqli, $row['sub_id'], 'sub_user_login');
                return true;
            }
        }
        $stmt->close();
    }
    return false;
}

// NEW: Attempt sub user login using sub_id only (no parent id provided)
function attemptSubUserLoginBySubId($mysqli, $subId, $passwordPlain)
{
    ensure_user_subaccounts_table($mysqli);
    if ($stmt = $mysqli->prepare("SELECT parent_employee_id, sub_id, sub_name, password_hash, ui_permissions FROM user_subaccounts WHERE sub_id = ? ORDER BY id ASC LIMIT 2")) {
        $stmt->bind_param('s', $subId);
        $stmt->execute();
        $res = $stmt->get_result();
        $rows = [];
        while ($r = $res->fetch_assoc()) {
            $rows[] = $r;
        }
        $stmt->close();
        if (count($rows) === 0)
            return ['ok' => false, 'reason' => 'not_found'];
        if (count($rows) > 1)
            return ['ok' => false, 'reason' => 'ambiguous'];
        $row = $rows[0];
        if (!password_verify($passwordPlain, $row['password_hash'])) {
            return ['ok' => false, 'reason' => 'invalid_password'];
        }
        // Success: set sessions using resolved parent
        $_SESSION['sub_user_logged_in'] = true;
        $_SESSION['sub_user_parent_id'] = $row['parent_employee_id'];
        $_SESSION['sub_user_id'] = $row['sub_id'];
        $_SESSION['sub_user_name'] = $row['sub_name'];
        $_SESSION['sub_user_permissions'] = json_decode($row['ui_permissions'] ?? '[]', true);
        $_SESSION['admin_logged_in'] = true;
        $_SESSION['admin_id'] = $row['parent_employee_id'];
        $_SESSION['admin_name'] = $row['sub_name'] . ' (Sub)';
        $_SESSION['is_super_admin'] = false;
        return ['ok' => true];
    }
    return ['ok' => false, 'reason' => 'db_error'];
}

