/**
 * បង្ហាប់រូបភាពឲ្យមានទំហំមិនលើសពីកំណត់ (សម្រាប់ Stock Control)
 */
function compressStockImage(string $source, string $destination, int $maxSizeBytes = 1048576, int $maxWidth = 1024): bool
{
    $info = getimagesize($source);
    if (!$info)
        return false;
    $mime = $info['mime'];
    $quality = 75;
    $scale = 1.0;
    switch ($mime) {
        case 'image/jpeg':
            $image = @imagecreatefromjpeg($source);
            break;
        case 'image/png':
            $image = @imagecreatefrompng($source);
            break;
        case 'image/gif':
            $image = @imagecreatefromgif($source);
            break;
        default:
            return false;
    }
    if (!$image)
        return false;
    $width = imagesx($image);
    $height = imagesy($image);
    $newWidth = $width;
    $newHeight = $height;
    $tempFile = tempnam(sys_get_temp_dir(), 'img');
    do {
        $newImage = imagecreatetruecolor($newWidth, $newHeight);
        if ($mime == 'image/png' || $mime == 'image/gif') {
            imagealphablending($newImage, false);
            imagesavealpha($newImage, true);
            $transparent = imagecolorallocatealpha($newImage, 0, 0, 0, 127);
            imagefill($newImage, 0, 0, $transparent);
        }
        imagecopyresampled($newImage, $image, 0, 0, 0, 0, $newWidth, $newHeight, $width, $height);
        if ($mime == 'image/jpeg')
            imagejpeg($newImage, $tempFile, $quality);
        elseif ($mime == 'image/png')
            imagepng($newImage, $tempFile, 9);
        elseif ($mime == 'image/gif')
            imagegif($newImage, $tempFile);

        $fileSize = filesize($tempFile);
        if ($fileSize > $maxSizeBytes) {
            if ($mime == 'image/jpeg')
                $quality -= 10;
            else {
                $scale *= 0.9;
                $newWidth = (int) ($width * $scale);
                $newHeight = (int) ($height * $scale);
            }
        }
    } while ($fileSize > $maxSizeBytes && ($quality > 10 || $scale > 0.5));
    if ($fileSize <= $maxSizeBytes)
        copy($tempFile, $destination);
    else
        copy($source, $destination);
    @unlink($tempFile);
    return true;
}

/**
 * លុបទំនិញ និងទិន្នន័យដែលពាក់ព័ន្ធ
 */
function deleteStockItem($pdo, int $id): void
{
    if ($id <= 0)
        throw new Exception("លេខសម្គាល់ទំនិញមិនត្រឹមត្រូវ។");
    $pdo->beginTransaction();
    try {
        $stmt = $pdo->prepare("SELECT image_path FROM stock_items WHERE id = ?");
        $stmt->execute([$id]);
        $item = $stmt->fetch(PDO::FETCH_ASSOC);
        if (!$item)
            throw new Exception("រកមិនឃើញទំនិញ។");
        $stmt = $pdo->prepare("DELETE FROM stock_request_items WHERE item_id = ?");
        $stmt->execute([$id]);
        $stmt = $pdo->prepare("DELETE FROM stock_count_history WHERE item_id = ?");
        $stmt->execute([$id]);
        if (!empty($item['image_path']) && file_exists($item['image_path']))
            @unlink($item['image_path']);
        $stmt = $pdo->prepare("DELETE FROM stock_items WHERE id = ?");
        $stmt->execute([$id]);
        $pdo->commit();
    } catch (Exception $e) {
        $pdo->rollBack();
        throw $e;
    }
}

