                $where[] = 'employment_status = ?';
                $types .= 's';
                $params[] = $employment_status;
            }

            if ($search !== '') {
                $like = '%' . $search . '%';
                $where[] = '(employee_id LIKE ? OR name LIKE ? OR latin_name LIKE ? OR username LIKE ? OR phone LIKE ? OR department LIKE ? OR position LIKE ?)';
                $types .= 'sssssss';
                array_push($params, $like, $like, $like, $like, $like, $like, $like);
            }

            $sql = "SELECT employee_id, name, latin_name, user_role, system_role, system_role_label, position, department, username, email, phone, avatar, employment_status, is_verified, joined_at FROM users";
            if (!empty($where)) {
                $sql .= " WHERE " . implode(' AND ', $where);
            }
            $sql .= " ORDER BY employee_id DESC LIMIT ?";
            $types .= 'i';
            $params[] = $limit;

            $users = [];
            if ($stmt = $mysqli->prepare($sql)) {
                $stmt->bind_param($types, ...$params);
                $stmt->execute();
                $result = $stmt->get_result();
                while ($row = $result->fetch_assoc()) {
                    $row['is_verified'] = (int) ($row['is_verified'] ?? 0);
                    $users[] = $row;
                }
                $stmt->close();
                $response = ['status' => 'success', 'data' => ['users' => $users]];
            } else {
                $response = ['status' => 'error', 'message' => 'Database prepare error: ' . $mysqli->error];
            }
            break;

        case 'save_meeting':
            // Require login for this action
            if (!checkAdminLogin($mysqli)) {
                $response = ['status' => 'error', 'message' => 'អ្នកមិនបាន Log In!'];
                echo json_encode($response, JSON_UNESCAPED_UNICODE);
                exit;
            }
            $current_admin_id = $_SESSION['admin_id'] ?? ($_SESSION['sub_user_parent_id'] ?? ($_SESSION['sub_user_id'] ?? 'SYSTEM_WIDE'));
            if (!hasPageAccess($mysqli, 'meetings', 'post_meeting', $current_admin_id)) {
                $response = ['status' => 'error', 'message' => 'Permission denied.'];
                echo json_encode($response, JSON_UNESCAPED_UNICODE);
                exit;
            }

            ensure_meeting_extended_columns($mysqli);

            $meeting_id = (int) ($_POST['id'] ?? 0);
            $meeting_title = trim((string) ($_POST['title'] ?? $_POST['topic'] ?? ''));
            $meeting_category = trim((string) ($_POST['category'] ?? $_POST['department'] ?? ''));
            $meeting_date = trim((string) ($_POST['meeting_date'] ?? $_POST['date'] ?? date('Y-m-d')));
            $external_url = trim((string) ($_POST['external_url'] ?? ''));
            $description = trim((string) ($_POST['description'] ?? ''));

            if ($meeting_category === '') {
                $meeting_category = 'General';
            }

            if ($meeting_title === '') {
                $response = ['status' => 'error', 'message' => 'សូមបំពេញចំណងជើងកិច្ចប្រជុំ។'];
                echo json_encode($response, JSON_UNESCAPED_UNICODE);
                exit;
            }

            $audio_path = trim((string) ($_POST['mp3_url'] ?? $_POST['audio_file_path'] ?? $_POST['audio_path'] ?? ''));
            foreach (['audio', 'audio_file'] as $audio_field) {
                if (!isset($_FILES[$audio_field]) || ($_FILES[$audio_field]['error'] ?? UPLOAD_ERR_NO_FILE) !== 0) {
                    continue;
                }
                $audio_dir = 'uploads/meetings/audio/';
                if (!is_dir($audio_dir)) {
                    mkdir($audio_dir, 0755, true);
                }
                $ext = strtolower(pathinfo($_FILES[$audio_field]['name'], PATHINFO_EXTENSION));
                if (in_array($ext, ['mp3', 'wav', 'm4a', 'aac', 'ogg', 'webm'], true)) {
                    $audio_name = 'audio_' . time() . '_' . uniqid() . '.' . $ext;
                    if (move_uploaded_file($_FILES[$audio_field]['tmp_name'], $audio_dir . $audio_name)) {
                        $audio_path = $audio_dir . $audio_name;
                    }
                }
                break;
            }

            $photo_url = trim((string) ($_POST['photo_url'] ?? ''));
            $photo_paths = [];
            if ($photo_url !== '') {
                $photo_paths[] = $photo_url;
            }

            if (isset($_FILES['photo']) && ($_FILES['photo']['error'] ?? UPLOAD_ERR_NO_FILE) === 0) {
                $photo_dir = 'uploads/meetings/photos/';
                if (!is_dir($photo_dir)) {
                    mkdir($photo_dir, 0755, true);
                }
                $ext = strtolower(pathinfo($_FILES['photo']['name'], PATHINFO_EXTENSION));
                if (in_array($ext, ['jpg', 'jpeg', 'png', 'gif', 'webp'], true)) {
                    $photo_name = 'photo_' . time() . '_' . uniqid() . '.' . $ext;
                    $dest = $photo_dir . $photo_name;
                    if (compressAndMoveImage($_FILES['photo']['tmp_name'], $dest, 75, 1200, 1200)) {
                        $photo_url = $dest;
                        $photo_paths = [$dest];
                    }
                }
            }

            if (isset($_FILES['related_photos'])) {
                $photo_dir = 'uploads/meetings/photos/';
                if (!is_dir($photo_dir)) {
                    mkdir($photo_dir, 0755, true);
                }
                foreach ($_FILES['related_photos']['tmp_name'] as $key => $tmp_name) {
                    if (($_FILES['related_photos']['error'][$key] ?? UPLOAD_ERR_NO_FILE) !== 0) {
                        continue;
                    }
                    $ext = strtolower(pathinfo($_FILES['related_photos']['name'][$key], PATHINFO_EXTENSION));
                    if (!in_array($ext, ['jpg', 'jpeg', 'png', 'gif', 'webp'], true)) {
                        continue;
                    }
                    $photo_name = 'photo_' . time() . '_' . uniqid() . '.' . $ext;
                    $dest = $photo_dir . $photo_name;
                    if (compressAndMoveImage($tmp_name, $dest, 75, 1200, 1200)) {
                        $photo_paths[] = $dest;
                        if ($photo_url === '') {
                            $photo_url = $dest;
                        }
                    }
                }
            }

            $photo_paths = array_values(array_unique(array_filter($photo_paths)));
            $photos_json = json_encode($photo_paths, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

            $meeting_topic = $meeting_title;
            $department = $meeting_category;

            if ($meeting_id > 0) {
                $sql = "UPDATE meetings
                        SET title = ?, topic = ?, category = ?, department = ?, meeting_date = ?, description = ?,
                            external_url = ?, photo_url = ?, mp3_url = ?, audio_path = ?, audio_file_path = ?,
                            photos = ?, related_photos = ?, admin_id = ?, created_by = ?
                        WHERE id = ?";
                if ($stmt = $mysqli->prepare($sql)) {
                    $stmt->bind_param(
                        'sssssssssssssssi',
                        $meeting_title,
                        $meeting_topic,
                        $meeting_category,
                        $department,
                        $meeting_date,
                        $description,
                        $external_url,
                        $photo_url,
                        $audio_path,
                        $audio_path,
                        $audio_path,
                        $photos_json,
                        $photos_json,
                        $current_admin_id,
                        $current_admin_id,
                        $meeting_id
                    );
                }
            } else {
                $sql = "INSERT INTO meetings
                        (title, topic, category, department, meeting_date, description, external_url, photo_url, mp3_url, audio_path, audio_file_path, photos, related_photos, admin_id, created_by)
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)";
                if ($stmt = $mysqli->prepare($sql)) {
                    $stmt->bind_param(
                        'sssssssssssssss',
                        $meeting_title,
                        $meeting_topic,
                        $meeting_category,
                        $department,
                        $meeting_date,
                        $description,
                        $external_url,
                        $photo_url,
                        $audio_path,
                        $audio_path,
                        $audio_path,
                        $photos_json,
                        $photos_json,
                        $current_admin_id,
                        $current_admin_id
                    );
                }
            }

            if (!isset($stmt) || !$stmt) {
                $response = ['status' => 'error', 'message' => 'DB prepare error: ' . $mysqli->error];
            } elseif ($stmt->execute()) {
                $response = ['status' => 'success', 'message' => $meeting_id > 0 ? 'កែប្រែកិច្ចប្រជុំដោយជោគជ័យ!' : 'កិច្ចប្រជុំត្រូវបានបង្ហោះដោយជោគជ័យ!'];
                $stmt->close();
            } else {
                $response = ['status' => 'error', 'message' => 'DB error: ' . $stmt->error];
                $stmt->close();
            }
            echo json_encode($response, JSON_UNESCAPED_UNICODE);
            exit;

        case 'sub_user_login':
            $sub_id = trim($_POST['sub_id'] ?? '');
            $sub_pass = $_POST['sub_password'] ?? '';
            $vvc_flag = isset($_POST['vvc']) ? 1 : 0;

            if ($sub_id === '' || $sub_pass === '') {
                $response = ['status' => 'error', 'message' => 'សូមបំពេញ ID និងពាក្យសម្ងាត់'];
            } else {
                $loginRes = attemptSubUserLoginBySubId($mysqli, $sub_id, $sub_pass);
                if ($loginRes['ok']) {
                    $_SESSION['sub_user_vvc'] = $vvc_flag;
                    $response = [
                        'status' => 'success',
                        'message' => 'Sub user login success',
                        'sub' => [
                            'id' => $_SESSION['sub_user_id'],
                            'name' => $_SESSION['sub_user_name'],
                            'permissions' => $_SESSION['sub_user_permissions'],
                            'vvc' => (int) $vvc_flag
                        ]
                    ];
                } else {
                    $msg = 'Invalid credentials';
                    if ($loginRes['reason'] === 'not_found')
                        $msg = 'User not found';
                    if ($loginRes['reason'] === 'ambiguous')
                        $msg = 'Multiple accounts found with this ID. Please use parent-linked login.';
                    if ($loginRes['reason'] === 'invalid_password')
                        $msg = 'Incorrect password';
                    $response = ['status' => 'error', 'message' => $msg];
                }
            }
            // Return early for login actions
            echo json_encode($response, JSON_UNESCAPED_UNICODE);
            exit;

        default:
            // All other AJAX actions require login
            if (!checkAdminLogin($mysqli)) {
                echo json_encode(['status' => 'error', 'message' => 'អ្នកមិនបាន Log In! ឬ Session ID បាត់។'], JSON_UNESCAPED_UNICODE);
                exit;
            }
            // Shared resolution logic
            $current_admin_id = $_SESSION['admin_id'] ?? ($_SESSION['sub_user_parent_id'] ?? ($_SESSION['sub_user_id'] ?? 'SYSTEM_WIDE'));

            // Converted shared AJAX actions
            switch ($ajax_action) {
                case 'save_notification_template':
                    if (!hasPageAccess($mysqli, 'notifications', 'send_notifications', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }

                    $template_id = (int) ($_POST['template_id'] ?? 0);
                    $template_name = trim((string) ($_POST['template_name'] ?? ''));
                    $template_key = trim((string) ($_POST['template_key'] ?? ''));
                    $title_template = trim((string) ($_POST['title_template'] ?? ''));
                    $message_template = trim((string) ($_POST['message_template'] ?? ''));
                    $target_type = trim((string) ($_POST['target_type'] ?? 'all'));
                    $target_roles = enterprise_parse_json_list($_POST['target_roles_text'] ?? ($_POST['target_roles'] ?? []));
                    $target_users = enterprise_parse_json_list($_POST['target_users_text'] ?? ($_POST['target_users'] ?? []));
                    $image_url = trim((string) ($_POST['image_url'] ?? ''));
                    $is_active = isset($_POST['is_active']) ? 1 : 0;

                    if ($template_name === '' || $title_template === '' || $message_template === '') {
                        $response = ['status' => 'error', 'message' => 'សូមបំពេញឈ្មោះ Template, Title និង Message។'];
                        break;
                    }

                    if (!in_array($target_type, ['all', 'role', 'user'], true)) {
                        $target_type = 'all';
                    }

                    $roles_json = enterprise_json_encode($target_roles);
                    $users_json = enterprise_json_encode($target_users);

                    if ($template_id > 0) {
                        $stmt = $mysqli->prepare("UPDATE notification_templates SET template_key = ?, template_name = ?, title_template = ?, message_template = ?, target_type = ?, target_roles_json = ?, target_users_json = ?, image_url = ?, is_active = ? WHERE id = ? AND admin_id = ?");
                        if ($stmt) {
                            $stmt->bind_param("ssssssssiis", $template_key, $template_name, $title_template, $message_template, $target_type, $roles_json, $users_json, $image_url, $is_active, $template_id, $current_admin_id);
                        }
                    } else {
                        $stmt = $mysqli->prepare("INSERT INTO notification_templates (admin_id, template_key, template_name, title_template, message_template, target_type, target_roles_json, target_users_json, image_url, is_active) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)");
                        if ($stmt) {
                            $stmt->bind_param("sssssssssi", $current_admin_id, $template_key, $template_name, $title_template, $message_template, $target_type, $roles_json, $users_json, $image_url, $is_active);
                        }
                    }

                    if (!$stmt) {
                        $response = ['status' => 'error', 'message' => 'Database prepare error: ' . $mysqli->error];
                        break;
                    }

                    if ($stmt->execute()) {
                        $response = ['status' => 'success', 'message' => 'Notification template saved successfully!'];
                    } else {
                        $response = ['status' => 'error', 'message' => $stmt->error];
                    }
                    $stmt->close();
                    break;

                case 'delete_notification_template':
                    if (!hasPageAccess($mysqli, 'notifications', 'send_notifications', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $template_id = (int) ($_POST['template_id'] ?? $_POST['id'] ?? 0);
                    if ($template_id <= 0) {
                        $response = ['status' => 'error', 'message' => 'Invalid template id.'];
                        break;
                    }
                    if ($stmt = $mysqli->prepare("DELETE FROM notification_templates WHERE id = ? AND admin_id = ?")) {
                        $stmt->bind_param("is", $template_id, $current_admin_id);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'Template deleted successfully!'];
                        } else {
                            $response = ['status' => 'error', 'message' => $stmt->error];
                        }
                        $stmt->close();
                    } else {
                        $response = ['status' => 'error', 'message' => 'Database error.'];
                    }
                    break;

                case 'save_notification_schedule':
                    if (!hasPageAccess($mysqli, 'notifications', 'send_notifications', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }

                    $schedule_id = (int) ($_POST['schedule_id'] ?? 0);
                    $schedule_name = trim((string) ($_POST['schedule_name'] ?? ''));
                    $template_id = (int) ($_POST['template_id'] ?? 0);
                    $title_override = trim((string) ($_POST['title_override'] ?? ''));
                    $message_override = trim((string) ($_POST['message_override'] ?? ''));
                    $target_type = trim((string) ($_POST['target_type'] ?? ''));
                    $target_roles = enterprise_parse_json_list($_POST['target_roles_text'] ?? ($_POST['target_roles'] ?? []));
                    $target_users = enterprise_parse_json_list($_POST['target_users_text'] ?? ($_POST['target_users'] ?? []));
                    $image_url = trim((string) ($_POST['image_url'] ?? ''));
                    $frequency = trim((string) ($_POST['frequency'] ?? 'once'));
                    $scheduled_at = trim((string) ($_POST['scheduled_at'] ?? ''));
                    $time_of_day = trim((string) ($_POST['time_of_day'] ?? '09:00'));
                    $day_of_week = ($_POST['day_of_week'] ?? '') === '' ? null : (int) $_POST['day_of_week'];
                    $day_of_month = ($_POST['day_of_month'] ?? '') === '' ? null : (int) $_POST['day_of_month'];
                    $is_active = isset($_POST['is_active']) ? 1 : 0;

                    if ($schedule_name === '') {
                        $response = ['status' => 'error', 'message' => 'សូមបញ្ចូលឈ្មោះ Schedule។'];
                        break;
                    }

                    if (!in_array($frequency, ['once', 'daily', 'weekly', 'monthly'], true)) {
                        $frequency = 'once';
                    }
                    if ($target_type !== '' && !in_array($target_type, ['all', 'role', 'user'], true)) {
                        $target_type = '';
                    }

                    $next_run_at = $is_active ? compute_notification_schedule_next_run($frequency, $scheduled_at !== '' ? $scheduled_at : null, $time_of_day !== '' ? $time_of_day : null, $day_of_week, $day_of_month) : null;
                    if ($is_active && $next_run_at === null) {
                        $response = ['status' => 'error', 'message' => 'សូមពិនិត្យកាលវិភាគ Schedule ម្តងទៀត។'];
                        break;
                    }

                    $roles_json = enterprise_json_encode($target_roles);
                    $users_json = enterprise_json_encode($target_users);
                    $scheduled_at_db = $scheduled_at !== '' ? $scheduled_at : null;
                    $time_of_day_db = $time_of_day !== '' ? $time_of_day : null;

                    if ($schedule_id > 0) {
                        $stmt = $mysqli->prepare("UPDATE notification_schedules SET template_id = ?, schedule_name = ?, title_override = ?, message_override = ?, target_type = ?, target_roles_json = ?, target_users_json = ?, image_url = ?, frequency = ?, scheduled_at = ?, time_of_day = ?, day_of_week = ?, day_of_month = ?, next_run_at = ?, is_active = ? WHERE id = ? AND admin_id = ?");
                        if ($stmt) {
                            $stmt->bind_param("isssssssssssiisiis", $template_id, $schedule_name, $title_override, $message_override, $target_type, $roles_json, $users_json, $image_url, $frequency, $scheduled_at_db, $time_of_day_db, $day_of_week, $day_of_month, $next_run_at, $is_active, $schedule_id, $current_admin_id);
                        }
                    } else {
                        $stmt = $mysqli->prepare("INSERT INTO notification_schedules (admin_id, template_id, schedule_name, title_override, message_override, target_type, target_roles_json, target_users_json, image_url, frequency, scheduled_at, time_of_day, day_of_week, day_of_month, next_run_at, is_active) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)");
                        if ($stmt) {
                            $stmt->bind_param("sisssssssssssiisi", $current_admin_id, $template_id, $schedule_name, $title_override, $message_override, $target_type, $roles_json, $users_json, $image_url, $frequency, $scheduled_at_db, $time_of_day_db, $day_of_week, $day_of_month, $next_run_at, $is_active);
                        }
                    }

                    if (!$stmt) {
                        $response = ['status' => 'error', 'message' => 'Database prepare error: ' . $mysqli->error];
                        break;
                    }

                    if ($stmt->execute()) {
                        $response = ['status' => 'success', 'message' => 'Notification schedule saved successfully!'];
                    } else {
                        $response = ['status' => 'error', 'message' => $stmt->error];
                    }
                    $stmt->close();
                    break;

                case 'toggle_notification_schedule':
                    if (!hasPageAccess($mysqli, 'notifications', 'send_notifications', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $schedule_id = (int) ($_POST['schedule_id'] ?? $_POST['id'] ?? 0);
                    if ($schedule_id <= 0) {
                        $response = ['status' => 'error', 'message' => 'Invalid schedule id.'];
                        break;
                    }

                    $schedule = null;
                    if ($stmt = $mysqli->prepare("SELECT * FROM notification_schedules WHERE id = ? AND admin_id = ? LIMIT 1")) {
                        $stmt->bind_param("is", $schedule_id, $current_admin_id);
                        $stmt->execute();
                        $res = $stmt->get_result();
                        $schedule = $res ? $res->fetch_assoc() : null;
                        $stmt->close();
                    }
                    if (!$schedule) {
                        $response = ['status' => 'error', 'message' => 'Schedule not found.'];
                        break;
                    }

                    $new_active = !empty($schedule['is_active']) ? 0 : 1;
                    $next_run_at = null;
                    if ($new_active) {
                        $next_run_at = compute_notification_schedule_next_run(
                            $schedule['frequency'] ?? 'once',
                            $schedule['scheduled_at'] ?? null,
                            $schedule['time_of_day'] ?? null,
                            $schedule['day_of_week'] ?? null,
                            $schedule['day_of_month'] ?? null
                        );
                    }

                    if ($stmt = $mysqli->prepare("UPDATE notification_schedules SET is_active = ?, next_run_at = ? WHERE id = ? AND admin_id = ?")) {
                        $stmt->bind_param("isis", $new_active, $next_run_at, $schedule_id, $current_admin_id);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => $new_active ? 'Schedule activated.' : 'Schedule paused.'];
                        } else {
                            $response = ['status' => 'error', 'message' => $stmt->error];
                        }
                        $stmt->close();
                    } else {
                        $response = ['status' => 'error', 'message' => 'Database error.'];
                    }
                    break;

                case 'delete_notification_schedule':
                    if (!hasPageAccess($mysqli, 'notifications', 'send_notifications', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $schedule_id = (int) ($_POST['schedule_id'] ?? $_POST['id'] ?? 0);
                    if ($schedule_id <= 0) {
                        $response = ['status' => 'error', 'message' => 'Invalid schedule id.'];
                        break;
                    }
                    if ($stmt = $mysqli->prepare("DELETE FROM notification_schedules WHERE id = ? AND admin_id = ?")) {
                        $stmt->bind_param("is", $schedule_id, $current_admin_id);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'Schedule deleted successfully!'];
                        } else {
                            $response = ['status' => 'error', 'message' => $stmt->error];
                        }
                        $stmt->close();
                    } else {
                        $response = ['status' => 'error', 'message' => 'Database error.'];
                    }
                    break;

                case 'save_notification':
                    if (!hasPageAccess($mysqli, 'notifications', 'send_notifications', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $title = trim($_POST['title'] ?? '');
                    $message = trim($_POST['message'] ?? '');
                    $expiry_date = !empty($_POST['expiry_date']) ? $_POST['expiry_date'] : null;
                    $target_type = $_POST['target_type'] ?? 'all';
                    $target_roles = isset($_POST['target_roles']) ? (is_array($_POST['target_roles']) ? $_POST['target_roles'] : [$_POST['target_roles']]) : [];
                    $target_users = isset($_POST['target_users']) ? (is_array($_POST['target_users']) ? $_POST['target_users'] : [$_POST['target_users']]) : [];

                    if (empty($title) || empty($message)) {
                        $response = ['status' => 'error', 'message' => 'សូមបញ្ចូលចំណងជើង និងសារ!'];
                        break;
                    }

                    // Handle Image Upload
                    $image_url = null;
                    if (isset($_FILES['notification_image']) && $_FILES['notification_image']['error'] === UPLOAD_ERR_OK) {
                        $upload_dir = 'uploads/notifications/';
                        if (!is_dir($upload_dir))
                            mkdir($upload_dir, 0777, true);

                        $file_ext = strtolower(pathinfo($_FILES['notification_image']['name'], PATHINFO_EXTENSION));
                        $file_name = time() . '_' . uniqid() . '.' . $file_ext;
                        $target_file = $upload_dir . $file_name;

                        if (move_uploaded_file($_FILES['notification_image']['tmp_name'], $target_file)) {
                            $proto = (isset($_SERVER['HTTPS']) && $_SERVER['HTTPS'] === 'on') ? 'https' : 'http';
                            $base_path = preg_replace('/[^\/]+$/', '', $_SERVER['SCRIPT_NAME']);
                            $image_url = $proto . '://' . $_SERVER['HTTP_HOST'] . $base_path . $target_file;
                        }
                    }

                    include_once 'notification_functions.php';
                    $success_count = 0;

                    if ($target_type === 'all') {
                        if (sendAppNotificationToAll($mysqli, $title, $message, $current_admin_id, $expiry_date, $image_url)) {
                            $success_count = 1;
                        }
                    } elseif ($target_type === 'role') {
                        if (empty($target_roles)) {
                            $response = ['status' => 'error', 'message' => 'សូមជ្រើសរើសតួនាទីយ៉ាងហោចណាស់មួយ!'];
                            break;
                        }
                        if (sendAppNotificationToRoles($mysqli, $target_roles, $title, $message, $current_admin_id, $expiry_date, $image_url)) {
                            $success_count = count($target_roles);
                        }
                    } elseif ($target_type === 'user') {
                        if (empty($target_users)) {
                            $response = ['status' => 'error', 'message' => 'សូមជ្រើសរើសអ្នកប្រើប្រាស់យ៉ាងហោចណាស់ម្នាក់!'];
                            break;
                        }
                        foreach ($target_users as $uid) {
                            if (sendAppNotificationToUser($mysqli, $uid, $title, $message, $current_admin_id, $expiry_date, $image_url)) {
                                $success_count++;
                            }
                        }
                    }

                    if ($success_count > 0) {
                        $response = ['status' => 'success', 'message' => 'សារជូនដំណឹងត្រូវបានផ្ញើដោយជោគជ័យ!'];
                    } else {
                        $response = ['status' => 'error', 'message' => 'មានបញ្ហាក្នុងការផ្ញើសារជូនដំណឹង។ សូមសាកល្បងម្តងទៀត!'];
                    }
                    break;

                case 'delete_notifications':
                    if (!hasPageAccess($mysqli, 'notifications', 'send_notifications', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $ids = $_POST['ids'] ?? [];
                    if (empty($ids)) {
                        $response = ['status' => 'error', 'message' => 'No items selected.'];
                        break;
                    }
                    if (!is_array($ids))
                        $ids = [$ids];

                    $placeholders = implode(',', array_fill(0, count($ids), '?'));
                    $stmt = $mysqli->prepare("DELETE FROM notifications WHERE id IN ($placeholders)");
                    if ($stmt) {
                        $types = str_repeat('i', count($ids));
                        $stmt->bind_param($types, ...$ids);
                        if ($stmt->execute()) {
                            // Also cleanup user_notifications mapping
                            $mysqli->query("DELETE FROM user_notifications WHERE notification_id IN (" . implode(',', array_map('intval', $ids)) . ")");
                            $response = ['status' => 'success', 'message' => 'បានលុបទិន្នន័យដោយជោគជ័យ!'];
                        } else {
                            $response = ['status' => 'error', 'message' => 'Delete failed.'];
                        }
                        $stmt->close();
                    } else {
                        $response = ['status' => 'error', 'message' => 'Database error.'];
                    }
                    break;

                // --- START: Banner Management AJAX ---
                case 'get_banners':
                    if (!hasPageAccess($mysqli, 'notifications', 'manage_banners', $current_admin_id)) {
