                        }
                    }

                    if ($id > 0) {
                        $stmt = $mysqli->prepare("UPDATE announcements SET title=?, `text`=?, image_url=?, external_link=?, order_index=?, is_active=? WHERE id=? AND admin_id=?");
                        if (!$stmt) {
                            $response = ['status' => 'error', 'message' => 'Prepare failed: ' . $mysqli->error];
                            break;
