                        $stmt->bind_param("ssssiiis", $title, $text, $image_url, $external_link, $order_index, $is_active, $id, $current_admin_id);
                    } else {
                        $stmt = $mysqli->prepare("INSERT INTO announcements (admin_id, title, `text`, image_url, external_link, order_index, is_active) VALUES (?, ?, ?, ?, ?, ?, ?)");
