                    }
                    break;
                // --- END: Banner Management AJAX ---


                case 'get_time_rules':
                    $user_id = $_POST['user_id'] ?? '';
                    if (!empty($user_id)) {
                        $rules = [];
                        $stmt = $mysqli->prepare("SELECT type, start_time, end_time, status FROM attendance_rules WHERE employee_id = ? ORDER BY type, start_time");
                        if ($stmt) {
                            $stmt->bind_param('s', $user_id);
