                case 'save_time_rules':
                    $user_id = $_POST['rule_employee_id'] ?? '';
                    $rules_json = $_POST['rules_json'] ?? '';
                    if (!empty($user_id)) {
                        $rules = json_decode($rules_json, true);
                        $mysqli->begin_transaction();
                        try {
                            $stmt = $mysqli->prepare("DELETE FROM attendance_rules WHERE employee_id = ?");
                            $stmt->bind_param('s', $user_id);
                            $stmt->execute();
                            $stmt->close();
                            if (!empty($rules)) {
                                $stmt = $mysqli->prepare("INSERT INTO attendance_rules (employee_id, type, start_time, end_time, status, created_by_admin_id) VALUES (?, ?, ?, ?, ?, ?)");
                                $admin_id = $_SESSION['admin_id'] ?? 'SYSTEM';
                                foreach ($rules as $r) {
                                    $s_time = $r['start_time'] ?? '';
                                    $e_time = $r['end_time'] ?? '';
                                    $stmt->bind_param('ssssss', $user_id, $r['type'], $s_time, $e_time, $r['status'], $admin_id);
                                    $stmt->execute();
                                }
                                $stmt->close();
                            }
                            $mysqli->commit();
                            $response = ['status' => 'success', 'message' => 'ច្បាប់ម៉ោងត្រូវបានរក្សាទុកបានជោគជ័យ!'];
                        } catch (Exception $e) {
                            $mysqli->rollback();
                            $response = ['status' => 'error', 'message' => $e->getMessage()];
                        }
                    }
                    break;
                case 'copy_time_rules':
                    $from_id = $_POST['from_user_id'] ?? '';
                    $to_id = $_POST['to_user_id'] ?? '';
                    if ($from_id && $to_id) {
                        $mysqli->begin_transaction();
                        try {
                            $stmt = $mysqli->prepare("DELETE FROM attendance_rules WHERE employee_id = ?");
                            $stmt->bind_param('s', $to_id);
                            $stmt->execute();
                            $stmt->close();
                            $admin_id = $_SESSION['admin_id'] ?? 'SYSTEM';
                            $stmt = $mysqli->prepare("INSERT INTO attendance_rules (employee_id, type, start_time, end_time, status, created_by_admin_id) SELECT ?, type, start_time, end_time, status, ? FROM attendance_rules WHERE employee_id = ?");
                            $stmt->bind_param('sss', $to_id, $admin_id, $from_id);
                            $stmt->execute();
                            $stmt->close();
                            $mysqli->commit();
                            $response = ['status' => 'success', 'message' => 'បានចម្លងជោគជ័យ!'];
                        } catch (Exception $e) {
                            $mysqli->rollback();
                            $response = ['status' => 'error', 'message' => $e->getMessage()];
                        }
                    }
                    break;
                case 'get_user_details':
                    $user_id = $_POST['user_id'] ?? '';
                    if (!empty($user_id)) {
                        $stmt = $mysqli->prepare("SELECT * FROM users WHERE employee_id = ?");
                        if ($stmt) {
                            $stmt->bind_param('s', $user_id);
                            $stmt->execute();
                            $result = $stmt->get_result();
                            $user = $result->fetch_assoc();
                            if ($user) {
                                // Parse custom_data if it's a JSON string
                                if (!empty($user['custom_data']) && is_string($user['custom_data'])) {
                                    $user['custom_data'] = json_decode($user['custom_data'], true) ?: [];
                                } else {
                                    $user['custom_data'] = (!empty($user['custom_data']) && is_array($user['custom_data'])) ? $user['custom_data'] : [];
                                }

                                // Fetch managers for the dropdown
                                $managers = [];
                                $m_res = $mysqli->query("SELECT employee_id, name FROM users WHERE user_role = 'Admin' OR user_role = 'Manager' ORDER BY name ASC");
                                while ($m = $m_res->fetch_assoc()) {
                                    $managers[] = $m;
                                }

                                $response = ['status' => 'success', 'user_data' => $user, 'managers' => $managers];
                            }
                            $stmt->close();
                        }
                    }
                    break;
                case 'delete_user':
                    $user_id = $_POST['user_id'] ?? '';
                    if (!empty($user_id)) {
                        $mysqli->begin_transaction();
                        try {
                            $mysqli->query("DELETE FROM attendance_rules WHERE employee_id = '" . $mysqli->real_escape_string($user_id) . "'");
                            $mysqli->query("DELETE FROM attendance WHERE employee_id = '" . $mysqli->real_escape_string($user_id) . "'");
                            $mysqli->query("DELETE FROM users WHERE employee_id = '" . $mysqli->real_escape_string($user_id) . "'");
                            $mysqli->commit();
                            $response = ['status' => 'success', 'message' => 'បានលុបជោគជ័យ!'];
                        } catch (Exception $e) {
                            $mysqli->rollback();
                            $response = ['status' => 'error', 'message' => $e->getMessage()];
                        }
                    }
                    break;
                case 'toggle_verification':
                    $user_id = $_POST['user_id'] ?? '';
                    if (!empty($user_id)) {
                        $user_id_esc = $mysqli->real_escape_string($user_id);
                        // First check current state
                        $cur_res = $mysqli->query("SELECT is_verified FROM users WHERE employee_id = '$user_id_esc' LIMIT 1");
                        $cur_row = $cur_res ? $cur_res->fetch_assoc() : null;
                        $current_val = isset($cur_row['is_verified']) ? (int)$cur_row['is_verified'] : 0;
                        $new_val = $current_val ? 0 : 1;
                        $mysqli->query("UPDATE users SET is_verified = $new_val WHERE employee_id = '$user_id_esc'");
                        $response = ['status' => 'success', 'message' => 'ស្ថានភាព Verification ត្រូវបានប្តូរ!', 'new_verified' => $new_val];
                    }
                    break;
                case 'toggle_user_status':
                    $user_id = $_POST['user_id'] ?? '';
                    if (!empty($user_id)) {
                        $mysqli->query("UPDATE users SET employment_status = IF(employment_status = 'Active', 'Inactive', 'Active') WHERE employee_id = '" . $mysqli->real_escape_string($user_id) . "'");
                        $response = ['status' => 'success', 'message' => 'ស្ថានភាពត្រូវបានប្តូរ!'];
                    }
                    break;
                case 'get_customers':
                    $customers = [];
                    $res = $mysqli->query("SELECT * FROM tracking_customers ORDER BY created_at DESC");
                    if ($res) {
                        while ($row = $res->fetch_assoc()) {
                            $customers[] = $row;
                        }
                    }
                    $response = ['status' => 'success', 'data' => $customers];
                    break;
                case 'save_customer':
                    $id = (int) ($_POST['cust_id'] ?? 0);
                    $name = trim($_POST['cust_name'] ?? '');
                    $phone = trim($_POST['cust_phone'] ?? '');
                    $lat = $_POST['cust_lat'] ?? '';
                    if ($lat === '')
                        $lat = 'NULL';
                    $lng = $_POST['cust_lng'] ?? '';
                    if ($lng === '')
                        $lng = 'NULL';
                    $img = trim($_POST['cust_img_path'] ?? '');

                    // Picture upload handling if any
                    if (isset($_FILES['cust_img']) && $_FILES['cust_img']['error'] === 0) {
                        $ext = strtolower(pathinfo($_FILES['cust_img']['name'], PATHINFO_EXTENSION));
                        $allowed = ['jpg', 'jpeg', 'png', 'gif'];
                        if (in_array($ext, $allowed)) {
                            if (!is_dir('uploads/customers'))
                                @mkdir('uploads/customers', 0755, true);
                            $dest = 'uploads/customers/' . time() . '_' . rand(100, 999) . '.' . $ext;
                            if (move_uploaded_file($_FILES['cust_img']['tmp_name'], $dest)) {
                                $img = $dest;
                            }
                        }
                    }

                    if ($name === '') {
                        $response = ['status' => 'error', 'message' => 'សូមបញ្ចូលឈ្មោះ!'];
                    } else {
                        if ($id > 0) {
                            $stmt = $mysqli->prepare("UPDATE tracking_customers SET name=?, phone=?, latitude=?, longitude=?, profile_image=? WHERE id=?");
                            $stmt->bind_param("sssssi", $name, $phone, $lat, $lng, $img, $id);
                            if ($stmt->execute()) {
                                $response = ['status' => 'success', 'message' => 'កែប្រែដោយជោគជ័យ!'];
                            } else {
                                $response = ['status' => 'error', 'message' => $mysqli->error];
                            }
                        } else {
                            $stmt = $mysqli->prepare("INSERT INTO tracking_customers (name, phone, latitude, longitude, profile_image) VALUES (?, ?, ?, ?, ?)");
                            $stmt->bind_param("sssss", $name, $phone, $lat, $lng, $img);
                            if ($stmt->execute()) {
                                $response = ['status' => 'success', 'message' => 'បន្ថែមដោយជោគជ័យ!'];
                            } else {
                                $response = ['status' => 'error', 'message' => $mysqli->error];
                            }
                        }
                    }
                    break;
                case 'delete_customer':
                    $id = (int) ($_POST['id'] ?? 0);
                    if ($id > 0) {
                        $mysqli->query("DELETE FROM tracking_customers WHERE id = $id");
                        $response = ['status' => 'success', 'message' => 'បានលុបជោគជ័យ!'];
                    } else {
                        $response = ['status' => 'error', 'message' => 'មិនមានទិន្នន័យដើម្បីលុប!'];
                    }
                    break;

                // ===============================================
                // GPS TRIP TRACKING AJAX HANDLERS
                // ===============================================
                case 'get_active_trips':
                    $trips = [];
                    $sql = "SELECT t.*, 
                            u.avatar,
                            c.latitude as target_lat, c.longitude as target_lng,
                            (SELECT COUNT(*) FROM trip_locations WHERE trip_id = t.id) as point_count
                            FROM employee_trips t 
                            LEFT JOIN users u ON t.employee_id = u.employee_id
                            LEFT JOIN tracking_customers c ON t.customer_id = c.id
                            WHERE t.status = 'active' 
                            ORDER BY t.started_at DESC";
                    $res = $mysqli->query($sql);
                    if ($res) {
                        while ($row = $res->fetch_assoc()) {
                            // Get latest location for this trip
                            $loc_stmt = $mysqli->prepare("SELECT latitude, longitude, speed, recorded_at FROM trip_locations WHERE trip_id = ? ORDER BY recorded_at DESC LIMIT 1");
                            $loc_stmt->bind_param('i', $row['id']);
                            $loc_stmt->execute();
                            $loc_res = $loc_stmt->get_result();
                            $row['latest_location'] = $loc_res->fetch_assoc();
                            $loc_stmt->close();
                            $trips[] = $row;
                        }
                    }
                    $response = ['status' => 'success', 'data' => $trips];
                    break;

                case 'get_trips':
                    $trips = [];
                    $date_from = $_POST['date_from'] ?? date('Y-m-d');
                    $date_to = $_POST['date_to'] ?? date('Y-m-d');
                    $emp_filter = trim($_POST['employee_filter'] ?? '');

                    $sql = "SELECT t.* FROM employee_trips t WHERE DATE(t.started_at) BETWEEN ? AND ?";
                    $params = [$date_from, $date_to];
                    $types = 'ss';

                    if (!empty($emp_filter)) {
                        $sql .= " AND (t.employee_id = ? OR t.employee_name LIKE ?)";
                        $params[] = $emp_filter;
                        $params[] = "%$emp_filter%";
                        $types .= 'ss';
                    }
                    $sql .= " ORDER BY t.started_at DESC LIMIT 200";

                    $stmt = $mysqli->prepare($sql);
                    if ($stmt) {
                        $stmt->bind_param($types, ...$params);
                        $stmt->execute();
                        $res = $stmt->get_result();
                        while ($row = $res->fetch_assoc()) {
                            $trips[] = $row;
                        }
                        $stmt->close();
                    }
                    $response = ['status' => 'success', 'data' => $trips];
                    break;

                case 'get_trip_locations':
                    $trip_id = (int) ($_POST['trip_id'] ?? 0);
                    $locations = [];
                    if ($trip_id > 0) {
                        $stmt = $mysqli->prepare("SELECT latitude, longitude, speed, accuracy, recorded_at FROM trip_locations WHERE trip_id = ? ORDER BY recorded_at ASC");
                        $stmt->bind_param('i', $trip_id);
                        $stmt->execute();
                        $res = $stmt->get_result();
                        while ($row = $res->fetch_assoc()) {
                            $locations[] = $row;
                        }
                        $stmt->close();
                        // Also fetch trip info with target coordinates
                        $trip_stmt = $mysqli->prepare("SELECT t.*, c.latitude as target_lat, c.longitude as target_lng 
                                                      FROM employee_trips t 
                                                      LEFT JOIN tracking_customers c ON t.customer_id = c.id 
                                                      WHERE t.id = ?");
                        $trip_stmt->bind_param('i', $trip_id);
                        $trip_stmt->execute();
                        $trip = $trip_stmt->get_result()->fetch_assoc();
                        $trip_stmt->close();
                    }
                    $snapped = gps_snap_trip_points_to_roads($locations);
                    $response = [
                        'status' => 'success',
                        'trip' => $trip ?? null,
                        'locations' => $locations,
                        'snapped_path' => $snapped['points'] ?? [],
                        'route_source' => $snapped['source'] ?? 'raw',
                        'route_message' => $snapped['message'] ?? null
                    ];
                    break;

                case 'admin_end_trip':
                    $trip_id = (int) ($_POST['trip_id'] ?? 0);
                    if ($trip_id > 0) {
                        // Get the last recorded location
                        $loc_stmt = $mysqli->prepare("SELECT latitude, longitude FROM trip_locations WHERE trip_id = ? ORDER BY recorded_at DESC LIMIT 1");
                        $loc_stmt->bind_param('i', $trip_id);
                        $loc_stmt->execute();
                        $last_loc = $loc_stmt->get_result()->fetch_assoc();
                        $loc_stmt->close();

                        $end_lat = $last_loc['latitude'] ?? 0;
                        $end_lng = $last_loc['longitude'] ?? 0;

                        // Calculate total distance using Haversine on all points
                        $pts_stmt = $mysqli->prepare("SELECT latitude, longitude FROM trip_locations WHERE trip_id = ? ORDER BY recorded_at ASC");
                        $pts_stmt->bind_param('i', $trip_id);
                        $pts_stmt->execute();
                        $pts_res = $pts_stmt->get_result();
                        $total_dist = 0;
                        $prev = null;
                        while ($pt = $pts_res->fetch_assoc()) {
                            if ($prev) {
                                $total_dist += haversine_distance($prev['latitude'], $prev['longitude'], $pt['latitude'], $pt['longitude']);
                            }
                            $prev = $pt;
                        }
                        $pts_stmt->close();

                        // Calculate duration
                        $trip_stmt = $mysqli->prepare("SELECT started_at FROM employee_trips WHERE id = ?");
                        $trip_stmt->bind_param('i', $trip_id);
                        $trip_stmt->execute();
                        $trip_info = $trip_stmt->get_result()->fetch_assoc();
                        $trip_stmt->close();

                        $duration = 0;
                        if ($trip_info) {
                            $start_time = new DateTime($trip_info['started_at']);
                            $end_time = new DateTime();
                            $duration = (int) round(($end_time->getTimestamp() - $start_time->getTimestamp()) / 60);
                        }

                        $update_stmt = $mysqli->prepare("UPDATE employee_trips SET status='completed', end_lat=?, end_lng=?, total_distance_km=?, duration_minutes=?, ended_at=NOW() WHERE id=?");
                        $update_stmt->bind_param('dddii', $end_lat, $end_lng, $total_dist, $duration, $trip_id);
                        $update_stmt->execute();
                        $update_stmt->close();

                        $response = ['status' => 'success', 'message' => 'ការធ្វើដំណើរត្រូវបានបញ្ចប់!'];
                    } else {
                        $response = ['status' => 'error', 'message' => 'Trip ID មិនត្រឹមត្រូវ!'];
                    }
                    break;
                    $response = ['status' => 'success', 'message' => 'ការកំណត់ត្រូវបានរក្សាទុក!'];
                    break;

                // --- START: Training Quiz AJAX ---
                case 'get_quiz_questions':
