                            'a' => 'កុំនិយាយប្រាប់នរណាម្នាក់',
                            'b' => 'សរសេរ Email ទៅក្រុមហ៊ុនជារៀងរាល់នាទី',
                            'c' => 'រាយការណ៍ប្រាប់ប្រធានផ្នែក ឬដាក់សំណើសុំយឺតជាមុន',
                            'd' => 'ធ្វើពុតជាអត់មានអីកើតឡើង',
                            'co' => 'C',
                            'exp' => 'ការដាក់សំណើសុំយឺត (Late Request) ឬការប្រាប់ប្រធានផ្នែកជាមុនបង្ហាញពីភាពទទួលខុសត្រូវ។'
                        ],
                        [
                            'q' => 'តើត្រូវការពារពាក្យសម្ងាត់ (Password) របស់អ្នកយ៉ាងដូចម្តេច?',
                            'a' => 'សរសេរវានៅលើក្រដាសបិតលើកុំព្យូទ័រ',
                            'b' => 'ប្រាប់ទៅកាន់មិត្តរួមការងារដើម្បីការភ្លេច',
                            'c' => 'ប្រើលេខទូរស័ព្ទជាលេខសម្ងាត់',
                            'd' => 'មិនចែករំលែកវាជាមួយនរណាម្នាក់ជាដាច់ខាត',
                            'co' => 'D',
