                    exit;
                case 'save_app_scan_settings':
                    $is_ajax_request = admin_is_ajax_request();
                    if (!hasPageAccess($mysqli, 'settings', 'manage_app_scan', $current_admin_id)) {
                        error_log("SAVE_APP_SCAN_SETTINGS: Access denied for $current_admin_id");
                        $deny_message = 'Permission denied.';
                        if ($is_ajax_request) {
                            echo json_encode(['status' => 'error', 'message' => $deny_message]);
                            exit;
                        }
                        app_scan_set_notice('error', $deny_message);
                        admin_redirect_to('?page=settings&action=manage_app_scan');
                    }

                    // Version-control keys must be shared globally because the mobile app
                    // checks these values outside of the admin panel session context.
                    $system_wide_app_keys = ['app_latest_version', 'app_latest_build', 'app_apk_url', 'app_update_message', 'app_force_update'];

                    // Get OLD build number before updating to detect changes
                    $old_build = max(
                        (int) get_app_scan_setting($mysqli, 'SYSTEM_WIDE', 'app_latest_build', '0'),
                        (int) get_app_scan_setting($mysqli, $current_admin_id, 'app_latest_build', '0')
                    );
                    if (isset($_FILES['header_logo']) && $_FILES['header_logo']['error'] === 0) {
                        $allowed = ['jpg', 'jpeg', 'png', 'gif', 'svg'];
                        $ext = strtolower(pathinfo($_FILES['header_logo']['name'], PATHINFO_EXTENSION));
                        if (in_array($ext, $allowed)) {
                            $dest = 'uploads/logos/app_logo_' . time() . '.' . $ext;
                            if (!is_dir('uploads/logos'))
                                @mkdir('uploads/logos', 0755, true);
                            if (move_uploaded_file($_FILES['header_logo']['tmp_name'], $dest)) {
                                update_app_scan_setting($mysqli, $current_admin_id, 'header_logo_path', $dest);
                            }
                        }
                    }

                    foreach ($_POST as $key => $value) {
                        if ($key === 'ajax_action')
                            continue;
                        if (is_array($value))
                            continue;
                        if (in_array($key, $system_wide_app_keys, true)) {
                            update_app_scan_setting($mysqli, 'SYSTEM_WIDE', $key, $value);
                            continue;
                        }

                        update_app_scan_setting($mysqli, $current_admin_id, $key, $value);
                    }
                    error_log("SAVE_APP_SCAN_SETTINGS: Settings updated");

                    // Candidates are now dynamic based on group
                    error_log("SAVE_APP_SCAN_SETTINGS: Success reached before notifications");

                    $checkboxes = ['telegram_notify_attendance', 'telegram_notify_requests', 'telegram_notify_attendance__worker', 'telegram_notify_requests__worker', 'app_default_dark_mode', 'attendance_reminder_enabled', 'app_force_update', 'payroll_biometric_required'];
                    $all_keys = ['stats_slider', 'attendance', 'outside_attendance', 'training_quiz', 'announcements', 'meetings', 'checklist', 'daily_report', 'mission', 'trip', 'user_management', 'request_form', 'reports', 'material_request', 'notification', 'notification_history', 'employee_report', 'payroll', 'profile_footer', 'home_footer'];
                    foreach (['skill', 'worker', 'hrm', 'admin'] as $role) {
                        foreach ($all_keys as $key) {
                            $checkboxes[] = "show_{$key}_card__{$role}";
                        }
                    }

                    foreach ($checkboxes as $cb) {
                        if (!isset($_POST[$cb])) {
                            if (in_array($cb, $system_wide_app_keys, true)) {
                                update_app_scan_setting($mysqli, 'SYSTEM_WIDE', $cb, '0');
                                continue;
                            }

                            update_app_scan_setting($mysqli, $current_admin_id, $cb, '0');
                        }
                    }


                    $new_build = (int) ($_POST['app_latest_build'] ?? 0);
                    if ($new_build > $old_build && $new_build > 0) {
                        $v_num = $_POST['app_latest_version'] ?? '1.0.0';
                        $u_msg = $_POST['app_update_message'] ?? "កម្មវិធីមានជំនាន់ថ្មី V$v_num! សូមធ្វើការអាប់ដេតដើម្បីទទួលបានមុខងារថ្មីៗ។";
                        $apk_url = trim((string) ($_POST['app_apk_url'] ?? ''));
                        $force_update_value = isset($_POST['app_force_update']) ? '1' : '0';

                        // Send automated broadcast notification with type 'version_update'
                        // This will trigger the update dialog on all active devices
                        if (function_exists('sendAppNotificationToAll')) {
                            sendAppNotificationToAll(
                                $mysqli,
                                "បច្ចុប្បន្នភាពកម្មវិធី V$v_num",
                                $u_msg,
                                $current_admin_id,
                                null,
                                null,
                                [
                                    'type' => 'version_update',
                                    'latest_version' => (string) $v_num,
                                    'latest_build' => (string) $new_build,
                                    'apk_url' => $apk_url,
                                    'message' => (string) $u_msg,
                                    'force_update' => $force_update_value,
                                ]
                            );
                        }
                    }

                    $success_message = 'ការកំណត់កម្មវិធីត្រូវបានរក្សាទុកដោយជោគជ័យ!';
                    if (!$is_ajax_request) {
                        app_scan_set_notice('success', $success_message);
                        admin_redirect_to('?page=settings&action=manage_app_scan');
                    }

                    $response = ['status' => 'success', 'message' => $success_message];
                    break;

                case 'process_purchase':
                    if (!hasPageAccess($mysqli, 'stock_control', 'stock_purchase', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $supplier = trim((string) ($_POST['supplier'] ?? ''));
                    $invoice_no = trim((string) ($_POST['invoice_number'] ?? ''));
                    $notes = trim((string) ($_POST['notes'] ?? ''));
                    $item_ids = $_POST['item_id'] ?? [];
                    $qtys = $_POST['quantity'] ?? [];
                    $prices = $_POST['price'] ?? [];

                    $mysqli->query("CREATE TABLE IF NOT EXISTS stock_purchase_history (
                        id INT AUTO_INCREMENT PRIMARY KEY,
                        supplier VARCHAR(255),
                        invoice_no VARCHAR(100),
                        invoice_image VARCHAR(255),
                        notes TEXT,
                        total_amount DECIMAL(15,2),
                        purchase_date DATETIME DEFAULT CURRENT_TIMESTAMP
                    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

                    $mysqli->query("CREATE TABLE IF NOT EXISTS stock_purchase_items (
                        id INT AUTO_INCREMENT PRIMARY KEY,
                        purchase_id INT,
                        item_id INT,
                        quantity INT,
                        price_per_unit DECIMAL(15,2),
                        FOREIGN KEY (purchase_id) REFERENCES stock_purchase_history(id) ON DELETE CASCADE
                    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

                    $img_path = '';
                    if (!empty($_FILES['invoice_image']['name'])) {
                        $target_dir = "uploads/stock/";
                        if (!is_dir($target_dir)) {
                            mkdir($target_dir, 0777, true);
                        }
                        $img_path = $target_dir . time() . "_" . basename($_FILES['invoice_image']['name']);
                        move_uploaded_file($_FILES['invoice_image']['tmp_name'], $img_path);
                    }

                    $total_amt = 0;
                    foreach ($qtys as $k => $q) {
                        $total_amt += (float) $q * (float) ($prices[$k] ?? 0);
                    }

                    try {
                        $mysqli->begin_transaction();

                        $stmt = $mysqli->prepare("INSERT INTO stock_purchase_history (supplier, invoice_no, invoice_image, notes, total_amount) VALUES (?, ?, ?, ?, ?)");
                        if (!$stmt) {
                            throw new Exception($mysqli->error);
                        }
                        $stmt->bind_param("ssssd", $supplier, $invoice_no, $img_path, $notes, $total_amt);
                        if (!$stmt->execute()) {
                            throw new Exception($stmt->error);
                        }
                        $purchase_id = (int) $mysqli->insert_id;
                        $stmt->close();

                        foreach ($item_ids as $k => $iid) {
                            $item_id = (int) $iid;
                            $qty = (int) ($qtys[$k] ?? 0);
                            $price = (float) ($prices[$k] ?? 0);
                            if ($item_id <= 0 || $qty <= 0) {
                                continue;
                            }

                            $stock_item = null;
                            if ($stock_stmt = $mysqli->prepare("SELECT item_name, quantity FROM stock_items WHERE id = ? LIMIT 1")) {
                                $stock_stmt->bind_param("i", $item_id);
                                $stock_stmt->execute();
                                $stock_res = $stock_stmt->get_result();
                                $stock_item = $stock_res ? $stock_res->fetch_assoc() : null;
                                $stock_stmt->close();
                            }
                            if (!$stock_item) {
                                throw new Exception('Stock item not found: #' . $item_id);
                            }

                            $quantity_before = (int) ($stock_item['quantity'] ?? 0);
                            $quantity_after = $quantity_before + $qty;

                            $si = $mysqli->prepare("INSERT INTO stock_purchase_items (purchase_id, item_id, quantity, price_per_unit) VALUES (?, ?, ?, ?)");
                            if (!$si) {
                                throw new Exception($mysqli->error);
                            }
                            $si->bind_param("iiid", $purchase_id, $item_id, $qty, $price);
                            if (!$si->execute()) {
                                throw new Exception($si->error);
                            }
                            $si->close();

                            $update_stmt = $mysqli->prepare("UPDATE stock_items SET quantity = ? WHERE id = ?");
                            if (!$update_stmt) {
                                throw new Exception($mysqli->error);
                            }
                            $update_stmt->bind_param("ii", $quantity_after, $item_id);
                            if (!$update_stmt->execute()) {
                                throw new Exception($update_stmt->error);
                            }
                            $update_stmt->close();

                            record_stock_movement($mysqli, [
                                'admin_id' => $current_admin_id,
                                'item_id' => $item_id,
                                'item_name' => (string) ($stock_item['item_name'] ?? ''),
                                'movement_type' => 'purchase',
                                'quantity_change' => $qty,
                                'quantity_before' => $quantity_before,
                                'quantity_after' => $quantity_after,
                                'reference_type' => 'stock_purchase',
                                'reference_id' => $purchase_id,
                                'reference_no' => $invoice_no !== '' ? $invoice_no : ('PUR-' . $purchase_id),
                                'unit_price' => $price,
                                'total_value' => $price * $qty,
                                'location' => $supplier,
                                'notes' => $notes,
                                'actor_name' => (string) ($_SESSION['admin_name'] ?? $current_admin_id),
                            ]);
                        }

                        $mysqli->commit();
                        $response = ['status' => 'success', 'message' => 'បានរក្សាទុកការទិញចូលជោគជ័យ!'];
                    } catch (Throwable $e) {
                        $mysqli->rollback();
                        $response = ['status' => 'error', 'message' => $e->getMessage()];
                    }
                    break;

                case 'process_purchase_legacy':
                    if (!hasPageAccess($mysqli, 'stock_control', 'stock_purchase', $current_admin_id)) {
                        echo json_encode(['status' => 'error', 'message' => 'Permission denied.']);
                        break;
                    }
                    $supplier = $_POST['supplier'] ?? '';
                    $invoice_no = $_POST['invoice_number'] ?? '';
                    $notes = $_POST['notes'] ?? '';
                    $item_ids = $_POST['item_id'] ?? [];
                    $qtys = $_POST['quantity'] ?? [];
                    $prices = $_POST['price'] ?? [];

                    $mysqli->query("CREATE TABLE IF NOT EXISTS stock_purchase_history (
                        id INT AUTO_INCREMENT PRIMARY KEY,
                        supplier VARCHAR(255),
                        invoice_no VARCHAR(100),
                        invoice_image VARCHAR(255),
                        notes TEXT,
                        total_amount DECIMAL(15,2),
                        purchase_date DATETIME DEFAULT CURRENT_TIMESTAMP
                    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

                    $mysqli->query("CREATE TABLE IF NOT EXISTS stock_purchase_items (
                        id INT AUTO_INCREMENT PRIMARY KEY,
                        purchase_id INT,
                        item_id INT,
                        quantity INT,
                        price_per_unit DECIMAL(15,2),
                        FOREIGN KEY (purchase_id) REFERENCES stock_purchase_history(id) ON DELETE CASCADE
                    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

                    $img_path = '';
                    if (!empty($_FILES['invoice_image']['name'])) {
                        $target_dir = "uploads/stock/";
                        if (!is_dir($target_dir))
                            mkdir($target_dir, 0777, true);
                        $img_path = $target_dir . time() . "_" . $_FILES['invoice_image']['name'];
                        move_uploaded_file($_FILES['invoice_image']['tmp_name'], $img_path);
                    }

                    $total_amt = 0;
                    foreach ($qtys as $k => $q) {
                        $total_amt += (float) $q * (float) ($prices[$k] ?? 0);
                    }

                    $stmt = $mysqli->prepare("INSERT INTO stock_purchase_history (supplier, invoice_no, invoice_image, notes, total_amount) VALUES (?, ?, ?, ?, ?)");
                    $stmt->bind_param("ssssd", $supplier, $invoice_no, $img_path, $notes, $total_amt);
                    if ($stmt->execute()) {
                        $p_id = $mysqli->insert_id;
                        foreach ($item_ids as $k => $iid) {
                            $qty = (int) $qtys[$k];
                            $price = (float) ($prices[$k] ?? 0);
                            $si = $mysqli->prepare("INSERT INTO stock_purchase_items (purchase_id, item_id, quantity, price_per_unit) VALUES (?, ?, ?, ?)");
                            $si->bind_param("iiid", $p_id, $iid, $qty, $price);
                            $si->execute();

                            // Update stock
                            $mysqli->query("UPDATE stock_items SET quantity = quantity + $qty WHERE id = $iid");
                        }
                        echo json_encode(['status' => 'success', 'message' => 'បានរក្សាទុកការទិញចូលជោគជ័យ!']);
                    } else {
                        echo json_encode(['status' => 'error', 'message' => $mysqli->error]);
                    }
                    exit;

                case 'process_direct_transfer':
                    if (!hasPageAccess($mysqli, 'stock_control', 'direct_transfer', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $title = trim((string) ($_POST['transfer_title'] ?? ''));
                    $req_no = trim((string) ($_POST['request_no'] ?? ''));
                    $location = trim((string) ($_POST['location'] ?? ''));
                    $items_data = $_POST['items'] ?? [];

                    $mysqli->query("CREATE TABLE IF NOT EXISTS stock_transfers (
                        id INT AUTO_INCREMENT PRIMARY KEY,
                        stock_item_id INT,
                        quantity_transferred INT,
                        to_location VARCHAR(255),
                        transfer_date DATETIME DEFAULT CURRENT_TIMESTAMP,
                        request_no VARCHAR(100),
                        title VARCHAR(255),
                        notes TEXT
                    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

                    $success_count = 0;
                    try {
                        $mysqli->begin_transaction();

                        foreach ($items_data as $iid => $v) {
                            $item_id = (int) $iid;
                            $qty = (int) ($v['qty'] ?? 0);
                            $note = trim((string) ($v['note'] ?? ''));
                            if ($item_id <= 0 || $qty <= 0) {
                                continue;
                            }

                            $stock_item = null;
                            if ($stock_stmt = $mysqli->prepare("SELECT item_name, quantity, price FROM stock_items WHERE id = ? LIMIT 1")) {
                                $stock_stmt->bind_param("i", $item_id);
                                $stock_stmt->execute();
                                $stock_res = $stock_stmt->get_result();
                                $stock_item = $stock_res ? $stock_res->fetch_assoc() : null;
                                $stock_stmt->close();
                            }
                            if (!$stock_item) {
                                throw new Exception('Stock item not found: #' . $item_id);
                            }

                            $quantity_before = (int) ($stock_item['quantity'] ?? 0);
                            if ($quantity_before < $qty) {
                                throw new Exception('Insufficient stock for ' . ((string) ($stock_item['item_name'] ?? 'item')));
                            }
                            $quantity_after = $quantity_before - $qty;

                            $stmt = $mysqli->prepare("INSERT INTO stock_transfers (stock_item_id, quantity_transferred, to_location, request_no, title, notes) VALUES (?, ?, ?, ?, ?, ?)");
                            if (!$stmt) {
                                throw new Exception($mysqli->error);
                            }
                            $stmt->bind_param("iissss", $item_id, $qty, $location, $req_no, $title, $note);
                            if (!$stmt->execute()) {
                                throw new Exception($stmt->error);
                            }
                            $transfer_id = (int) $mysqli->insert_id;
                            $stmt->close();

                            $update_stmt = $mysqli->prepare("UPDATE stock_items SET quantity = ? WHERE id = ?");
                            if (!$update_stmt) {
                                throw new Exception($mysqli->error);
                            }
                            $update_stmt->bind_param("ii", $quantity_after, $item_id);
                            if (!$update_stmt->execute()) {
                                throw new Exception($update_stmt->error);
                            }
                            $update_stmt->close();

                            record_stock_movement($mysqli, [
                                'admin_id' => $current_admin_id,
                                'item_id' => $item_id,
                                'item_name' => (string) ($stock_item['item_name'] ?? ''),
                                'movement_type' => 'direct_transfer',
                                'quantity_change' => -$qty,
                                'quantity_before' => $quantity_before,
                                'quantity_after' => $quantity_after,
                                'reference_type' => 'stock_transfer',
                                'reference_id' => $transfer_id,
                                'reference_no' => $req_no !== '' ? $req_no : ('TRN-' . $transfer_id),
                                'unit_price' => isset($stock_item['price']) ? (float) $stock_item['price'] : null,
                                'total_value' => isset($stock_item['price']) ? ((float) $stock_item['price'] * $qty) : null,
                                'location' => $location,
                                'notes' => $note !== '' ? $note : $title,
                                'actor_name' => (string) ($_SESSION['admin_name'] ?? $current_admin_id),
                            ]);
                            $success_count++;
                        }

                        if ($success_count <= 0) {
                            throw new Exception('No stock items were transferred.');
                        }

                        $mysqli->commit();
                        $response = ['status' => 'success', 'message' => 'បានផ្ទេរទំនិញជោគជ័យ ចំនួន ' . $success_count . ' មុខ!'];
                    } catch (Throwable $e) {
                        $mysqli->rollback();
                        $response = ['status' => 'error', 'message' => $e->getMessage()];
                    }
                    break;

                case 'process_direct_transfer_legacy':
                    if (!hasPageAccess($mysqli, 'stock_control', 'direct_transfer', $current_admin_id)) {
                        echo json_encode(['status' => 'error', 'message' => 'Permission denied.']);
                        break;
                    }
                    $title = $_POST['transfer_title'] ?? '';
                    $req_no = $_POST['request_no'] ?? '';
                    $location = $_POST['location'] ?? '';
                    $items_data = $_POST['items'] ?? [];

                    $mysqli->query("CREATE TABLE IF NOT EXISTS stock_transfers (
                        id INT AUTO_INCREMENT PRIMARY KEY,
                        stock_item_id INT,
                        quantity_transferred INT,
                        to_location VARCHAR(255),
                        transfer_date DATETIME DEFAULT CURRENT_TIMESTAMP,
                        request_no VARCHAR(100),
                        title VARCHAR(255),
                        notes TEXT
                    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

                    $success_count = 0;
                    foreach ($items_data as $iid => $v) {
                        $qty = (int) $v['qty'];
                        $note = $v['note'] ?? '';
                        $stmt = $mysqli->prepare("INSERT INTO stock_transfers (stock_item_id, quantity_transferred, to_location, request_no, title, notes) VALUES (?, ?, ?, ?, ?, ?)");
                        $stmt->bind_param("iissss", $iid, $qty, $location, $req_no, $title, $note);
                        if ($stmt->execute()) {
                            $mysqli->query("UPDATE stock_items SET quantity = quantity - $qty WHERE id = $iid");
                            $success_count++;
                        }
                    }

                    if ($success_count > 0) {
                        echo json_encode(['status' => 'success', 'message' => 'បានផ្ទេរទំនិញជោគជ័យ ចំនួន ' . $success_count . ' មុខ!']);
                    } else {
                        echo json_encode(['status' => 'error', 'message' => 'បរាជ័យក្នុងការផ្ទេរ!']);
                    }
                    exit;

                case 'search_employees':
                    $term = $mysqli->real_escape_string($_REQUEST['term'] ?? '');
                    $users = [];
                    $res = $mysqli->query("SELECT employee_id, name, avatar, position FROM users WHERE (name LIKE '%$term%' OR employee_id LIKE '%$term%') AND employment_status = 'Active' LIMIT 10");
                    if ($res) {
                        while ($r = $res->fetch_assoc())
                            $users[] = $r;
                    }
                    header('Content-Type: application/json');
                    echo json_encode(['status' => 'success', 'data' => $users]);
                    exit;

                case 'add_user_group':
                    $gname = trim($_POST['group_name'] ?? '');
                    if ($gname === '') {
                        $response = ['status' => 'error', 'message' => 'សូមបញ្ចូលឈ្មោះក្រុម!'];
                        break;
                    }
                    $stmt = $mysqli->prepare("INSERT INTO user_skill_groups (group_name, sort_order) VALUES (?, 0)");
                    if ($stmt) {
                        $stmt->bind_param("s", $gname);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'បានបន្ថែមក្រុមថ្មីជោគជ័យ!', 'id' => $mysqli->insert_id];
                        } else {
                            $response = ['status' => 'error', 'message' => $mysqli->error];
                        }
                        $stmt->close();
                    }
                    break;

                case 'rename_user_group':
                    $gid = (int) ($_POST['group_id'] ?? 0);
                    $gname = trim($_POST['group_name'] ?? '');
                    if ($gid > 0 && $gname !== '') {
                        $stmt = $mysqli->prepare("UPDATE user_skill_groups SET group_name = ? WHERE id = ?");
                        $stmt->bind_param("si", $gname, $gid);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'បានប្តូរឈ្មោះក្រុមជោគជ័យ!'];
                        }
                        $stmt->close();
                    }
                    break;

                case 'delete_user_group':
                    $gid = (int) ($_POST['id'] ?? ($_POST['group_id'] ?? 0));
                    if ($gid > 0) {
                        $mysqli->query("DELETE FROM user_skill_groups WHERE id = $gid");
                        $response = ['status' => 'success', 'message' => 'បានលុបក្រុមរួចរាល់!'];
                    }
                    break;

                case 'update_groups_sort':
                    $orders = $_POST['orders'] ?? []; // Array of {id, sort}
                    foreach ($orders as $o) {
                        $id = (int) ($o['id'] ?? 0);
                        $sort = (int) ($o['sort'] ?? 0);
                        if ($id > 0) {
                            $mysqli->query("UPDATE user_skill_groups SET sort_order = $sort WHERE id = $id");
                        }
                    }
                    $response = ['status' => 'success', 'message' => 'រក្សាទុកលំដាប់ជោគជ័យ!'];
                    break;

                case 'assign_user_group':
                    $employee_ids = $_POST['employee_ids'] ?? [];
                    $group_id = isset($_POST['group_id']) && $_POST['group_id'] !== '' ? (int) $_POST['group_id'] : null;

                    if (empty($employee_ids)) {
                        echo json_encode(['status' => 'error', 'message' => 'សូមជ្រើសរើសបុគ្គលិកយ៉ាងតិចម្នាក់']);
                        exit;
                    }

                    $success_count = 0;
                    foreach ($employee_ids as $eid) {
                        $eid = trim($eid);
                        $stmt = $mysqli->prepare("SELECT custom_data FROM users WHERE employee_id = ?");
                        $stmt->bind_param("s", $eid);
                        $stmt->execute();
                        $res = $stmt->get_result();
                        if ($row = $res->fetch_assoc()) {
                            $cd = json_decode($row['custom_data'] ?? '{}', true);
                            if ($group_id === null) {
                                unset($cd['group_id']);
                            } else {
                                $cd['group_id'] = $group_id;
                            }
                            $new_cd = json_encode($cd, JSON_UNESCAPED_UNICODE);

                            $upd = $mysqli->prepare("UPDATE users SET custom_data = ? WHERE employee_id = ?");
                            $upd->bind_param("ss", $new_cd, $eid);
                            if ($upd->execute()) {
                                $success_count++;
                            }
                        }
                    }
                    echo json_encode(['status' => 'success', 'message' => "បានកំណត់ក្រុមជូនបុគ្គលិកចំនួន $success_count នាក់ដោយជោគជ័យ"]);
                    exit;

                case 'get_request_timeline':
                    if (!hasPageAccess($mysqli, 'requests', 'requests', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $request_id = (int) ($_POST['request_id'] ?? $_GET['request_id'] ?? 0);
                    if ($request_id <= 0) {
                        $response = ['status' => 'error', 'message' => 'Invalid request id.'];
                        break;
                    }
                    $timeline_bundle = build_request_workflow_timeline($mysqli, $request_id);
                    if (empty($timeline_bundle['request'])) {
                        $response = ['status' => 'error', 'message' => 'Request not found.'];
                    } else {
                        $response = [
                            'status' => 'success',
                            'request' => $timeline_bundle['request'],
                            'timeline' => $timeline_bundle['timeline'],
                        ];
                    }
                    break;

                case 'get_requests':
                    $status_filter = $_POST['status'] ?? 'pending';
                    $requests = [];
                    $query = "SELECT r.*, COALESCE(r.requester_name, u.name) as employee_name, u.employee_id as employee_id, u.avatar as avatar FROM requests r LEFT JOIN users u ON r.user_id = u.id";
                    if ($status_filter !== 'all') {
                        $query .= " WHERE r.status = '" . $mysqli->real_escape_string($status_filter) . "'";
                    }
                    $query .= " ORDER BY r.created_at DESC LIMIT 100";
                    $res = $mysqli->query($query);
                    if ($res) {
                        while ($row = $res->fetch_assoc()) {
                            $requests[] = $row;
                        }
                    }
                    $response = ['status' => 'success', 'data' => $requests];
                    break;

                case 'get_stock_request_items':
                    $req_id = (int) ($_POST['id'] ?? 0);
                    $items = [];
                    $st = $pdo->prepare("SELECT sri.*, si.unit FROM stock_request_items sri LEFT JOIN stock_items si ON sri.item_id = si.id WHERE sri.stock_request_id = ?");
                    $st->execute([$req_id]);
                    $items = $st->fetchAll();
                    $response = ['status' => 'success', 'data' => $items];
                    break;

                case 'process_stock_request':
                    if (!hasPageAccess($mysqli, 'stock', 'stock_requests', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }

                    $req_id = (int) ($_POST['id'] ?? 0);
                    $new_status = trim((string) ($_POST['status'] ?? ''));
                    if ($req_id <= 0 || !in_array($new_status, ['approved', 'rejected'], true)) {
                        $response = ['status' => 'error', 'message' => 'Invalid data'];
                        break;
                    }

                    try {
                        $pdo->beginTransaction();

                        $request_stmt = $pdo->prepare("SELECT * FROM stock_request WHERE id = ? LIMIT 1");
                        $request_stmt->execute([$req_id]);
                        $stock_request = $request_stmt->fetch();
                        if (!$stock_request) {
                            throw new Exception('Stock request not found.');
                        }
                        if (($stock_request['status'] ?? '') !== 'pending') {
                            throw new Exception('This stock request was already processed.');
                        }

                        if ($new_status === 'approved') {
                            $item_stmt = $pdo->prepare("SELECT sri.*, si.item_name, si.quantity, si.price FROM stock_request_items sri LEFT JOIN stock_items si ON sri.item_id = si.id WHERE sri.stock_request_id = ?");
                            $item_stmt->execute([$req_id]);
                            $request_items = $item_stmt->fetchAll();
                            if (empty($request_items)) {
                                throw new Exception('No stock items found in this request.');
                            }

                            foreach ($request_items as $item) {
                                $item_id = (int) ($item['item_id'] ?? 0);
                                $requested_qty = (int) ($item['requested_quantity'] ?? 0);
                                $item_name = trim((string) ($item['item_name_custom'] ?? $item['item_name'] ?? 'Unknown Item'));
                                $quantity_before = (int) ($item['quantity'] ?? 0);
                                $unit_price = isset($item['price']) ? (float) $item['price'] : null;

                                if ($item_id <= 0 || $requested_qty <= 0) {
                                    continue;
                                }
                                if ($quantity_before < $requested_qty) {
                                    throw new Exception('Insufficient stock for ' . $item_name . '.');
                                }

                                $quantity_after = $quantity_before - $requested_qty;
                                $update_item_stmt = $pdo->prepare("UPDATE stock_items SET quantity = ? WHERE id = ?");
                                $update_item_stmt->execute([$quantity_after, $item_id]);

                                record_stock_movement($mysqli, [
                                    'admin_id' => $current_admin_id,
                                    'item_id' => $item_id,
                                    'item_name' => $item_name,
                                    'movement_type' => 'request_issue',
                                    'quantity_change' => -$requested_qty,
                                    'quantity_before' => $quantity_before,
                                    'quantity_after' => $quantity_after,
                                    'reference_type' => 'stock_request',
                                    'reference_id' => $req_id,
                                    'reference_no' => (string) ($stock_request['request_no'] ?? ''),
                                    'unit_price' => $unit_price,
                                    'total_value' => ($unit_price !== null ? ($unit_price * $requested_qty) : null),
                                    'location' => (string) ($stock_request['location'] ?? ''),
                                    'notes' => (string) ($item['notes'] ?? $stock_request['title'] ?? ''),
                                    'actor_name' => (string) ($_SESSION['admin_name'] ?? $current_admin_id),
                                ]);
                            }
                        }

                        $status_stmt = $pdo->prepare("UPDATE stock_request SET status = ? WHERE id = ?");
                        $status_stmt->execute([$new_status, $req_id]);
                        $pdo->commit();
                        $response = ['status' => 'success', 'message' => 'Stock request updated to ' . $new_status];
                    } catch (Throwable $e) {
                        if ($pdo->inTransaction()) {
                            $pdo->rollBack();
                        }
                        $response = ['status' => 'error', 'message' => $e->getMessage()];
                    }
                    break;

                case 'process_stock_request_legacy':
                    $req_id = (int) ($_POST['id'] ?? 0);
                    $new_status = $_POST['status'] ?? ''; // approved or rejected
                    if ($req_id > 0 && in_array($new_status, ['approved', 'rejected'])) {
                        $st = $pdo->prepare("UPDATE stock_request SET status = ? WHERE id = ?");
                        if ($st->execute([$new_status, $req_id])) {
                            $response = ['status' => 'success', 'message' => 'Stock request updated to ' . $new_status];
                        } else {
                            $response = ['status' => 'error', 'message' => 'Failed to update request'];
                        }
                    } else {
                        $response = ['status' => 'error', 'message' => 'Invalid data'];
                    }
                    break;

                case 'process_request':
                    if (!isset($_SESSION['admin_id'])) {
                        $response = ['status' => 'error', 'message' => 'Session expired'];
                        break;
                    }
                    if (!hasPageAccess($mysqli, 'requests', 'requests', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }

                    $rid = (int) ($_POST['request_id'] ?? 0);
                    $new_status = trim((string) ($_POST['status'] ?? ''));
                    $admin_comment = trim((string) ($_POST['comment'] ?? $_POST['admin_comment'] ?? ''));
                    if ($rid <= 0 || !in_array($new_status, ['approved', 'rejected'], true)) {
                        $response = ['status' => 'error', 'message' => 'ទិន្នន័យមិនត្រឹមត្រូវ!'];
                        break;
                    }

                    $mysqli->query("ALTER TABLE requests ADD COLUMN IF NOT EXISTS admin_comment TEXT DEFAULT NULL");
                    $mysqli->query("ALTER TABLE requests ADD COLUMN IF NOT EXISTS approved_by VARCHAR(191) DEFAULT NULL");
                    $mysqli->query("ALTER TABLE requests ADD COLUMN IF NOT EXISTS approved_at DATETIME DEFAULT NULL");

                    $request_row = null;
                    if ($stmt = $mysqli->prepare("SELECT r.id, r.status, r.request_type, u.employee_id, COALESCE(r.requester_name, u.name) AS employee_name FROM requests r LEFT JOIN users u ON r.user_id = u.id WHERE r.id = ? LIMIT 1")) {
                        $stmt->bind_param("i", $rid);
                        $stmt->execute();
                        $res = $stmt->get_result();
                        $request_row = $res ? $res->fetch_assoc() : null;
                        $stmt->close();
                    }
                    if (!$request_row) {
                        $response = ['status' => 'error', 'message' => 'រកមិនឃើញសំណើរ។'];
                        break;
                    }

                    $approved_by = (string) ($_SESSION['admin_name'] ?? $current_admin_id);
                    if ($stmt = $mysqli->prepare("UPDATE requests SET status = ?, admin_comment = ?, approved_by = ?, approved_at = NOW() WHERE id = ?")) {
                        $stmt->bind_param('sssi', $new_status, $admin_comment, $approved_by, $rid);
                        if ($stmt->execute()) {
                            add_request_workflow_log(
                                $mysqli,
                                $rid,
                                $new_status === 'approved' ? 'approved' : 'rejected',
                                (string) ($request_row['status'] ?? ''),
                                $new_status,
                                $current_admin_id,
                                $approved_by,
                                isSuperAdmin() ? 'Super Admin' : 'Admin',
                                $admin_comment !== '' ? $admin_comment : ('Request ' . $new_status . '.'),
                                ['request_type' => (string) ($request_row['request_type'] ?? '')]
                            );

                            $target_employee = trim((string) ($request_row['employee_id'] ?? ''));
                            if ($target_employee !== '') {
                                $notify_title = $new_status === 'approved' ? 'Request Approved' : 'Request Rejected';
                                $notify_message = 'Your ' . ((string) ($request_row['request_type'] ?? 'request')) . ' request was ' . $new_status . ' by ' . $approved_by;
                                if ($admin_comment !== '') {
                                    $notify_message .= ': ' . $admin_comment;
                                }
                                sendAppNotificationToUser($mysqli, $target_employee, $notify_title, $notify_message, $current_admin_id);
                            }

                            $response = [
                                'status' => 'success',
                                'message' => 'សំណើរត្រូវបាន ' . ($new_status === 'approved' ? 'យល់ព្រម' : 'បដិសេធ'),
                                'timeline' => build_request_workflow_timeline($mysqli, $rid)['timeline'] ?? [],
                            ];
                        } else {
                            $response = ['status' => 'error', 'message' => $stmt->error];
                        }
                        $stmt->close();
                    } else {
                        $response = ['status' => 'error', 'message' => $mysqli->error];
                    }
                    break;

                case 'process_request_legacy':
                    if (!isset($_SESSION['admin_id'])) {
                        $response = ['status' => 'error', 'message' => 'Session expired'];
                        break;
                    }
                    $rid = (int) ($_POST['request_id'] ?? 0);
                    $new_status = $_POST['status'] ?? '';
                    if ($rid > 0 && in_array($new_status, ['approved', 'rejected'])) {
                        $stmt = $mysqli->prepare("UPDATE requests SET status = ? WHERE id = ?");
                        if ($stmt) {
                            $stmt->bind_param('si', $new_status, $rid);
                            if ($stmt->execute()) {
                                $response = ['status' => 'success', 'message' => 'សំណើរត្រូវបាន ' . ($new_status === 'approved' ? 'យល់ព្រម' : 'បដិសេធ')];
                            } else {
                                $response = ['status' => 'error', 'message' => $mysqli->error];
                            }
                            $stmt->close();
                        }
                    } else {
                        $response = ['status' => 'error', 'message' => 'ទិន្នន័យមិនត្រឹមត្រូវ!'];
                    }
                    break;

                case 'get_meetings':
                    $meetings = [];
                    ensure_meeting_extended_columns($mysqli);
                    $res = $mysqli->query("SELECT m.*, a.name as admin_name
                                           FROM meetings m
                                           LEFT JOIN users a ON a.employee_id = COALESCE(NULLIF(m.admin_id, ''), NULLIF(m.created_by, ''))
                                           ORDER BY m.meeting_date DESC, m.created_at DESC");
                    if ($res) {
                        while ($row = $res->fetch_assoc()) {
                            $photos = [];
                            foreach (['related_photos', 'photos'] as $photo_field) {
                                $raw = $row[$photo_field] ?? '';
                                if (!is_string($raw) || trim($raw) === '') {
                                    continue;
                                }
                                $decoded = json_decode($raw, true);
                                if (is_array($decoded)) {
                                    foreach ($decoded as $photo_path) {
                                        $photo_path = trim((string) $photo_path);
                                        if ($photo_path !== '') {
                                            $photos[] = $photo_path;
                                        }
                                    }
                                }
                            }
                            $photos = array_values(array_unique($photos));
                            $display_photo = trim((string) ($row['photo_url'] ?? ''));
                            if ($display_photo === '' && !empty($photos)) {
                                $display_photo = $photos[0];
                            }

                            $display_audio = '';
                            foreach (['mp3_url', 'audio_file_path', 'audio_path'] as $audio_field) {
                                $candidate = trim((string) ($row[$audio_field] ?? ''));
                                if ($candidate !== '') {
                                    $display_audio = $candidate;
                                    break;
                                }
                            }

                            $row['display_title'] = trim((string) ($row['title'] ?? '')) !== '' ? $row['title'] : ((string) ($row['topic'] ?? ''));
                            $row['display_category'] = trim((string) ($row['category'] ?? '')) !== '' ? $row['category'] : ((string) ($row['department'] ?? 'General'));
                            $row['display_description'] = (string) ($row['description'] ?? '');
                            $row['display_audio_url'] = $display_audio;
                            $row['display_photo_url'] = $display_photo;
                            $row['display_photos'] = $photos;
                            $meetings[] = $row;
                        }
                    }
                    $response = ['status' => 'success', 'data' => $meetings];
                    break;

                case 'save_meeting':
                    $id = (int) ($_POST['id'] ?? 0);
                    $title = trim($_POST['title'] ?? '');
                    $date = $_POST['meeting_date'] ?? date('Y-m-d');
                    $cat = $_POST['category'] ?? 'General';
                    $desc = $_POST['description'] ?? '';
                    $ext_url = $_POST['external_url'] ?? '';
                    $photo_url = $_POST['photo_url'] ?? '';
                    $mp3_url = $_POST['mp3_url'] ?? '';
                    $admin_id = $_SESSION['admin_id'] ?? 'SYSTEM';

                    // Photo upload handling
                    if (isset($_FILES['photo']) && $_FILES['photo']['error'] === 0) {
                        $ext = strtolower(pathinfo($_FILES['photo']['name'], PATHINFO_EXTENSION));
                        if (in_array($ext, ['jpg', 'jpeg', 'png', 'gif'])) {
                            if (!is_dir('uploads/meetings'))
                                @mkdir('uploads/meetings', 0755, true);
                            $dest = 'uploads/meetings/' . time() . '_' . rand(100, 999) . '.' . $ext;
                            if (move_uploaded_file($_FILES['photo']['tmp_name'], $dest)) {
                                $photo_url = $dest;
                            }
                        }
                    }

                    // Audio upload handling
                    if (isset($_FILES['audio']) && $_FILES['audio']['error'] === 0) {
                        $ext = strtolower(pathinfo($_FILES['audio']['name'], PATHINFO_EXTENSION));
                        if (in_array($ext, ['mp3', 'wav', 'm4a', 'aac'])) {
                            if (!is_dir('uploads/meetings/audio'))
                                @mkdir('uploads/meetings/audio', 0755, true);
                            $dest = 'uploads/meetings/audio/' . time() . '_' . rand(100, 999) . '.' . $ext;
                            if (move_uploaded_file($_FILES['audio']['tmp_name'], $dest)) {
                                $mp3_url = $dest;
                            }
                        }
                    }

                    if ($title === '') {
                        $response = ['status' => 'error', 'message' => 'សូមបញ្ចូលចំណងជើង!'];
                    } else {
                        if ($id > 0) {
                            $stmt = $mysqli->prepare("UPDATE meetings SET title=?, category=?, meeting_date=?, description=?, external_url=?, photo_url=?, mp3_url=? WHERE id=?");
                            $stmt->bind_param("sssssssi", $title, $cat, $date, $desc, $ext_url, $photo_url, $mp3_url, $id);
                        } else {
                            $stmt = $mysqli->prepare("INSERT INTO meetings (title, category, meeting_date, description, external_url, photo_url, mp3_url, admin_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?)");
                            $stmt->bind_param("ssssssss", $title, $cat, $date, $desc, $ext_url, $photo_url, $mp3_url, $admin_id);
                        }

                        if ($stmt && $stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'រក្សាទុកកិច្ចប្រជុំបានជោគជ័យ!'];
                            $stmt->close();
                        } else {
                            $response = ['status' => 'error', 'message' => $mysqli->error];
                        }
                    }
                    break;

                case 'delete_meeting':
                    $id = (int) ($_POST['id'] ?? 0);
                    if ($id > 0) {
                        $mysqli->query("DELETE FROM meetings WHERE id = $id");
                        $response = ['status' => 'success', 'message' => 'បានលុបជោគជ័យ!'];
                    }
                    break;
                case 'save_panel_settings':
                    if (!hasPageAccess($mysqli, 'settings', 'panel_settings', $current_admin_id)) {
                        echo json_encode(['status' => 'error', 'message' => 'Permission denied.']);
                        exit;
                    }
                    $panel_title = $_POST['panel_title'] ?? 'Admin Panel';
