                    $response = ['status' => 'success', 'message' => 'ការកំណត់ទូទៅត្រូវបានរក្សាទុក!'];
                    break;
                case 'save_menu_settings':
                    if (!hasPageAccess($mysqli, 'settings', 'menu_settings', $current_admin_id)) {
                        echo json_encode(['status' => 'error', 'message' => 'Permission denied.']);
                        exit;
                    }
                    $menu_texts = $_POST['menu_text'] ?? [];
                    $menu_orders = $_POST['menu_order'] ?? [];
                    $submenu_texts = $_POST['submenu_text'] ?? [];

                    foreach ($menu_texts as $key => $text) {
                        $order = (int) ($menu_orders[$key] ?? 0);
                        $stmt = $mysqli->prepare("UPDATE sidebar_settings SET menu_text = ?, menu_order = ? WHERE menu_key = ?");
                        if ($stmt) {
                            $stmt->bind_param('sis', $text, $order, $key);
                            $stmt->execute();
                            $stmt->close();
                        }
                    }
                    foreach ($submenu_texts as $menu_key => $actions) {
                        foreach ($actions as $action_key => $sub_text) {
                            $stmt = $mysqli->prepare("UPDATE submenu_settings SET submenu_text = ? WHERE menu_key = ? AND action_key = ?");
                            if ($stmt) {
                                $stmt->bind_param('sss', $sub_text, $menu_key, $action_key);
                                $stmt->execute();
                                if ($stmt->affected_rows === 0) {
                                    $ins = $mysqli->prepare("INSERT IGNORE INTO submenu_settings (menu_key, action_key, submenu_text) VALUES (?, ?, ?)");
                                    if ($ins) {
                                        $ins->bind_param('sss', $menu_key, $action_key, $sub_text);
                                        $ins->execute();
                                        $ins->close();
                                    }
                                }
                                $stmt->close();
                            }
                        }
                    }
                    $response = ['status' => 'success', 'message' => 'ម៉ឺនុយត្រូវបានរក្សាទុក!'];
                    break;
                case 'save_sidebar_visibility':
                    if (!hasPageAccess($mysqli, 'settings', 'menu_settings', $current_admin_id)) {
                        echo json_encode(['status' => 'error', 'message' => 'Permission denied.']);
                        exit;
                    }
                    $hide_pages = $_POST['hide_page'] ?? [];
                    $hide_actions = $_POST['hide_action'] ?? [];
                    $hidden_items = array_merge($hide_pages, $hide_actions);

