                    update_setting($mysqli, $visibility_owner_id, 'sidebar_hidden_items', json_encode($hidden_items));
                    $response = ['status' => 'success', 'message' => 'ការបង្ហាញម៉ឺនុយត្រូវបានផ្លាស់ប្តូរ!'];
