                case 'save_workspace_order':
                    $ordered_pages = $_POST['ordered_pages'] ?? [];
                    if (!is_array($ordered_pages)) {
                        $ordered_pages = [$ordered_pages];
                    }
                    $workspace_order_owner_id = resolveVisibilityOwnerId($mysqli, $current_admin_id);
                    $requested_owner_id = trim((string) ($_POST['workspace_owner'] ?? ''));
                    if ($requested_owner_id !== '' && hash_equals($workspace_order_owner_id, $requested_owner_id)) {
                        $workspace_order_owner_id = $requested_owner_id;
                    }

                    $allowed_pages = array_keys($admin_pages_list);
                    $allowed_pages[] = 'homes';
                    $allowed_pages[] = 'stock';
                    $allowed_pages = array_values(array_unique($allowed_pages));

                    $clean_order = [];
                    foreach ($ordered_pages as $raw_key) {
                        $raw_key = trim((string) $raw_key);
                        if ($raw_key === '') {
                            continue;
                        }

                        [$normalized_page, $normalized_action] = normalize_access_target($raw_key, $raw_key);
                        if ($normalized_page === '' || !in_array($normalized_page, $allowed_pages, true)) {
                            continue;
                        }
                        if (isset($clean_order[$normalized_page])) {
                            continue; // dedupe
                        }
                        // Order preferences are harmless metadata.
                        // The drag list already comes from cards the user can currently see,
                        // so avoid re-filtering here with a different default action rule.
                        $clean_order[$normalized_page] = true;
                    }

                    $new_order = array_keys($clean_order);
                    $save_ok = save_workspace_card_order($mysqli, $workspace_order_owner_id, $new_order, $allowed_pages);
                    if (!$save_ok) {
                        $response = [
                            'status' => 'error',
                            'message' => 'មិនអាចរក្សាទុកលំដាប់ Workspace បានទេ'
                        ];
                        break;
                    }

                    $response = [
                        'status' => 'success',
                        'ordered' => get_workspace_card_order($mysqli, $workspace_order_owner_id, $allowed_pages),
                        'owner_id' => $workspace_order_owner_id,
                        'message' => 'បានរក្សាទុកលំដាប់ Workplace រួចរាល់'
                    ];
                    break;

                // RESTORED: User Management AJAX Handlers
                case 'add_user':
                    if (!$is_super_admin && !hasPageAccess($mysqli, 'users', 'create_user', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $uid = $_POST['new_id'] ?? '';
                    $name = $_POST['new_name'] ?? ($_POST['edit_name'] ?? '');
                    $latin_name = $_POST['latin_name'] ?? '';
