                                $dept,
                                $uname,
                                $email,
                                $phone,
                                $address,
                                $joined,
                                $marital,
                                $c_start,
                                $c_end,
                                $c_type,
                                $mgr,
                                $al_total,
                                $al_rem,
                                $al_rem, // Sync annual_leave_balance
                                $salary,
                                $nssf,
                                $bank_str,
                                $custom_json,
                                $pass
                            );

                            if ($stmt->execute()) {
                                $response = ['status' => 'success', 'message' => 'បុគ្គលិកត្រូវបានបន្ថែមជោគជ័យ!'];

                                // Handle File Uploads
                                $file_fields = [
                                    'avatar_file' => 'avatar',
                                    'jd_file' => 'jd_file_url',
                                    'workflow_file' => 'workflow_file_url',
                                    'bank_qr_file' => 'bank_qr_code_url'
                                ];
                                foreach ($file_fields as $f_key => $col_name) {
                                    if (isset($_FILES[$f_key]) && $_FILES[$f_key]['error'] === 0) {
                                        $ext = strtolower(pathinfo($_FILES[$f_key]['name'], PATHINFO_EXTENSION));
                                        $dir = 'uploads/users/' . str_replace('_file', '', $f_key) . '/';
                                        if (!is_dir($dir))
                                            @mkdir($dir, 0755, true);
                                        $filename = $dir . $uid . '_' . time() . '.' . $ext;
                                        if (move_uploaded_file($_FILES[$f_key]['tmp_name'], $filename)) {
                                            $mysqli->query("UPDATE users SET $col_name = '" . $mysqli->real_escape_string($filename) . "' WHERE employee_id = '" . $mysqli->real_escape_string($uid) . "'");
                                        }
                                    }
                                }
                            } else {
                                $response = ['status' => 'error', 'message' => $stmt->error];
                            }
                            $stmt->close();
                        } else {
                            $response = ['status' => 'error', 'message' => $mysqli->error];
                        }
                    } else {
                        $response = ['status' => 'error', 'message' => 'ID or Name cannot be empty.'];
                    }
                    break;



                case 'update_user_info':
                    $old_id = $_POST['edit_id'] ?? ($_POST['employee_id'] ?? '');
                    $new_id = $_POST['new_id'] ?? $old_id;
                    $name = $_POST['edit_name'] ?? ($_POST['name'] ?? '');
                    $latin_name = $_POST['latin_name'] ?? '';
                    $role = $_POST['user_role'] ?? '';
                    $sys_role = $_POST['system_role'] ?? '';
                    $sys_label = $_POST['system_role_label'] ?? '';
                    $pos = $_POST['position'] ?? '';
                    $dept = $_POST['department'] ?? '';
                    $uname = $_POST['username'] ?? '';
                    $email = $_POST['email'] ?? '';
                    $phone = $_POST['phone'] ?? '';
                    $address = $_POST['current_address'] ?? '';
                    $joined = !empty($_POST['joined_at']) ? $_POST['joined_at'] : null;
                    $marital = $_POST['marital_status'] ?? '';
                    $c_start = !empty($_POST['contract_start']) ? $_POST['contract_start'] : null;
                    $c_end = !empty($_POST['contract_end']) ? $_POST['contract_end'] : null;
