                        ];
                        $types = "sssssssssssssssssdddddsss";

                        if (!empty($pass)) {
                            $update_sql .= ", password = ?";
                            $params[] = $pass;
                            $types .= "s";
                        }

                        // Handle File Uploads
                        $file_fields = [
                            'avatar_file' => 'avatar',
                            'jd_file' => 'jd_file_url',
                            'workflow_file' => 'workflow_file_url',
