                                $dir = 'uploads/users/' . str_replace('_file', '', $f_key) . '/';
                                if (!is_dir($dir))
                                    @mkdir($dir, 0755, true);
                                $filename = $dir . $old_id . '_' . time() . '.' . $ext;
                                if (move_uploaded_file($_FILES[$f_key]['tmp_name'], $filename)) {
                                    $update_sql .= ", $col_name = ?";
                                    $params[] = $filename;
                                    $types .= "s";
                                }
                            }
                        }

                        $update_sql .= " WHERE employee_id = ?";
                        $params[] = $old_id;
                        $types .= "s";

                        $stmt = $mysqli->prepare($update_sql);
                        if ($stmt) {
