                        $response = ['status' => 'error', 'message' => 'Only Super Admin can edit permissions.'];
                        break;
                    }
                    $target_uid = $_POST['target_admin_id'] ?? '';
                    $permissions = $_POST['permissions'] ?? [];
                    if (!empty($target_uid)) {
                        ensure_admin_permissions_table($mysqli);
                        if ($delete_stmt = $mysqli->prepare("DELETE FROM admin_permissions WHERE admin_id = ?")) {
                            $delete_stmt->bind_param('s', $target_uid);
                            $delete_stmt->execute();
                            $delete_stmt->close();
                        }
                        $normalized_permissions = [];
                        if (!empty($permissions)) {
                            foreach ($permissions as $page_key => $actions) {
                                foreach ((array) $actions as $action_key) {
                                    [$page_key, $action_key] = normalize_access_target($page_key, $action_key);
                                    if (!isset($admin_pages_list[$page_key][$action_key])) {
                                        continue;
                                    }
                                    if ($page_key === 'users' && in_array($action_key, ['create_admin', 'edit_admin_access'], true)) {
                                        continue;
                                    }
                                    $normalized_permissions[$page_key][$action_key] = true;
                                }
                            }
                        }
                        if (!empty($normalized_permissions['users']['edit_rules'])) {
                            $normalized_permissions['users']['list_users'] = true;
                        }
                        if (!empty($normalized_permissions)) {
                            $stmt = $mysqli->prepare("INSERT INTO admin_permissions (admin_id, page_key, action_key) VALUES (?, ?, ?)");
                            if ($stmt) {
                                foreach ($normalized_permissions as $page_key => $actions) {
                                    foreach (array_keys($actions) as $action_key) {
                                        if (!isset($admin_pages_list[$page_key][$action_key])) {
                                            continue;
                                        }
                                        $stmt->bind_param('sss', $target_uid, $page_key, $action_key);
                                        $stmt->execute();
                                    }
                                }
                                $stmt->close();
                            }
                        }
                        // Turn on strict permission mode only when super admin saves access rules.
                        update_setting($mysqli, $target_uid, 'admin_permission_mode', '1');
                        $response = ['status' => 'success', 'message' => 'សិទ្ធិត្រូវបានរក្សាទុកជោគជ័យ!'];
                    }
                    break;

                case 'add_admin':
