                        break;
                    }
                    $aid = $_POST['admin_id'] ?? '';
                    $aname = $_POST['admin_name'] ?? '';
                    $apass = $_POST['admin_password'] ?? '';
                    if (!empty($aid) && !empty($apass)) {
                        $apass_hashed = hashPassword($apass);
                        $stmt = $mysqli->prepare("INSERT INTO users (employee_id, name, password, user_role) VALUES (?, ?, ?, 'Admin') ON DUPLICATE KEY UPDATE name=VALUES(name), password=VALUES(password), user_role='Admin'");
                        $stmt->bind_param("sss", $aid, $aname, $apass_hashed);
                        if ($stmt->execute()) {
                            ensure_admin_permissions_table($mysqli);
                            update_setting($mysqli, $aid, 'admin_permission_mode', '1');
                            $response = [
                                'status' => 'success',
                                'message' => 'Admin ត្រូវបានបង្កើតហើយ។ សូមកំណត់ workspace/access បន្ត។',
                                'redirect_url' => '?page=users&action=edit_admin_access&id=' . rawurlencode($aid),
                            ];
                        } else {
                            $response = ['status' => 'error', 'message' => $stmt->error];
                        }
                        $stmt->close();
                    }
                    break;

                case 'payroll_get_config':
                    $uid = $_POST['user_id'] ?? '';
