                        $stmt->bind_param('s', $uid);
                        $stmt->execute();
                        $result = $stmt->get_result();
                        $config = $result->fetch_assoc();
                        $stmt->close();
                        $response = ['status' => 'success', 'data' => $config];
                    }
                    break;

                case 'payroll_save_config':
                    $uid = $_POST['employee_id'] ?? '';
                    $base = $_POST['base_salary'] ?? 0;
                    $bank = $_POST['bank_name'] ?? ''; // used for concatenation
                    $acc = $_POST['bank_account_number'] ?? ''; // used for concatenation
                    $bank_str = trim($bank . " " . $acc);

                    if ($uid) {
                        // Handle QR Code Upload
                        $bank_qr_url = null;
                        if (isset($_FILES['bank_qr']) && $_FILES['bank_qr']['error'] === 0) {
                            $ext = strtolower(pathinfo($_FILES['bank_qr']['name'], PATHINFO_EXTENSION));
                            $upload_dir = 'uploads/users/bank_qr/';
                            if (!is_dir($upload_dir))
                                mkdir($upload_dir, 0755, true);
                            $new_file = $upload_dir . $uid . '_' . time() . '.' . $ext;
                            if (move_uploaded_file($_FILES['bank_qr']['tmp_name'], $new_file)) {
                                $bank_qr_url = $new_file;
                            }
                        }

                        // Update both for safety, but primarily users table
                        $sql = "UPDATE users SET base_salary = ?, bank_data_str = ?";
                        if ($bank_qr_url)
                            $sql .= ", bank_qr_code_url = ?";
                        $sql .= " WHERE employee_id = ?";

                        $stmt = $mysqli->prepare($sql);
                        if ($stmt) {
                            if ($bank_qr_url) {
                                $stmt->bind_param('dsss', $base, $bank_str, $bank_qr_url, $uid);
                            } else {
                                $stmt->bind_param('dss', $base, $bank_str, $uid);
                            }
                            $stmt->execute();
                            $stmt->close();
                        }

                        // Also update payroll_configs
                        $mysqli->query("INSERT INTO payroll_configs (employee_id, base_salary, bank_name, bank_account_number) VALUES ('$uid', $base, '$bank', '$acc') ON DUPLICATE KEY UPDATE base_salary=VALUES(base_salary), bank_name=VALUES(bank_name), bank_account_number=VALUES(bank_account_number)");

                        $response = ['status' => 'success', 'message' => 'រក្សាទុកបានជោគជ័យ!'];
                    }
                    break;

                case 'calculate_payroll':
                    $mysqli->query("CREATE TABLE IF NOT EXISTS payroll_history (
                        id INT AUTO_INCREMENT PRIMARY KEY,
                        employee_id VARCHAR(50),
                        payroll_month VARCHAR(2),
                        payroll_year VARCHAR(4),
                        base_salary DECIMAL(10,2),
                        present_days INT,
                        calculated_salary DECIMAL(10,2),
                        status VARCHAR(20) DEFAULT 'Paid',
                        payment_date DATETIME DEFAULT CURRENT_TIMESTAMP
                    ) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");
                    $mysqli->query("ALTER TABLE payroll_history CONVERT TO CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");

                    $month = $_POST['month'] ?? date('m');
                    $year = $_POST['year'] ?? date('Y');
                    $month_padded = str_pad($month, 2, '0', STR_PAD_LEFT);
                    $target_month_year = $year . "-" . $month_padded;

                    $data = [];
                    $users_sql = "SELECT u.employee_id, u.name, u.base_salary FROM users u ORDER BY u.employee_id ASC";
                    $result = $mysqli->query($users_sql);
                    if ($result) {
                        while ($row = $result->fetch_assoc()) {
                            $emp_id = $row['employee_id'];
                            $base_salary = $row['base_salary'] ? (float) $row['base_salary'] : 0;

                            // 1. Present days
                            $stmt = $mysqli->prepare("SELECT COUNT(DISTINCT DATE(log_datetime)) as present_days FROM checkin_logs WHERE employee_id=? AND MONTH(log_datetime)=? AND YEAR(log_datetime)=?");
                            $present_days = 0;
                            if ($stmt) {
                                $stmt->bind_param("sii", $emp_id, $month, $year);
                                $stmt->execute();
                                $r = $stmt->get_result()->fetch_assoc();
                                $present_days = $r['present_days'] ?? 0;
                                $stmt->close();
                            }

                            // 2. Base Calculation
                            $base_component = ($base_salary / 30) * $present_days;

                            // 3. Deductions
                            $deduct_sum = 0;
                            $d_stmt = $mysqli->prepare("SELECT SUM(amount) as total FROM payroll_deductions WHERE employee_id=? AND MONTH(deduction_date)=? AND YEAR(deduction_date)=?");
                            if ($d_stmt) {
                                $d_stmt->bind_param("sii", $emp_id, $month, $year);
                                $d_stmt->execute();
                                $dr = $d_stmt->get_result()->fetch_assoc();
                                $deduct_sum = (float) ($dr['total'] ?? 0);
                                $d_stmt->close();
                            }

                            // 4. OT Bonus
                            $ot_sum = 0;
                            $o_stmt = $mysqli->prepare("SELECT SUM(amount) as total FROM payroll_ot WHERE employee_id=? AND ot_month=? AND ot_year=?");
                            if ($o_stmt) {
                                $o_stmt->bind_param("sss", $emp_id, $month_padded, $year);
                                $o_stmt->execute();
                                $or = $o_stmt->get_result()->fetch_assoc();
                                $ot_sum = (float) ($or['total'] ?? 0);
                                $o_stmt->close();
                            }

                            // 5. Loan Repayment
                            $loan_sum = 0;
                            $l_stmt = $mysqli->prepare("
                                SELECT SUM(monthly_deduction) as total 
                                FROM payroll_loans 
                                WHERE employee_id=? 
                                AND ? >= start_month 
                                AND PERIOD_DIFF(REPLACE(?, '-', ''), REPLACE(start_month, '-', '')) < duration_months
                            ");
                            if ($l_stmt) {
                                $l_stmt->bind_param("sss", $emp_id, $target_month_year, $target_month_year);
                                $l_stmt->execute();
                                $lr = $l_stmt->get_result()->fetch_assoc();
                                $loan_sum = (float) ($lr['total'] ?? 0);
                                $l_stmt->close();
                            }

                            // 6. Net Calculation
                            $net_salary = $base_component - $deduct_sum + $ot_sum - $loan_sum;
                            if ($net_salary < 0)
                                $net_salary = 0;

                            // Check status
                            $paid_stmt = $mysqli->prepare("SELECT id FROM payroll_history WHERE employee_id=? AND payroll_month=? AND payroll_year=?");
                            $is_paid = false;
                            if ($paid_stmt) {
                                $paid_stmt->bind_param("sss", $emp_id, $month_padded, $year);
                                $paid_stmt->execute();
                                if ($paid_stmt->get_result()->num_rows > 0) {
                                    $is_paid = true;
                                }
                                $paid_stmt->close();
                            }

                            $data[] = [
                                'employee_id' => $row['employee_id'],
                                'name' => $row['name'],
                                'base_salary' => $base_salary,
                                'present_days' => $present_days,
                                'base_component' => round($base_component, 2),
                                'deductions' => round($deduct_sum, 2),
                                'ot_bonus' => round($ot_sum, 2),
                                'loan_deduct' => round($loan_sum, 2),
                                'calculated_salary' => round($net_salary, 2),
                                'is_paid' => $is_paid
                            ];
                        }
                    }
                    $response = ['status' => 'success', 'data' => $data];
                    break;

                case 'process_payroll':
                    $month = $_POST['month'] ?? date('m');
                    $year = $_POST['year'] ?? date('Y');
                    $emp_id = $_POST['employee_id'] ?? '';
                    $base_salary = $_POST['base_salary'] ?? 0;
                    $present_days = $_POST['present_days'] ?? 0;
                    $calculated_salary = $_POST['calculated_salary'] ?? 0;

                    if ($emp_id) {
                        $stmt = $mysqli->prepare("INSERT INTO payroll_history (employee_id, payroll_month, payroll_year, base_salary, present_days, calculated_salary, status) VALUES (?, ?, ?, ?, ?, ?, 'Paid')");
                        if ($stmt) {
                            $stmt->bind_param("sssddd", $emp_id, $month, $year, $base_salary, $present_days, $calculated_salary);
                            if ($stmt->execute()) {
                                $response = ['status' => 'success', 'message' => 'បើកប្រាក់បៀវត្សបានជោគជ័យ!'];

                                // Send push notification to user
                                if (file_exists('notification_functions.php')) {
                                    require_once 'notification_functions.php';
                                    $title = "ប្រាក់ខែប្រចាំខែ ($month/$year)";
                                    $body = "ប្រាក់ខែរបស់អ្នកត្រូវបានបើកជោគជ័យ! ទឹកប្រាក់ទទួលបានគឺ: $" . number_format($calculated_salary, 2) . "។";
                                    sendAppNotificationToUser($mysqli, $emp_id, $title, $body);
                                }
                            } else {
                                $response = ['status' => 'error', 'message' => $stmt->error];
                            }
                            $stmt->close();
                        } else {
                            $response = ['status' => 'error', 'message' => $mysqli->error];
                        }
                    } else {
                        $response = ['status' => 'error', 'message' => 'Employee ID is required.'];
                    }
                    break;

                case 'save_deduction':
                    $emp_id = $_POST['emp_id'] ?? '';
                    $amount = $_POST['amount'] ?? 0;
                    $reason = $_POST['reason'] ?? '';
                    $deduction_date = !empty($_POST['deduction_date']) ? $_POST['deduction_date'] : date('Y-m-d');

                    if ($emp_id) {
                        $mysqli->query("CREATE TABLE IF NOT EXISTS payroll_deductions (
                            id INT AUTO_INCREMENT PRIMARY KEY,
                            employee_id VARCHAR(50),
                            amount DECIMAL(10,2),
                            reason VARCHAR(255),
                            deduction_date DATE,
                            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
                        ) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");

                        $stmt = $mysqli->prepare("INSERT INTO payroll_deductions (employee_id, amount, reason, deduction_date) VALUES (?, ?, ?, ?)");
                        $stmt->bind_param("sdss", $emp_id, $amount, $reason, $deduction_date);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'បានរក្សាទុកការកាត់ប្រាក់បៀវត្សជោគជ័យ!'];
                        } else {
                            $response = ['status' => 'error', 'message' => $stmt->error];
                        }
                        $stmt->close();
                    }
                    break;

                case 'save_ot':
                    $emp_id = $_POST['emp_id'] ?? '';
                    $ot_month = $_POST['ot_month'] ?? date('m');
                    $ot_year = $_POST['ot_year'] ?? date('Y');
                    $amount = $_POST['amount'] ?? 0;
                    $note = $_POST['note'] ?? '';

                    if ($emp_id) {
                        $mysqli->query("CREATE TABLE IF NOT EXISTS payroll_ot (
                            id INT AUTO_INCREMENT PRIMARY KEY,
                            employee_id VARCHAR(50),
                            ot_month VARCHAR(2),
                            ot_year VARCHAR(4),
                            amount DECIMAL(10,2),
                            note VARCHAR(255),
                            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
                        ) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");

                        $stmt = $mysqli->prepare("INSERT INTO payroll_ot (employee_id, ot_month, ot_year, amount, note) VALUES (?, ?, ?, ?, ?)");
                        $stmt->bind_param("sssds", $emp_id, $ot_month, $ot_year, $amount, $note);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'បានរក្សាទុកប្រាក់ថែមម៉ោងជោគជ័យ!'];
                        } else {
                            $response = ['status' => 'error', 'message' => $stmt->error];
                        }
                        $stmt->close();
                    }
                    break;

                case 'save_loan':
                    $emp_id = $_POST['emp_id'] ?? '';
                    $loan_amount = $_POST['loan_amount'] ?? 0;
                    $monthly_deduct = $_POST['monthly_deduct'] ?? 0;
                    $loan_date = !empty($_POST['loan_date']) ? $_POST['loan_date'] : date('Y-m-d');
                    $start_month = !empty($_POST['start_month']) ? $_POST['start_month'] : date('Y-m');
                    $duration = $_POST['duration'] ?? 1;
                    $note = $_POST['note'] ?? '';
                    $adjust_request = $_POST['adjust_request'] ?? '';

                    if ($emp_id) {
                        $mysqli->query("CREATE TABLE IF NOT EXISTS payroll_loans (
                            id INT AUTO_INCREMENT PRIMARY KEY,
                            employee_id VARCHAR(50),
                            loan_amount DECIMAL(10,2),
                            monthly_deduction DECIMAL(10,2),
                            loan_date DATE,
                            start_month VARCHAR(7),
                            duration_months INT,
                            note VARCHAR(255),
                            adjust_request VARCHAR(255),
                            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
                        ) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");

                        $stmt = $mysqli->prepare("INSERT INTO payroll_loans (employee_id, loan_amount, monthly_deduction, loan_date, start_month, duration_months, note, adjust_request) VALUES (?, ?, ?, ?, ?, ?, ?, ?)");
                        $stmt->bind_param("sddssiss", $emp_id, $loan_amount, $monthly_deduct, $loan_date, $start_month, $duration, $note, $adjust_request);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'បានរក្សាទុកទិន្នន័យបំណុលជោគជ័យ!'];
                        } else {
                            $response = ['status' => 'error', 'message' => $stmt->error];
                        }
                        $stmt->close();
                    }
                    break;

                case 'revoke_token':
                    if (!hasPageAccess($mysqli, 'tokens', 'active_sessions', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $token = $mysqli->real_escape_string($_POST['token'] ?? '');
                    if ($mysqli->query("DELETE FROM active_tokens WHERE auth_token = '$token'")) {
                        $response = ['status' => 'success', 'message' => 'Token revoked successfully.'];
                    } else {
                        $response = ['status' => 'error', 'message' => 'Failed to revoke token.'];
                    }
                    break;

                case 'revoke_bulk_tokens':
                    if (!hasPageAccess($mysqli, 'tokens', 'active_sessions', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $tokens = $_POST['tokens'] ?? [];
                    if (!is_array($tokens) || empty($tokens)) {
                        $response = ['status' => 'error', 'message' => 'No sessions selected.'];
                        break;
                    }

                    $placeholders = implode(',', array_fill(0, count($tokens), '?'));
                    $stmt = $mysqli->prepare("DELETE FROM active_tokens WHERE auth_token IN ($placeholders)");
                    if ($stmt) {
                        $types = str_repeat('s', count($tokens));
                        $stmt->bind_param($types, ...$tokens);
                        if ($stmt->execute()) {
                            $response = ['status' => 'success', 'message' => 'Successfully revoked ' . $stmt->affected_rows . ' sessions.'];
                        } else {
                            $response = ['status' => 'error', 'message' => 'Bulk delete failed.'];
                        }
                        $stmt->close();
                    } else {
                        $response = ['status' => 'error', 'message' => 'Database prepare error.'];
                    }
                    break;

                case 'revoke_all_my_users_tokens':
                    if (!hasPageAccess($mysqli, 'tokens', 'active_sessions', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    // For now, allow admin to clear ALL tokens if they have access to this page
                    if ($mysqli->query("DELETE FROM active_tokens")) {
                        $response = ['status' => 'success', 'message' => 'All sessions have been revoked.'];
                    } else {
                        $response = ['status' => 'error', 'message' => 'Failed to revoke sessions.'];
                    }
                    break;

                case 'set_global_max_tokens':
                    if (!hasPageAccess($mysqli, 'tokens', 'global_settings', $current_admin_id)) {
                        $response = ['status' => 'error', 'message' => 'Permission denied.'];
                        break;
                    }
                    $max = (int) ($_POST['global_max_tokens'] ?? 1);
                    if ($max < 1)
                        $max = 1;
                    if ($max > 10)
                        $max = 10;

                    if ($mysqli->query("UPDATE users SET global_max_tokens = $max WHERE employee_id = '$current_admin_id'")) {
                        $response = ['status' => 'success', 'message' => "កំណត់ចំនួន Token អតិបរមាទៅកាន់ $max បានជោគជ័យ!"];
                    } else {
                        $response = ['status' => 'error', 'message' => 'Database error during update.'];
                    }
                    break;

                case 'save_policy':
                    $mysqli->query("CREATE TABLE IF NOT EXISTS payroll_settings (
                        setting_key VARCHAR(50) PRIMARY KEY,
                        setting_value VARCHAR(255)
                    ) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");

                    $forgot_scan = $_POST['forgot_scan'] ?? '0';
                    $ot_multiplier = $_POST['ot_multiplier'] ?? '1';

                    $mysqli->query("INSERT INTO payroll_settings (setting_key, setting_value) VALUES ('forgot_scan_deduct', '{$forgot_scan}') ON DUPLICATE KEY UPDATE setting_value = '{$forgot_scan}'");
                    $mysqli->query("INSERT INTO payroll_settings (setting_key, setting_value) VALUES ('ot_multiplier', '{$ot_multiplier}') ON DUPLICATE KEY UPDATE setting_value = '{$ot_multiplier}'");

                    $response = ['status' => 'success', 'message' => 'បានរក្សាទុកការកំណត់គោលការណ៍ជោគជ័យ!'];
                    break;
            }


            // Clear any potential warnings/errors that would break JSON
            if (!admin_is_ajax_request() && strtoupper((string) ($_SERVER['REQUEST_METHOD'] ?? 'GET')) === 'POST') {
                $flash_status = !empty($response['success']) ? 'success' : (string) ($response['status'] ?? 'info');
                if (!in_array($flash_status, ['success', 'error', 'warning', 'info'], true)) {
                    $flash_status = 'info';
                }
                $flash_message = (string) ($response['message'] ?? ($flash_status === 'success' ? 'រក្សាទុកបានជោគជ័យ!' : 'មានកំហុសបានកើតឡើង'));
                admin_set_flash_message($flash_status, $flash_message);

                $redirect_url = (string) ($response['redirect_url'] ?? '');
                if ($redirect_url === '' || strpos($redirect_url, "\n") !== false || strpos($redirect_url, "\r") !== false) {
                    $redirect_url = admin_safe_return_url();
                }
                if (ob_get_length()) {
                    ob_clean();
                }
                admin_redirect_to($redirect_url);
            }

            if (ob_get_length())
                ob_clean();
            header('Content-Type: application/json; charset=UTF-8');
            echo json_encode($response, JSON_UNESCAPED_UNICODE);
            exit;
    }
}
// ----------------------------------------------------
// END AJAX HANDLER BLOCK
// ----------------------------------------------------


// ដំណើរការ Logout
if (isset($_GET['logout'])) {
    unset($_SESSION['admin_logged_in']);
    unset($_SESSION['admin_id']);
    unset($_SESSION['admin_name']);
    unset($_SESSION['is_super_admin']); // លុប Session ថ្មី
    // Clear sub user session data if present
    unset($_SESSION['sub_user_logged_in']);
    unset($_SESSION['sub_user_parent_id']);
    unset($_SESSION['sub_user_id']);
    unset($_SESSION['sub_user_name']);
    unset($_SESSION['sub_user_permissions']);
    unset($_SESSION['combined_admin_sub_mode']);

    // If a remember cookie exists for admin, remove its token from DB and clear cookie
    if (!empty($_COOKIE['remember_admin'])) {
        list($selector, ) = explode(':', $_COOKIE['remember_admin'], 2);
        if (!empty($selector) && $stmt = $mysqli->prepare("DELETE FROM auth_tokens WHERE selector = ?")) {
            $stmt->bind_param('s', $selector);
            $stmt->execute();
            $stmt->close();
        }
        setcookie('remember_admin', '', time() - 3600, '/');
    }

    session_destroy();
    ob_end_clean();
    header("Location: admin_attendance.php");
    exit;
}

// ពេលមិនទាន់ Login គឺកំណត់ទៅជា 'login'
$current_page = $_GET['page'] ?? 'login';
$current_action = $_GET['action'] ?? $current_page; // Set default action for page check

// ពិនិត្យ Login មុននឹងបន្តទៅ Logic
$show_admin_pages = checkAdminLogin($mysqli);
$is_super_admin = isSuperAdmin();

// Load Login Page settings before checking if the user is logged in
$login_page_title = get_setting($mysqli, 'SYSTEM_WIDE', 'login_page_title', 'Admin Panel Login');
$login_page_logo_path = get_setting($mysqli, 'SYSTEM_WIDE', 'login_page_logo_path', '');
$login_page_icon_class = get_setting($mysqli, 'SYSTEM_WIDE', 'login_page_icon_class', 'fa-solid fa-user-shield');

if ($show_admin_pages) {
    $current_admin_id = $_SESSION['admin_id'] ?? ($_SESSION['sub_user_parent_id'] ?? ($_SESSION['sub_user_id'] ?? 'SYSTEM_WIDE'));

    initialize_sidebar_settings($mysqli, $current_admin_id); // Ensure settings exist
    $panel_title = get_setting($mysqli, $current_admin_id, 'panel_title', 'Admin Panel');
    $panel_logo_path = get_setting($mysqli, $current_admin_id, 'panel_logo_path', '');
    $show_title_with_logo = (bool) get_setting($mysqli, $current_admin_id, 'show_title_with_logo', '1');

    $default_footer = '&copy; ' . date("Y") . ' **Attendance Check-In System**. រៀបចំដោយ <a href="#" target="_blank">Your Company Name</a>. រក្សាសិទ្ធិគ្រប់យ៉ាង។';
    $footer_text = get_setting($mysqli, $current_admin_id, 'footer_text', $default_footer);

    if ($current_page == 'login' || $current_page == 'setup') {
        $current_page = 'dashboard';
        $current_action = 'dashboard';
    }

    // Check Access Permission for Non-Super Admins
    $admin_id_check = $current_admin_id;
    if (!$is_super_admin && !hasPageAccess($mysqli, $current_page, $current_action, $admin_id_check)) {
        // បើ Admin ធម្មតា ហើយទំព័រនេះមិនមានសិទ្ធិចូលប្រើ គឺបញ្ជូនទៅ Dashboard
        ob_end_clean();
        header("Location: admin_attendance.php?page=dashboard");
        exit;
    }

    // រាប់ PENDING REQUESTS
    $pending_requests_count = 0;
    if (hasPageAccess($mysqli, 'requests', 'requests', $_SESSION['admin_id'])) {
        $count_query_sql = "SELECT COUNT(*) as pending_count FROM `requests` WHERE `status` = 'pending'";
        if ($stmt = $mysqli->prepare($count_query_sql)) {
            $stmt->execute();
            $result = $stmt->get_result();
            $row = $result ? $result->fetch_assoc() : null;
            $pending_requests_count = (int) ($row['pending_count'] ?? 0);
            $stmt->close();
        }
    }


    // PHP Logic សម្រាប់ Dashboard Data Cards
    $today_date = date('Y-m-d');
    $total_users = 0;
    $total_admins = 0;
    $total_locations = 0;
    $active_sessions_count = 0;
    $today_good_count = 0;
    $today_late_count = 0;

    // Scope dashboard queries by admin_id
    $admin_scope_sql_users = " WHERE user_role = 'User' ";
    $admin_scope_sql_locations = "";

    // Total Users
    if ($result = $mysqli->query("SELECT COUNT(*) as count FROM users" . $admin_scope_sql_users)) {
        $total_users = $result->fetch_assoc()['count'];
        $result->close();
    }
    // Total Admins (Super admin sees all non-super admins, normal admin sees none)
    if ($result = $mysqli->query("SELECT COUNT(*) as count FROM users WHERE user_role = 'Admin'")) {
        $total_admins = $result->fetch_assoc()['count'];
        $result->close();
    }
    // Total Locations
    if ($result = $mysqli->query("SELECT COUNT(*) as count FROM locations" . $admin_scope_sql_locations)) {
        $total_locations = $result->fetch_assoc()['count'];
        $result->close();
    }
    // Active Sessions (scoped for normal admin)
    if ($result = $mysqli->query("SELECT COUNT(*) as count FROM active_tokens")) {
        $active_sessions_count = $result->fetch_assoc()['count'];
        $result->close();
    }

    // Today Attendance Summary (Good and Late)
    $today_summary_sql = "
		SELECT
			SUM(CASE WHEN status = 'Good' THEN 1 ELSE 0 END) as good_count,
			SUM(CASE WHEN status = 'Late' THEN 1 ELSE 0 END) as late_count
		FROM checkin_logs
		WHERE DATE(log_datetime) = '{$today_date}'
	";

    if ($result = $mysqli->query($today_summary_sql)) {
        $summary_data = $result->fetch_assoc();
        $today_good_count = (int) ($summary_data['good_count'] ?? 0);
        $today_late_count = (int) ($summary_data['late_count'] ?? 0);
        $result->close();
    }
}


