                        transform: translateY(-1px);
                        color: #ffffff;
                        background: linear-gradient(135deg, #6d58c9, #4f3fa4);
                        border-color: #5f4db5;
                        box-shadow: 0 12px 22px -15px rgba(86, 67, 181, 0.95);
                    }

                    @media (max-width: 900px) {
                        .launcher-menubar {
                            flex-direction: column;
                            align-items: stretch;
                            padding: 12px;
                            gap: 10px;
                        }

                        .launcher-menubar-left {
                            width: 100%;
                            flex-direction: column;
                            align-items: stretch;
                            gap: 8px;
                        }

                        .launcher-menubar-title {
                            width: fit-content;
                        }

                        .launcher-back-link {
                            justify-content: center;
                            width: 100%;
                        }
                    }

                    /* ---------- Content Cards ---------- */
                    .card,
                    .content-card {
                        background: #fff;
                        border: 1px solid #e2e8f0;
                        border-radius: 16px;
                        padding: 24px 28px;
                        margin-bottom: 24px;
                        box-shadow: 0 1px 4px rgba(0, 0, 0, 0.04), 0 1px 2px rgba(0, 0, 0, 0.02);
                        transition: box-shadow 0.25s ease;
                    }

                    .card:hover,
                    .content-card:hover {
                        box-shadow: 0 4px 16px rgba(0, 0, 0, 0.07);
                    }

                    .card-header,
                    .content-card-header {
                        display: flex;
                        justify-content: space-between;
                        align-items: center;
                        margin-bottom: 20px;
                        padding-bottom: 16px;
                        border-bottom: 1px solid #f1f5f9;
                        gap: 12px;
                        flex-wrap: wrap;
                    }

                    .card-title,
                    .content-card-title {
                        font-size: 1rem;
                        font-weight: 700;
                        color: #1e293b;
                        display: flex;
                        align-items: center;
                        gap: 8px;
                        margin: 0;
                    }

                    .card-title i,
                    .content-card-title i {
                        color: #6366f1;
                    }

                    .card-title {
                        font-size: 0.72rem;
                        font-weight: 600;
                        text-transform: uppercase;
                        letter-spacing: 0.6px;
                        margin-bottom: 10px;
                        color: #64748b;
                        line-height: 1.4;
                    }

                    /* Dashboard header / date row */
                    .dashboard-header-row {
                        display: flex;
                        justify-content: space-between;
                        align-items: center;
                        margin-bottom: 24px;
                        flex-wrap: wrap;
                        gap: 12px;
                    }

                    .dashboard-title-box h2 {
                        margin: 0;
                        font-size: 1.55rem;
                        font-weight: 800;
                        color: #1e293b;
                        letter-spacing: -0.5px;
                        display: flex;
                        align-items: center;
                        gap: 10px;
                    }

                    .dashboard-title-box h2 i {
                        color: #6366f1;
                    }

                    .dashboard-title-box p {
                        margin: 5px 0 0;
                        color: #94a3b8;
                        font-size: 0.88rem;
                        font-weight: 500;
                    }

                    /* ---------- Tables ---------- */
                    .table-wrapper {
                        width: 100%;
                        overflow-x: auto;
                        border-radius: 12px;
                        border: 1px solid #e2e8f0;
                    }

                    .table,
                    table.table {
                        width: 100%;
                        border-collapse: separate;
                        border-spacing: 0;
                        font-size: 0.875rem;
                        color: #1e293b;
                    }

                    .table thead th {
                        background: #f8fafc;
                        padding: 12px 16px;
                        font-weight: 700;
                        font-size: 0.72rem;
                        text-transform: uppercase;
                        letter-spacing: 0.6px;
                        color: #64748b;
                        border-bottom: 2px solid #e2e8f0;
                        white-space: nowrap;
                        text-align: left;
                        position: sticky;
                        top: 0;
                        z-index: 2;
                    }

                    .table tbody tr {
                        transition: background 0.15s ease;
                    }

                    .table tbody tr:hover td {
                        background: #f8fafc;
                    }

                    .table td {
                        padding: 13px 16px;
                        border-bottom: 1px solid #f1f5f9;
                        vertical-align: middle;
                        color: #334155;
                    }

                    .table tbody tr:last-child td {
                        border-bottom: none;
                    }

                    /* ---------- Toolbar (filter row above table) ---------- */
                    .toolbar {
                        display: flex;
                        align-items: center;
                        justify-content: space-between;
                        gap: 12px;
                        margin-bottom: 18px;
                        flex-wrap: wrap;
                    }

                    .toolbar-left,
                    .toolbar-right {
                        display: flex;
                        align-items: center;
                        gap: 10px;
                        flex-wrap: wrap;
                    }

                    /* ---------- Form Controls ---------- */
                    .form-control,
                    input[type="text"].form-control,
                    input[type="email"].form-control,
                    input[type="password"].form-control,
                    input[type="number"].form-control,
                    input[type="date"].form-control,
                    input[type="time"].form-control,
                    select.form-control,
                    textarea.form-control {
                        display: block;
                        width: 100%;
                        padding: 11px 16px;
                        font-size: 0.9rem;
                        color: #1e293b;
                        background: #f8fafc;
                        border: 1.5px solid #e2e8f0;
                        border-radius: 12px;
                        transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
                        outline: none;
                        font-family: inherit;
                    }

                    .form-control:focus {
                        background: #fff;
                        border-color: #6366f1;
                        box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.1);
                        transform: translateY(-1px);
                    }

                    .form-control::placeholder {
                        color: #94a3b8;
                    }

                    .form-group {
                        margin-bottom: 20px;
                    }

                    .form-group label {
                        display: block;
                        margin-bottom: 8px;
                        font-size: 0.78rem;
                        font-weight: 700;
                        color: #64748b;
                        text-transform: uppercase;
                        letter-spacing: 0.5px;
                        display: flex;
                        align-items: center;
                        gap: 6px;
                    }

                    .form-group label i {
                        color: #6366f1;
                        font-size: 0.85rem;
                        width: 16px;
                        text-align: center;
                    }

                    .form-grid {
                        display: grid;
                        grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
                        gap: 16px;
                    }

                    /* ---------- Buttons ---------- */
                    .btn {
                        display: inline-flex;
                        align-items: center;
                        justify-content: center;
                        gap: 7px;
                        padding: 9px 18px;
                        border-radius: 9px;
                        border: none;
                        font-family: inherit;
                        font-size: 0.855rem;
                        font-weight: 600;
                        cursor: pointer;
                        transition: all 0.2s ease;
                        text-decoration: none;
                        white-space: nowrap;
                        outline: none;
                        line-height: 1.4;
                    }

                    .btn i {
                        font-size: 0.9rem;
                    }

                    .btn-primary {
                        background: #6366f1;
                        color: #fff;
                    }

                    .btn-primary:hover {
                        background: #4f46e5;
                        transform: translateY(-1px);
                        box-shadow: 0 4px 12px rgba(99, 102, 241, 0.35);
                    }

                    .btn-secondary {
                        background: #f1f5f9;
                        color: #475569;
                        border: 1px solid #e2e8f0;
                    }

                    .btn-secondary:hover {
                        background: #e2e8f0;
                    }

                    .btn-success {
                        background: #22c55e;
                        color: #fff;
                    }

                    .btn-success:hover {
                        background: #16a34a;
                        transform: translateY(-1px);
                    }

                    .btn-danger {
                        background: #ef4444;
                        color: #fff;
                    }

                    .btn-danger:hover {
                        background: #dc2626;
                        transform: translateY(-1px);
                    }

                    .btn-warning {
                        background: #f59e0b;
                        color: #fff;
                    }

                    .btn-warning:hover {
                        background: #d97706;
                    }

                    .btn-info {
                        background: #3b82f6;
                        color: #fff;
                    }

                    .btn-info:hover {
                        background: #2563eb;
                    }

                    .btn-sm {
                        padding: 6px 12px;
                        font-size: 0.78rem;
                        border-radius: 7px;
                    }

                    .btn-lg {
                        padding: 12px 24px;
                        font-size: 1rem;
                        border-radius: 11px;
                    }

                    .btn-outline-primary {
                        background: transparent;
                        color: #6366f1;
                        border: 1px solid #6366f1;
                    }

                    .btn-outline-primary:hover {
                        background: #6366f1;
                        color: #fff;
                    }

                    /* ---------- Badges / Status ---------- */
                    .badge {
                        display: inline-flex;
                        align-items: center;
                        padding: 3px 10px;
                        border-radius: 20px;
                        font-size: 0.72rem;
                        font-weight: 700;
                        letter-spacing: 0.4px;
                    }

                    .badge-success {
                        background: #dcfce7;
                        color: #15803d;
                    }

                    .badge-danger {
                        background: #fee2e2;
                        color: #b91c1c;
                    }

                    .badge-warning {
                        background: #fef3c7;
                        color: #b45309;
                    }

                    .badge-info {
                        background: #dbeafe;
                        color: #1d4ed8;
                    }

                    .badge-primary {
                        background: #ede9fe;
                        color: #5b21b6;
                    }

                    .badge-secondary {
                        background: #f1f5f9;
                        color: #475569;
                    }

                    /* Status badges */
                    .status-badge {
                        display: inline-flex;
                        align-items: center;
                        gap: 5px;
                        padding: 4px 10px;
                        border-radius: 20px;
                        font-size: 0.72rem;
                        font-weight: 700;
                    }

                    .status-badge::before {
                        content: '';
                        width: 6px;
                        height: 6px;
                        border-radius: 50%;
                        background: currentColor;
                        flex-shrink: 0;
                    }

                    .status-active,
                    .status-approved,
                    .status-good {
                        background: #dcfce7;
                        color: #15803d;
                    }

                    .status-inactive,
                    .status-rejected {
                        background: #fee2e2;
                        color: #b91c1c;
                    }

                    .status-pending,
                    .status-late {
                        background: #fef3c7;
                        color: #b45309;
                    }

                    .status-absent {
                        background: #fee2e2;
                        color: #b91c1c;
                    }

                    /* ---------- Alerts ---------- */
                    .alert {
                        padding: 13px 18px;
                        border-radius: 10px;
                        margin-bottom: 18px;
                        display: flex;
                        align-items: flex-start;
                        gap: 12px;
                        font-size: 0.875rem;
                    }

                    .alert i {
                        margin-top: 1px;
                        flex-shrink: 0;
                    }

                    .alert-info {
                        background: #dbeafe;
                        border-left: 4px solid #3b82f6;
                        color: #1d4ed8;
                    }

                    .alert-success {
                        background: #dcfce7;
                        border-left: 4px solid #22c55e;
                        color: #15803d;
                    }

                    .alert-danger {
                        background: #fee2e2;
                        border-left: 4px solid #ef4444;
                        color: #b91c1c;
                    }

                    .alert-warning {
                        background: #fef3c7;
                        border-left: 4px solid #f59e0b;
                        color: #b45309;
                    }


                    /* ---------- Tabs (Nav Tabs) ---------- */
                    .nav-tabs,
                    .hrm-tabs {
                        display: flex;
                        gap: 8px;
                        border-bottom: 2px solid #f1f5f9;
                        margin-bottom: 25px;
                        overflow-x: auto;
                        padding-bottom: 0;
                        padding-left: 5px;
                        flex-wrap: nowrap;
                    }

                    .nav-link,
                    .hrm-tab-btn {
                        padding: 12px 20px;
                        font-size: 0.88rem;
                        font-weight: 700;
                        color: #94a3b8;
                        border: none;
                        background: transparent;
                        border-radius: 12px 12px 0 0;
                        cursor: pointer;
                        border-bottom: 3px solid transparent;
                        margin-bottom: -2px;
                        transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
                        white-space: nowrap;
                        display: inline-flex;
                        align-items: center;
                        gap: 10px;
                        text-decoration: none;
                        font-family: inherit;
                    }

                    .nav-link:hover,
                    .hrm-tab-btn:hover {
                        color: #6366f1;
                        background: rgba(99, 102, 241, 0.05);
                    }

                    .nav-link.active,
                    .hrm-tab-btn.active {
                        color: #6366f1;
                        border-bottom-color: #6366f1;
                        background: rgba(99, 102, 241, 0.08);
                    }

                    /* Tab Content Logic */
                    .hrm-tab-content {
                        display: none;
                        animation: tabFadeIn 0.3s ease-out;
                    }

                    .hrm-tab-content.active {
                        display: block;
                    }

                    @keyframes tabFadeIn {
                        from {
                            opacity: 0;
                            transform: translateY(8px);
                        }

                        to {
                            opacity: 1;
                            transform: translateY(0);
                        }
                    }

                    /* ---------- HRM / Page Toolbars ---------- */
                    .hrm-toolbar,
                    .page-toolbar {
                        display: flex;
                        align-items: center;
                        justify-content: space-between;
                        gap: 12px;
                        margin-bottom: 20px;
                        flex-wrap: wrap;
                    }

                    .hrm-filter-group,
                    .hrm-toolbar-actions {
                        display: flex;
                        align-items: center;
                        gap: 10px;
                        flex-wrap: wrap;
                    }

                    .hrm-grid {
                        display: grid;
                        grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
                        gap: 18px;
                        margin-bottom: 24px;
                    }

                    .hrm-card {
                        background: #fff;
                        border: 1px solid #e2e8f0;
                        border-radius: 14px;
                        padding: 20px;
                        transition: box-shadow 0.2s, transform 0.2s;
                    }

                    .hrm-card:hover {
                        box-shadow: 0 6px 20px rgba(0, 0, 0, 0.07);
                        transform: translateY(-2px);
                    }

                    /* ---------- Modal Override ---------- */
                    .modal-content {
                        border-radius: 18px !important;
                        box-shadow: 0 20px 60px rgba(0, 0, 0, 0.18) !important;
                        overflow: hidden;
                    }

                    .modal-header {
                        padding: 18px 24px !important;
                        background: linear-gradient(135deg, #6366f1, #4f46e5) !important;
                        color: #fff !important;
                        border-radius: 18px 18px 0 0 !important;
                    }

                    .modal-header h3 {
                        margin: 0;
                        font-size: 1.05rem;
                        font-weight: 700;
                    }

                    .modal-body {
                        padding: 22px 24px !important;
                    }

                    .modal-footer {
                        padding: 16px 24px !important;
                        border-top: 1px solid #f1f5f9 !important;
                    }

                    /* ---------- Avatar ---------- */
                    .avatar {
                        width: 36px;
                        height: 36px;
                        border-radius: 50%;
                        object-fit: cover;
                        border: 2px solid #e2e8f0;
                        flex-shrink: 0;
                    }

                    .avatar-lg {
                        width: 56px;
                        height: 56px;
                        border-width: 3px;
                    }

                    /* ---------- User Row (table) ---------- */
                    .user-row {
                        transition: background 0.15s;
                    }

                    .user-row:hover {
                        background: #f8fafc !important;
                    }

                    /* ---------- Pagination ---------- */
                    .pagination {
                        display: flex;
                        align-items: center;
                        gap: 4px;
                        margin-top: 16px;
                        flex-wrap: wrap;
                    }

                    .page-item .page-link,
                    .pagination a {
                        padding: 7px 13px;
                        border: 1px solid #e2e8f0;
                        border-radius: 8px;
                        font-size: 0.83rem;
                        color: #475569;
                        text-decoration: none;
                        background: #fff;
                        transition: background 0.2s, color 0.2s;
                        display: inline-block;
                    }

                    .page-item.active .page-link,
                    .pagination a.active {
                        background: #6366f1;
                        color: #fff;
                        border-color: #6366f1;
                    }

                    .pagination a:hover {
                        background: #f1f5f9;
                    }

                    /* ---------- Ajax Message Container ---------- */
                    #ajax-message-container {
                        position: fixed;
                        top: 20px;
                        right: 20px;
                        z-index: 999999;
                        display: flex;
                        flex-direction: column;
                        align-items: flex-end;
                        gap: 12px;
                        width: min(360px, calc(100vw - 24px));
                        min-height: 0;
                        pointer-events: none;
                    }

                    #ajax-message-container:empty {
                        display: none;
                    }

                    .ajax-toast {
                        width: 100%;
                        display: grid;
                        grid-template-columns: auto 1fr auto;
                        align-items: start;
                        gap: 12px;
                        padding: 14px 16px;
                        border-radius: 14px;
                        color: #fff;
                        box-shadow: 0 18px 40px -24px rgba(15, 23, 42, 0.55);
                        backdrop-filter: blur(12px);
                        border: 1px solid rgba(255, 255, 255, 0.18);
                        animation: ajaxToastIn 0.24s ease-out;
                        pointer-events: auto;
                    }

                    .ajax-toast.success {
                        background: linear-gradient(135deg, rgba(34, 197, 94, 0.96), rgba(22, 163, 74, 0.92));
                    }

                    .ajax-toast.error {
                        background: linear-gradient(135deg, rgba(239, 68, 68, 0.97), rgba(220, 38, 38, 0.92));
                    }

                    .ajax-toast.warning {
                        background: linear-gradient(135deg, rgba(245, 158, 11, 0.97), rgba(217, 119, 6, 0.92));
                    }

                    .ajax-toast.info {
                        background: linear-gradient(135deg, rgba(59, 130, 246, 0.97), rgba(37, 99, 235, 0.92));
                    }

                    .ajax-toast > .fa-solid:first-child {
                        font-size: 1rem;
                        line-height: 1.2;
                        margin-top: 2px;
                    }

                    .ajax-toast-content {
                        font-size: 0.94rem;
                        font-weight: 600;
                        line-height: 1.45;
                        word-break: break-word;
                    }

                    .ajax-toast-close {
                        width: 28px;
                        height: 28px;
                        border: none;
                        border-radius: 999px;
                        background: rgba(255, 255, 255, 0.16);
                        color: #fff;
                        display: inline-flex;
                        align-items: center;
                        justify-content: center;
                        cursor: pointer;
                        transition: background 0.18s ease, transform 0.18s ease;
                    }

                    .ajax-toast-close:hover {
                        background: rgba(255, 255, 255, 0.24);
                        transform: scale(1.04);
                    }

                    .ajax-toast.fade-out {
                        opacity: 0;
                        transform: translateX(18px);
                        transition: opacity 0.22s ease, transform 0.22s ease;
                    }

                    @keyframes ajaxToastIn {
                        from {
                            opacity: 0;
                            transform: translateX(18px) scale(0.98);
                        }

                        to {
                            opacity: 1;
                            transform: translateX(0) scale(1);
                        }
                    }

                    /* ---------- Section Divider ---------- */
                    .section-divider {
                        height: 1px;
                        background: linear-gradient(90deg, transparent, #e2e8f0, transparent);
                        margin: 24px 0;
                    }

                    /* ---------- Responsive ---------- */
                    @media (max-width: 1024px) {
                        :root {
                            --breadcrumb-sticky-top: 90px;
                        }

                        .content-wrapper {
                            margin-left: 0;
                        }

                        .main-content > .header {
                            top: 8px;
                            padding: 10px 12px;
                        }

                        .main-content {
                            padding: 0 16px 32px;
                        }
                    }

                    @media (max-width: 768px) {
                        :root {
                            --breadcrumb-sticky-top: 118px;
                        }

                        #ajax-message-container {
                            top: 12px;
                            right: 12px;
                            left: 12px;
                            width: auto;
                        }

                        .main-content > .header {
                            min-height: auto;
                            top: 6px;
                            padding: 10px 12px;
                            flex-wrap: wrap;
                            gap: 10px;
                            border-radius: 14px;
                        }

                        .main-content > .header .left-actions {
                            width: 100%;
                            gap: 10px;
                        }

                        .main-content > .header .left-actions h1 {
                            font-size: 1.08rem;
                        }

                        .main-content > .header .header-subtext {
                            display: none;
                        }

                        .main-content > .header .right-actions {
                            width: 100%;
                            justify-content: flex-end;
                        }

                        .main-content {
                            padding: 0 12px 24px;
                        }

                        .card,
                        .content-card {
                            padding: 16px;
                        }

                        .form-grid {
                            grid-template-columns: 1fr;
                        }

                        .hrm-grid {
                            grid-template-columns: 1fr;
                        }

                        .nav-tabs,
                        .hrm-tabs {
                            gap: 2px;
                        }

                        .nav-link,
                        .hrm-tab-btn {
                            padding: 8px 12px;
                            font-size: 0.78rem;
                        }

                        .btn-lg {
                            padding: 10px 18px;
                            font-size: 0.9rem;
                        }
                    }

                    @media (max-width: 576px) {
                        .table thead {
                            display: none;
                        }

                        .table td {
                            display: block;
                            padding: 8px 12px;
                            border: none;
                        }

                        .table tbody tr {
                            border: 1px solid #e2e8f0;
                            border-radius: 10px;
                            margin-bottom: 10px;
                            display: block;
                        }
                    }

                    /* ---------- Odoo Launcher Grid ---------- */
                    .odoo-shell {
                        position: relative;
                        isolation: isolate;
                        overflow: visible;
                        max-width: 1320px;
                        margin: 6px auto 24px;
                        padding: 14px 10px 18px;
                    }

                    .odoo-shell::before,
                    .odoo-shell::after {
                        display: none;
                    }

                    .odoo-shell-header {
                        display: none;
                    }

                    .odoo-shell > :not(.odoo-shell-bg) {
                        position: relative;
                        z-index: 1;
                    }

                    .odoo-shell-bg {
                        position: fixed;
                        inset: 0;
                        z-index: 0;
                        pointer-events: none;
                        overflow: hidden;
                        background:
                            radial-gradient(circle at 10% 12%, rgba(59, 130, 246, 0.08), transparent 35%),
                            radial-gradient(circle at 88% 18%, rgba(168, 85, 247, 0.08), transparent 33%),
                            radial-gradient(circle at 50% 95%, rgba(16, 185, 129, 0.06), transparent 38%);
                    }

                    .odoo-float-orb {
                        position: absolute;
                        border-radius: 999px;
                        opacity: 0.35;
                        filter: blur(0.5px);
                        animation: odooFloatY 10s ease-in-out infinite;
                        will-change: transform;
                    }

                    .odoo-float-orb.orb-1 {
                        width: 160px;
                        height: 160px;
                        left: -34px;
                        top: 22%;
                        background: radial-gradient(circle at 35% 35%, rgba(96, 165, 250, 0.45), rgba(96, 165, 250, 0.08) 70%);
                        animation-duration: 12s;
                    }

                    .odoo-float-orb.orb-2 {
                        width: 220px;
                        height: 220px;
                        right: -62px;
                        top: 8%;
                        background: radial-gradient(circle at 40% 40%, rgba(167, 139, 250, 0.45), rgba(167, 139, 250, 0.08) 72%);
                        animation-duration: 15s;
                        animation-delay: -3s;
                    }

                    .odoo-float-orb.orb-3 {
                        width: 140px;
                        height: 140px;
                        left: 26%;
                        bottom: -44px;
                        background: radial-gradient(circle at 35% 35%, rgba(45, 212, 191, 0.45), rgba(45, 212, 191, 0.08) 72%);
                        animation-duration: 13s;
                        animation-delay: -6s;
                    }

                    .odoo-float-orb.orb-4 {
                        width: 110px;
                        height: 110px;
                        right: 28%;
                        bottom: 2%;
                        background: radial-gradient(circle at 35% 35%, rgba(251, 146, 60, 0.38), rgba(251, 146, 60, 0.08) 74%);
                        animation-duration: 11s;
                        animation-delay: -1s;
                    }

                    @keyframes odooFloatY {
                        0% {
