                        'tokens' => 'fa-solid fa-key',
                        'stock' => 'fa-solid fa-boxes-stacked',
                        'settings' => 'fa-solid fa-sliders',
                        'gps_tracking' => 'fa-solid fa-route',
                        'payroll' => 'fa-solid fa-money-check-dollar',
                        'meetings' => 'fa-solid fa-handshake',
                        'training' => 'fa-solid fa-graduation-cap',
                    ];

                    $workspace_theme_by_key = [
                        'dashboard' => 'green',
                        'homes' => 'amber',
                        'users' => 'cyan',
                        'reports' => 'purple',
                        'requests' => 'orange',
                        'notifications' => 'pink',
                        'locations' => 'red',
                        'categories' => 'steel',
                        'tokens' => 'indigo',
                        'stock' => 'orange',
                        'settings' => 'purple',
                        'gps_tracking' => 'blue',
                        'payroll' => 'steel',
                        'meetings' => 'cyan',
                        'training' => 'amber',
                    ];

                    $menu_source_for_workspace = $sidebar_menu_items;
                    if (empty($menu_source_for_workspace)) {
                        foreach ($admin_pages_list as $fallback_key => $fallback_actions) {
                            $menu_source_for_workspace[$fallback_key] = [
                                'menu_key' => $fallback_key,
                                'menu_text' => ucwords(str_replace('_', ' ', $fallback_key)),
                                'icon_class' => $workspace_default_icons[$fallback_key] ?? 'fa-solid fa-folder',
                            ];
                        }
                    }

                    // Show launcher cards only for known/allowed pages.
                    // This prevents legacy DB menu keys like "work" / "hrm" from appearing.
                    $allowed_workspace_pages = array_keys($admin_pages_list);
                    $allowed_workspace_pages[] = 'homes'; // dashboard shortcut
                    $allowed_workspace_pages[] = 'stock'; // stock module root
                    $allowed_workspace_pages = array_values(array_unique($allowed_workspace_pages));

                    $workspace_order_owner_id = resolveVisibilityOwnerId($mysqli, $current_admin_id);
                    $workspace_order_map = [];
                    $workspace_order_decoded = get_workspace_card_order($mysqli, $workspace_order_owner_id, $allowed_workspace_pages);
                    if (is_array($workspace_order_decoded)) {
                        $order_pos = 0;
                        foreach ($workspace_order_decoded as $order_key) {
                            $order_key = trim((string) $order_key);
                            if ($order_key !== '' && in_array($order_key, $allowed_workspace_pages, true) && !isset($workspace_order_map[$order_key])) {
                                $workspace_order_map[$order_key] = $order_pos++;
