                                $href = '?page=' . rawurlencode($stock_action ?: 'stock_control');
                                $subtitle = (string) ($admin_pages_list['stock'][$stock_action] ?? 'Stock');
                                $visible = ($stock_action !== '');
                                if ((int) $pending_stock_request_count > 0) {
                                    $badge = number_format($pending_stock_request_count);
                                    $badge_class = 'odoo-badge-danger';
                                } elseif ((int) $low_stock_count > 0) {
                                    $badge = number_format($low_stock_count);
                                    $badge_class = 'odoo-badge-warning';
                                }
                                break;

                            case 'settings':
                                $settings_default_action = resolveFirstAccessibleAdminAction($mysqli, 'settings', $admin_id_check, $workspace_action_preferences['settings'], $current_admin_id);
                                if ($settings_default_action === '') {
                                    $settings_default_action = 'panel_settings';
                                }
                                $href = '?page=settings&action=' . rawurlencode($settings_default_action);
                                $subtitle = (string) ($submenu_texts['settings'][$settings_default_action] ?? ($admin_pages_list['settings'][$settings_default_action] ?? 'Settings'));
                                $visible = hasPageAccess($mysqli, 'settings', $settings_default_action, $admin_id_check) && !isSidebarHidden($mysqli, 'settings', null, $current_admin_id);
                                break;

                            case 'gps_tracking':
                                $gps_action = resolveFirstAccessibleAdminAction($mysqli, 'gps_tracking', $admin_id_check, $workspace_action_preferences['gps_tracking'], $current_admin_id);
                                $href = '?page=gps_tracking&action=' . rawurlencode($gps_action ?: 'trip_dashboard');
                                $subtitle = (string) ($submenu_texts['gps_tracking'][$gps_action] ?? ($admin_pages_list['gps_tracking'][$gps_action] ?? 'Trip Dashboard'));
                                $visible = ($gps_action !== '');
                                break;

                            case 'payroll':
                                $payroll_action = resolveFirstAccessibleAdminAction($mysqli, 'payroll', $admin_id_check, $workspace_action_preferences['payroll'], $current_admin_id);
                                $href = '?page=payroll&action=' . rawurlencode($payroll_action ?: 'payroll_dashboard');
                                $subtitle = (string) ($submenu_texts['payroll'][$payroll_action] ?? ($admin_pages_list['payroll'][$payroll_action] ?? 'Payroll'));
                                $visible = ($payroll_action !== '');
                                break;

                            case 'meetings':
                                $meetings_action = resolveFirstAccessibleAdminAction($mysqli, 'meetings', $admin_id_check, $workspace_action_preferences['meetings'], $current_admin_id);
                                $href = '?page=meetings&action=' . rawurlencode($meetings_action ?: 'list_meetings');
                                $subtitle = (string) ($submenu_texts['meetings'][$meetings_action] ?? ($admin_pages_list['meetings'][$meetings_action] ?? 'Meetings'));
                                $visible = ($meetings_action !== '');
                                break;

                            case 'training':
                                $training_action = resolveFirstAccessibleAdminAction($mysqli, 'training', $admin_id_check, $workspace_action_preferences['training'], $current_admin_id);
                                $href = '?page=training&action=' . rawurlencode($training_action ?: 'quiz_questions');
                                $subtitle = (string) ($submenu_texts['training'][$training_action] ?? ($admin_pages_list['training'][$training_action] ?? 'Training'));
                                $visible = ($training_action !== '');
                                break;
                        }

                        if (!$visible) {
                            continue;
                        }

                        $visible_dashboard_apps[] = [
                            'page_key' => $page_key,
                            'title' => $title,
                            'subtitle' => $subtitle,
                            'href' => $href,
                            'icon' => $icon,
                            'theme' => $workspace_theme_by_key[$page_key] ?? 'indigo',
                            'badge' => $badge,
                            'badge_class' => $badge_class,
                            'manual_order' => (int) ($workspace_order_map[$page_key] ?? (10000 + $app_sort_index)),
                            'sort_index' => $app_sort_index++,
                        ];
                    }

                    if (!empty($visible_dashboard_apps)) {
                        usort($visible_dashboard_apps, function ($a, $b) {
                            $a_idx = (int) ($a['manual_order'] ?? ($a['sort_index'] ?? 0));
                            $b_idx = (int) ($b['manual_order'] ?? ($b['sort_index'] ?? 0));
                            if ($a_idx !== $b_idx) {
                                return $a_idx <=> $b_idx;
                            }
                            $a_idx = (int) ($a['sort_index'] ?? 0);
                            $b_idx = (int) ($b['sort_index'] ?? 0);
                            return $a_idx <=> $b_idx;
                        });
                    }

