                                <div class="odoo-app-grid" data-order-owner="<?php echo htmlspecialchars($workspace_order_owner_id); ?>">
                                    <?php foreach ($visible_dashboard_apps as $app): ?>
                                        <a class="odoo-app-card" href="<?php echo htmlspecialchars($app['href']); ?>"
                                            draggable="true"
                                            data-page-key="<?php echo htmlspecialchars($app['page_key']); ?>"
                                            title="<?php echo htmlspecialchars($app['title']); ?>">
                                            <span class="odoo-app-tile">
                                                <?php if (!empty($app['badge'])): ?>
                                                    <span class="odoo-app-badge <?php echo htmlspecialchars($app['badge_class']); ?>">
                                                        <?php echo htmlspecialchars($app['badge']); ?>
                                                    </span>
                                                <?php endif; ?>
                                                <span class="odoo-app-icon odoo-theme-<?php echo htmlspecialchars($app['theme']); ?>">
                                                    <i class="<?php echo htmlspecialchars($app['icon']); ?>"></i>
                                                </span>
                                            </span>
                                            <span class="odoo-app-name"><?php echo htmlspecialchars($app['title']); ?></span>
