                                        </a>
                                    <?php endforeach; ?>
                                </div>
                            </div>
                            <script>
                                (function () {
                                    "use strict";

                                    var grid = document.querySelector(".odoo-app-grid[data-order-owner]");
                                    if (!grid) {
                                        return;
                                    }

                                    var endpoint = window.location.pathname + window.location.search;
                                    var orderOwner = grid.getAttribute("data-order-owner") || "";
                                    var draggingCard = null;
                                    var orderChanged = false;

                                    function matchesSelector(el, selector) {
                                        if (!el || el.nodeType !== 1) {
                                            return false;
                                        }
                                        var fn = el.matches || el.msMatchesSelector || el.webkitMatchesSelector;
                                        if (!fn) {
                                            return false;
                                        }
                                        return fn.call(el, selector);
                                    }

                                    function closestEl(el, selector) {
                                        while (el && el !== document) {
                                            if (matchesSelector(el, selector)) {
                                                return el;
                                            }
                                            el = el.parentElement;
                                        }
                                        return null;
                                    }

                                    function getCards() {
                                        var list = grid.querySelectorAll(".odoo-app-card[data-page-key]");
                                        return Array.prototype.slice.call(list);
                                    }

                                    function collectOrderedKeys() {
                                        var cards = getCards();
                                        var orderedKeys = [];
                                        for (var i = 0; i < cards.length; i++) {
                                            var key = cards[i].getAttribute("data-page-key") || "";
                                            if (key) {
                                                orderedKeys.push(key);
                                            }
                                        }
                                        return orderedKeys;
                                    }

                                    function notify(status, msg) {
                                        if (window.showAjaxMessage) {
                                            window.showAjaxMessage(status, msg);
                                        }
                                    }

                                    function postForm(formData, onDone) {
                                        var xhr = new XMLHttpRequest();
                                        xhr.open("POST", endpoint, true);
                                        xhr.onreadystatechange = function () {
                                            if (xhr.readyState !== 4) {
                                                return;
                                            }
                                            if (xhr.status < 200 || xhr.status >= 300) {
                                                onDone(new Error("network"), null);
                                                return;
                                            }
                                            try {
                                                onDone(null, JSON.parse(xhr.responseText));
                                            } catch (e) {
                                                onDone(new Error("parse"), null);
                                            }
                                        };
                                        xhr.send(formData);
                                    }

                                    var cards0 = getCards();
                                    for (var i = 0; i < cards0.length; i++) {
                                        cards0[i].setAttribute("draggable", "true");
                                    }

                                    grid.addEventListener("dragstart", function (e) {
                                        var card = closestEl(e.target, ".odoo-app-card[data-page-key]");
                                        if (!card) {
                                            return;
                                        }

                                        draggingCard = card;
                                        orderChanged = false;
                                        card.classList.add("dragging");

                                        if (e.dataTransfer) {
                                            e.dataTransfer.effectAllowed = "move";
                                            try {
                                                e.dataTransfer.setData("text/plain", card.getAttribute("data-page-key") || "");
                                            } catch (ignore) {
                                            }
                                        }
                                    });

                                    grid.addEventListener("dragover", function (e) {
                                        if (!draggingCard) {
                                            return;
                                        }

                                        e.preventDefault();
                                        var target = closestEl(e.target, ".odoo-app-card[data-page-key]");
                                        if (!target || target === draggingCard || !target.parentNode) {
                                            return;
                                        }

                                        var rect = target.getBoundingClientRect();
                                        var centerX = rect.left + (rect.width / 2);
                                        var centerY = rect.top + (rect.height / 2);
                                        var sameRow = Math.abs(e.clientY - centerY) < (rect.height * 0.6);
                                        var before = sameRow ? (e.clientX < centerX) : (e.clientY < centerY);

                                        if (before) {
                                            if (target.previousElementSibling !== draggingCard) {
                                                target.parentNode.insertBefore(draggingCard, target);
                                                orderChanged = true;
                                            }
                                        } else {
                                            var next = target.nextSibling;
                                            if (next !== draggingCard) {
                                                target.parentNode.insertBefore(draggingCard, next);
                                                orderChanged = true;
                                            }
                                        }
                                    });

                                    grid.addEventListener("drop", function (e) {
                                        if (!draggingCard) {
                                            return;
                                        }
                                        e.preventDefault();
                                    });

                                    grid.addEventListener("dragend", function () {
                                        if (!draggingCard) {
                                            return;
                                        }

                                        draggingCard.classList.remove("dragging");
                                        draggingCard = null;

                                        if (!orderChanged) {
                                            return;
                                        }

                                        var orderedKeys = collectOrderedKeys();
                                        if (!orderedKeys.length) {
                                            return;
                                        }

                                        var fd = new FormData();
                                        fd.append("ajax_action", "save_workspace_order");
                                        if (orderOwner) {
                                            fd.append("workspace_owner", orderOwner);
                                        }
                                        for (var x = 0; x < orderedKeys.length; x++) {
                                            fd.append("ordered_pages[]", orderedKeys[x]);
                                        }

                                        postForm(fd, function (err, data) {
                                            if (err || !data || data.status !== "success") {
                                                notify("error", data && data.message ? data.message : "Cannot save order");
                                                return;
                                            }
                                            notify("success", data.message || "Order saved");
                                        });
                                    });
                                })();
                            </script>
                        <?php else: ?>
                            <div class="odoo-home-panel">
                                <h3><i class="fa-solid fa-lock"></i> No modules available</h3>
                                <p>Your account does not have module permissions yet.</p>
                            </div>
                        <?php endif; ?>

