                        <script>
                            /**
                             * GPS Tracking Management Logic
                             */
                            window.openCustomerModal = function (data = null) {
                                const form = document.getElementById('customerForm');
                                if (!form) return;
                                form.reset();
                                if (data) {
                                    document.getElementById('modalTitle').innerHTML = '<i class="fa-solid fa-user-pen"></i> កែប្រែអតិថិជន';
                                    document.getElementById('cust_id').value = data.id;
                                    document.getElementById('cust_name').value = data.name;
                                    if (document.getElementById('cust_phone')) document.getElementById('cust_phone').value = data.phone || '';
                                    if (document.getElementById('cust_lat')) document.getElementById('cust_lat').value = data.latitude || '';
                                    if (document.getElementById('cust_lng')) document.getElementById('cust_lng').value = data.longitude || '';
                                    document.getElementById('cust_img_path').value = data.profile_image || '';
                                } else {
                                    document.getElementById('modalTitle').innerHTML = '<i class="fa-solid fa-user-plus"></i> បន្ថែមអតិថិជន';
                                    document.getElementById('cust_id').value = '';
                                    document.getElementById('cust_img_path').value = '';
                                }
                                document.getElementById('customerModal').style.display = 'block';
                            };

                            window.closeCustomerModal = function () {
                                const modal = document.getElementById('customerModal');
                                if (modal) modal.style.display = 'none';
                            };

                            window.saveCustomer = function (e) {
                                e.preventDefault();
                                const form = e.target;
                                const fd = new FormData(form);
                                fd.append('ajax_action', 'save_customer');

                                fetch(window.location.href, { method: 'POST', body: fd })
                                    .then(r => r.json())
                                    .then(res => {
                                        if (res.status === 'success') {
                                            if (typeof showToast === 'function') {
                                                showToast(res.message, 'success');
                                            } else {
                                                showAjaxMessage('info', res.message);
                                            }
                                            window.closeCustomerModal();
                                            window.loadCustomers();
                                        } else {
                                            showAjaxMessage('info', res.message);
                                        }
                                    })
                                    .catch(err => console.error('Save customer error:', err));
                            };

                            window.deleteCustomer = function (id) {
                                if (!confirm('តើអ្នកប្រាកដថាចង់លុបអតិថិជននេះទេ?')) return;
                                const fd = new FormData();
                                fd.append('ajax_action', 'delete_customer');
                                fd.append('id', id);

                                fetch(window.location.href, { method: 'POST', body: fd })
                                    .then(r => r.json())
                                    .then(res => {
                                        if (res.status === 'success') {
                                            window.loadCustomers();
                                        } else {
                                            showAjaxMessage('info', res.message);
                                        }
                                    })
                                    .catch(err => console.error('Delete customer error:', err));
                            };

                            window.loadCustomers = function () {
                                const grid = document.getElementById('customer-grid');
                                if (!grid) return;

                                const fd = new FormData();
                                fd.append('ajax_action', 'get_customers');

                                fetch(window.location.href, { method: 'POST', body: fd })
                                    .then(r => r.json())
                                    .then(res => {
                                        if (res.status === 'success') {
                                            let html = '';
                                            if (!res.data || res.data.length === 0) {
                                                html = '<div class="hrm-card text-center p-5 text-muted" style="grid-column: 1/-1;"><i class="fa-solid fa-users-slash" style="font-size:3rem; opacity:0.2; margin-bottom:15px; display:block;"></i>មិនមានអតិថិជនសកម្ម។</div>';
                                            } else {
                                                res.data.forEach(c => {
                                                    const img = c.profile_image || 'https://i.ibb.co/kRJFYbC/Logo.png';
                                                    const safeData = JSON.stringify(c).replace(/'/g, "&apos;");
                                                    html += `
                                            <div class="hrm-card" style="text-align:center;">
                                                <div style="position:relative; margin-bottom:20px;">
                                                    <img src="${img}" style="width:100px; height:100px; border-radius:50%; object-fit:cover; border:4px solid var(--primary-light); box-shadow: var(--shadow-sm);">
                                                </div>
                                                <h3 style="margin:0 0 8px 0; font-size: 1.1rem;">${c.name}</h3>
                                                <div class="detail-row" style="justify-content:center;"><i class="fa-solid fa-phone"></i> ${c.phone || 'N/A'}</div>
                                                
                                                <div style="display:flex; justify-content:flex-end; margin-top:20px;">
                                                    <div class="action-dropdown">
                                                        <button type="button" class="crud-dots-btn" onclick="toggleActionMenu(this, event)" title="Actions">
                                                            <i class="fa-solid fa-ellipsis-vertical"></i>
                                                        </button>
                                                        <div class="action-menu">
                                                            <button type="button" class="action-item" onclick='window.openCustomerModal(${safeData})'>
                                                                <i class="fa-solid fa-pen-to-square"></i> Edit
                                                            </button>
                                                            <button type="button" class="action-item text-danger" onclick="window.deleteCustomer(${c.id})">
                                                                <i class="fa-solid fa-trash"></i> Delete
                                                            </button>
                                                        </div>
                                                    </div>
                                                </div>
                                                <a href="https://www.google.com/maps/search/?api=1&query=${c.latitude},${c.longitude}" target="_blank" class="btn btn-primary" style="width:100%; margin-top:12px;"><i class="fa-solid fa-location-dot"></i> បង្ហាញលើផែនទី</a>
                                            </div>
                                        `;
                                                });
                                            }
                                            grid.innerHTML = html;
                                        }
                                    })
                                    .catch(err => {
                                        console.error('Load customers error:', err);
                                        grid.innerHTML = '<div class="hrm-card text-center p-5 text-danger" style="grid-column: 1/-1;">មានបញ្ហាក្នុងការផ្ទុកទិន្នន័យ។</div>';
                                    });
                            };

                            // Initialize on load
                            if (document.readyState === 'complete') {
                                window.loadCustomers();
                            } else {
                                window.addEventListener('load', window.loadCustomers);
                            }
                        </script>

