                        <script>
                            if (typeof tripMap === 'undefined') window.tripMap = null;
                            if (typeof tripMarkers === 'undefined') window.tripMarkers = {};
                            if (typeof tripPolylines === 'undefined') window.tripPolylines = {};
                            let directionsService = null;
                            let directionsRenderer = null;
                            let refreshInterval = null;
                            if (typeof window.historyMapInstance === 'undefined') window.historyMapInstance = null;

                            function normalizeTripRoute(points) {
                                if (!Array.isArray(points)) return [];
                                return points.map(point => ({
                                    lat: parseFloat(point.lat ?? point.latitude),
                                    lng: parseFloat(point.lng ?? point.longitude)
                                })).filter(point => !isNaN(point.lat) && !isNaN(point.lng));
                            }

                            function buildRenderableTripPath(res) {
                                const rawPath = normalizeTripRoute(res.locations || []);
                                const snappedPath = normalizeTripRoute(res.snapped_path || []);
                                return {
                                    rawPath,
                                    displayPath: snappedPath.length >= 2 ? snappedPath : rawPath,
                                    source: snappedPath.length >= 2 ? (res.route_source || 'roads') : 'raw',
                                    message: res.route_message || ''
                                };
                            }

                            function removeMapOverlay(overlay) {
                                if (!overlay) return;
                                if (typeof overlay.setMap === 'function') {
                                    overlay.setMap(null);
                                    return;
                                }
                                if ('map' in overlay) {
                                    overlay.map = null;
                                }
                            }

                            function getMarkerPosition(marker) {
                                if (!marker) return null;
                                if (marker.position) return marker.position;
                                if (typeof marker.getPosition === 'function') return marker.getPosition();
                                return null;
                            }

                            function setMarkerPosition(marker, newPos) {
                                if (!marker) return;
                                if (typeof marker.setPosition === 'function') {
                                    marker.setPosition(newPos);
                                    return;
                                }
                                marker.position = newPos;
                            }

                            function getTripAvatarUrl(trip) {
                                const raw = String(trip?.avatar || '').trim();
                                if (!raw) return '';
                                if (/^(https?:)?\/\//i.test(raw) || raw.startsWith('data:')) {
                                    return raw;
                                }
                                if (raw.startsWith('/')) {
                                    return raw;
                                }
                                return raw;
                            }

                            function getTripInitials(trip) {
                                const source = String(trip?.employee_name || trip?.employee_id || '?').trim();
                                if (!source) return '?';
                                const parts = source.split(/\s+/).filter(Boolean);
                                if (parts.length >= 2) {
                                    return (parts[0][0] + parts[1][0]).toUpperCase();
                                }
                                return source.substring(0, 1).toUpperCase();
                            }

                            function createTripAvatarMarker(trip) {
                                const avatarUrl = getTripAvatarUrl(trip);
                                const initials = getTripInitials(trip);
                                const wrapper = document.createElement('div');
                                wrapper.style.position = 'relative';
                                wrapper.style.width = '46px';
                                wrapper.style.height = '46px';
                                wrapper.style.display = 'flex';
                                wrapper.style.alignItems = 'center';
                                wrapper.style.justifyContent = 'center';

                                const bubble = document.createElement('div');
                                bubble.style.width = '38px';
                                bubble.style.height = '38px';
                                bubble.style.borderRadius = '999px';
                                bubble.style.overflow = 'hidden';
                                bubble.style.display = 'flex';
                                bubble.style.alignItems = 'center';
                                bubble.style.justifyContent = 'center';
                                bubble.style.border = '3px solid #10b981';
                                bubble.style.boxShadow = '0 10px 18px rgba(15, 23, 42, 0.22)';
                                bubble.style.background = '#e2e8f0';
                                bubble.style.color = '#0f172a';
                                bubble.style.fontWeight = '700';
                                bubble.style.fontSize = '13px';
                                bubble.style.fontFamily = 'system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif';

                                if (avatarUrl) {
                                    const img = document.createElement('img');
                                    img.src = avatarUrl;
                                    img.alt = trip?.employee_name || trip?.employee_id || 'User';
                                    img.loading = 'lazy';
                                    img.referrerPolicy = 'no-referrer';
                                    img.style.width = '100%';
                                    img.style.height = '100%';
                                    img.style.objectFit = 'cover';
                                    img.onerror = function () {
                                        bubble.innerHTML = '';
                                        bubble.textContent = initials;
                                    };
                                    bubble.appendChild(img);
                                } else {
                                    bubble.textContent = initials;
                                }

                                const dot = document.createElement('div');
                                dot.style.position = 'absolute';
                                dot.style.right = '4px';
                                dot.style.bottom = '5px';
                                dot.style.width = '11px';
                                dot.style.height = '11px';
                                dot.style.borderRadius = '999px';
                                dot.style.background = '#22c55e';
                                dot.style.border = '2px solid #ffffff';
                                dot.style.boxShadow = '0 0 0 1px rgba(15, 23, 42, 0.08)';

                                wrapper.appendChild(bubble);
                                wrapper.appendChild(dot);
                                return wrapper;
                            }

                            function initTripMap() {
                                if (typeof google === 'undefined' || !google.maps) {
                                    console.error('Google Maps API not loaded properly.');
                                    return;
                                }

                                tripMap = new google.maps.Map(document.getElementById('tripMap'), {
                                    center: { lat: 11.5564, lng: 104.9282 },
                                    zoom: 12,
                                    mapId: 'DEMO_MAP_ID',
                                    mapTypeControl: true,
                                    streetViewControl: false,
                                    fullscreenControl: true
                                });

                                // Initialize directions tools
                                directionsService = new google.maps.DirectionsService();
                                directionsRenderer = new google.maps.DirectionsRenderer({
                                    map: tripMap,
                                    suppressMarkers: true,
                                    polylineOptions: {
                                        strokeColor: '#6366f1',
                                        strokeWeight: 6,
                                        strokeOpacity: 0.8
                                    }
                                });

                                refreshTrips();
                                refreshInterval = setInterval(refreshTrips, 5000);
                            }

                            function refreshTrips() {
                                const btn = document.getElementById('refreshBtn');
                                if (btn) btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> កំពុងផ្ទុក...';

                                const fd = new FormData();
                                fd.append('ajax_action', 'get_active_trips');

                                fetch(window.location.href.split('?')[0] + '?page=gps_tracking&action=trip_dashboard', { method: 'POST', body: fd })
                                    .then(r => r.json())
                                    .then(res => {
                                        if (btn) btn.innerHTML = '<i class="fa-solid fa-arrows-rotate"></i> ផ្ទុកឡើងវិញ';
                                        if (res.status !== 'success') return;

                                        const rawData = res.data;
                                        const trips = Array.isArray(rawData) ? rawData : [];

                                        // Update stats
                                        document.getElementById('statActiveTrips').textContent = trips.length;
                                        const uniqueEmps = [...new Set(trips.map(t => t.employee_id))];
                                        document.getElementById('statActiveEmployees').textContent = uniqueEmps.length;

                                        // Update trip cards
                                        renderTripCards(trips);

                                        // Update map markers
                                        updateMapMarkers(trips);
                                    })
                                    .catch(err => {
                                        console.error('Refresh trips error:', err);
                                        if (btn) btn.innerHTML = '<i class="fa-solid fa-arrows-rotate"></i> ផ្ទុកឡើងវិញ';
                                    });
                            }

                            function renderTripCards(trips = []) {
                                if (!Array.isArray(trips)) trips = [];
                                const container = document.getElementById('activeTripsContainer');
                                if (!container) return;

                                if (trips.length === 0) {
                                    container.innerHTML = `
                            <div class="trip-card" style="grid-column: 1/-1; text-align:center; padding: 40px;">
                                <i class="fa-solid fa-car-side" style="font-size:3rem; opacity:0.15; margin-bottom:15px; display:block;"></i>
                                <p style="color: var(--text-secondary);">មិនមានដំណើរសកម្មនៅពេលនេះ។</p>
                            </div>`;
                                    return;
                                }

                                let html = '';
                                trips.forEach(t => {
                                    const startTime = new Date(t.started_at).toLocaleTimeString('km-KH', { hour: '2-digit', minute: '2-digit' });
                                    const latestLoc = t.latest_location;
                                    const lastUpdate = latestLoc ? new Date(latestLoc.recorded_at).toLocaleTimeString('km-KH', { hour: '2-digit', minute: '2-digit', second: '2-digit' }) : 'N/A';
                                    const speed = latestLoc ? parseFloat(latestLoc.speed || 0).toFixed(1) : '0';

                                    html += `
                            <div class="trip-card" onclick="viewTripRoute(${t.id})" style="cursor:pointer;">
                                <div class="trip-card-header">
                                    <div>
                                        <h4><i class="fa-solid fa-user"></i> ${t.employee_name || t.employee_id}</h4>
                                        <small style="color:var(--text-secondary);">→ ${t.customer_name || 'គ្មានទិសដៅ'}</small>
                                    </div>
                                    <span class="trip-status-badge active"><span class="pulse-dot"></span> កំពុងដំណើរការ</span>
                                </div>
                                <div class="trip-detail-row"><i class="fa-solid fa-clock"></i> ចាប់ផ្ដើម: ${startTime}</div>
                                <div class="trip-detail-row"><i class="fa-solid fa-gauge-high"></i> ល្បឿន: ${speed} km/h</div>
                                <div class="trip-detail-row"><i class="fa-solid fa-map-pin"></i> ចំណុច GPS: ${t.point_count || 0}</div>
                                <div class="trip-detail-row"><i class="fa-solid fa-signal"></i> អាប់ដេតចុងក្រោយ: ${lastUpdate}</div>
                                <div style="display:flex; gap:8px; margin-top:12px;">
                                    <button class="btn btn-sm btn-primary" style="flex:1;" onclick="event.stopPropagation(); viewTripRoute(${t.id})"><i class="fa-solid fa-route"></i> មើលផ្លូវ</button>
                                    <button class="btn btn-sm btn-danger" style="flex:1;" onclick="event.stopPropagation(); endTrip(${t.id})"><i class="fa-solid fa-flag-checkered"></i> បញ្ចប់</button>
                                </div>
                            </div>`;
                                });
                                container.innerHTML = html;
                            }

                            function updateMapMarkers(trips = []) {
                                if (!Array.isArray(trips)) trips = [];
                                // Ensure google maps is available and map is initialized
                                if (typeof google === 'undefined' || !google.maps || !tripMap) return;

                                // Safety check for tripMarkers
                                if (typeof tripMarkers === 'undefined') {
                                    window.tripMarkers = {};
                                }
                                if (typeof tripPolylines === 'undefined') {
                                    window.tripPolylines = {};
                                }

                                // Clear old markers that are no longer active
                                try {
                                    Object.keys(tripMarkers).forEach(id => {
                                        if (!trips.find(t => t.id == id)) {
                                            removeMapOverlay(tripMarkers[id]);
                                            delete tripMarkers[id];
                                            if (tripPolylines[id]) {
                                                removeMapOverlay(tripPolylines[id]);
                                                delete tripPolylines[id];
                                            }
                                        }
                                    });
                                } catch (e) {
                                    console.warn('Error clearing markers:', e);
                                }

                                trips.forEach(t => {
                                    if (!t.latest_location) return;
                                    const lat = parseFloat(t.latest_location.latitude);
                                    const lng = parseFloat(t.latest_location.longitude);
                                    if (isNaN(lat) || isNaN(lng)) return;

                                    const pos = { lat, lng };

                                    if (tripMarkers[t.id]) {
                                        // Smoothly animate marker to new position
                                        animateMarker(tripMarkers[t.id], pos);
                                    } else {
                                        // Only use AdvancedMarkerElement if the library is loaded
                                        if (google.maps.marker && google.maps.marker.AdvancedMarkerElement) {
                                            tripMarkers[t.id] = new google.maps.marker.AdvancedMarkerElement({
                                                position: pos,
                                                map: tripMap,
                                                title: t.employee_name || t.employee_id,
                                                content: createTripAvatarMarker(t)
                                            });
                                        } else {
                                            // Fallback to standard Marker
                                            const avatarUrl = getTripAvatarUrl(t);
                                            tripMarkers[t.id] = new google.maps.Marker({
                                                position: pos,
                                                map: tripMap,
                                                title: t.employee_name || t.employee_id,
                                                icon: avatarUrl ? {
                                                    url: avatarUrl,
                                                    scaledSize: new google.maps.Size(40, 40),
                                                    anchor: new google.maps.Point(20, 20)
                                                } : undefined
                                            });
                                        }

                                        // Info window
                                        const avatarHtml = getTripAvatarUrl(t)
                                            ? `<div style="width:42px; height:42px; border-radius:999px; overflow:hidden; border:2px solid #10b981; margin-bottom:8px;"><img src="${getTripAvatarUrl(t)}" alt="" style="width:100%; height:100%; object-fit:cover;"></div>`
                                            : `<div style="width:42px; height:42px; border-radius:999px; background:#e2e8f0; color:#0f172a; display:flex; align-items:center; justify-content:center; font-weight:700; border:2px solid #10b981; margin-bottom:8px;">${getTripInitials(t)}</div>`;
                                        const infoWindow = new google.maps.InfoWindow({
                                            content: `<div style="font-family:sans-serif; padding:5px; min-width:170px;">
                                    ${avatarHtml}
                                    <strong>${t.employee_name || t.employee_id}</strong><br>
                                    <small style="color:#6366f1;">→ ${t.customer_name || 'N/A'}</small><br>
                                    <div style="margin-top:5px; font-size:11px;">
                                        ល្បឿន: ${parseFloat(t.latest_location.speed || 0).toFixed(1)} km/h<br>
                                        ចម្ងាយ: ${parseFloat(t.total_distance_km || 0).toFixed(2)} km
                                    </div>
                                </div>`
                                        });
                                        tripMarkers[t.id].addListener('click', () => infoWindow.open(tripMap, tripMarkers[t.id]));
                                    }

                                    // Start marker
                                    if (t.start_lat && t.start_lng) {
                                        const startKey = 'start_' + t.id;
                                        if (!tripMarkers[startKey]) {
                                            if (google.maps.marker && google.maps.marker.PinElement && google.maps.marker.AdvancedMarkerElement) {
                                                const startPin = new google.maps.marker.PinElement({
                                                    background: '#3b82f6',
                                                    borderColor: '#fff',
                                                    glyphColor: '#fff',
                                                    scale: 0.8
                                                });
                                                tripMarkers[startKey] = new google.maps.marker.AdvancedMarkerElement({
                                                    position: { lat: parseFloat(t.start_lat), lng: parseFloat(t.start_lng) },
                                                    map: tripMap,
                                                    title: 'ចំណុចចាប់ផ្ដើម',
                                                    content: startPin.element
                                                });
                                            } else {
                                                tripMarkers[startKey] = new google.maps.Marker({
                                                    position: { lat: parseFloat(t.start_lat), lng: parseFloat(t.start_lng) },
                                                    map: tripMap,
                                                    title: 'ចំណុចចាប់ផ្ដើម',
                                                    icon: { url: 'https://maps.google.com/mapfiles/ms/icons/blue-dot.png' }
                                                });
                                            }
                                        }
                                    }

                                    // Target marker
                                    if (t.target_lat && t.target_lng) {
                                        const targetKey = 'target_' + t.id;
                                        if (!tripMarkers[targetKey]) {
                                            if (google.maps.marker && google.maps.marker.AdvancedMarkerElement) {
                                                const destImg = document.createElement('img');
                                                destImg.src = 'https://maps.google.com/mapfiles/ms/icons/red-pushpin.png';
                                                tripMarkers[targetKey] = new google.maps.marker.AdvancedMarkerElement({
                                                    position: { lat: parseFloat(t.target_lat), lng: parseFloat(t.target_lng) },
                                                    map: tripMap,
                                                    title: 'គោលដៅ: ' + t.customer_name,
                                                    content: destImg
                                                });
                                            } else {
                                                tripMarkers[targetKey] = new google.maps.Marker({
                                                    position: { lat: parseFloat(t.target_lat), lng: parseFloat(t.target_lng) },
                                                    map: tripMap,
                                                    title: 'គោលដៅ: ' + t.customer_name,
                                                    icon: { url: 'https://maps.google.com/mapfiles/ms/icons/red-pushpin.png' }
                                                });
                                            }
                                        }
                                    }
                                });
                            }

                            function animateMarker(marker, newPos) {
                                const startPos = getMarkerPosition(marker);
                                if (!startPos) { setMarkerPosition(marker, newPos); return; }

                                const startLat = typeof startPos.lat === 'function' ? startPos.lat() : startPos.lat;
                                const startLng = typeof startPos.lng === 'function' ? startPos.lng() : startPos.lng;
                                const newLat = typeof newPos.lat === 'function' ? newPos.lat() : newPos.lat;
                                const newLng = typeof newPos.lng === 'function' ? newPos.lng() : newPos.lng;

                                const deltaLat = newLat - startLat;
                                const deltaLng = newLng - startLng;
                                const steps = 20;
                                let step = 0;

                                function doStep() {
                                    step++;
                                    const progress = step / steps;
                                    setMarkerPosition(marker, {
                                        lat: startLat + (deltaLat * progress),
                                        lng: startLng + (deltaLng * progress)
                                    });
                                    if (step < steps) requestAnimationFrame(doStep);
                                }
                                requestAnimationFrame(doStep);
                            }

                            function viewTripRoute(tripId) {
                                const fd = new FormData();
                                fd.append('ajax_action', 'get_trip_locations');
                                fd.append('trip_id', tripId);

                                fetch(window.location.href.split('?')[0] + '?page=gps_tracking&action=trip_dashboard', { method: 'POST', body: fd })
                                    .then(r => r.json())
                                    .then(res => {
                                        if (res.status !== 'success' || !res.locations || res.locations.length === 0) {
                                            if (typeof showAjaxMessage === 'function') showAjaxMessage('info', 'មិនមានទិន្នន័យផ្លូវសម្រាប់ដំណើរនេះ។');
                                            return;
                                        }

                                        if (tripPolylines[tripId]) {
                                            removeMapOverlay(tripPolylines[tripId]);
                                        }
                                        if (directionsRenderer && typeof directionsRenderer.setDirections === 'function') {
                                            directionsRenderer.setDirections({ routes: [] });
                                        }

                                        const { rawPath, displayPath } = buildRenderableTripPath(res);

                                        if (displayPath.length >= 2) {
                                            tripPolylines[tripId] = new google.maps.Polyline({
                                                path: displayPath,
                                                geodesic: true,
                                                strokeColor: '#6366f1',
                                                strokeOpacity: 0.9,
                                                strokeWeight: 6,
                                                map: tripMap
                                            });
                                        }

                                        // Fit bounds
                                        const bounds = new google.maps.LatLngBounds();
                                        const fitPath = displayPath.length > 0 ? displayPath : rawPath;
                                        fitPath.forEach(p => bounds.extend(p));

                                        if (res.trip && res.trip.target_lat && res.trip.target_lng) {
                                            const targetPos = { lat: parseFloat(res.trip.target_lat), lng: parseFloat(res.trip.target_lng) };
                                            bounds.extend(targetPos);
                                            if (!tripMarkers['target_' + tripId]) {
                                                tripMarkers['target_' + tripId] = new google.maps.Marker({
                                                    position: targetPos,
                                                    map: tripMap,
                                                    icon: { url: 'https://maps.google.com/mapfiles/ms/icons/red-pushpin.png' },
                                                    title: 'គោលដៅ: ' + (res.trip.customer_name || 'N/A')
                                                });
                                            }
                                        }
                                        tripMap.fitBounds(bounds);
                                    })
                                    .catch(err => console.error('View route error:', err));
                            }

                            function endTrip(tripId) {
                                if (!confirm('តើអ្នកប្រាកដថាចង់បញ្ចប់ដំណើរនេះទេ?')) return;
                                const fd = new FormData();
                                fd.append('ajax_action', 'admin_end_trip');
                                fd.append('trip_id', tripId);

                                fetch(window.location.href.split('?')[0] + '?page=gps_tracking&action=trip_dashboard', { method: 'POST', body: fd })
                                    .then(r => r.json())
                                    .then(res => {
                                        if (typeof showAjaxMessage === 'function') {
                                            showAjaxMessage(res.status === 'success' ? 'success' : 'error', res.message);
                                        }
                                        refreshTrips();
                                    })
                                    .catch(err => console.error('End trip error:', err));
                            }

                            // Cleanup interval on page leave
                            window.addEventListener('beforeunload', () => {
                                if (refreshInterval) clearInterval(refreshInterval);
                            });
                        </script>

