                        <script>
                            if (typeof window.historyMapInstance === 'undefined') window.historyMapInstance = null;

                            function loadTripHistory() {
                                const fd = new FormData();
                                fd.append('ajax_action', 'get_trips');
                                fd.append('date_from', document.getElementById('histDateFrom').value);
                                fd.append('date_to', document.getElementById('histDateTo').value);
                                fd.append('employee_filter', document.getElementById('histEmpFilter').value);

                                const tbody = document.getElementById('tripHistoryBody');
                                tbody.innerHTML = '<tr><td colspan="9" style="text-align:center; padding:20px;"><i class="fa-solid fa-spinner fa-spin"></i> កំពុងផ្ទុក...</td></tr>';

                                fetch(window.location.href.split('?')[0] + '?page=gps_tracking&action=trip_history', { method: 'POST', body: fd })
                                    .then(r => r.json())
                                    .then(res => {
                                        if (res.status !== 'success' || !res.data || res.data.length === 0) {
                                            tbody.innerHTML = '<tr><td colspan="9" style="text-align:center; padding:30px; color:var(--text-secondary);"><i class="fa-solid fa-inbox" style="font-size:2rem; opacity:0.2; display:block; margin-bottom:10px;"></i>មិនមានទិន្នន័យក្នុងចន្លោះពេលនេះ។</td></tr>';
                                            return;
                                        }

                                        let html = '';
                                        let totalKm = 0;
                                        res.data.forEach((t, i) => {
                                            const dist = parseFloat(t.total_distance_km || 0);
                                            totalKm += dist;
                                            const startDt = new Date(t.started_at);
                                            const endDt = t.ended_at ? new Date(t.ended_at) : null;
                                            const startStr = startDt.toLocaleDateString('km-KH') + ' ' + startDt.toLocaleTimeString('km-KH', { hour: '2-digit', minute: '2-digit' });
                                            const endStr = endDt ? endDt.toLocaleTimeString('km-KH', { hour: '2-digit', minute: '2-digit' }) : '—';
                                            const durationStr = t.duration_minutes > 0 ? Math.floor(t.duration_minutes / 60) + 'ម៉ ' + (t.duration_minutes % 60) + 'ន' : '—';
                                            const statusBadge = t.status === 'active'
                                                ? '<span class="trip-status-badge active"><span class="pulse-dot"></span> កំពុង</span>'
                                                : '<span class="trip-status-badge completed">? បានបញ្ចប់</span>';

                                            html += `<tr>
                                    <td>${i + 1}</td>
                                    <td><strong>${t.employee_name || t.employee_id}</strong></td>
                                    <td>${t.customer_name || '—'}</td>
                                    <td>${startStr}</td>
                                    <td>${endStr}</td>
                                    <td class="trip-km">${dist.toFixed(2)}</td>
                                    <td class="trip-duration">${durationStr}</td>
                                    <td>${statusBadge}</td>
                                    <td><button class="btn btn-sm btn-primary" onclick="showHistoryRoute(${t.id}, '${(t.employee_name || t.employee_id).replace(/'/g, "\\'")}')"><i class="fa-solid fa-map"></i></button></td>
                                </tr>`;
                                });

                                // Summary row
                                html += `<tr style="background: rgba(99,102,241,0.06); font-weight: 600;">
                                                        <td colspan="5" style="text-align:right;">សរុប:</td>
                                                        <td class="trip-km">${totalKm.toFixed(2)} Km</td>
                                                        <td colspan="3">${res.data.length} ដំណើរ</td>
                                                    </tr>`;

                                tbody.innerHTML = html;
                            })
                            .catch(err => {
                                console.error('Load history error:', err);
                                tbody.innerHTML = '<tr><td colspan="9" style="text-align:center; color:var(--danger);">មានបញ្ហាក្នុងការផ្ទុក។</td></tr>';
                            });
                    }

                    function showHistoryRoute(tripId, empName) {
                        document.getElementById('tripHistoryMapModal').style.display = 'block';
                        document.getElementById('historyMapTitle').innerHTML = '<i class="fa-solid fa-route"></i> ផ្លូវដំណើរ: ' + empName;

                        const fd = new FormData();
                        fd.append('ajax_action', 'get_trip_locations');
                        fd.append('trip_id', tripId);

                        fetch(window.location.href.split('?')[0] + '?page=gps_tracking&action=trip_history', { method: 'POST', body: fd })
                            .then(r => r.json())
                            .then(res => {
                                // Initialize map if not yet
                                if (!window.historyMapInstance) {
                                    window.historyMapInstance = new google.maps.Map(document.getElementById('historyMap'), {
                                        center: { lat: 11.5564, lng: 104.9282 },
                                        zoom: 13,
                                        mapId: 'DEMO_MAP_ID',
                                        streetViewControl: false
                                    });
                                }

                                // Clear previous overlays
                                if (window._histOverlays) {
                                    window._histOverlays.forEach(o => removeMapOverlay(o));
                                }
                                window._histOverlays = [];

                                if (!res.locations || res.locations.length === 0) {
                                    document.getElementById('historyMapInfo').innerHTML = '<span>មិនមានទិន្នន័យ GPS សម្រាប់ដំណើរនេះ។</span>';
                                    return;
                                }

                                const { rawPath, displayPath, source, message } = buildRenderableTripPath(res);
                                const path = displayPath.length > 0 ? displayPath : rawPath;

                                // Route line
                                const polyline = new google.maps.Polyline({
                                    path: path,
                                    geodesic: true,
                                    strokeColor: '#6366f1',
                                    strokeOpacity: 0.9,
                                    strokeWeight: 5,
                                    map: window.historyMapInstance,
                                    icons: [{
                                        icon: { path: google.maps.SymbolPath.FORWARD_CLOSED_ARROW, scale: 3, strokeColor: '#fff' },
                                        offset: '100%', repeat: '80px'
                                    }]
                                });
                                window._histOverlays.push(polyline);

                                // Start marker
                                const startPin = new google.maps.marker.PinElement({
                                    background: '#3b82f6',
                                    borderColor: '#fff'
                                });
                                const startMarker = new google.maps.marker.AdvancedMarkerElement({
                                    position: path[0],
                                    map: window.historyMapInstance,
                                    title: 'ចាប់ផ្ដើម',
                                    content: startPin.element
                                });
                                window._histOverlays.push(startMarker);

                                // End marker
                                const endPin = new google.maps.marker.PinElement({
                                    background: '#ef4444',
                                    borderColor: '#fff'
                                });
                                const endMarker = new google.maps.marker.AdvancedMarkerElement({
                                    position: path[path.length - 1],
                                    map: window.historyMapInstance,
                                    title: 'បញ្ចប់',
                                    content: endPin.element
                                });
                                window._histOverlays.push(endMarker);

                                // Fit bounds
                                const bounds = new google.maps.LatLngBounds();
                                path.forEach(p => bounds.extend(p));
                                window.historyMapInstance.fitBounds(bounds);

                                // Info
                                const trip = res.trip;
                                if (trip) {
                                    document.getElementById('historyMapInfo').innerHTML = `
                                                            <span><i class="fa-solid fa-road"></i> ${parseFloat(trip.total_distance_km || 0).toFixed(2)} Km</span>
                                                            <span><i class="fa-solid fa-clock"></i> ${trip.duration_minutes || 0} នាទី</span>
                                                            <span><i class="fa-solid fa-map-pin"></i> ${res.locations.length} ចំណុច GPS</span>
                                                            <span><i class="fa-solid fa-route"></i> ${source === 'raw' ? 'GPS ដើម' : 'ផ្លូវជាប់ផ្លូវពិត'}</span>
                                                            ${message ? `<span title="${String(message).replace(/"/g, '&quot;')}"><i class="fa-solid fa-circle-info"></i> បង្ហាញ GPS ដើម</span>` : ''}
                                                        `;
                                }
                            })
                            .catch(err => console.error('Show route error:', err));
                    }

                    function closeHistoryMap() {
                        document.getElementById('tripHistoryMapModal').style.display = 'none';
                    }

                    // Auto-load on page ready
                    document.addEventListener('DOMContentLoaded', loadTripHistory);
                </script>

                <?php endif; // end gps_action ?>

