                <script>
                    let _currentReqFilter = 'pending';

                    function setReqFilter(status) {
                        _currentReqFilter = status;
                        ['pending', 'approved', 'rejected', 'all'].forEach(s => {
                            const btn = document.getElementById('filter-' + s);
                            if (btn) { btn.className = 'req-filter-btn' + (s === status ? ' active-' + s : ''); }
                        });
                        window.loadRequests();
                    }

                    window.fetchRequestTimeline = async function (requestId) {
                        const fd = new FormData();
                        fd.append('ajax_action', 'get_request_timeline');
                        fd.append('request_id', requestId);

                        const res = await fetch(window.location.href, { method: 'POST', body: fd });
                        return await res.json();
                    };

                    window.renderRequestTimeline = function (timeline) {
                        if (!Array.isArray(timeline) || timeline.length === 0) {
                            return '<div style="padding:14px 16px; border:1px dashed #cbd5e1; border-radius:12px; color:#64748b;">មិនទាន់មានប្រវត្តិ workflow នៅឡើយទេ។</div>';
                        }

                        return `<div style="display:flex; flex-direction:column; gap:12px;">${timeline.map(entry => {
                            const action = (entry.action_type || 'updated').replace(/_/g, ' ');
                            const actor = entry.actor_name || entry.actor_id || 'System';
                            const role = entry.actor_role || '';
                            const statusText = entry.status_to ? `<div style="margin-top:4px; font-size:0.82rem; color:#475569;">${entry.status_from || '—'} → <strong>${entry.status_to}</strong></div>` : '';
                            const note = entry.note ? `<div style="margin-top:8px; color:#334155; white-space:pre-wrap;">${entry.note}</div>` : '';
                            return `
                                <div style="display:flex; gap:12px; align-items:flex-start;">
                                    <div style="width:12px; height:12px; border-radius:999px; background:#6366f1; margin-top:8px; box-shadow:0 0 0 4px rgba(99,102,241,0.14); flex-shrink:0;"></div>
                                    <div style="flex:1; background:#fff; border:1px solid #e2e8f0; border-radius:14px; padding:14px 16px;">
                                        <div style="display:flex; justify-content:space-between; gap:14px; flex-wrap:wrap;">
                                            <div>
                                                <div style="font-weight:800; color:#1e293b; text-transform:capitalize;">${action}</div>
                                                <div style="font-size:0.82rem; color:#64748b;">${actor}${role ? ' • ' + role : ''}</div>
                                            </div>
                                            <div style="font-size:0.8rem; color:#94a3b8;">${entry.created_at || ''}</div>
                                        </div>
                                        ${statusText}
                                        ${note}
                                    </div>
                                </div>
                            `;
                        }).join('')}</div>`;
                    };

                    window.loadRequests = function () {
                        const tbody = document.getElementById('requests-list-body');
                        if (!tbody) return;
                        tbody.innerHTML = '<tr><td colspan="7" class="req-empty"><i class="fa-solid fa-circle-notch fa-spin fa-2x" style="opacity:0.3;"></i><p>កំពុងផ្ទុក...</p></td></tr>';
                        const fd = new FormData();
                        fd.append('ajax_action', 'get_requests');
                        fd.append('status', _currentReqFilter);
                        fetch(window.location.href, { method: 'POST', body: fd })
                            .then(r => r.json())
                            .then(res => {
                                if (res.status === 'success') {
                                    if (!res.data || res.data.length === 0) {
                                        const labels = { pending: 'Pending', approved: 'Approved', rejected: 'Rejected', all: 'ទាំងអស់' };
                                        tbody.innerHTML = `<tr><td colspan="7" class="req-empty"><i class="fa-solid fa-inbox"></i><p>មិនមានសំណើរ ${labels[_currentReqFilter] || ''} ទេ</p></td></tr>`;
                                        return;
                                    }
                                    let html = '';
                                    res.data.forEach(r => {
                                        const initials = (r.employee_name || '?').charAt(0).toUpperCase();
                                        const avatarHtml = r.avatar ? `<img src="${r.avatar}" alt="">` : `<span>${initials}</span>`;
                                        const rawType = String(r.request_type || r.type || '').toLowerCase();

                                        const typeMap = {
                                            'leave': '<span class="req-type-badge req-type-leave"><i class="fa-solid fa-calendar-minus"></i> ច្បាប់ (Leave)</span>',
                                            'late': '<span class="req-type-badge req-type-late"><i class="fa-solid fa-clock"></i> មកយឺត (Late)</span>',
                                            'forgotten_scan': '<span class="req-type-badge req-type-forgotten"><i class="fa-solid fa-fingerprint"></i> ភ្លេចស្កេន</span>',
                                            'deo': '<span class="req-type-badge req-type-deo"><i class="fa-solid fa-right-from-bracket"></i> ដេអូស</span>'
                                        };
                                        const typeHtml = typeMap[rawType] || `<span class="req-type-badge req-type-other"><i class="fa-solid fa-tag"></i> ${r.request_type || r.type || 'Other'}</span>`;

                                        const statusMap = {
                                            'pending': '<span class="req-status-pending"><i class="fa-solid fa-clock fa-xs"></i> Pending</span>',
                                            'approved': '<span class="req-status-approved"><i class="fa-solid fa-check fa-xs"></i> Approved</span>',
                                            'rejected': '<span class="req-status-rejected"><i class="fa-solid fa-xmark fa-xs"></i> Rejected</span>'
                                        };
                                        const statusHtml = statusMap[r.status] || `<span class="req-status-pending">${r.status}</span>`;

                                        const dateStr = r.created_at ? r.created_at.split(' ')[0] : (r.request_date || '');

                                        const reqPayload = encodeURIComponent(JSON.stringify(r));
                                        const pendingActions = (r.status === 'pending')
                                            ? `
                                                <button type="button" class="action-item" onclick="updateRequestStatus(${r.id}, 'approved')">
                                                    <i class="fa-solid fa-check"></i> Approve
                                                </button>
                                                <button type="button" class="action-item text-danger" onclick="updateRequestStatus(${r.id}, 'rejected')">
                                                    <i class="fa-solid fa-xmark"></i> Reject
                                                </button>
                                                <div class="crud-dots-divider"></div>
                                            `
                                            : `
                                                <div class="action-item" style="opacity:0.65; pointer-events:none;">
                                                    <i class="fa-solid fa-circle-check"></i> បានដំណើរការ
                                                </div>
                                                <div class="crud-dots-divider"></div>
                                            `;

                                        const actionBtns = `
                                            <div class="action-dropdown" style="justify-content:center;">
                                                <button type="button" class="crud-dots-btn" onclick="toggleActionMenu(this, event)"
                                                    title="Actions" aria-label="Actions" aria-expanded="false">
                                                    <i class="fa-solid fa-ellipsis-vertical"></i>
                                                </button>
                                                <div class="action-menu">
                                                    ${pendingActions}
                                                    <button type="button" class="action-item" onclick='viewReqDetail("${reqPayload}")'>
                                                        <i class="fa-solid fa-eye"></i> មើល / Print
                                                    </button>
                                                </div>
                                            </div>
                                        `;

                                        html += `<tr>
                                                    <td><span class="req-id-badge">#${r.id}</span></td>
                                                    <td>
                                                        <div class="req-emp-info">
                                                            <div class="req-emp-avatar">${avatarHtml}</div>
                                                            <div>
                                                                <div class="req-emp-name">${r.employee_name || 'N/A'}</div>
                                                                <div class="req-emp-id">${r.employee_id || ''}</div>
                                                            </div>
                                                        </div>
                                                    </td>
                                                    <td>${typeHtml}</td>
                                                    <td><div class="req-reason" title="${(r.reason || '').replace(/"/g, '&quot;')}">${r.reason || '—'}</div></td>
                                                    <td><div class="req-date"><i class="fa-regular fa-calendar" style="margin-right:4px;"></i>${dateStr || '—'}</div></td>
                                                    <td>${statusHtml}</td>
                                                    <td style="text-align:center;">${actionBtns}</td>
                                                </tr>`;
                                    });
                                    tbody.innerHTML = html;
                                }
                            })
                            .catch(err => {
                                tbody.innerHTML = '<tr><td colspan="7" class="req-empty"><i class="fa-solid fa-triangle-exclamation" style="color:#ef4444;"></i><p style="color:#ef4444;">Error loading requests</p></td></tr>';
                            });
                    };

                    window.updateRequestStatus = async function (requestId, nextStatus) {
                        const comment = window.prompt(nextStatus === 'approved' ? 'បញ្ចូល comment សម្រាប់ការយល់ព្រម (optional)' : 'បញ្ចូលមូលហេតុបដិសេធ');
                        if (comment === null) {
                            return;
                        }

                        const fd = new FormData();
                        fd.append('ajax_action', 'process_request');
                        fd.append('request_id', requestId);
                        fd.append('status', nextStatus);
                        fd.append('comment', comment);

                        try {
                            const res = await fetch(window.location.href, { method: 'POST', body: fd });
                            const json = await res.json();
                            if (json.status === 'success') {
                                showAjaxMessage('success', json.message || 'Saved');
                                window.loadRequests();
                            } else {
                                showAjaxMessage('error', json.message || 'Error');
                            }
                        } catch (err) {
                            showAjaxMessage('error', 'Network error: ' + err);
                        }
                    };

                    window.viewReqDetail = async function (encStr) {
                        try {
                            const r = JSON.parse(decodeURIComponent(encStr));
                            const timelineResult = await window.fetchRequestTimeline(r.id);
                            if (timelineResult && timelineResult.status === 'success') {
                                Object.assign(r, timelineResult.request || {});
                            }
                            const timelineHtml = window.renderRequestTimeline((timelineResult && timelineResult.timeline) || []);
                            const modal = document.getElementById('reqDetailModal');
                            const body = document.getElementById('reqDetailBody');
                            const btnPrint = document.getElementById('btnReqPrint');

                            let statusBadge = '';
                            if (r.status === 'pending') statusBadge = '<span style="background:#fef08a;color:#854d0e;padding:3px 8px;border-radius:6px;">Pending</span>';
                            else if (r.status === 'approved') statusBadge = '<span style="background:#bbf7d0;color:#166534;padding:3px 8px;border-radius:6px;">Approved</span>';
                            else statusBadge = '<span style="background:#fecaca;color:#991b1b;padding:3px 8px;border-radius:6px;">Rejected</span>';

                            const dateStr = r.created_at ? r.created_at.split(' ')[0] : (r.request_date || '');
                            body.innerHTML = `
                                    <table style="width:100%; border-collapse:collapse; margin-bottom:15px;">
                                        <tr><td style="padding:8px 0; border-bottom:1px solid #f1f5f9; width:40%; font-weight:bold; color:#64748b;">លេខសំណើរ (ID):</td><td style="padding:8px 0; border-bottom:1px solid #f1f5f9;">#REQ-${r.id}</td></tr>
                                        <tr><td style="padding:8px 0; border-bottom:1px solid #f1f5f9; font-weight:bold; color:#64748b;">កាលបរិច្ឆេទ:</td><td style="padding:8px 0; border-bottom:1px solid #f1f5f9;">${dateStr}</td></tr>
                                        <tr><td style="padding:8px 0; border-bottom:1px solid #f1f5f9; font-weight:bold; color:#64748b;">ឈ្មោះបុគ្គលិក:</td><td style="padding:8px 0; border-bottom:1px solid #f1f5f9;">${r.employee_name || 'N/A'} (ID: ${r.employee_id || ''})</td></tr>
                                        <tr><td style="padding:8px 0; border-bottom:1px solid #f1f5f9; font-weight:bold; color:#64748b;">ប្រភេទសំណើរ:</td><td style="padding:8px 0; border-bottom:1px solid #f1f5f9;">${r.request_type || r.type || 'Other'}</td></tr>
                                        <tr><td style="padding:8px 0; border-bottom:1px solid #f1f5f9; font-weight:bold; color:#64748b;">ស្ថានភាព:</td><td style="padding:8px 0; border-bottom:1px solid #f1f5f9;">${statusBadge}</td></tr>
                                        <tr><td style="padding:8px 0; border-bottom:1px solid #f1f5f9; font-weight:bold; color:#64748b;">Approved By:</td><td style="padding:8px 0; border-bottom:1px solid #f1f5f9;">${r.approved_by || '—'}</td></tr>
                                    </table>
                                    <div style="font-weight:bold; color:#64748b; margin-bottom:8px;">មូលហេតុ (Reason / Note):</div>
                                    <div style="background:#f8fafc; padding:15px; border-radius:8px; border:1px solid #e2e8f0; min-height:80px; white-space:pre-wrap;">${r.reason || '—'}</div>
                                    <div style="margin-top:14px; font-weight:bold; color:#64748b; margin-bottom:8px;">Admin Comment</div>
                                    <div style="background:#fff; padding:15px; border-radius:8px; border:1px solid #e2e8f0; min-height:60px; white-space:pre-wrap;">${r.admin_comment || '—'}</div>
                                    <div style="margin-top:18px; font-weight:bold; color:#64748b; margin-bottom:10px;">Workflow Timeline</div>
                                    <div style="background:#f8fafc; border:1px solid #e2e8f0; border-radius:14px; padding:16px;">${timelineHtml}</div>
                                `;

                            btnPrint.onclick = function () {
                                const printWindow = window.open('', '_blank');
                                const allTypes = [
                                    'សម្រាកប្រចាំឆ្នាំ (Annual Leave)',
                                    'សម្រាកដោយជំងឺ (Sick Leave)',
                                    'ភ្លេចស្កេនមេដៃ (Forgot FP)',
                                    'សម្រាកលំហែមាតុភាព (Maternity Leave)',
                                    'ថែមម៉ោង (OT)',
                                    'ចេញមុនម៉ោង (Early)',
                                    'ប្តូរថ្ងៃសម្រាក (Changing day off)',
                                    'សម្រាកពិសេស (Special Leave)',
                                    'មកយឺត (Late)'
                                ];

                                const typeStr = (r.request_type || r.type || '').toLowerCase();
                                let typesHtml = '';

                                // Improved matching logic to handle app's internal type strings
                                const getMatchState = (label) => {
                                    if (!typeStr) return false;
                                    const l = label.toLowerCase();

                                    if (typeStr === 'leave') return l.includes('annual'); // Default to annual for generic Leave
                                    if (typeStr.includes('sick')) return l.includes('sick');
                                    if (typeStr.includes('maternity')) return l.includes('maternity');
                                    if (typeStr.includes('special')) return l.includes('special');

                                    if (typeStr.includes('late')) return l.includes('late');
                                    // Use more specific check for OT to avoid matching 'forgotten'
                                    if ((typeStr === 'ot' || typeStr === 'overtime' || typeStr.includes('ot-') || typeStr.includes(' ot')) && l.includes('ot')) return true;
                                    if (typeStr.includes('early')) return l.includes('early');
                                    if (typeStr.includes('forgot') || typeStr.includes('fp')) return l.includes('forgot');
                                    if (typeStr.includes('change')) return l.includes('change');

                                    return l.includes(typeStr) || typeStr.includes(l);
                                };

                                allTypes.forEach(t => {
                                    const isSelected = getMatchState(t);
                                    let checkbox = isSelected ? '<div class="checkbox checked"><span class="checkmark">✔</span></div>' : '<div class="checkbox"></div>';
                                    typesHtml += `<div class="type-item">${checkbox} ${t}</div>`;
                                });

                                const formatDate = (d) => {
                                    if (!d || d === 'N/A') return 'N/A';
                                    try { return d.split(' ')[0].split('-').reverse().join('/'); } catch (e) { return d; }
                                };
                                const formatTime = (t) => {
                                    if (!t || t === 'N/A') return 'N/A';
                                    try {
                                        let parts = t.split(':');
                                        let h = parseInt(parts[0], 10);
                                        let ampm = h >= 12 ? 'PM' : 'AM';
                                        h = h % 12; if (h === 0) h = 12;
                                        return h + ':' + parts[1] + ' ' + ampm;
                                    } catch (e) { return t; }
                                };

                                let sigImg = '';
                                if (r.signature && r.signature.startsWith('data:image')) {
                                    sigImg = `<img src="${r.signature}" style="max-height: 40px;">`;
                                }
                                let deptSigImg = '';
                                if (r.department_head_signature && r.department_head_signature.startsWith('data:image')) {
                                    deptSigImg = `<img src="${r.department_head_signature}" style="max-height: 40px;">`;
                                }

                                printWindow.document.write(`
                                        <html>
                                        <head>
                                            <title>Request Print - REQ-${r.id}</title>
                                            <style>
                                                @import url('https://fonts.googleapis.com/css2?family=Kantumruy+Pro:wght@400;600;700&display=swap');
                                                body { font-family: 'Kantumruy Pro', sans-serif, Arial; padding: 20px; color: #000; font-size: 11px; }
                                                .document-frame { border: 2px solid #000; padding: 20px; border-radius: 4px; }
                                                .header { text-align: center; margin-bottom: 20px; }
                                                .header img { width: 100px; height: 100px; object-fit: contain; }
                                                .header-title { font-size: 16px; font-weight: bold; margin-top: 10px; }
                                                .types-box { border: 1px solid #999; padding: 15px; border-radius: 8px; display: flex; flex-wrap: wrap; gap: 15px; justify-content: center; background: #fafafa; margin-bottom: 20px; }
                                                .type-item { display: flex; align-items: center; font-size: 10px; color: #333; }
                                                .checkbox { width: 14px; height: 14px; border: 1.2px solid #000; border-radius: 3px; display: inline-flex; align-items: center; justify-content: center; margin-right: 8px; position: relative; background: #fff; }
                                                .checkbox.checked { background: #F2994A; border-color: #F2994A; }
                                                .checkmark { color: #fff; font-size: 10px; font-weight: bold; }
                                                table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }
                                                td, th { border: 1px solid #000; padding: 10px 12px; font-size: 11.5px; }
                                                .label-cell { font-weight: 600; background: #fdfdfd; }
                                            
                                                .sig-table { margin-top: 30px; }
                                                .sig-table th { background: #f8f9fa; font-weight: bold; text-align: center; padding: 12px; }
                                                .sig-table td { text-align: center; height: 60px; vertical-align: middle; }
                                            
                                                @media print {
                                                   @page { margin: 10mm; size: A4; }
                                                   body { padding: 0; }
                                                   .document-frame { border: 1.5px solid #000; page-break-inside: avoid; }
                                                }
                                            </style>
                                        </head>
                                        <body>
                                          <div class="document-frame">
                                              <div class="header">
                                                  <img src="https://i.ibb.co/r2JWnd2x/Logo-Van-Van-1.png" alt="Logo">
                                                  <div class="header-title">សំណើសុំច្បាប់ឈប់សម្រាក ប្តូរវេន ចូលមុនម៉ោង មកយឺត និងភ្លេចស្កេនមេដៃផ្សេងៗ</div>
                                              </div>
                                          
                                              <div class="types-box">
                                                  ${typesHtml}
                                              </div>
                                          
                                              <table>
                                                 <tr>
                                                    <td class="label-cell" style="width:22%;">ឈ្មោះអ្នកស្នើសុំ៖</td>
                                                    <td style="width:26%;">${r.employee_name || r.name || 'N/A'}</td>
                                                    <td class="label-cell" style="width:22%;">ចំនួនថ្ងៃ/ច្បាប់នៅសល់៖</td>
                                                    <td style="width:18%;">${r.number_of_days || '0'} ថ្ងៃ</td>
                                                    <td style="width:12%;">N/A ថ្ងៃ</td>
                                                 </tr>
                                                 <tr>
                                                    <td class="label-cell">ផ្នែក/មុខតំណែង/សាខា៖</td>
                                                    <td>${r.department || 'N/A'}</td>
                                                    <td>${r.position || 'N/A'}</td>
                                                    <td>${r.branch || 'N/A'}</td>
                                                    <td></td>
                                                 </tr>
                                                 <tr>
                                                    <td class="label-cell">ថ្ងៃខែឆ្នាំសុំឈប់៖</td>
                                                    <td>${formatDate(r.request_date)}</td>
                                                    <td class="label-cell">ចំនួនម៉ោងយឺត/ចេញមុន៖</td>
                                                    <td>${r.late_hours || 'N/A'}</td>
                                                    <td></td>
                                                 </tr>
                                                 <tr>
                                                    <td class="label-cell">ថ្ងៃចូលធ្វើការវិញ៖</td>
                                                    <td>${formatDate(r.return_date)}</td>
                                                    <td class="label-cell">ភ្លេចស្កេនមេដៃ៖</td>
                                                    <td>${r.forgot_scan_in || 'N/A'}</td>
                                                    <td>${r.forgot_scan_out || 'N/A'}</td>
                                                 </tr>
                                                 <tr>
                                                    <td class="label-cell">ម៉ោងចេញចូល៖</td>
                                                    <td>ចូល៖ ${formatTime(r.time_in)}</td>
                                                    <td>ចេញ៖ ${formatTime(r.time_out)}</td>
                                                    <td>សរុប៖ ${r.total_hours || 'N/A'}</td>
                                                    <td></td>
                                                 </tr>
                                                 <tr>
                                                    <td class="label-cell">ម៉ោងធ្វើការសងវិញ៖</td>
                                                    <td>ចូលសង៖ ${formatTime(r.repay_time_in)}</td>
                                                    <td>ចេញសង៖ ${formatTime(r.repay_time_out)}</td>
                                                    <td>សរុប៖ ${r.repay_total_hours || 'N/A'}</td>
                                                    <td></td>
                                                 </tr>
                                                 <tr>
                                                    <td class="label-cell">មូលហេតុ៖</td>
                                                    <td colspan="4">${r.reason || 'N/A'}</td>
                                                 </tr>
                                                 <tr>
                                                    <td class="label-cell">ទីកន្លែងអំឡុងពេលឈប់៖</td>
                                                    <td colspan="4">${r.location || 'N/A'}</td>
                                                 </tr>
                                                 <tr>
                                                    <td class="label-cell">ទំនាក់ទំនងបន្ទាន់៖</td>
                                                    <td colspan="2">${r.contact_number || 'N/A'}</td>
                                                    <td class="label-cell">ប្រគល់ការងារឱ្យ៖</td>
                                                    <td>${r.assigned_to || 'N/A'}</td>
                                                 </tr>
                                              </table>

                                              <table class="sig-table">
                                                  <tr>
                                                      <th>បញ្ជាក់/អនុម័តដោយ</th>
                                                      <th>ឈ្មោះ (Name)</th>
                                                      <th>ហត្ថលេខា (Signature)</th>
                                                      <th>ថ្ងៃខែឆ្នាំ (Date)</th>
                                                  </tr>
                                                  <tr>
                                                      <td style="font-weight:bold;">អ្នកស្នើសុំ</td>
                                                      <td>${r.employee_name || r.name || 'N/A'}</td>
                                                      <td>${sigImg}</td>
                                                      <td>${formatDate(r.signature_date || r.request_date || r.created_at)}</td>
                                                  </tr>
                                                  <tr>
                                                      <td style="font-weight:bold;">ប្រធានផ្នែក</td>
                                                      <td>${r.department_head_name || ''}</td>
                                                      <td>${deptSigImg}</td>
                                                      <td>${formatDate(r.department_head_signature_date)}</td>
                                                  </tr>
                                                  <tr>
                                                      <td style="font-weight:bold;">ប្រធានធនធានមនុស្ស</td>
                                                      <td></td><td></td><td></td>
                                                  </tr>
                                                  <tr>
                                                      <td style="font-weight:bold;">ប្រធានគ្រប់គ្រងទូទៅ</td>
                                                      <td></td><td></td><td></td>
                                                  </tr>
                                                  <tr>
                                                      <td style="font-weight:bold;">អគ្គនាយិកា</td>
                                                      <td></td><td></td><td></td>
                                                  </tr>
                                              </table>
                                          </div>
                                        </body>
                                        </html>
                                    `);
                                    printWindow.document.close();
                                    printWindow.focus();
                                    setTimeout(() => {
                                        printWindow.print();
                                    }, 600);
                                };

                                modal.style.display = 'block';
                            } catch (e) {
                                console.error("Error viewing request:", e);
                                alert("មិនអាចអានទិន្នន័យបានទេ");
                            }
                        };

                        if (document.readyState === 'complete') { window.loadRequests(); }
                        else { window.addEventListener('load', window.loadRequests); }
                    </script>

