                    <script>
                        window.__meetingPayloadCache = window.__meetingPayloadCache || {};

                        window.escapeMeetingHtml = function (value) {
                            const div = document.createElement('div');
                            div.textContent = value == null ? '' : String(value);
                            return div.innerHTML;
                        };

                        window.parseMeetingPayload = function (payload) {
                            if (!payload) return {};
                            if (typeof payload !== 'string') return payload;
                            try { return JSON.parse(payload); } catch (e) { }
                            try { return JSON.parse(decodeURIComponent(payload)); } catch (e) { }
                            return {};
                        };

                        window.normalizeMeetingData = function (payload) {
                            const raw = window.parseMeetingPayload(payload) || {};
                            const photos = [];
                            const pushPhotos = (source) => {
                                if (!source) return;
                                if (Array.isArray(source)) {
                                    source.forEach(item => {
                                        const path = String(item || '').trim();
                                        if (path && !photos.includes(path)) photos.push(path);
                                    });
                                    return;
                                }
                                if (typeof source === 'string') {
                                    const trimmed = source.trim();
                                    if (!trimmed) return;
                                    try {
                                        const decoded = JSON.parse(trimmed);
                                        pushPhotos(decoded);
                                        return;
                                    } catch (e) { }
                                    if (!photos.includes(trimmed)) photos.push(trimmed);
                                }
                            };

                            pushPhotos(raw.display_photos);
                            pushPhotos(raw.related_photos);
                            pushPhotos(raw.photos);
                            pushPhotos(raw.photo_url);
                            pushPhotos(raw.display_photo_url);

                            const title = String(raw.display_title || raw.title || raw.topic || 'គ្មានចំណងជើង').trim() || 'គ្មានចំណងជើង';
                            const category = String(raw.display_category || raw.category || raw.department || 'General').trim() || 'General';
                            const description = String(raw.display_description || raw.description || '').trim();
                            const audioUrl = String(raw.display_audio_url || raw.mp3_url || raw.audio_file_path || raw.audio_path || '').trim();
                            const photoUrl = String(raw.display_photo_url || raw.photo_url || photos[0] || '').trim();

                            return {
                                ...raw,
                                title: title,
                                topic: String(raw.topic || title),
                                category: category,
                                department: String(raw.department || category),
                                meeting_date: String(raw.meeting_date || ''),
                                description: description,
                                external_url: String(raw.external_url || '').trim(),
                                photo_url: photoUrl,
                                mp3_url: audioUrl,
                                photos: photos
                            };
                        };

                        window.openMeetingViewModal = function (payload) {
                            const meeting = window.normalizeMeetingData(payload);
                            const body = document.getElementById('meetingViewBody');
                            if (!body) return;

                            const photoGallery = meeting.photos.length > 0
                                ? `<div class="meeting-view-gallery">${meeting.photos.map(photo => `<img src="${window.escapeMeetingHtml(photo)}" alt="" onclick="window.open(this.src, '_blank')">`).join('')}</div>`
                                : '<div style="padding:18px; border:1px dashed #dbe2ea; border-radius:14px; color:#94a3b8; text-align:center;">មិនមានរូបភាពភ្ជាប់ទេ។</div>';

                            const audioBlock = meeting.mp3_url
                                ? `<div style="padding:18px; border:1px solid #dbe2ea; border-radius:14px; background:#f8fafc;">
                                        <div style="font-weight:700; color:#334155; margin-bottom:10px;"><i class="fa-solid fa-microphone"></i> សំឡេងកិច្ចប្រជុំ</div>
                                        <audio controls style="width:100%;">
                                            <source src="${window.escapeMeetingHtml(meeting.mp3_url)}">
                                        </audio>
                                   </div>`
                                : '<div style="padding:18px; border:1px dashed #dbe2ea; border-radius:14px; color:#94a3b8; text-align:center;">មិនមានសំឡេងភ្ជាប់ទេ។</div>';

                            const linkBlock = meeting.external_url
                                ? `<a href="${window.escapeMeetingHtml(meeting.external_url)}" target="_blank" class="btn btn-secondary" style="min-height:42px;"><i class="fa-solid fa-link"></i> បើកតំណភ្ជាប់</a>`
                                : '';

                            body.innerHTML = `
                                <div style="display:flex; flex-direction:column; gap:18px;">
                                    <div style="display:flex; flex-wrap:wrap; align-items:center; gap:10px;">
                                        <span class="badge" style="background:var(--primary-light); color:var(--primary); padding:6px 14px; border-radius:999px; font-weight:800;">${window.escapeMeetingHtml(meeting.category)}</span>
                                        <span style="color:#64748b; font-weight:700;"><i class="fa-solid fa-calendar-day"></i> ${window.escapeMeetingHtml(meeting.meeting_date || '—')}</span>
                                    </div>
                                    <div>
                                        <h2 style="margin:0 0 10px 0; color:#162033; font-size:1.45rem; font-weight:800;">${window.escapeMeetingHtml(meeting.title)}</h2>
                                        <div style="color:#475569; line-height:1.75; white-space:pre-wrap;">${window.escapeMeetingHtml(meeting.description || 'មិនមានការពិពណ៌នា។')}</div>
                                    </div>
                                    ${linkBlock ? `<div style="display:flex; gap:10px; flex-wrap:wrap;">${linkBlock}</div>` : ''}
                                    ${audioBlock}
                                    <div>
                                        <div style="font-weight:700; color:#334155; margin-bottom:12px;"><i class="fa-solid fa-image"></i> រូបភាពពាក់ព័ន្ធ</div>
                                        ${photoGallery}
                                    </div>
                                </div>
                            `;

                            document.getElementById('meetingViewModal').style.display = 'block';
                        };

                        window.closeMeetingViewModal = function () {
                            const modal = document.getElementById('meetingViewModal');
                            if (modal) modal.style.display = 'none';
                        };

                        window.renderMeetingCard = function (payload) {
                            const meeting = window.normalizeMeetingData(payload);
                            const meetingKey = `meeting_${Number(meeting.id || 0) || Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
                            window.__meetingPayloadCache[meetingKey] = meeting;
                            const preview = meeting.photo_url
                                ? `<div class="meeting-card-preview"><img src="${window.escapeMeetingHtml(meeting.photo_url)}" alt=""></div>`
                                : `<div class="meeting-card-preview"><i class="fa-solid fa-handshake" style="font-size:2.2rem; color:#6366f1; opacity:0.55;"></i></div>`;
                            const audioBtn = meeting.mp3_url
                                ? `<a href="${window.escapeMeetingHtml(meeting.mp3_url)}" target="_blank" class="btn btn-sm btn-success" style="min-width:96px;"><i class="fa-solid fa-play"></i> Audio</a>`
                                : '';
                            const urlBtn = meeting.external_url
                                ? `<a href="${window.escapeMeetingHtml(meeting.external_url)}" target="_blank" class="btn btn-sm btn-secondary" style="min-width:90px;"><i class="fa-solid fa-link"></i> Link</a>`
                                : '';

                            return `
                                <div class="hrm-card meeting-admin-card" style="display:flex; flex-direction:column;">
                                    <button type="button" onclick="window.openMeetingViewModal(window.__meetingPayloadCache['${meetingKey}'])" style="all:unset; display:block; width:100%; cursor:pointer; text-align:left;">
                                        ${preview}
                                        <div style="display:flex; align-items:center; justify-content:space-between; gap:10px; margin-bottom:12px;">
                                            <span class="badge" style="background:var(--primary-light); color:var(--primary); font-size:0.72rem; font-weight:800; padding:5px 12px; border-radius:999px; text-transform:uppercase;">${window.escapeMeetingHtml(meeting.category)}</span>
                                            <span style="color:#64748b; font-size:0.82rem; font-weight:700;"><i class="fa-solid fa-calendar-day"></i> ${window.escapeMeetingHtml(meeting.meeting_date || '—')}</span>
                                        </div>
                                        <h3 style="margin:0 0 10px 0; font-size:1.15rem; line-height:1.4; color:#162033;">${window.escapeMeetingHtml(meeting.title)}</h3>
                                        <div style="font-size:0.92rem; color:var(--text-secondary); margin-bottom:16px; line-height:1.65; display:-webkit-box; -webkit-line-clamp:4; -webkit-box-orient:vertical; overflow:hidden;">${window.escapeMeetingHtml(meeting.description || 'មិនមានការពិពណ៌នា។')}</div>
                                    </button>

                                    <div style="display:flex; gap:8px; align-items:center; margin-top:auto; padding-top:16px; border-top:1px solid var(--border); flex-wrap:wrap;">
                                        <button type="button" class="btn btn-primary btn-sm" style="min-width:105px;" onclick="window.openMeetingViewModal(window.__meetingPayloadCache['${meetingKey}'])">
                                            <i class="fa-solid fa-eye"></i> មើល
                                        </button>
                                        ${audioBtn}
                                        ${urlBtn}
                                        <div style="margin-left:auto;" class="action-dropdown">
                                            <button type="button" class="crud-dots-btn" onclick="toggleActionMenu(this, event)" title="Actions">
                                                <i class="fa-solid fa-ellipsis-vertical"></i>
                                            </button>
                                            <div class="action-menu">
                                                <button type="button" class="action-item" onclick="window.openMeetingModal(window.__meetingPayloadCache['${meetingKey}'])">
                                                    <i class="fa-solid fa-pen-to-square"></i> Edit
                                                </button>
                                                <button type="button" class="action-item text-danger" onclick="window.deleteMeeting(${Number(meeting.id || 0)})">
                                                    <i class="fa-solid fa-trash"></i> Delete
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            `;
                        };

                        window.loadMeetings = function () {
                            const grid = document.getElementById('meetings-grid');
                            if (!grid) return;
                            const fd = new FormData();
                            fd.append('ajax_action', 'get_meetings');
                            fetch(window.location.href, { method: 'POST', body: fd })
                                .then(r => r.json())
                                .then(res => {
                                    if (res.status === 'success') {
                                        if (!res.data || res.data.length === 0) {
                                            grid.innerHTML = '<div class="hrm-card text-center p-5 text-muted" style="grid-column: 1/-1;"><i class="fa-solid fa-calendar-xmark" style="font-size:3rem; opacity:0.1; margin-bottom:15px; display:block;"></i>មិនទាន់មានកិច្ចប្រជុំទេ។</div>';
                                            return;
                                        }
                                        grid.innerHTML = res.data.map(window.renderMeetingCard).join('');
                                    } else {
                                        grid.innerHTML = '<div class="hrm-card text-center p-5 text-danger" style="grid-column: 1/-1;">មិនអាចទាញយកកិច្ចប្រជុំបានទេ។</div>';
                                    }
                                })
                                .catch(() => {
                                    grid.innerHTML = '<div class="hrm-card text-center p-5 text-danger" style="grid-column: 1/-1;">មានបញ្ហាក្នុងការភ្ជាប់ទៅ Server។</div>';
                                });
                        };
                        window.openMeetingModal = function (data = null) {
                            const form = document.getElementById('meetingForm');
                            if (!form) return;
                            form.reset();
                            if (data) {
                                data = window.normalizeMeetingData(data);
                                document.getElementById('meetingModalTitle').innerHTML = '<i class="fa-solid fa-calendar-check"></i> កែប្រែកិច្ចប្រជុំ';
                                document.getElementById('meet_id').value = data.id;
                                document.getElementById('meet_title').value = data.title;
                                document.getElementById('meet_date').value = data.meeting_date;
                                document.getElementById('meet_cat').value = data.category;
                                document.getElementById('meet_desc').value = data.description;
                                document.getElementById('meet_url').value = data.external_url || '';
                                document.getElementById('meet_photo_path').value = data.photo_url || '';
                                document.getElementById('meet_audio_path').value = data.mp3_url || '';
                            } else {
                                document.getElementById('meetingModalTitle').innerHTML = '<i class="fa-solid fa-calendar-plus"></i> បង្ហោះកិច្ចប្រជុំថ្មី';
                                document.getElementById('meet_id').value = '';
                                document.getElementById('meet_url').value = '';
                                document.getElementById('meet_photo_path').value = '';
                                document.getElementById('meet_audio_path').value = '';
                                document.getElementById('meet_date').value = new Date().toISOString().split('T')[0];
                            }
                            document.getElementById('meetingModal').style.display = 'block';
                        };
                        window.closeMeetingModal = function () { document.getElementById('meetingModal').style.display = 'none'; };
                        window.saveMeeting = function (eventOrForm, explicitForm) {
                            const evt = eventOrForm && typeof eventOrForm.preventDefault === 'function' ? eventOrForm : null;
                            if (evt) {
                                evt.preventDefault();
                                evt.stopPropagation();
                            }

                            const form = explicitForm
                                || (evt && evt.target instanceof HTMLFormElement ? evt.target : null)
                                || document.getElementById('meetingForm');

                            if (!form) {
                                return false;
                            }

                            const submitBtn = form.querySelector('button[type="submit"]');
                            const originalBtnHtml = submitBtn ? submitBtn.innerHTML : '';
                            if (submitBtn) {
                                submitBtn.disabled = true;
                                submitBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> កំពុងបង្ហោះ...';
                            }

                            const fd = new FormData(form);
                            fd.append('ajax_action', 'save_meeting');

                            fetch(window.location.href, {
                                method: 'POST',
                                body: fd,
                                headers: { 'X-Requested-With': 'XMLHttpRequest' }
                            })
                                .then(async (r) => {
                                    const text = await r.text();
                                    try {
                                        return JSON.parse(text);
                                    } catch (err) {
                                        throw new Error('Invalid server response');
                                    }
                                })
                                .then(res => {
                                    if (res.status === 'success') {
                                        showAjaxMessage('success', res.message || 'រក្សាទុកបានជោគជ័យ');
                                        window.closeMeetingModal();
                                        window.loadMeetings();
                                    } else {
                                        showAjaxMessage('error', res.message || 'មិនអាចរក្សាទុកបានទេ');
                                    }
                                })
                                .catch((err) => {
                                    showAjaxMessage('error', err && err.message ? err.message : 'មានបញ្ហាក្នុងការភ្ជាប់ជាមួយ Server');
                                })
                                .finally(() => {
                                    if (submitBtn) {
                                        submitBtn.disabled = false;
                                        submitBtn.innerHTML = originalBtnHtml;
                                    }
                                });

                            return false;
                        };
                        (function bindMeetingFormSubmit() {
                            const form = document.getElementById('meetingForm');
                            if (!form || form.dataset.submitBound === '1') return;
                            form.dataset.submitBound = '1';
                            form.addEventListener('submit', function (e) {
                                window.saveMeeting(e, form);
                            });
                        })();
                        window.deleteMeeting = function (id) {
                            if (!confirm('តើអ្នកពិតជាចង់លុបមែនទេ?')) return;
                            const fd = new FormData();
                            fd.append('ajax_action', 'delete_meeting');
                            fd.append('id', id);
                            fetch(window.location.href, { method: 'POST', body: fd }).then(r => r.json()).then(res => { if (res.status === 'success') window.loadMeetings(); });
                        };
                        window.loadMeetings();
                    </script>
                <?php endif; ?>

