                    <script>
                        window.importSampleQuiz = function () {
                            if (!confirm("តើអ្នកចង់នាំចូលសំណួរគំរូដែលធ្លាប់មានក្នុង App ដែរឬទេ? (វានឹងមិនបន្ថែមសំណួរដែលស្ទួនគ្នាទេ)")) return;
                            const fd = new FormData();
                            fd.append('ajax_action', 'import_sample_quiz');
                            fetch(window.location.href, { method: 'POST', body: fd })
                                .then(r => r.json())
                                .then(res => {
                                    if (res.status === 'success') {
                                        if (typeof showAjaxMessage === 'function') showAjaxMessage('success', res.message);
                                        window.loadQuizQuestions();
                                    } else {
                                        if (typeof showAjaxMessage === 'function') showAjaxMessage('error', res.message);
                                    }
                                }).catch(err => console.error(err));
                        };

                        window.loadQuizQuestions = function () {
                            const body = document.getElementById('quiz-list-body');
                            if (!body) return;
                            const fd = new FormData();
                            fd.append('ajax_action', 'get_quiz_questions');
                            fetch(window.location.href, { method: 'POST', body: fd })
                                .then(r => r.json())
                                .then(res => {
                                    if (res.status === 'success') {
                                        let html = '';
                                        if (!res.data || res.data.length === 0) {
                                            html = '<tr><td colspan="6" class="text-center p-5 text-muted" style="font-size:1.1rem; font-weight:600;"><i class="fa-solid fa-clipboard-question" style="font-size:3rem; opacity:0.1; display:block; margin-bottom:15px;"></i>មិនទាន់មានសំណួរ Quiz ទេ។</td></tr>';
                                        } else {
                                            res.data.forEach(q => {
                                                const status = q.is_active == 1 ? '<span class="badge" style="background:#dcfce7; color:#15803d; border-radius:30px; padding:6px 14px; font-weight:700;">Active</span>' : '<span class="badge" style="background:#fee2e2; color:#b91c1c; border-radius:30px; padding:6px 14px; font-weight:700;">Inactive</span>';
                                                const options = `<div style="font-size:0.88rem; line-height:1.6;"><b>A:</b> ${q.option_a}<br><b>B:</b> ${q.option_b}${q.option_c ? '<br><b>C:</b> ' + q.option_c : ''}${q.option_d ? '<br><b>D:</b> ' + q.option_d : ''}</div>`;
                                                const safeData = JSON.stringify(q).replace(/'/g, "&apos;");
                                                html += `<tr>
                                            <td style="font-weight:800; color:var(--muted);">#${q.id}</td>
                                            <td style="font-weight:700; color:#1e293b; max-width:350px;">${q.question}</td>
                                            <td style="color:#475569;">${options}</td>
                                            <td style="text-align:center;"><span class="badge" style="background:#e0e7ff; color:#4338ca; border-radius:10px; padding:10px 15px; font-size:1.1rem; font-weight:800;">${q.correct_option}</span></td>
                                            <td style="text-align:center;">${status}</td>
                                            <td style="text-align:center;">
                                                <div class="action-dropdown" style="justify-content:center;">
                                                    <button type="button" class="crud-dots-btn" onclick="toggleActionMenu(this, event)" title="Actions">
                                                        <i class="fa-solid fa-ellipsis-vertical"></i>
                                                    </button>
                                                    <div class="action-menu">
                                                        <button type="button" class="action-item" onclick='window.openQuizModal(${safeData})'>
                                                            <i class="fa-solid fa-pen-to-square"></i> Edit
                                                        </button>
                                                        <button type="button" class="action-item text-danger" onclick="window.deleteQuizQuestion(${q.id})">
                                                            <i class="fa-solid fa-trash-can"></i> Delete
                                                        </button>
                                                    </div>
                                                </div>
                                            </td>
                                        </tr>`;
                                            });
                                        }
                                        body.innerHTML = html;
                                    }
                                });
                        };
                        window.openQuizModal = function (data = null) {
                            const form = document.getElementById('quizForm');
                            if (!form) return;
                            form.reset();
                            if (data) {
                                document.getElementById('quizModalTitle').innerHTML = '<i class="fa-solid fa-pen-to-square"></i> កែប្រែសំណួរ';
                                document.getElementById('quiz_id').value = data.id;
                                document.getElementById('quiz_question').value = data.question;
                                document.getElementById('quiz_oa').value = data.option_a;
                                document.getElementById('quiz_ob').value = data.option_b;
                                document.getElementById('quiz_oc').value = data.option_c || '';
                                document.getElementById('quiz_od').value = data.option_d || '';
                                document.getElementById('quiz_correct').value = data.correct_option;
                                document.getElementById('quiz_active').value = data.is_active;
                                document.getElementById('quiz_exp').value = data.explanation || '';
                            } else {
                                document.getElementById('quizModalTitle').innerHTML = '<i class="fa-solid fa-clipboard-question"></i> បន្ថែមសំណួរថ្មី';
                                document.getElementById('quiz_id').value = '';
                            }
                            const modal = document.getElementById('quizModal');
                            modal.style.display = 'flex';
                        };
                        window.closeQuizModal = function () { document.getElementById('quizModal').style.display = 'none'; };
                        window.saveQuizQuestion = function (e) {
                            e.preventDefault();
                            const btn = e.target.querySelector('button[type="submit"]');
                            const oldHtml = btn.innerHTML;
                            btn.innerHTML = '<i class="fa-solid fa-circle-notch fa-spin"></i> កំពុងរក្សាទុក...';
                            btn.disabled = true;

                            const fd = new FormData(e.target);
                            fd.append('ajax_action', 'save_quiz_question');
                            fetch(window.location.href, { method: 'POST', body: fd })
                                .then(r => r.json())
                                .then(res => {
                                    btn.innerHTML = oldHtml;
                                    btn.disabled = false;
                                    if (res.status === 'success') {
                                        if (typeof showAjaxMessage === 'function') showAjaxMessage('success', res.message);
                                        window.closeQuizModal();
                                        window.loadQuizQuestions();
                                    } else {
                                        if (typeof showAjaxMessage === 'function') showAjaxMessage('error', res.message);
                                    }
                                }).catch(err => {
                                    btn.innerHTML = oldHtml;
                                    btn.disabled = false;
                                    console.error(err);
                                });
                        };
                        window.deleteQuizQuestion = function (id) {
                            if (!confirm('តើអ្នកពិតជាចង់លុបសំណួរនេះមែនទេ?')) return;
                            const fd = new FormData();
                            fd.append('ajax_action', 'delete_quiz_question');
                            fd.append('id', id);
                            fetch(window.location.href, { method: 'POST', body: fd })
                                .then(r => r.json())
                                .then(res => {
                                    if (res.status === 'success') {
                                        if (typeof showAjaxMessage === 'function') showAjaxMessage('success', res.message);
                                        window.loadQuizQuestions();
                                    }
                                });
                        };
                        if (document.readyState === 'loading') {
                            document.addEventListener('DOMContentLoaded', window.loadQuizQuestions);
                        } else {
                            window.loadQuizQuestions();
                        }
                    </script>
                <?php endif; ?>

                <?php if ($current_page == 'reports' && ($current_action == 'reports' || $current_action == '')): ?>
                    <?php
                    $dates_query_sql = "SELECT DISTINCT DATE(cl.log_datetime) as attendance_date
                        FROM checkin_logs cl
                        JOIN users u ON cl.employee_id = u.employee_id
                        ORDER BY attendance_date DESC";

                    $dates_stmt = $mysqli->prepare($dates_query_sql);
                    $dates_stmt->execute();
                    $dates_result = $dates_stmt->get_result();
                    $available_dates = [];
                    if ($dates_result) {
                        while ($row = $dates_result->fetch_assoc()) {
                            $available_dates[] = $row['attendance_date'];
                        }
                    }
                    $dates_stmt->close();

                    $filter_date = $_GET['filter_date'] ?? ($available_dates[0] ?? date('Y-m-d'));
                    $filter_status = $_GET['filter_status'] ?? 'All';
                    $filter_department = $_GET['filter_department'] ?? 'department';

                    // Late employees summary for selected date
                    $late_summary = [];
                    $start_dt = $filter_date . ' 00:00:00';
                    $end_dt = $filter_date . ' 23:59:59';

                    $late_sql = "SELECT u.employee_id, u.name, COUNT(*) as late_count
                 FROM checkin_logs cl
                 JOIN users u ON cl.employee_id = u.employee_id
                 WHERE cl.log_datetime BETWEEN ? AND ? AND cl.status = 'Late'";
                    $late_types = 'ss';
                    $late_params = [$start_dt, $end_dt];
                    $late_sql .= " GROUP BY u.employee_id, u.name ORDER BY u.name ASC";

                    if ($stmt_late = $mysqli->prepare($late_sql)) {
                        $stmt_late->bind_param($late_types, ...$late_params);
                        $stmt_late->execute();
                        $res_late = $stmt_late->get_result();
                        if ($res_late) {
                            $late_summary = $res_late->fetch_all(MYSQLI_ASSOC);
                        }
                        $stmt_late->close();
                    }

                    // Optimization: Batch fetch entries and rules for all late users to avoid N+1 queries
                    if (!empty($late_summary)) {
                        $late_user_ids = array_column($late_summary, 'employee_id');
                        $placeholders = implode(',', array_fill(0, count($late_user_ids), '?'));

                        // 1. Fetch ALL late entries for these users on this date
                        $all_entries = [];
                        $entries_sql = "SELECT cl.employee_id, cl.location_name, cl.log_datetime
                        FROM checkin_logs cl
                        JOIN users u ON cl.employee_id = u.employee_id
                        WHERE cl.employee_id IN ($placeholders)
                        AND cl.log_datetime BETWEEN ? AND ?
                        AND cl.status = 'Late'
                        ORDER BY cl.log_datetime ASC";

                        if ($stmt_e = $mysqli->prepare($entries_sql)) {
                            $e_types = str_repeat('s', count($late_user_ids)) . 'ss';
                            $e_params = array_merge($late_user_ids, [$start_dt, $end_dt]);
                            $stmt_e->bind_param($e_types, ...$e_params);
                            $stmt_e->execute();
                            $res_e = $stmt_e->get_result();
                            if ($res_e) {
                                while ($row_e = $res_e->fetch_assoc()) {
                                    $all_entries[$row_e['employee_id']][] = $row_e;
                                }
                            }
                            $stmt_e->close();
                        }

                        // 2. Fetch ALL checkin rules for these users
                        $all_rules = [];
                        $rules_sql = "SELECT employee_id, type, start_time, end_time, status
                      FROM attendance_rules
                      WHERE employee_id IN ($placeholders) AND type = 'checkin'";
                        if ($stmt_r = $mysqli->prepare($rules_sql)) {
                            $stmt_r->bind_param(str_repeat('s', count($late_user_ids)), ...$late_user_ids);
                            $stmt_r->execute();
                            $res_r = $stmt_r->get_result();
                            if ($res_r) {
                                while ($row_r = $res_r->fetch_assoc()) {
                                    $all_rules[$row_r['employee_id']][] = $row_r;
                                }
                            }
                            $stmt_r->close();
                        }

                        // 3. Map entries and calculate late minutes
                        foreach ($late_summary as &$usr) {
                            $eid = $usr['employee_id'];
                            $usr['entries'] = $all_entries[$eid] ?? [];

                            if (!empty($usr['entries'])) {
                                foreach ($usr['entries'] as &$entry) {
                                    $entry['late_minutes'] = null;
                                    $log_hms = date('H:i:s', strtotime($entry['log_datetime']));

                                    // Pivot logic matching scan.php
                                    $pivot_time = '';
                                    $u_rules = $all_rules[$eid] ?? [];

                                    // Try to find Good end_time <= log_time
                                    $best_good = null;
                                    foreach ($u_rules as $r) {
                                        if ($r['status'] === 'Good' && $r['end_time'] <= $log_hms) {
                                            if ($best_good === null || $r['end_time'] > $best_good['end_time']) {
                                                $best_good = $r;
                                            }
                                        }
                                    }
                                    if ($best_good) {
                                        $pivot_time = $best_good['end_time'];
                                    } else {
                                        // Fallback to earliest start time
                                        $earliest = null;
                                        foreach ($u_rules as $r) {
                                            if ($earliest === null || $r['start_time'] < $earliest['start_time']) {
                                                $earliest = $r;
                                            }
                                        }
                                        if ($earliest)
                                            $pivot_time = $earliest['start_time'];
                                    }

                                    if ($pivot_time !== '') {
                                        if (preg_match('/^\d{1,2}:\d{2}$/', $pivot_time)) {
                                            $pivot_time .= ':00';
                                        }
                                        $base_dt = date('Y-m-d', strtotime($entry['log_datetime'])) . ' ' . $pivot_time;
                                        $late_secs = strtotime($entry['log_datetime']) - strtotime($base_dt);
                                        if ($late_secs > 0) {
                                            // FIX: Use ceil for accuracy
                                            $mins = (int) ceil($late_secs / 60);
                                            $entry['late_minutes'] = $mins;
                                        }
                                    }
                                }
                                unset($entry);
                            }
                        }
                        unset($usr);
                    }

                    $records_per_page = 200;
                    $current_p_page = isset($_GET['p']) ? (int) $_GET['p'] : 1;
                    if ($current_p_page < 1) {
                        $current_p_page = 1;
                    }
                    $offset = ($current_p_page - 1) * $records_per_page;

                    $count_sql = "SELECT COUNT(*) as total
                  FROM checkin_logs cl
                  JOIN users u ON cl.employee_id = u.employee_id
                  WHERE cl.log_datetime BETWEEN ? AND ?";
                    $count_params = [$start_dt, $end_dt];
                    $count_types = "ss";

                    if ($filter_status !== 'All') {
                        $count_sql .= " AND cl.status = ?";
                        $count_params[] = $filter_status;
                        $count_types .= "s";
                    }
                    if ($filter_department === 'worker') {
                        $count_sql .= " AND JSON_EXTRACT(u.custom_data, '$.department') = ?";
                        $count_params[] = 'Worker';
                        $count_types .= "s";
                    } elseif ($filter_department === 'department') {
                        $count_sql .= " AND (JSON_EXTRACT(u.custom_data, '$.department') != ? OR JSON_EXTRACT(u.custom_data, '$.department') IS NULL)";
                        $count_params[] = 'Worker';
                        $count_types .= "s";
                    }


                    $total_records = 0;
                    if ($stmt_count = $mysqli->prepare($count_sql)) {
                        if (!empty($count_types))
                            $stmt_count->bind_param($count_types, ...$count_params);
                        $stmt_count->execute();
                        $count_result = $stmt_count->get_result();
                        if ($count_result)
                            $total_records = $count_result->fetch_assoc()['total'];
                        $stmt_count->close();
                    }

                    $total_pages = ceil($total_records / $records_per_page);

                    // [កូដដែលបានកែសម្រួល] ????? cl.custom_fields_data
                    $sql = "SELECT cl.*, u.custom_data, cl.custom_fields_data,
                           COALESCE(NULLIF(TRIM(cl.name), ''), NULLIF(TRIM(u.name), ''), cl.employee_id) AS name
            FROM checkin_logs cl
            LEFT JOIN users u ON cl.employee_id = u.employee_id
            WHERE cl.log_datetime BETWEEN ? AND ?";
                    $params = [$start_dt, $end_dt];
                    $types = "ss";

                    if ($filter_status !== 'All') {
                        $sql .= " AND cl.status = ?";
                        $params[] = $filter_status;
                        $types .= "s";
                    }
                    // Apply department filter to paginated query (same logic as count/export)
                    if ($filter_department === 'worker') {
                        $sql .= " AND JSON_EXTRACT(u.custom_data, '$.department') = ?";
                        $params[] = 'Worker';
                        $types .= "s";
                    } elseif ($filter_department === 'department') {
                        $sql .= " AND (JSON_EXTRACT(u.custom_data, '$.department') != ? OR JSON_EXTRACT(u.custom_data, '$.department') IS NULL)";
                        $params[] = 'Worker';
                        $types .= "s";
                    }


                    $sql .= " ORDER BY name ASC, cl.log_datetime ASC LIMIT ? OFFSET ?";
                    $params[] = $records_per_page;
                    $params[] = $offset;
                    $types .= "ii";

                    $report_data = [];
                    if ($stmt = $mysqli->prepare($sql)) {
                        if (!empty($types))
                            $stmt->bind_param($types, ...$params);
                        $stmt->execute();
                        $report_data = $stmt->get_result()->fetch_all(MYSQLI_ASSOC);
                        $stmt->close();
                    } else {
                        echo "<div class='alert alert-danger'>SQL ERROR: " . htmlspecialchars($mysqli->error) . "</div>";
                    }

                    // [កូដដែលបានកែសម្រួល] ????? cl.custom_fields_data
                    $export_sql = "SELECT cl.*, u.custom_data, cl.custom_fields_data,
                                  COALESCE(NULLIF(TRIM(cl.name), ''), NULLIF(TRIM(u.name), ''), cl.employee_id) AS name
                   FROM checkin_logs cl
                   LEFT JOIN users u ON cl.employee_id = u.employee_id
                   WHERE cl.log_datetime BETWEEN ? AND ?";
                    $export_params = [$start_dt, $end_dt];
                    $export_types = "ss";

                    if ($filter_status !== 'All') {
                        $export_sql .= " AND cl.status = ?";
                        $export_params[] = $filter_status;
                        $export_types .= "s";
                    }
                    if ($filter_department === 'worker') {
                        $export_sql .= " AND JSON_EXTRACT(u.custom_data, '$.department') = ?";
                        $export_params[] = 'Worker';
                        $export_types .= "s";
                    } elseif ($filter_department === 'department') {
                        $export_sql .= " AND (JSON_EXTRACT(u.custom_data, '$.department') != ? OR JSON_EXTRACT(u.custom_data, '$.department') IS NULL)";
                        $export_params[] = 'Worker';
                        $export_types .= "s";
                    }

                    $export_sql .= " ORDER BY u.name ASC, cl.log_datetime ASC";

                    $export_data = [];
                    if ($stmt_exp = $mysqli->prepare($export_sql)) {
                        if (!empty($export_types))
                            $stmt_exp->bind_param($export_types, ...$export_params);
                        $stmt_exp->execute();
                        $export_data = $stmt_exp->get_result()->fetch_all(MYSQLI_ASSOC);
                        $stmt_exp->close();
                    }
