                                <script>
                                    window.loadBanners = function () {
                                        const list = document.getElementById('banners-list');
                                        if (!list) return;
                                        const fd = new FormData();
                                        fd.append('ajax_action', 'get_banners');

                                        fetch('admin_attendance.php', { method: 'POST', body: fd })
                                            .then(r => r.json())
                                            .then(res => {
                                                if (res.status === 'success') {
                                                    let html = '';
                                                    if (!res.data || res.data.length === 0) {
                                                        html = '<tr><td colspan="5" style="text-align:center; padding:40px; color:#94a3b8;"><i class="fa-solid fa-images" style="font-size:2rem; opacity:0.2; display:block; margin-bottom:10px;"></i>មិនទាន់មានស្លាយនៅឡើយទេ។</td></tr>';
                                                    } else {
                                                        res.data.forEach(b => {
                                                            const activeClass = b.is_active == 1 ? 'badge-success' : 'badge-danger';
                                                            const activeText = b.is_active == 1 ? 'Active' : 'Hidden';
                                                            const safeData = JSON.stringify(b).replace(/'/g, "&apos;");
                                                            html += `
                                                                <tr>
                                                                    <td style="font-weight:800; color:#64748b; text-align:center;">${b.order_index}</td>
                                                                    <td><img src="${b.image_url}" style="width:100px; height:60px; object-fit:cover; border-radius:8px; border:1px solid #e2e8f0; cursor:pointer;" onclick="window.open(this.src)"></td>
                                                                    <td>
                                                                        <div style="font-weight:800; color:var(--primary);">${b.title}</div>
                                                                        <div style="font-size:0.8rem; color:#64748b; margin-top:2px;">${b.text || 'No description'}</div>
                                                                        ${b.external_link ? `<div style="font-size:0.75rem; color:#6366f1; margin-top:2px;"><i class="fa-solid fa-link"></i> ${b.external_link}</div>` : ''}
                                                                    </td>
                                                                    <td><span class="badge ${activeClass}" style="cursor:pointer;" onclick="window.toggleBannerStatus(${b.id})">${activeText}</span></td>
                                                                    <td style="text-align:center;">
                                                                        <div class="action-dropdown" style="justify-content:center;">
                                                                            <button type="button" class="crud-dots-btn" onclick="toggleActionMenu(this, event)" title="Actions">
                                                                                <i class="fa-solid fa-ellipsis-vertical"></i>
                                                                            </button>
                                                                            <div class="action-menu">
                                                                                <button type="button" class="action-item" onclick='window.editBanner(${safeData})'>
                                                                                    <i class="fa-solid fa-pen-to-square"></i> Edit
                                                                                </button>
                                                                                <button type="button" class="action-item text-danger" onclick="window.deleteBanner(${b.id})">
                                                                                    <i class="fa-solid fa-trash"></i> Delete
                                                                                </button>
                                                                            </div>
                                                                        </div>
                                                                    </td>
                                                                </tr>
                                                            `;
                                                        });
                                                    }
                                                    list.innerHTML = html;
                                                } else {
                                                    list.innerHTML = '<tr><td colspan="5" style="text-align:center; padding:40px; color:#ef4444;">' + (res.message || 'កំហុសក្នុងការទាញយកទិន្នន័យ។') + '</td></tr>';
                                                }
                                            })
                                            .catch(err => {
                                                console.error('Load banners error:', err);
                                                list.innerHTML = '<tr><td colspan="5" style="text-align:center; padding:40px; color:#ef4444;">កំហុសបច្ចេកទេស (Network Error)។ សូមព្យាយាម Refresh ម្តងទៀត។</td></tr>';
                                            });
                                    };

                                    window.openBannerModal = function () {
                                        const form = document.getElementById('bannerForm');
                                        if (form) form.reset();
                                        document.getElementById('banner_id').value = '';
                                        document.getElementById('existing_image_url').value = '';
                                        document.getElementById('banner_preview_container').style.display = 'none';
                                        document.getElementById('bannerModalTitle').innerHTML = '<i class="fa-solid fa-plus-circle"></i> បន្ថែមស្លាយថ្មី';
                                        document.getElementById('bannerModal').style.display = 'block';
                                    };

                                    window.closeBannerModal = function () {
                                        document.getElementById('bannerModal').style.display = 'none';
                                    };

                                    window.editBanner = function (b) {
                                        document.getElementById('banner_id').value = b.id;
                                        document.getElementById('banner_title').value = b.title;
                                        document.getElementById('banner_text').value = b.text;
                                        document.getElementById('banner_link').value = b.external_link;
                                        document.getElementById('banner_order').value = b.order_index;
                                        document.getElementById('banner_active').checked = b.is_active == 1;
                                        document.getElementById('existing_image_url').value = b.image_url;

                                        if (b.image_url) {
                                            document.getElementById('banner_preview').src = b.image_url;
                                            document.getElementById('banner_preview_container').style.display = 'block';
                                        }

                                        document.getElementById('bannerModalTitle').innerHTML = '<i class="fa-solid fa-image"></i> កែសម្រួលស្លាយ';
                                        document.getElementById('bannerModal').style.display = 'block';
                                    };

                                    window.saveBanner = function (e) {
                                        e.preventDefault();
                                        const form = e.target;
                                        const fd = new FormData(form);
                                        fd.append('ajax_action', 'save_banner');

                                        fetch('admin_attendance.php', { method: 'POST', body: fd })
                                            .then(r => r.json())
                                            .then(res => {
                                                if (res.status === 'success') {
                                                    if (typeof showToast === 'function') {
                                                        showToast(res.message, 'success');
                                                    } else {
                                                        showAjaxMessage('success', res.message);
                                                    }
                                                    window.closeBannerModal();
                                                    window.loadBanners();
                                                } else {
                                                    showAjaxMessage('error', res.message);
                                                }
                                            })
                                            .catch(err => {
                                                console.error('Save banner error:', err);
                                                showAjaxMessage('error', 'មានបញ្ហាបច្ចេកទេស។');
                                            });
                                    };

                                    window.deleteBanner = function (id) {
                                        if (!confirm('តើអ្នកប្រាកដថាចង់លុបស្លាយនេះទេ?')) return;
                                        const fd = new FormData();
                                        fd.append('ajax_action', 'delete_banner');
                                        fd.append('id', id);

                                        fetch('admin_attendance.php', { method: 'POST', body: fd })
                                            .then(r => r.json())
                                            .then(res => {
                                                if (res.status === 'success') {
                                                    window.loadBanners();
                                                } else {
                                                    showAjaxMessage('error', res.message);
                                                }
                                            });
                                    };

                                    window.toggleBannerStatus = function (id) {
                                        const fd = new FormData();
                                        fd.append('ajax_action', 'toggle_banner_status');
                                        fd.append('id', id);

                                        fetch('admin_attendance.php', { method: 'POST', body: fd })
                                            .then(r => r.json())
                                            .then(res => {
                                                if (res.status === 'success') {
                                                    window.loadBanners();
                                                }
                                            });
                                    };

                                    const bannerImageInput = document.getElementById('banner_image_input');
                                    if (bannerImageInput) {
                                        bannerImageInput.addEventListener('change', function (e) {
                                            if (this.files && this.files[0]) {
                                                const reader = new FileReader();
                                                reader.onload = function (ex) {
                                                    document.getElementById('banner_preview').src = ex.target.result;
                                                    document.getElementById('banner_preview_container').style.display = 'block';
                                                }
                                                reader.readAsDataURL(this.files[0]);
                                            }
                                        });
                                    }

                                    // Initialize for management page
                                    if (document.readyState === 'complete') {
                                        window.loadBanners();
                                    } else {
                                        window.addEventListener('load', window.loadBanners);
                                    }
                                </script>
                            <?php else: ?>
                                <?php include 'admin_notifications.php'; ?>
                            <?php endif; ?>
                        <?php endif; ?>

