                                        <script>
                                            document.addEventListener('DOMContentLoaded', function () {
                                                $('#addStockForm').submit(function (e) {
                                                    e.preventDefault();
                                                    var formData = new FormData(this);
                                                    var btn = $(this).find('button[type="submit"]');
                                                    var oldHtml = btn.html();
                                                    btn.html('<i class="fa-solid fa-spinner fa-spin"></i> កំពុងរក្សាទុក...').prop('disabled', true);

                                                    $.ajax({
                                                        url: '', type: 'POST', data: formData, processData: false, contentType: false,
                                                        success: function (res) {
                                                            try {
                                                                var r = JSON.parse(res);
                                                                if (r.status === 'success') { showAjaxMessage('success', r.message); setTimeout(() => window.adminSoftReload(), 1200); }
                                                                else showAjaxMessage('error', r.message);
                                                            } catch (e) { showAjaxMessage('error', 'Error parsing response'); console.log(res); }
                                                        },
                                                        complete: function () { btn.html(oldHtml).prop('disabled', false); }
                                                    });
                                                });

                                                $('#editStockForm').submit(function (e) {
                                                    e.preventDefault();
                                                    var formData = new FormData(this);
                                                    var btn = $(this).find('button[type="submit"]');
                                                    var oldHtml = btn.html();
                                                    btn.html('<i class="fa-solid fa-spinner fa-spin"></i> កំពុងរក្សាទុក...').prop('disabled', true);

                                                    $.ajax({
                                                        url: '', type: 'POST', data: formData, processData: false, contentType: false,
                                                        success: function (res) {
                                                            try {
                                                                var r = JSON.parse(res);
                                                                if (r.status === 'success') { showAjaxMessage('success', r.message); setTimeout(() => window.adminSoftReload(), 1200); }
                                                                else showAjaxMessage('error', r.message);
                                                            } catch (e) { showAjaxMessage('error', 'Error parsing response'); console.log(res); }
                                                        },
                                                        complete: function () { btn.html(oldHtml).prop('disabled', false); }
                                                    });
                                                });
                                            });

                                            function showEditStock(id) {
                                                $.get('', { ajax_action: 'get_stock_item', id: id }, function (res) {
                                                    try {
                                                        var r = JSON.parse(res);
                                                        if (r.status === 'success') {
                                                            $('#edit_item_id').val(r.data.id);
                                                            $('#edit_item_name').val(r.data.item_name);
                                                            $('#edit_quantity').val(r.data.quantity);
                                                            $('#edit_price').val(r.data.price);
                                                            $('#edit_category').val(r.data.category);
                                                            $('#editStockModal').show();
                                                        } else {
                                                            if (typeof window.showAjaxMessage === 'function') {
                                                                window.showAjaxMessage('error', r.message || 'Error occurred');
                                                            }
                                                        }
                                                    } catch (e) {
                                                        console.log(res);
                                                        if (typeof window.showAjaxMessage === 'function') {
                                                            window.showAjaxMessage('error', "Error loading details!");
                                                        }
                                                    }
                                                });
                                            }

                                            function showDeductStock(id, name, currentQty) {
                                                var qty = prompt("កាត់បន្ថយស្តុកសម្រាប់ '" + name + "'\nបរិមាណបច្ចុប្បន្ន: " + currentQty + "\nសូមបញ្ចូលចំនួនដែលត្រូវដកចេញ:");
                                                if (qty && qty > 0) {
                                                    if (parseInt(qty) > parseInt(currentQty)) {
                                                        if (typeof window.showAjaxMessage === 'function') {
                                                            window.showAjaxMessage('warning', "បរិមាណដែលដកចេញ មិនអាចធំជាងបរិមាណក្នុងស្តុកឡើយ!");
                                                        }
                                                        return;
                                                    }
                                                    $.post('', { ajax_action: 'deduct_stock', item_id: id, deduct_quantity: qty }, function (res) {
                                                        var r = JSON.parse(res);
                                                        if (r.status === 'success') {
                                                            if (typeof window.showAjaxMessage === 'function') {
                                                                window.showAjaxMessage('success', r.message || 'បានកាត់បន្ថយជោគជ័យ');
                                                            }
                                                            setTimeout(() => { window.adminSoftReload(); }, 1200);
                                                        } else {
                                                            if (typeof window.showAjaxMessage === 'function') {
                                                                window.showAjaxMessage('error', r.message || 'Error occurred');
                                                            }
                                                        }
                                                    });
                                                }
                                            }
                                            function deleteStockItem(id) {
                                                if (confirm('តើអ្នកប្រាកដថាចង់លុបទំនិញនេះ? ប្រវត្តិដែលពាក់ព័ន្ធទាំងអស់នឹងត្រូវលុបចេញជារៀងរហូត។')) {
                                                    $.post('', { ajax_action: 'delete_stock_item', item_id: id }, function (res) {
                                                        var r = JSON.parse(res);
                                                        if (r.status === 'success') {
                                                            if (typeof window.showAjaxMessage === 'function') {
                                                                window.showAjaxMessage('success', r.message || 'បានលុបជោគជ័យ');
                                                            }
                                                            setTimeout(() => { window.adminSoftReload(); }, 1200);
                                                        } else {
                                                            if (typeof window.showAjaxMessage === 'function') {
                                                                window.showAjaxMessage('error', r.message || 'Error occurred');
                                                            }
                                                        }
                                                    });
                                                }
                                            }
                                        </script>
