                                        <script>
                                            function switchCountTab(tab, btn) {
                                                $('.tab-trigger').removeClass('active');
                                                $(btn).addClass('active');
                                                if (tab == 'new_count') {
                                                    $('#new_count_tab').fadeIn(200);
                                                    $('#count_history_tab').hide();
                                                } else {
                                                    $('#new_count_tab').hide();
                                                    $('#count_history_tab').fadeIn(200);
                                                }
                                            }
                                            function stepQty(btn, step) {
                                                let input = $(btn).siblings('input');
                                                let val = parseInt(input.val()) || 0;
                                                input.val(Math.max(0, val + step)).trigger('input');
                                            }
                                            function setMatchQty(btn) {
                                                let row = $(btn).closest('tr');
                                                let sys = parseInt(row.find('.sys-qty').text()) || 0;
                                                row.find('.qty-input').val(sys).trigger('input');
                                            }
                                            function calcDiff(input) {
                                                let row = $(input).closest('tr');
                                                let sys = parseInt(row.find('.sys-qty').text()) || 0;
                                                let physText = $(input).val();
                                                let diffCell = row.find('.diff-val');

                                                if (physText === '') {
                                                    diffCell.text('-').css('color', '#a0aec0');
                                                    row.css('background-color', 'transparent');
                                                    return;
                                                }

                                                let phys = parseInt(physText);
                                                let diff = phys - sys;

                                                diffCell.text((diff > 0 ? '+' : '') + diff);
                                                diffCell.css('color', diff < 0 ? '#ef4444' : (diff > 0 ? '#10b981' : '#059669'));

                                                if (diff !== 0) row.css('background-color', '#fff5f5');
                                                else row.css('background-color', '#f0fdf4');
                                            }
                                            function filterCountingItems() {
                                                let q = $('#itemCountSearch').val().toLowerCase().trim();
                                                $('.counting-row').each(function () {
                                                    let name = $(this).data('name');
                                                    if (name.indexOf(q) !== -1) $(this).show();
                                                    else $(this).hide();
                                                });
                                            }
                                            $('#saveCountingForm').submit(function (e) {
                                                e.preventDefault();
                                                let formDataArray = $(this).serializeArray();
                                                let postData = { ajax_action: 'save_stock_count', phase: $('#counting_phase').val(), counts: {} };
                                                let hasData = false;
                                                formDataArray.forEach(item => {
                                                    if (item.name.startsWith('physical_count') && item.value !== '') {
