                                                $users_sql = "SELECT u.employee_id, u.name, u.base_salary, pc.bank_name, pc.bank_account_number, u.bank_data_str, u.bank_qr_code_url FROM users u LEFT JOIN payroll_configs pc ON u.employee_id = pc.employee_id COLLATE utf8mb4_unicode_ci ORDER BY u.employee_id ASC";
