                                                        echo "<td><input type='text' id='bank_{$eid}' value='{$ebank}" . ($eacc ? " - " : "") . "{$eacc}' placeholder='ABA - 12345' class='form-control' style='width:180px;'></td>";
                                                        echo "<td style='text-align:center;'>";
