                                                        }
                                                        echo "<button type='button' onclick=\"openQrCropModal('{$eid}')\" style='cursor:pointer;display:inline-flex;align-items:center;gap:5px;background:#f1f5f9;padding:5px 10px;border-radius:8px;font-size:0.72rem;color:#6366f1;border:1.5px solid #c7d2fe;font-weight:600;' id='qr_label_{$eid}'><i class='fa-solid fa-qrcode'></i> " . ($eqr ? 'ប្ដូរ QR' : 'Upload QR') . "</button>";
                                                        echo "<input type='file' id='qr_{$eid}' accept='image/*' style='display:none;' onchange=\"openQrCropModal('{$eid}')\">";
                                                        echo "</td>";
                                                        echo "<td style='text-align:center;'><button class='btn btn-sm btn-primary' onclick='savePayrollConfig(\"{$eid}\")' style='padding:6px 15px; border-radius:8px;'><i class='fa-solid fa-save'></i> រក្សាទុក</button></td>";
