                                                } else {
                                                    echo '<tr><td colspan="6" style="text-align:center; padding:30px; color:#94a3b8;">មិនមានទិន្នន័យ (No Data Found)</td></tr>';
                                                }
                                                ?>
                                            </tbody>
                                        </table>
                                    </div>

                                    <script>
                                        /* ===== QR Crop Modal State ===== */
                                        let _qrCropEid = null;
                                        let _qrCroppedBlob = null;
                                        let _qrCropImg = new Image();
                                        let _qrCropDragging = false;
                                        let _qrCropStart = { x: 0, y: 0 };
                                        let _qrCropBox = { x: 30, y: 30, w: 200, h: 200 };
                                        let _qrCropCanvas, _qrCropCtx;

                                        function openQrPreview(url) {
                                            let overlay = document.getElementById('qrPreviewOverlay');
                                            if (!overlay) {
                                                overlay = document.createElement('div');
                                                overlay.id = 'qrPreviewOverlay';
                                                overlay.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.85);display:flex;align-items:center;justify-content:center;cursor:zoom-out;';
                                                overlay.innerHTML = '<img id="qrPreviewImg" style="max-width:90vw;max-height:90vh;border-radius:16px;box-shadow:0 25px 60px rgba(0,0,0,.5);">';
                                                overlay.addEventListener('click', () => overlay.style.display = 'none');
                                                document.body.appendChild(overlay);
                                            }
                                            document.getElementById('qrPreviewImg').src = url;
                                            overlay.style.display = 'flex';
                                        }

                                        function openQrCropModal(eid) {
                                            _qrCropEid = eid;
                                            _qrCroppedBlob = null;
                                            const input = document.getElementById('qr_' + eid);
                                            input.onchange = function () {
                                                if (this.files[0]) _startQrCrop(this.files[0]);
                                            };
                                            input.value = '';
                                            input.click();
                                        }

                                        function _startQrCrop(file) {
                                            const reader = new FileReader();
                                            reader.onload = function (e) {
                                                _qrCropImg = new Image();
                                                _qrCropImg.onload = function () { _showQrCropModal(e.target.result); };
                                                _qrCropImg.src = e.target.result;
                                            };
                                            reader.readAsDataURL(file);
                                        }

                                        function _showQrCropModal(src) {
                                            let modal = document.getElementById('qrCropModal');
                                            if (!modal) {
                                                modal = document.createElement('div');
                                                modal.id = 'qrCropModal';
                                                modal.style.cssText = 'position:fixed;inset:0;z-index:99998;background:rgba(15,23,42,.75);display:flex;align-items:center;justify-content:center;';
                                                modal.innerHTML = `<div style="background:#fff;border-radius:20px;padding:28px;width:480px;max-width:95vw;box-shadow:0 30px 80px rgba(0,0,0,.4);">
                                    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;">
                                        <h3 style="margin:0;font-size:1.1rem;font-weight:800;color:#1e293b;"><i class="fa-solid fa-crop-simple" style="color:#6366f1;"></i> Crop QR Code</h3>
                                        <button onclick="document.getElementById('qrCropModal').style.display='none'" style="background:none;border:none;font-size:1.5rem;cursor:pointer;color:#94a3b8;line-height:1;">&times;</button>
                                    </div>
                                    <p style="font-size:0.8rem;color:#64748b;margin-bottom:12px;">ទាញប្រអប់ ដើម្បី Crop ចំណែក QR Code ដែលត្រឹមត្រូវ</p>
                                    <div style="border-radius:12px;overflow:hidden;background:#0f172a;display:flex;justify-content:center;">
                                        <canvas id="qrCropCanvas" style="display:block;cursor:move;max-width:100%;"></canvas>
                                    </div>
                                    <div style="display:flex;gap:10px;margin-top:18px;justify-content:flex-end;">
                                        <button onclick="document.getElementById('qrCropModal').style.display='none'" style="padding:10px 22px;border-radius:10px;border:1.5px solid #e2e8f0;background:#f8fafc;color:#64748b;font-weight:600;cursor:pointer;">បោះបង់</button>
                                        <button onclick="_applyQrCrop()" style="padding:10px 28px;border-radius:10px;background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;font-weight:700;border:none;cursor:pointer;box-shadow:0 4px 15px rgba(99,102,241,.35);"><i class="fa-solid fa-check"></i> យល់ព្រម &amp; រក្សាទុក</button>
                                    </div>
                                </div>`;
                                                document.body.appendChild(modal);
                                            }
                                            modal.style.display = 'flex';
                                            _qrCropCanvas = document.getElementById('qrCropCanvas');
                                            const maxW = 420;
                                            const scale = Math.min(maxW / _qrCropImg.width, maxW / _qrCropImg.height, 1);
                                            _qrCropCanvas.width = Math.round(_qrCropImg.width * scale);
                                            _qrCropCanvas.height = Math.round(_qrCropImg.height * scale);
                                            _qrCropCtx = _qrCropCanvas.getContext('2d');
                                            _qrCropCanvas._scale = scale;
                                            const s = Math.min(_qrCropCanvas.width, _qrCropCanvas.height) * 0.72;
                                            _qrCropBox = { x: (_qrCropCanvas.width - s) / 2, y: (_qrCropCanvas.height - s) / 2, w: s, h: s };
                                            _qrDrawCrop();
                                            _qrCropCanvas.onmousedown = (e) => {
                                                const r = _qrCropCanvas.getBoundingClientRect();
                                                _qrCropStart = { x: e.clientX - r.left - _qrCropBox.x, y: e.clientY - r.top - _qrCropBox.y };
                                                _qrCropDragging = true;
                                            };
                                            _qrCropCanvas.onmousemove = (e) => {
                                                if (!_qrCropDragging) return;
                                                const r = _qrCropCanvas.getBoundingClientRect();
                                                _qrCropBox.x = Math.max(0, Math.min(e.clientX - r.left - _qrCropStart.x, _qrCropCanvas.width - _qrCropBox.w));
                                                _qrCropBox.y = Math.max(0, Math.min(e.clientY - r.top - _qrCropStart.y, _qrCropCanvas.height - _qrCropBox.h));
                                                _qrDrawCrop();
                                            };
                                            _qrCropCanvas.onmouseup = _qrCropCanvas.onmouseleave = () => { _qrCropDragging = false; };
                                            _qrCropCanvas.ontouchstart = (e) => { e.preventDefault(); const t = e.touches[0]; _qrCropCanvas.onmousedown({ clientX: t.clientX, clientY: t.clientY }); };
                                            _qrCropCanvas.ontouchmove = (e) => { e.preventDefault(); const t = e.touches[0]; _qrCropCanvas.onmousemove({ clientX: t.clientX, clientY: t.clientY }); };
                                            _qrCropCanvas.ontouchend = () => { _qrCropDragging = false; };
                                        }

                                        function _qrDrawCrop() {
                                            _qrCropCtx.clearRect(0, 0, _qrCropCanvas.width, _qrCropCanvas.height);
                                            _qrCropCtx.drawImage(_qrCropImg, 0, 0, _qrCropCanvas.width, _qrCropCanvas.height);
                                            _qrCropCtx.fillStyle = 'rgba(0,0,0,.5)';
                                            _qrCropCtx.fillRect(0, 0, _qrCropCanvas.width, _qrCropCanvas.height);
                                            const sc = _qrCropCanvas._scale;
                                            _qrCropCtx.drawImage(_qrCropImg, _qrCropBox.x / sc, _qrCropBox.y / sc, _qrCropBox.w / sc, _qrCropBox.h / sc, _qrCropBox.x, _qrCropBox.y, _qrCropBox.w, _qrCropBox.h);
                                            _qrCropCtx.strokeStyle = '#6366f1';
                                            _qrCropCtx.lineWidth = 2.5;
                                            _qrCropCtx.strokeRect(_qrCropBox.x, _qrCropBox.y, _qrCropBox.w, _qrCropBox.h);
                                            [[0, 0], [1, 0], [0, 1], [1, 1]].forEach(([rx, ry]) => {
                                                _qrCropCtx.fillStyle = '#6366f1';
                                                _qrCropCtx.fillRect(_qrCropBox.x + rx * _qrCropBox.w - 5, _qrCropBox.y + ry * _qrCropBox.h - 5, 10, 10);
                                            });
                                        }

                                        function _applyQrCrop() {
                                            const sc = _qrCropCanvas._scale;
                                            const off = document.createElement('canvas');
                                            off.width = Math.round(_qrCropBox.w / sc);
                                            off.height = Math.round(_qrCropBox.h / sc);
                                            off.getContext('2d').drawImage(_qrCropImg, _qrCropBox.x / sc, _qrCropBox.y / sc, off.width, off.height, 0, 0, off.width, off.height);
                                            off.toBlob(function (blob) {
                                                _qrCroppedBlob = blob;
                                                const url = URL.createObjectURL(blob);
                                                const row = document.getElementById('row_' + _qrCropEid);
                                                if (row) {
                                                    let pd = row.querySelector('.qr-live-preview');
                                                    if (!pd) {
                                                        pd = document.createElement('div');
                                                        pd.className = 'qr-live-preview';
                                                        pd.style.cssText = 'margin-bottom:5px;';
                                                        const lbl = document.getElementById('qr_label_' + _qrCropEid);
                                                        lbl.parentNode.insertBefore(pd, lbl);
                                                    }
                                                    pd.innerHTML = '<img src="' + url + '" onclick="openQrPreview(\'' + url + '\')" style="width:44px;height:44px;object-fit:cover;border-radius:8px;border:2px solid #22c55e;cursor:pointer;">';
                                                }
                                                const lbl = document.getElementById('qr_label_' + _qrCropEid);
                                                if (lbl) lbl.innerHTML = '<i class="fa-solid fa-check-circle" style="color:#22c55e;"></i> Cropped!';
                                                document.getElementById('qrCropModal').style.display = 'none';
                                            }, 'image/jpeg', 0.92);
                                        }

                                        function savePayrollConfig(eid) {
                                            const base_sal = document.getElementById('base_' + eid).value;
                                            let bank_val = document.getElementById('bank_' + eid).value.split('-');
                                            let bank_name = bank_val[0] ? bank_val[0].trim() : '';
                                            let bank_acc = bank_val[1] ? bank_val[1].trim() : '';
                                            const fd = new FormData();
                                            fd.append('ajax_action', 'payroll_save_config');
                                            fd.append('employee_id', eid);
                                            fd.append('base_salary', base_sal);
                                            fd.append('bank_name', bank_name);
                                            fd.append('bank_account_number', bank_acc);
                                            fd.append('payment_type', 'Monthly');
                                            if (_qrCropEid === eid && _qrCroppedBlob) {
                                                fd.append('bank_qr', _qrCroppedBlob, 'qr_' + eid + '.jpg');
                                            } else {
                                                const qi = document.getElementById('qr_' + eid);
                                                if (qi && qi.files.length > 0) fd.append('bank_qr', qi.files[0]);
                                            }
                                            const btn = document.querySelector('#row_' + eid + ' .btn-primary');
                                            const oldHtml = btn ? btn.innerHTML : '';
                                            if (btn) btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i>';
                                            fetch('admin_attendance.php', { method: 'POST', body: fd })
                                                .then(r => r.json())
                                                .then(res => {
                                                    if (btn) btn.innerHTML = oldHtml;
                                                    if (res.status === 'success') {
                                                        if (typeof window.showAjaxMessage === 'function') window.showAjaxMessage('success', res.message);
                                                        _qrCroppedBlob = null;
                                                        setTimeout(() => window.adminSoftReload(), 1400);
                                                    } else {
                                                        if (typeof window.showAjaxMessage === 'function') window.showAjaxMessage('error', res.message || 'Error');
                                                    }
                                                });
                                        }
                                    </script>
                                <?php endif; ?>

                                <?php if ($payroll_action === 'payroll_history'): ?>
                                    <div class="table-responsive">
                                        <table class="table" style="width:100%;">
                                            <thead>
                                                <tr>
                                                    <th>បុគ្គលិក (Employee)</th>
                                                    <th>ខែ-ឆ្នាំ (Month-Year)</th>
                                                    <th>ប្រាក់ខែសរុប
                                                        (Net Salary)</th>
                                                    <th>ថ្ងៃបើកប្រាក់
                                                        (Payment Date)</th>
                                                    <th>ស្ថានភាព (Status)</th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                <?php
