                                                        echo '<tr>';
                                                        echo '<td style="font-weight:600;">' . htmlspecialchars($hr['emp_name']) . ' <br><small style="color:#94a3b8;">' . $hr['employee_id'] . '</small></td>';
                                                        echo '<td>' . htmlspecialchars($hr['payroll_month'] . '/' . $hr['payroll_year']) . '</td>';
                                                        echo '<td style="color:#22c55e; font-weight:700;">$' . number_format($hr['calculated_salary'], 2) . '</td>';
                                                        echo '<td>' . date('d/m/Y H:i A', strtotime($hr['payment_date'])) . '</td>';
                                                        echo '<td><span style="background:#22c55e; color:#fff; padding:4px 10px; border-radius:12px; font-size:0.75rem; font-weight:700;">' . $hr['status'] . '</span></td>';
                                                        echo '</tr>';
                                                    }
                                                } else {
                                                    echo '<tr><td colspan="5" style="text-align:center; padding:30px; color:#94a3b8;">មិនទាន់មានប្រវត្តិទូទាត់ប្រាក់នៅឡើយទេ។</td></tr>';
                                                }
                                                ?>
                                            </tbody>
                                        </table>
                                    </div>
                                <?php endif; ?>
                            </div>

                            <?php if (in_array($payroll_action, ['adjustments', 'payroll_settings'], true)): ?>
                                <div class="hrm-tabs" style="margin-bottom:20px;">
                                    <button type="button" class="hrm-tab-btn active"
                                        onclick="showAdjustTab(event, 'adjust-tab-deduction')"><i
                                            class="fa-solid fa-minus-circle"></i>
                                        កាត់ប្រាក់ (Deductions)</button>
