                                            class="fa-solid fa-plus-circle"></i>
                                        ប្រាក់ថែមម៉ោង
                                        (OT Bonus)</button>
                                    <button type="button" class="hrm-tab-btn"
                                        onclick="showAdjustTab(event, 'adjust-tab-loan')"><i
