                                        (Loan)</button>
                                    <button type="button" class="hrm-tab-btn"
                                        onclick="showAdjustTab(event, 'adjust-tab-policy')"><i class="fa-solid fa-cogs"></i>
                                        ប្រព័ន្ធគោលការណ៍
                                        (Policies)</button>
