                                <?php
                                $emps = [];
                                $e_res = $mysqli->query("SELECT employee_id, name FROM users ORDER BY name ASC");
                                if ($e_res) {
                                    while ($er = $e_res->fetch_assoc())
                                        $emps[] = $er;
