                                <script>
                                    function showAdjustTab(e, tabId) {
                                        if (e) {
                                            document.querySelectorAll('.hrm-tabs .hrm-tab-btn').forEach(b => b.classList.remove('active'));
                                            e.currentTarget.classList.add('active');
                                        }
                                        document.querySelectorAll('#adjust-tab-deduction, #adjust-tab-ot, #adjust-tab-loan, #adjust-tab-policy').forEach(el => {
                                            el.style.display = (el.id === tabId) ? 'block' : 'none';
                                        });
                                    }
                                    // Refresh script to handle post-save table updates by reloading page
                                </script>

                                <script>
                                    function saveAdjustment(e, actionType) {
                                        e.preventDefault();
                                        const form = e.target;
                                        const fd = new FormData(form);
                                        fd.append('ajax_action', actionType);

                                        const btn = form.querySelector('button');
                                        const oldHtml = btn.innerHTML;
                                        btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> រក្សាទុក...';

                                        fetch(window.location.href, { method: 'POST', body: fd })
                                            .then(r => r.json())
                                            .then(res => {
                                                btn.innerHTML = oldHtml;
                                                if (res.status === 'success') {
                                                    if (typeof window.showAjaxMessage === 'function') window.showAjaxMessage('success', res.message);
                                                    form.reset();
                                                    setTimeout(() => window.adminSoftReload(), 1200);
                                                } else {
                                                    if (typeof window.showAjaxMessage === 'function') window.showAjaxMessage('error', res.message);
                                                    else alert(res.message);
                                                }
                                            });
                                    }
                                </script>
                            <?php endif; ?>
                        </div>

                        <script>
                            function paySalary(empId, base, present, calculated) {
                                if (!confirm('តើអ្នកពិតជាចង់បើកប្រាក់ខែអោយបុគ្គលិកនេះមែនទេ?')) return;
                                const month = document.getElementById('payroll-month').value;
                                const year = document.getElementById('payroll-year').value;

                                const fd = new FormData();
                                fd.append('ajax_action', 'process_payroll');
                                fd.append('employee_id', empId);
                                fd.append('month', month);
                                fd.append('year', year);
                                fd.append('base_salary', base);
                                fd.append('present_days', present);
                                fd.append('calculated_salary', calculated);

                                fetch(window.location.href, { method: 'POST', body: fd })
                                    .then(r => r.json())
                                    .then(res => {
                                        if (res.status === 'success') {
                                            if (typeof window.showAjaxMessage === 'function') window.showAjaxMessage('success', res.message);
                                            runPayrollCalculation(); // Refresh
                                        } else {
                                            if (typeof window.showAjaxMessage === 'function') window.showAjaxMessage('error', res.message);
                                            else alert(res.message);
                                        }
                                    });
                            }
                        </script>
                    <?php endif; ?>


