                                <script>
                                    $(document).ready(function () {
                                        const targetUserId = '<?php echo $target_user['employee_id']; ?>';
                                        // Initial Load
                                        $.ajax({
                                            url: 'admin_attendance.php',
                                            type: 'POST',
                                            data: { ajax_action: 'get_time_rules', user_id: targetUserId },
                                            dataType: 'json',
                                            success: function (res) {
                                                if (res.status === 'success' && res.rules) {
                                                    res.rules.forEach(r => {
                                                        const container = (r.type === 'checkin') ? $('#checkinRulesContainer') : $('#checkoutRulesContainer');
                                                        const div = $('<div class="time-rule-row">');
                                                        div.html(`
                                                        <label style="margin:0; font-size:0.8rem;"><i class="fa-solid fa-play"></i></label>
                                                        <input type="time" class="rule-start" value="${r.start_time}" step="1">
                                                        <label style="margin:0; font-size:0.8rem;"><i class="fa-solid fa-stop"></i></label>
                                                        <input type="time" class="rule-end" value="${r.end_time}" step="1">
                                                        <select class="rule-status">
                                                            <option value="Good" ${r.status === 'Good' ? 'selected' : ''}>✅ Good</option>
                                                            <option value="Late" ${r.status === 'Late' ? 'selected' : ''}>⚠️ Late</option>
                                                            <option value="Absent" ${r.status === 'Absent' ? 'selected' : ''}>❌ Absent</option>
                                                        </select>
                                                        <button type="button" class="btn btn-danger remove-rule" style="width:36px; height:36px; padding:0; border-radius:8px;" onclick="this.parentNode.remove()"><i class="fa-solid fa-trash-can"></i></button>
                                                    `);
                                                        container.append(div);
                                                    });
                                                }
                                            }
                                        });

                                        $('#saveRulesForm').on('submit', function (e) {
                                            e.preventDefault();
                                            let rules = [];
                                            $('.time-rule-row').each(function () {
                                                rules.push({
                                                    type: (this.closest('#checkinRulesContainer') ? 'checkin' : 'checkout'),
                                                    start_time: $(this).find('.rule-start').val(),
                                                    end_time: $(this).find('.rule-end').val(),
                                                    status: $(this).find('.rule-status').val()
                                                });
                                            });
                                            $.ajax({
                                                url: 'admin_attendance.php',
                                                type: 'POST',
                                                data: { ajax_action: 'save_time_rules', rule_employee_id: targetUserId, rules_json: JSON.stringify(rules) },
                                                dataType: 'json',
                                                success: function (res) {
                                                    if (typeof window.showAjaxMessage === 'function') {
                                                        window.showAjaxMessage(res.status, res.message || 'បានរក្សាទុកច្បាប់ម៉ោងដោយជោគជ័យ');
                                                    }
                                                }
                                            });
                                        });
                                    });
                                </script>
