                                <script>
                                    (function () {
                                        var form = document.getElementById('saveAdminAccessForm');
                                        if (!form) return;

                                        function syncPageToggle(pageKey) {
                                            var pageInputs = form.querySelectorAll('.js-action-toggle[data-page-key="' + pageKey + '"]');
                                            var pageToggle = form.querySelector('.js-page-toggle[data-page-key="' + pageKey + '"]');
                                            if (!pageToggle || !pageInputs.length) return;
                                            var checkedCount = 0;
                                            pageInputs.forEach(function (input) {
                                                if (input.checked) checkedCount++;
                                            });
                                            pageToggle.checked = checkedCount === pageInputs.length;
                                            pageToggle.indeterminate = checkedCount > 0 && checkedCount < pageInputs.length;
                                        }

                                        form.querySelectorAll('.js-page-toggle').forEach(function (toggle) {
                                            toggle.addEventListener('change', function () {
                                                var pageKey = this.getAttribute('data-page-key') || '';
                                                form.querySelectorAll('.js-action-toggle[data-page-key="' + pageKey + '"]').forEach(function (input) {
                                                    input.checked = toggle.checked;
                                                });
                                                syncPageToggle(pageKey);
                                            });
                                            syncPageToggle(toggle.getAttribute('data-page-key') || '');
                                        });

                                        form.querySelectorAll('.js-action-toggle').forEach(function (input) {
                                            input.addEventListener('change', function () {
                                                syncPageToggle(this.getAttribute('data-page-key') || '');
                                            });
                                        });

                                        document.querySelectorAll('[data-access-bulk]').forEach(function (button) {
                                            button.addEventListener('click', function () {
                                                var shouldCheck = this.getAttribute('data-access-bulk') === 'all';
                                                form.querySelectorAll('.js-bulk-access-toggle').forEach(function (input) {
                                                    input.checked = shouldCheck;
                                                });
                                                form.querySelectorAll('.js-page-toggle').forEach(function (toggle) {
                                                    syncPageToggle(toggle.getAttribute('data-page-key') || '');
                                                });
                                            });
                                        });
                                    })();
                                </script>
