                        <script>
                            document.addEventListener('DOMContentLoaded', function () {
                                const searchInput = document.getElementById('assignSearchInput');
                                const scrollArea = id => document.getElementById(id);
                                const userCards = document.querySelectorAll('.assign-user-card');
                                const selectAll = document.getElementById('assignSelectAll');
                                const selectionStatus = document.getElementById('selectionStatus');
                                const selectedCountText = document.getElementById('selectedCount');

                                // Search Filtering
                                searchInput?.addEventListener('input', function (e) {
                                    const term = e.target.value.toLowerCase();
                                    userCards.forEach(card => {
                                        const name = card.querySelector('.assign-name').textContent.toLowerCase();
                                        const id = card.querySelector('.assign-id').textContent.toLowerCase();
                                        if (name.includes(term) || id.includes(term)) {
                                            card.style.display = 'flex';
                                        } else {
                                            card.style.display = 'none';
                                        }
                                    });
                                });

                                // Select All logic
                                selectAll?.addEventListener('change', function () {
                                    const isChecked = this.checked;
                                    userCards.forEach(card => {
                                        if (card.style.display !== 'none') {
                                            const cb = card.querySelector('input[type="checkbox"]');
                                            cb.checked = isChecked;
                                            if (isChecked) card.classList.add('selected');
                                            else card.classList.remove('selected');
                                        }
                                    });
                                    updateSelectionCount();
                                });

                                // Checkbox visual toggle
                                userCards.forEach(card => {
                                    const cb = card.querySelector('input[type="checkbox"]');
                                    cb.addEventListener('change', (e) => {
                                        if (cb.checked) card.classList.add('selected');
                                        else card.classList.remove('selected');
                                        updateSelectionCount();
                                    });
                                });

                                function updateSelectionCount() {
                                    const checked = document.querySelectorAll('.assign-user-card input[type="checkbox"]:checked').length;
                                    if (checked > 0) {
                                        selectionStatus.style.display = 'block';
                                        selectedCountText.textContent = checked;
                                    } else {
                                        selectionStatus.style.display = 'none';
                                    }
                                }
                            });
                        </script>
