                        <script>
                            function toggleManualScanInput(selectEl, type) {
                                var inputId = 'manual_scan_users_' + type;
                                var inputEl = document.getElementById(inputId);
                                if (selectEl.value === 'specific') {
                                    inputEl.style.display = 'block';
                                } else {
                                    inputEl.style.display = 'none';
                                }
                            }

                            (function () {
                                function initTabs() {
                                    var form = document.getElementById('appScanSettingsForm');
                                    if (!form) return;
                                    var tabs = form.querySelectorAll('.appscan-tab-btn');
                                    var panels = form.querySelectorAll('.appscan-tab-panel');

                                    function showTab(tabId) {
                                        tabs.forEach(function (btn) {
                                            var isActive = btn.getAttribute('data-tab') === tabId;
                                            btn.classList.toggle('active', isActive);
                                            btn.setAttribute('aria-selected', isActive ? 'true' : 'false');
                                        });
                                        panels.forEach(function (panel) {
                                            var isActive = panel.id === tabId;
                                            panel.classList.toggle('active', isActive);
                                            panel.style.display = isActive ? 'block' : 'none';
                                        });
                                    }

                                    tabs.forEach(function (btn) {
                                        btn?.addEventListener('click', function (e) {
                                            e.preventDefault();
                                            var target = btn.getAttribute('data-tab');
                                            showTab(target);
                                        });
                                    });

                                    // Ensure first tab is visible if any active exists
                                    var activeBtn = form.querySelector('.appscan-tab-btn.active');
                                    if (activeBtn) {
                                        showTab(activeBtn.getAttribute('data-tab'));
                                    }
                                }

                                if (document.readyState === 'loading') {
                                    document.addEventListener('DOMContentLoaded', initTabs);
                                } else {
                                    initTabs();
                                }
                            })();
                        </script>
