                            <script>
                                function postPayrollBiometricAction(action, recordId) {
                                    var fd = new FormData();
                                    fd.append('ajax_action', action);
                                    if (recordId) fd.append('record_id', recordId);
                                    fetch('admin_attendance.php', {
                                        method: 'POST',
                                        body: fd,
                                        headers: { 'X-Requested-With': 'XMLHttpRequest', 'Accept': 'application/json' }
                                    })
                                        .then(function (res) { return res.json(); })
                                        .then(function (json) {
                                            if (json.status === 'success') {
                                                window.location.reload();
                                            } else {
                                                alert(json.message || 'Action failed.');
                                            }
                                        })
                                        .catch(function () {
                                            alert('Action failed.');
                                        });
                                }

                                function deletePayrollBiometricRecord(recordId) {
                                    if (!confirm('តើអ្នកចង់លុប verification record នេះមែនទេ?')) return;
                                    postPayrollBiometricAction('delete_payroll_biometric_record', recordId);
                                }

                                function clearPayrollBiometricRecords() {
                                    if (!confirm('តើអ្នកចង់លុប verification records ទាំងអស់មែនទេ?')) return;
                                    postPayrollBiometricAction('clear_payroll_biometric_records');
                                }
                            </script>
