                        <script>
                            (function () {
                                function initSortable(id, inputId) {
                                    var el = document.getElementById(id);
                                    if (!el) return;
                                    Sortable.create(el, {
                                        animation: 150,
                                        ghostClass: 'sortable-ghost',
                                        onEnd: function () {
                                            var keys = [];
                                            el.querySelectorAll('.sortable-item').forEach(function (item) {
                                                keys.push(item.getAttribute('data-key'));
                                            });
                                            document.getElementById(inputId).value = keys.join(',');
                                        }
                                    });
                                }
                                if (window.Sortable) {
                                    initSortable('sortable-hrm', 'input-order-hrm');
                                    initSortable('sortable-admin', 'input-order-admin');
                                    initSortable('sortable-skill', 'input-order-skill');
                                    initSortable('sortable-worker', 'input-order-worker');
                                } else {
                                    setTimeout(function () {
                                        initSortable('sortable-hrm', 'input-order-hrm');
                                        initSortable('sortable-admin', 'input-order-admin');
                                        initSortable('sortable-skill', 'input-order-skill');
                                        initSortable('sortable-worker', 'input-order-worker');
                                    }, 1000);
                                }
                            })();
                        </script>

