    <script>

        // Reports fullscreen toggle
        (function () {
            const $btn = $('#toggleReportsFullscreen');
            if ($btn.length === 0) return;
            const $wrap = $('#reportsTableWrapper');
            function setIcon(isFull) {
                const i = $btn.find('i');
                i.toggleClass('fa-expand', !isFull);
                i.toggleClass('fa-compress', isFull);
                $btn.attr('title', isFull ? 'បិទ Fullscreen' : 'បង្ហាញពេញអេក្រង់');
            }
            function isNativeFs() { return !!(document.fullscreenElement || document.webkitFullscreenElement || document.msFullscreenElement); }
            function requestFs(el) {
                if (el.requestFullscreen) return el.requestFullscreen();
                if (el.webkitRequestFullscreen) return el.webkitRequestFullscreen();
                if (el.msRequestFullscreen) return el.msRequestFullscreen();
            }
            function exitFs() {
                if (document.exitFullscreen) return document.exitFullscreen();
                if (document.webkitExitFullscreen) return document.webkitExitFullscreen();
                if (document.msExitFullscreen) return document.msExitFullscreen();
            }
            // Inject all data rows when entering fullscreen; revert on exit
            function applyAllData() {
                if ($wrap.data('allDataApplied')) return; // already applied
                const dhCount = parseInt($wrap.data('dh-count'), 10) || 0;
                const $exportRows = $('#reportsTableExport tbody tr');
                if ($exportRows.length === 0) return;
                const $tbody = $('#reportsTable tbody');
                $wrap.data('originalPaginatedHtml', $tbody.html());
                let newHtml = '';
                // Build rows using current visible headers order so cloned table columns match exactly
                const headers = getHeaders();
                $exportRows.each(function () {
                    const $r = $(this);
                    const logPk = $r.data('log-pk') || 0;
                    const dt = $r.data('dt') || '';
                    if (!logPk && logPk !== 0) return;
                    newHtml += '<tr data-log-pk="' + logPk + '" data-dt="' + dt + '">';

                    headers.forEach(function (h) {
                        // Handle special 'select' column
                        if (h.key === 'select') {
                            newHtml += '<td class="col-select" style="text-align:center;"><input type="checkbox" class="report-select" data-id="' + logPk + '"></td>';
                            return;
                        }

                        // Find matching cell in export row by class
                        const $cell = $r.find('.col-' + h.key).first();
                        const cls = 'col-' + h.key + ($cell.attr('class') ? ' ' + $cell.attr('class') : '');
                        const inner = ($cell.length) ? $cell.html() : '';

                        // For noted column, ensure contenteditable and data-log-id
                        if (h.key === 'noted') {
                            newHtml += '<td class="' + cls + ' noted-cell" contenteditable="true" data-log-id="' + logPk + '">' + inner + '</td>';
                        } else {
                            newHtml += '<td class="' + cls + '">' + inner + '</td>';
                        }
                    });

                    newHtml += '</tr>';
                });
                $tbody.html(newHtml);
                $wrap.data('allDataApplied', true);
            }
            function revertPaginated() {
                if (!$wrap.data('allDataApplied')) return;
                const original = $wrap.data('originalPaginatedHtml');
                if (original != null) { $('#reportsTable tbody').html(original); }
                $wrap.removeData('allDataApplied').removeData('originalPaginatedHtml');
            }
            $btn.on('click', function () {
                const wrapperEl = $wrap.get(0);
                if (!wrapperEl) return;
                if (!isNativeFs() && !$wrap.hasClass('fullscreen-fallback')) {
                    // Try native first
                    const p = requestFs(wrapperEl);
                    if (p && typeof p.then === 'function') {
                        p.catch(function () { $wrap.addClass('fullscreen-fallback'); setIcon(true); $('body').addClass('no-scroll'); applyAllData(); });
                    } else {
                        // No promise support -> fallback
                        $wrap.addClass('fullscreen-fallback'); setIcon(true); $('body').addClass('no-scroll'); applyAllData();
                    }
                } else {
                    // Exit
                    if (isNativeFs()) { exitFs(); }
                    $wrap.removeClass('fullscreen-fallback'); setIcon(false); $('body').removeClass('no-scroll'); revertPaginated();
                }
            });
            // Update icon when native fullscreen changes (user presses ESC)
            ['fullscreenchange', 'webkitfullscreenchange', 'MSFullscreenChange'].forEach(evt => {
                document.addEventListener(evt, function () {
                    const active = isNativeFs();
                    if (active) {
                        // entering native fullscreen
                        setIcon(true); $('body').addClass('no-scroll'); applyAllData();
                    } else {
                        // exiting
                        $wrap.removeClass('fullscreen-fallback'); $('body').removeClass('no-scroll'); setIcon(false); revertPaginated();
                    }
                });
            });
        })();

        // Auto-update polling for reports has been disabled to avoid automatic reloads.
        // If you need to re-enable polling later, restore the fetchReportsData IIFE above.

    </script>

    <script>
        // Sidebar Requests badge: live pending count updater
        (function () {
            function getAjaxUrl() { return window.location.pathname; }
            function ensureBadge() {
                const link = document.querySelector('.sidebar a[href*="?page=requests"]');
                if (!link) return { link: null, badge: null };
                let badge = link.querySelector('.notification-badge');
                if (!badge) {
                    badge = document.createElement('span');
                    badge.className = 'notification-badge';
                    badge.style.display = 'none';
                    link.appendChild(badge);
                }
                return { link, badge };
            }
            async function refresh() {
                const { link, badge } = ensureBadge();
                if (!link || !badge) return;
                try {
                    const fd = new FormData();
                    fd.append('ajax_action', 'get_request_counts');
                    const res = await fetch(getAjaxUrl(), { method: 'POST', body: fd, credentials: 'same-origin' });
                    if (!res.ok) return;
                    const json = await res.json();
                    if (json && json.status === 'success' && json.data) {
                        const pending = Number(json.data.Pending || 0);
                        if (pending > 0) {
                            const prev = badge.textContent;
                            const next = pending > 99 ? '99+' : String(pending);
                            if (badge.style.display === 'none' || prev !== next) {
                                badge.textContent = next;
                                badge.style.display = 'inline-flex';
                                badge.classList.remove('badge-pulse');
                                void badge.offsetWidth; // reflow to restart animation
                                badge.classList.add('badge-pulse');
                            } else {
                                badge.textContent = next;
                                badge.style.display = 'inline-flex';
                            }
                        } else {
                            badge.style.display = 'none';
                        }
                    }
                } catch (e) { /* ignore */ }
            }
            document.addEventListener('DOMContentLoaded', function () {
                refresh();
                setInterval(refresh, 60000);
                document.addEventListener('visibilitychange', function () { if (!document.hidden) refresh(); });
            });
        })();
    </script>

    <!-- Global Admin Loader (overlay) -->
    <style>
        #adminGlobalLoader {
            position: fixed;
            inset: 0;
            display: flex;
            align-items: center;
            justify-content: center;
            visibility: hidden;
            opacity: 0;
            pointer-events: none;
            background: radial-gradient(ellipse at center, rgba(255, 255, 255, 0.92) 0%, rgba(255, 255, 255, 0.78) 55%, rgba(245, 247, 250, 0.55) 100%);
            backdrop-filter: blur(12px);
            -webkit-backdrop-filter: blur(12px);
            z-index: 8000;
            transition: opacity .18s ease
        }

        #adminGlobalLoader.is-visible {
            visibility: visible;
            opacity: 1;
            pointer-events: auto;
        }

        #adminGlobalLoader.fadeout {
            opacity: 0
        }

        #adminGlobalLoader .agl-box {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 14px;
            padding: 26px 34px;
            border-radius: 24px;
            background: linear-gradient(145deg, #ffffff 0%, #f4f8ff 55%, #eef3fb 100%);
            box-shadow: 0 18px 48px -8px rgba(20, 60, 120, 0.18), 0 2px 6px rgba(20, 60, 120, 0.08), inset 0 1px 0 rgba(255, 255, 255, 0.7)
        }

        #adminGlobalLoader .agl-progress {
            width: 210px;
            height: 8px;
            border-radius: 6px;
            background: rgba(10, 132, 255, 0.14);
            position: relative;
            overflow: hidden;
            box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.15), 0 1px 0 rgba(255, 255, 255, 0.6)
        }

        #adminGlobalLoader .agl-progress-bar {
            position: absolute;
            inset: 0;
            left: 0;
            top: 0;
            height: 100%;
            width: 0%;
            background: linear-gradient(90deg, #0a84ff, #52a8ff, #0a84ff);
            background-size: 220% 100%;
            animation: aglBarMove 1.6s linear infinite;
            filter: drop-shadow(0 0 4px rgba(10, 132, 255, 0.5))
        }

        @keyframes aglBarMove {
            0% {
                background-position: 0 0
            }

            100% {
                background-position: 200% 0
            }
        }

        #adminGlobalLoader .agl-spinner {
            position: relative;
            width: 86px;
            height: 86px
        }

        #adminGlobalLoader .agl-spinner .ring {
            position: absolute;
            inset: 0;
            border: 7px solid transparent;
            border-top-color: #0a84ff;
            border-radius: 50%;
            animation: aglSpin 1.05s linear infinite
        }

        #adminGlobalLoader .agl-spinner .ring.r2 {
            border-top-color: #52a8ff;
            animation-duration: 1.55s;
            filter: drop-shadow(0 0 6px rgba(10, 132, 255, 0.45))
        }

        #adminGlobalLoader .agl-spinner .ring.r3 {
            border-top-color: #b3d9ff;
            animation-duration: 2.1s;
            filter: blur(0.5px);
            opacity: .65
        }

        #adminGlobalLoader .agl-spinner .dot {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            width: 20px;
            height: 20px;
            border-radius: 50%;
            background: linear-gradient(135deg, #0a84ff, #0060d1);
            box-shadow: 0 6px 18px rgba(10, 132, 255, 0.45), 0 0 0 6px rgba(10, 132, 255, 0.15);
            animation: aglPulse 1.9s ease-in-out infinite
        }

        #adminGlobalLoader .agl-text {
            font-family: 'Kantumruy Pro', system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
            color: #143451;
            font-weight: 700;
            letter-spacing: .3px;
            font-size: 1.05rem;
            text-align: center;
            text-shadow: 0 1px 0 rgba(255, 255, 255, 0.6)
        }

        @keyframes aglSpin {
            to {
                transform: rotate(360deg)
            }
        }

        @keyframes aglPulse {

            0%,
            100% {
                transform: translate(-50%, -50%) scale(1);
                opacity: 1
            }

            50% {
                transform: translate(-50%, -50%) scale(.7);
                opacity: .78
            }
        }

        @media (max-width:640px) {
            #adminGlobalLoader .agl-box {
                width: 78%;
                padding: 24px 20px
            }

            .agl-text {
                font-size: .95rem
            }
        }
    </style>
    <div id="adminGlobalLoader" aria-hidden="true" role="status" aria-live="polite">
        <div class="agl-box">
            <div class="agl-spinner" aria-hidden="true">
                <span class="ring r1"></span>
                <span class="ring r2"></span>
                <span class="ring r3"></span>
                <span class="dot"></span>
            </div>
            <div class="agl-text" id="adminGlobalLoaderText">
                កំពុងដំណើរការ...</div>
            <div class="agl-progress" aria-hidden="true">
                <div class="agl-progress-bar" id="adminGlobalProgressBar"></div>
            </div>
        </div>
    </div>

    <script>
        var _aglProgTimer = null, _aglTarget = 0, _aglCurr = 0, _aglDone = false;
        function _aglTick() {
            if (_aglDone) return;
            _aglCurr += (_aglTarget - _aglCurr) * 0.18 + 0.55; // faster ease + base increment
            if (_aglCurr > _aglTarget) _aglCurr = _aglTarget;
            var bar = document.getElementById('adminGlobalProgressBar');
            if (bar) { bar.style.width = _aglCurr + '%'; }
            if (_aglCurr >= 98) { _aglDone = true; }
            if (!_aglDone) _aglProgTimer = requestAnimationFrame(_aglTick);
        }
        // Enhanced state & safety timers
        var _aglVisible = false, _aglLastShow = 0, _aglForceHideTimer = null, _aglAjaxDelayTimer = null, _aglBatchTimer = null, _aglActiveAjax = 0;
        var _aglMinDisplay = 140, _aglMaxDisplay = 8000; // ms (shorter minimum & lower max to avoid long spins)
        // Thresholds for grouping multiple ajax calls
        var _aglShowDelay = 280, _aglBatchWindow = 200; // increased delay to avoid flash on fast AJAX
        function showAdminLoader(message) {
            var el = document.getElementById('adminGlobalLoader'); if (!el) return;
            var textEl = document.getElementById('adminGlobalLoaderText');
            // If already visible just update message (avoid flicker / re-init)
            if (_aglVisible) { if (message && textEl) { textEl.textContent = message; } return; }
            if (message && textEl) { textEl.textContent = message; }
            _aglVisible = true; _aglLastShow = performance.now();
            _aglCurr = 0; _aglTarget = 82; _aglDone = false; cancelAnimationFrame(_aglProgTimer);
            clearTimeout(_aglForceHideTimer);
            var bar = document.getElementById('adminGlobalProgressBar'); if (bar) { bar.style.width = '0%'; }
            el.style.display = 'flex';
            el.classList.remove('fadeout');
            el.classList.add('is-visible');
            el.setAttribute('aria-hidden', 'false');
            _aglProgTimer = requestAnimationFrame(_aglTick);
            // staged target bumps (earlier and higher for perceived speed)
            setTimeout(function () { if (!_aglDone) { _aglTarget = 94; } }, 400);
            setTimeout(function () { if (!_aglDone) { _aglTarget = 97; } }, 800);
            // Force hide fallback (never leave overlay stuck)
            _aglForceHideTimer = setTimeout(function () { if (_aglVisible) { forceHideAdminLoader(); } }, _aglMaxDisplay);
        }
        function forceHideAdminLoader() {
            var el = document.getElementById('adminGlobalLoader'); if (!el) return;
            _aglTarget = 100; _aglDone = true; cancelAnimationFrame(_aglProgTimer);
            el.classList.remove('fadeout', 'is-visible');
            el.style.display = '';
            el.setAttribute('aria-hidden', 'true');
            _aglVisible = false; clearTimeout(_aglForceHideTimer); _aglForceHideTimer = null;
        }
        function hideAdminLoader() {
            if (!_aglVisible) return; // nothing to hide
            var el = document.getElementById('adminGlobalLoader'); if (!el) return;
            var elapsed = performance.now() - _aglLastShow;
            var delay = Math.max(0, _aglMinDisplay - elapsed); // ensure minimum visible time
            // Drive progress to completion during wait
            _aglTarget = 100; _aglDone = false;
            setTimeout(function () {
                el.classList.add('fadeout');
                setTimeout(function () {
                    el.classList.remove('fadeout', 'is-visible');
                    el.style.display = '';
                    el.setAttribute('aria-hidden', 'true');
                    _aglDone = true;
                    _aglVisible = false; clearTimeout(_aglForceHideTimer); _aglForceHideTimer = null;
                }, 180);
            }, delay);
        }
        // Smarter auto show/hide for jQuery Ajax (batch multiple calls, skip trivial)
        if (window.jQuery) {
            (function ($) {
                // Actions that should NOT trigger the global loader (uploads, meeting saves, etc.)
                var _aglBypassActions = ['save_meeting', 'save_combined_report', 'upload_audio', 'batch_compress_existing_images'];

                function scheduleShow() {
                    clearTimeout(_aglAjaxDelayTimer);
                    _aglAjaxDelayTimer = setTimeout(function () {
                        if (_aglActiveAjax > 0) { showAdminLoader('កំពុងផ្ទុកទិន្នន័យ...'); }
                    }, _aglShowDelay);
                }
                $(document).ajaxSend(function (evt, jqXHR, settings) {
                    // Skip loader for lightweight or explicitly bypassed requests
                    if (settings && settings.headers && settings.headers['X-Bypass-Loader'] === '1') return;
                    if (settings && settings.type === 'GET' && (settings.url || '').match(/fetch_(latest|requests|counts)/)) {
                        // polling endpoints kept silent unless long-running
                        jqXHR.setRequestHeader('X-Bypass-Loader', '1');
                        return;
                    }
                    // Skip loader for meeting/upload actions that have their own progress UI
                    if (settings && settings.data) {
                        var shouldBypass = false;
                        if (typeof settings.data === 'string') {
                            for (var i = 0; i < _aglBypassActions.length; i++) {
                                if (settings.data.indexOf(_aglBypassActions[i]) !== -1) {
                                    shouldBypass = true; break;
                                }
                            }
                        } else if (window.FormData && settings.data instanceof FormData) {
                            if (settings.data.has('ajax_action')) {
                                var act = settings.data.get('ajax_action');
                                for (var i = 0; i < _aglBypassActions.length; i++) {
                                    if (act === _aglBypassActions[i]) {
                                        shouldBypass = true; break;
                                    }
                                }
                            }
                        }
                        if (shouldBypass) {
                            jqXHR.setRequestHeader('X-Bypass-Loader', '1');
                            return;
                        }
                    }
                    _aglActiveAjax++;
                    // Batch multiple near-simultaneous ajax calls
                    if (!_aglBatchTimer) {
                        _aglBatchTimer = setTimeout(function () { _aglBatchTimer = null; if (_aglActiveAjax > 0) { scheduleShow(); } }, _aglBatchWindow);
                    }
                });
                function ajaxComplete() {
                    _aglActiveAjax = Math.max(0, _aglActiveAjax - 1);
                    if (_aglActiveAjax === 0) {
                        clearTimeout(_aglAjaxDelayTimer); _aglAjaxDelayTimer = null;
                        hideAdminLoader();
                    }
                }
                $(document).ajaxSuccess(ajaxComplete);
                $(document).ajaxError(function () { ajaxComplete(); });
                $(document).ajaxComplete(function () { ajaxComplete(); });
            })(jQuery);
        }
        // Hide on various lifecycle events, even if internal state got out of sync.
        document.addEventListener('DOMContentLoaded', function () { forceHideAdminLoader(); });
        window.addEventListener('load', function () { forceHideAdminLoader(); });
        window.addEventListener('pageshow', function () { forceHideAdminLoader(); });
    </script>

    <script>
        // Soft navigation for internal admin links/forms to avoid hard browser reloads.
        (function () {
            var activeSoftNavController = null;

            function supportsSoftNav() {
                return !!(window.fetch && window.history && typeof window.history.pushState === 'function');
            }

            function resolveSoftNavUrl(url) {
                try {
                    return new URL(url, window.location.href);
                } catch (e) {
                    return null;
                }
            }

            function isSameOriginSoftNav(urlObj) {
                return !!urlObj && urlObj.origin === window.location.origin;
            }

            function isSoftNavigableLink(a) {
                if (!supportsSoftNav() || !a || a.tagName !== 'A') return false;
                if (a.target && a.target !== '_self') return false;
                if (a.hasAttribute('download')) return false;
                if (a.dataset.softNav === 'off' || a.classList.contains('no-soft-nav') || a.classList.contains('no-loader')) return false;

                var href = (a.getAttribute('href') || '').trim();
                if (!href || href === '#' || /^#[^/]/.test(href)) return false;
                if (/^(javascript|tel|mailto|sms|data):/i.test(href)) return false;

                if (a.dataset.toggle || a.dataset.bsToggle ||
                    a.dataset.target || a.dataset.bsTarget ||
                    a.dataset.dismiss || a.dataset.bsDismiss ||
                    a.getAttribute('data-bs-toggle') ||
                    a.getAttribute('data-toggle')) return false;

                var role = (a.getAttribute('role') || '').toLowerCase();
                if (role === 'button' || role === 'tab') return false;

                if (a.classList.contains('dropdown-toggle') ||
                    (a.classList.contains('nav-link') && (a.dataset.bsToggle || a.dataset.toggle || role === 'tab')) ||
                    a.classList.contains('ajax-delete-link')) {
                    return false;
                }

                var urlObj = resolveSoftNavUrl(href);
                if (!isSameOriginSoftNav(urlObj)) return false;
                if (!/admin_attendance\.php$/i.test(urlObj.pathname) && urlObj.pathname !== window.location.pathname) return false;

                return true;
            }

            async function performSoftNavigation(targetUrl, options) {
                options = options || {};
                if (!supportsSoftNav()) {
                    window.location.href = targetUrl;
                    return;
                }

                var urlObj = resolveSoftNavUrl(targetUrl);
                if (!isSameOriginSoftNav(urlObj)) {
                    window.location.href = targetUrl;
                    return;
                }

                if (activeSoftNavController) {
                    try { activeSoftNavController.abort(); } catch (e) { }
                }

                activeSoftNavController = new AbortController();
                showAdminLoader(options.message || 'កំពុងផ្ទុកទំព័រ...');

                try {
                    var response = await fetch(urlObj.toString(), {
                        method: 'GET',
                        credentials: 'same-origin',
                        cache: 'no-store',
                        headers: {
                            'X-Requested-With': 'soft-nav',
                            'X-Soft-Navigation': '1'
                        },
                        signal: activeSoftNavController.signal
                    });

                    if (!response.ok) {
                        throw new Error('Soft navigation request failed: ' + response.status);
                    }

                    var html = await response.text();
                    var finalUrl = response.url || urlObj.toString();

                    if (options.historyMode === 'replace') {
                        window.history.replaceState({ softNav: true, url: finalUrl }, '', finalUrl);
                    } else {
                        window.history.pushState({ softNav: true, url: finalUrl }, '', finalUrl);
                    }

                    document.open();
                    document.write(html);
                    document.close();
                } catch (error) {
                    if (error && error.name === 'AbortError') {
                        return;
                    }
                    console.error('Soft navigation fallback:', error);
                    window.location.href = urlObj.toString();
                }
            }

            window.adminSoftGo = function (targetUrl, options) {
                options = options || {};
                return performSoftNavigation(targetUrl, options);
            };

            window.adminSoftReload = function (options) {
                options = options || {};
                options.historyMode = 'replace';
                options.message = options.message || 'កំពុងធ្វើបច្ចុប្បន្នភាព...';
                return performSoftNavigation(window.location.href, options);
            };

            document.addEventListener('click', function (e) {
                if (e.defaultPrevented || e.button !== 0 || e.metaKey || e.ctrlKey || e.shiftKey || e.altKey) return;
                var anchor = e.target && e.target.closest ? e.target.closest('a') : null;
                if (!isSoftNavigableLink(anchor)) return;
                e.preventDefault();
                window.adminSoftGo(anchor.href, { historyMode: 'push' });
            }, true);

            document.addEventListener('submit', function (e) {
                var form = e.target;
                if (!(form instanceof HTMLFormElement)) return;
                if (e.defaultPrevented || form.classList.contains('ajax-form')) return;

                var method = (form.getAttribute('method') || 'GET').toUpperCase();
                if (method !== 'GET') return;
                if (form.dataset.softNav === 'off' || form.classList.contains('no-soft-nav')) return;

                var actionUrl = resolveSoftNavUrl(form.getAttribute('action') || window.location.href);
                if (!isSameOriginSoftNav(actionUrl)) return;

                e.preventDefault();
                var formData = new FormData(form);
                var params = new URLSearchParams();
                formData.forEach(function (value, key) {
                    if (typeof value === 'string') {
                        params.append(key, value);
                    }
                });

                var nextUrl = actionUrl.pathname + (params.toString() ? ('?' + params.toString()) : '');
                window.adminSoftGo(nextUrl, { historyMode: 'push' });
            }, true);

            window.addEventListener('popstate', function () {
                if (!supportsSoftNav()) return;
                window.adminSoftGo(window.location.href, { historyMode: 'replace', message: 'កំពុងត្រឡប់ទៅទំព័រមុន...' });
            });

            document.addEventListener('DOMContentLoaded', function () {
                if (!window.history.state || !window.history.state.softNav) {
                    window.history.replaceState({ softNav: true, url: window.location.href }, '', window.location.href);
                }
            });

            // Safety net for true browser navigations that we do not intercept.
            window.addEventListener('beforeunload', function () {
                try { if (typeof showAdminLoader === 'function') showAdminLoader('កំពុងផ្ទុកទំព័រ...'); } catch (_) { }
            });
        })();
    </script>


