    <style>
        /* Styles for draggable rows and inline editing */
        .draggable-field-row.dragging {
            opacity: 0.45;
        }

        .draggable-field-row.placeholder {
            outline: 2px dashed #3498db;
            background: #f8fbfd;
        }

