            box-sizing: border-box;
            padding: 6px;
        }

        /* Late employees section styles */
        .late-employee-card:hover {
            transform: translateY(-2px);
            box-shadow: 0 8px 20px rgba(239, 68, 68, 0.15);
        }

        .late-toggle-btn:hover {
            background: #f3f4f6 !important;
            border-color: #d1d5db !important;
            color: #374151 !important;
        }

        .late-toggle-btn[aria-expanded="true"] i.fa-chevron-down {
            transform: rotate(180deg);
        }

        /* CRUD 3-dots action menu */
        .action-dropdown,
        .action-dropdown-container {
            position: relative;
            display: inline-flex;
            align-items: center;
            justify-content: center;
        }

        .crud-dots-btn,
        .action-toggle-btn {
            width: 36px;
            height: 36px;
            border: 1px solid var(--border);
            background: #fff;
            border-radius: 10px;
            display: inline-flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s ease;
            color: #64748b;
            padding: 0;
            margin: 0;
        }

        .crud-dots-btn:hover,
        .crud-dots-btn:focus-visible,
        .action-toggle-btn:hover {
            background: #eef2ff !important;
            border-color: #c7d2fe !important;
            color: #4f46e5 !important;
            transform: translateY(-1px);
            box-shadow: 0 6px 14px rgba(79, 70, 229, 0.12);
            outline: none;
        }

        .action-menu,
        .action-dropdown-menu {
            position: absolute;
            top: calc(100% + 8px);
            right: 0;
            background: #fff;
            border: 1px solid #e2e8f0;
            border-radius: 12px;
            box-shadow: 0 14px 32px rgba(15, 23, 42, 0.18);
            z-index: 1001;
            min-width: 170px;
            max-width: min(280px, calc(100vw - 24px));
            padding: 8px;
            display: none;
            animation: actionMenuPop 0.15s ease-out;
        }

        .action-menu.show,
        .action-dropdown-menu.show {
            display: block;
        }

        .action-dropdown.menu-open,
        .action-dropdown-container.menu-open {
            z-index: 6000;
        }

        .action-dropdown.menu-open .crud-dots-btn,
        .action-dropdown.menu-open .crud-dots-btn:hover,
        .action-dropdown-container.menu-open .crud-dots-btn,
        .action-dropdown-container.menu-open .crud-dots-btn:hover {
