    <!-- Printable Report Area -->
    <div id="printableReportArea" style="display:none;"></div>

    <style>
        /* Printing Styles */
        @media print {
            body * {
                visibility: hidden !important;
            }

            #printableReportArea,
            #printableReportArea * {
                visibility: visible !important;
            }

            #printableReportArea {
                position: absolute;
                left: 0;
                top: 0;
                width: 100%;
                display: block !important;
                background: #fff;
            }

            @page {
                size: A4;
                margin: 10mm;
            }

            /* Ensure table styles carry over */
            .print-table th {
                -webkit-print-color-adjust: exact;
                print-color-adjust: exact;
            }

            .print-table tr:nth-child(even) {
                -webkit-print-color-adjust: exact;
                print-color-adjust: exact;
            }

            .print-title-block {
                -webkit-print-color-adjust: exact;
                print-color-adjust: exact;
            }

            .print-subtitle-block {
                -webkit-print-color-adjust: exact;
                print-color-adjust: exact;
            }
        }

        /* Report Layout Styles */
        #printableReportArea {
            font-family: 'Khmer OS Siemreap', 'Siemreap', sans-serif;
        }

        .print-header {
            text-align: center;
            margin-bottom: 20px;
        }

        .print-logo-text {
            font-family: 'Khmer OS Moul', 'Khmer OS Siemreap', sans-serif;
            color: #b7950b;
            font-weight: bold;
            font-size: 28px;
