        }

        .print-company {
            font-weight: bold;
            font-size: 20px;
            color: #b7950b;
            margin-bottom: 15px;
            letter-spacing: 2px;
        }

        .print-title-block {
            background: #1e2d4a !important;
            color: #ffc107 !important;
            padding: 15px;
            text-align: center;
            border-radius: 4px;
            margin-bottom: 5px;
        }

        .print-title-block h1 {
            margin: 0;
            font-size: 24px;
            font-weight: bold;
            font-family: 'Khmer OS Moul', sans-serif;
        }

        .print-subtitle-block {
            background: #1e2d4a !important;
            color: #fff !important;
            padding: 10px;
            text-align: center;
            border-radius: 4px;
            margin-bottom: 20px;
        }

        .print-info {
            color: #f1c40f !important;
            font-size: 15px;
            font-weight: bold;
            margin-bottom: 5px;
        }

        .print-range {
            font-size: 13px;
        }

        .print-table {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 20px;
            border: 1.5px solid #000;
        }

        .print-table thead tr:first-child th {
            background: #ffc107 !important;
            color: #000 !important;
            border: 1px solid #000;
            padding: 8px 5px;
            font-size: 13px;
            font-weight: bold;
        }

        .print-table thead tr:nth-child(2) th {
            background: #ffc107 !important;
            color: #000 !important;
            border: 1px solid #000;
            padding: 5px;
            font-size: 11px;
        }

        .print-table td {
            border: 1px solid #000;
            padding: 6px 5px;
            font-size: 12px;
            text-align: center;
        }

        .print-table td:nth-child(3),
        .print-table td:nth-child(5) {
            text-align: left;
        }

        .print-table tr:nth-child(even) {
            background-color: #fff9e6 !important;
        }

        .print-table tfoot td {
            background: #ffc107 !important;
            color: #000 !important;
            font-weight: bold;
            padding: 8px;
            border: 1px solid #000;
        }

        .print-footer {
            display: flex;
            justify-content: space-between;
            margin-top: 40px;
            padding: 0 40px;
        }

        .sig-block {
            text-align: center;
