        })();

        /**
         * Global AJAX Helpers & Message System
         */
        window.showAjaxMessage = function (type, message, duration) {
            var container = document.getElementById('ajax-message-container');
            if (!container) {
                container = document.createElement('div');
                container.id = 'ajax-message-container';
            }
            if (container.parentNode !== document.body) {
                document.body.appendChild(container);
            }
            container.style.position = 'fixed';
            container.style.top = '20px';
            container.style.right = '20px';
            container.style.zIndex = '999999';
            container.style.display = 'flex';
            container.style.flexDirection = 'column';
            container.style.alignItems = 'flex-end';
            container.style.gap = '12px';
            container.style.width = 'min(360px, calc(100vw - 24px))';
            container.style.pointerEvents = 'none';

            var safeType = ['success', 'error', 'warning', 'info'].indexOf(type) !== -1 ? type : 'info';
            var iconClass = 'fa-circle-info';
            if (safeType === 'success') iconClass = 'fa-circle-check';
            else if (safeType === 'error') iconClass = 'fa-circle-exclamation';
            else if (safeType === 'warning') iconClass = 'fa-triangle-exclamation';

            var toast = document.createElement('div');
            toast.className = 'ajax-toast ' + safeType;

            var icon = document.createElement('i');
            icon.className = 'fa-solid ' + iconClass;

            var content = document.createElement('div');
            content.className = 'ajax-toast-content';
            content.textContent = String(message == null ? '' : message);

            var closeBtn = document.createElement('button');
            closeBtn.type = 'button';
            closeBtn.className = 'ajax-toast-close';
            closeBtn.setAttribute('aria-label', 'Close message');
            closeBtn.innerHTML = '<i class="fa-solid fa-xmark"></i>';

            toast.appendChild(icon);
            toast.appendChild(content);
            toast.appendChild(closeBtn);

            container.appendChild(toast);

            var dismiss = function () {
                if (!toast.parentNode) return;
                toast.classList.add('fade-out');
                setTimeout(function () { if (toast.parentNode) toast.remove(); }, 400);
            };

            if (closeBtn) closeBtn?.addEventListener('click', dismiss);
            setTimeout(dismiss, duration || 3500);
        };

