        window.resetTransientUiLayers = function () {
            try {
                if (typeof forceHideAdminLoader === 'function') {
                    forceHideAdminLoader();
                }
            } catch (_) { }

            try {
                document.body.classList.remove('no-scroll', 'modal-open');
                document.documentElement.classList.remove('no-scroll', 'modal-open');
            } catch (_) { }

            document.querySelectorAll('.fullscreen-fallback').forEach(function (el) {
                el.classList.remove('fullscreen-fallback');
            });

            document.querySelectorAll('.modal, .sidebar-overlay, .colvis-modal').forEach(function (el) {
                el.style.display = 'none';
                el.classList.remove('show', 'active', 'fade', 'fadeout', 'is-visible');
            });

            document.querySelectorAll('[id]').forEach(function (el) {
                var id = el.id || '';
                if (id !== 'adminGlobalLoader' && !/(Modal|Overlay)$/.test(id)) {
                    return;
                }
                var style = window.getComputedStyle(el);
                if (id === 'adminGlobalLoader' || style.position === 'fixed') {
                    el.style.display = 'none';
                    el.classList.remove('show', 'active', 'fade', 'fadeout', 'is-visible');
                }
            });

            // Safety scrubber: if a fullscreen fixed backdrop is somehow restored
            // from cached browser state, hide it after the page is already usable.
            document.querySelectorAll('body > *').forEach(function (el) {
                if (!el || el.id === 'adminGlobalLoader' || el.classList.contains('admin-container')) {
                    return;
                }

                var style = window.getComputedStyle(el);
                if (style.position !== 'fixed' || style.display === 'none' || style.visibility === 'hidden') {
                    return;
                }

                var rect = el.getBoundingClientRect();
                var coversViewport = rect.width >= window.innerWidth * 0.94 && rect.height >= window.innerHeight * 0.94;
                var zIndex = parseInt(style.zIndex || '0', 10) || 0;
                var looksLikeBackdrop = /(modal|overlay|loader|backdrop)/i.test((el.id || '') + ' ' + (el.className || ''));
                var hasBackdropFx = (style.backdropFilter && style.backdropFilter !== 'none') ||
                    (style.webkitBackdropFilter && style.webkitBackdropFilter !== 'none');

                if (!coversViewport || zIndex < 1500 || (!looksLikeBackdrop && !hasBackdropFx)) {
                    return;
                }

                el.style.display = 'none';
                el.classList.remove('show', 'active', 'fade', 'fadeout', 'is-visible');
            });
        };

        window.scheduleTransientUiCleanup = function () {
            var attempts = 0;
            var timer = setInterval(function () {
                attempts++;
                window.resetTransientUiLayers();
                if (attempts >= 12) {
                    clearInterval(timer);
                }
            }, 250);
        };

        document.addEventListener('DOMContentLoaded', function () {
            window.resetTransientUiLayers();
            setTimeout(window.resetTransientUiLayers, 120);
            window.scheduleTransientUiCleanup();
        });
        window.addEventListener('load', function () {
            window.resetTransientUiLayers();
            setTimeout(window.resetTransientUiLayers, 250);
            window.scheduleTransientUiCleanup();
        });
        window.addEventListener('pageshow', function () {
            window.resetTransientUiLayers();
            setTimeout(window.resetTransientUiLayers, 120);
            window.scheduleTransientUiCleanup();
        });

        window.submitAjaxForm = function (form) {
            if (!form) return;

            if (form.id === 'timeRulesForm') {
                const rules = [];
                $('.time-rule-row').each(function () {
                    rules.push({
                        type: $(this).data('type'),
                        start: $(this).find('.rule-start').val(),
                        end: $(this).find('.rule-end').val(),
                        status: $(this).find('.rule-status').val()
                    });
                });
                var rulesInput = form.querySelector('#rulesJsonInput');
                if (rulesInput) rulesInput.value = JSON.stringify(rules);
            }

            const $form = $(form);
            const btn = $form.find('button[type="submit"]');
            const oldHtml = btn.html();

            btn.html('<i class="fa-solid fa-spinner fa-spin"></i> កំពុងរក្សាទុក...').prop('disabled', true);

            const fd = new FormData(form);

            $.ajax({
                url: window.location.pathname + window.location.search,
                type: 'POST',
                data: fd,
                processData: false,
                contentType: false,
                success: function (res) {
                    try {
                        const r = typeof res === 'string' ? JSON.parse(res) : res;
                        if (r.status === 'success' || r.success) {
                            showAjaxMessage('success', r.message || 'រក្សាទុកបានជោគជ័យ!');
                            if (r.redirect_url) {
                                setTimeout(function () { window.adminSoftGo(r.redirect_url); }, 900);
                            } else {
                                setTimeout(function () { window.adminSoftReload(); }, 1200);
                            }
                        } else {
                            showAjaxMessage('error', r.message || 'មានកំហុសបានកើតឡើង');
                            btn.html(oldHtml).prop('disabled', false);
                        }
                    } catch (e) {
                        console.error("AJAX Parse Error:", e, res);
                        window.adminSoftReload();
                    }
                },
                error: function (xhr) {
                    showAjaxMessage('error', 'បាត់បង់ការភ្ជាប់ទៅកាន់ Server។');
                    btn.html(oldHtml).prop('disabled', false);
                }
            });
        };

        $(document).on('submit', '.ajax-form', function (e) {
            e.preventDefault();
            window.submitAjaxForm(this);
        });

        function toggleMobileSidebar() {
            const sidebar = document.querySelector('.sidebar');
            const overlay = document.getElementById('sidebarOverlay');
            const btn = document.getElementById('sidebarToggleBtn');
            const isOpen = sidebar && sidebar.classList.contains('mobile-open');
            if (sidebar) sidebar.classList.toggle('mobile-open', !isOpen);
            if (overlay) overlay.classList.toggle('active', !isOpen);
            if (btn) btn.innerHTML = isOpen
                ? '<i class="fa-solid fa-bars"   style="font-size:1.1rem"></i>'
                : '<i class="fa-solid fa-xmark"  style="font-size:1.1rem"></i>';
        }
        // Sidebar Toggles (Collapsed & Mobile)
        document.addEventListener('DOMContentLoaded', function () {
            const sidebar = document.querySelector('.sidebar');
            const toggleSidebarDesktop = document.getElementById('toggleSidebar');
            if (toggleSidebarDesktop) {
                toggleSidebarDesktop?.addEventListener('click', function () {
                    document.body.classList.toggle('sidebar-collapsed');
                    // Store state? (Optional)
                });
            }

            const mobileToggle = document.getElementById('sidebarToggleBtn');
            if (mobileToggle) {
                mobileToggle?.addEventListener('click', toggleMobileSidebar);
            }

            // Submenu toggles - and ensure they stay open when active
            document.querySelectorAll('.sidebar-item.has-submenu').forEach(function (item) {
                const toggle = item.querySelector('.submenu-toggle');
                if (toggle) {
                    toggle?.addEventListener('click', function (e) {
                        // If clicking the parent text area while it's NOT an active navigation, toggle it
                        // But if it has an href, it should still navigate UNLESS we want it to be just a toggle
                        // For reports, let's make it a toggle if it's already on that page.

                        const isCurrentlyActive = item.classList.contains('active');
                        if (isCurrentlyActive) {
                            // item.classList.toggle('open');
                            // e.preventDefault();
                        }

                        // Always allow toggling if clicking the chevron specifically?
                        // Actually, just let the class toggle work.
                        item.classList.toggle('open');

                        const href = this.getAttribute('href');
                        if (!href || href === '#' || href.includes('javascript:')) {
                            e.preventDefault();
                        }
                    });
                }
            });
        });

        (function () {
            const wrapper = document.getElementById('reportsTableWrapper');
            if (!wrapper) return;

            // Insert button into the controls area if present
            const controlsParent = document.querySelector('.header .right-actions') || document.body;
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.id = 'columnToggleBtn';
            btn.className = 'btn btn-sm';
            btn.style.marginLeft = '8px';
            btn.innerHTML = '<i class="fa-solid fa-table-columns"></i> កំណត់ជម្រើសជួរឈរ';
            // append near top controls
            if (controlsParent) controlsParent.appendChild(btn);

            function getHeaders() {
                const ths = Array.from(document.querySelectorAll('#reportsTable thead th[data-col]'));
                return ths.map(t => ({ key: t.getAttribute('data-col'), label: (t.textContent || t.innerText).trim() }));
            }

            function applyVisibility(map) {
                const headers = getHeaders();
                headers.forEach(h => {
                    const show = (map[h.key] === undefined) ? 1 : (parseInt(map[h.key]) === 1);
                    const th = document.querySelector('#reportsTable thead th[data-col="' + h.key + '"]');
                    if (th) th.style.display = show ? '' : 'none';
                    const tds = document.querySelectorAll('.col-' + h.key);
                    tds.forEach(td => td.style.display = show ? '' : 'none');
                    // also hide export table header/cols
                    const thExp = document.querySelector('#reportsTableExport thead th[data-col="' + h.key + '"]'); if (thExp) thExp.style.display = show ? '' : 'none';
                    const tdsExp = document.querySelectorAll('#reportsTableExport .col-' + h.key); tdsExp.forEach(td => td.style.display = show ? '' : 'none');
                });
            }

            async function loadVisibility() {
                try {
                    const fd = new FormData(); fd.append('ajax_action', 'get_column_visibility');
                    const res = await fetch('admin_attendance.php', { method: 'POST', body: fd });
                    const j = await res.json();
                    if (j && j.status === 'success') { applyVisibility(j.data || {}); }
                } catch (e) { console.error('colvis load error', e); }
            }

            function openPanel(currentMap) {
                const headers = getHeaders();
                const modal = document.createElement('div'); modal.className = 'colvis-modal';
                const panel = document.createElement('div'); panel.className = 'colvis-panel';
                panel.innerHTML = '<h4>បង្ហាញ/លាក់ ជួរឈរ</h4>';
                const list = document.createElement('div'); list.className = 'colvis-list';
                headers.forEach(h => {
                    const item = document.createElement('label'); item.className = 'colvis-item';
                    const chk = document.createElement('input'); chk.type = 'checkbox'; chk.value = h.key; chk.checked = (currentMap[h.key] === undefined) ? true : (parseInt(currentMap[h.key]) === 1);
                    const span = document.createElement('span'); span.textContent = h.label;
                    item.appendChild(chk); item.appendChild(span); list.appendChild(item);
                });
                panel.appendChild(list);
                const actions = document.createElement('div'); actions.className = 'colvis-actions';
                const btnCancel = document.createElement('button'); btnCancel.type = 'button'; btnCancel.className = 'btn btn-sm'; btnCancel.textContent = 'Cancel';
                const btnSave = document.createElement('button'); btnSave.type = 'button'; btnSave.className = 'btn btn-primary btn-sm'; btnSave.textContent = 'Save';
                actions.appendChild(btnCancel); actions.appendChild(btnSave); panel.appendChild(actions);
                modal.appendChild(panel); document.body.appendChild(modal);

                btnCancel?.addEventListener('click', () => modal.remove());
                btnSave?.addEventListener('click', async () => {
                    const boxes = list.querySelectorAll('input[type="checkbox"]');
                    const map = {};
                    boxes.forEach(b => map[b.value] = b.checked ? 1 : 0);
                    // send to server
                    try {
                        const fd = new FormData(); fd.append('ajax_action', 'save_column_visibility'); fd.append('visibility', JSON.stringify(map));
                        const res = await fetch('admin_attendance.php', { method: 'POST', body: fd });
                        const j = await res.json();
                        if (j && j.status === 'success') {
                            applyVisibility(map);
                            if (typeof window.showAjaxMessage === 'function') {
                                window.showAjaxMessage('success', 'រក្សាទុកការកំណត់ជោគជ័យ!');
                            }
                        } else {
                            if (typeof window.showAjaxMessage === 'function') {
