        async function saveData(action, data) {
            const formData = new FormData();
            formData.append('ajax_action', action);
            formData.append('store', storeId);
            for (const key in data) { formData.append(key, data[key]); }
            try {
                const response = await fetch('admin_attendance.php', { method: 'POST', body: formData });
                if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
                const result = await response.json();
                if (result.success) {
                    showToast(result.message || 'ជោគជ័យ!');
                    return result;
                } else {
                    showToast(result.message || 'មានបញ្ហា!', 'error');
                    return null;
                }
            } catch (error) {
                console.error(error);
                showToast('បរាជ័យក្នុងការតភ្ជាប់ទៅ Server', 'error');
                return null;
            }
        }

