        /**
                             * Client-side optimization/compression for Audio and Images
                             */
        document.getElementById('postMeetingForm')?.addEventListener('submit', async function (e) {
            e.preventDefault();
            const form = this;
            const submitBtn = form.querySelector('button[type="submit"]');
            const originalBtnText = submitBtn.innerHTML;
            const messageContainer = document.getElementById('ajax-message-container');

            submitBtn.disabled = true;
            submitBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> កំពុងរៀបចំឯកសារ...';

            const formData = new FormData(form);

            // 1. Process Audio (WAV Downsampling / Size Check)
            const audioFile = formData.get('audio_file');
            if (audioFile && audioFile.size > 0) {
                const ext = audioFile.name.split('.').pop().toLowerCase();

                // If it's a WAV, we can try to downsample it to Mono/22kHz to save space
                if (ext === 'wav' && audioFile.size > 2 * 1024 * 1024) {
                    submitBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> កំពុងបង្រួមសំឡេង (WAV)...';
                    try {
                        const optimizedAudio = await optimizeWavAudio(audioFile);
                        formData.set('audio_file', optimizedAudio, audioFile.name.replace('.wav', '_optimized.wav'));
                    } catch (err) {
                        console.warn('Audio optimization failed, using original.', err);
                    }
                } else if (audioFile.size > 200 * 1024 * 1024) {
                    showAjaxMessage('error', 'ឯកសារសំឡេងធំព័ក (លើសពី 200MB)។ សូមប្រើប្រាស់ប្រភេទ MP3 ឬបង្រួមវាជាមុនសិន។');
                    submitBtn.disabled = false;
                    submitBtn.innerHTML = originalBtnText;
                    return;
                }
            }

            // 2. Process Images (Client-side compression)
            const photosInput = form.querySelector('[name="related_photos[]"]');
            if (photosInput && photosInput.files.length > 0) {
                submitBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> កំពុងបង្រួមរូបភាព...';
                formData.delete('related_photos[]');
                for (let i = 0; i < photosInput.files.length; i++) {
                    try {
                        const compressed = await compressImage(photosInput.files[i], 1200, 1200, 0.7);
                        formData.append('related_photos[]', compressed, `photo_${Date.now()}_${i}.jpg`);
                    } catch (err) {
                        formData.append('related_photos[]', photosInput.files[i]);
                    }
                }
            }

            // 3. Submit via AJAX
            submitBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> កំពុងបង្ហោះ...';
            $.ajax({
                type: 'POST',
                url: window.location.href,
                data: formData,
                processData: false,
                contentType: false,
                dataType: 'json',
                xhr: function () {
                    var xhr = new window.XMLHttpRequest();
                    xhr.upload.addEventListener("progress", function (evt) {
                        if (evt.lengthComputable) {
                            var percentComplete = Math.round((evt.loaded / evt.total) * 100);
                            submitBtn.innerHTML = '<i class="fa-solid fa-cloud-arrow-up"></i> កំពុងបង្ហោះ (' + percentComplete + '%)';
                        }
                    }, false);
                    return xhr;
                },
                success: function (res) {
                    if (res.status === 'success') {
                        showAjaxMessage('success', res.message);
                        setTimeout(() => { window.adminSoftGo('?page=meetings&action=list_meetings'); }, 1500);
                    } else {
                        showAjaxMessage('error', res.message);
                    }
                },
                error: function () { showAjaxMessage('error', 'មានបញ្ហាក្នុងការភ្ជាប់ជាមួយ Server'); },
                complete: function () {
                    submitBtn.disabled = false;
                    submitBtn.innerHTML = originalBtnText;
                }
            });
        });

        /**
         * WAV Downsampler: Convert to Mono and reduce sample rate using Web Audio API
         */
        async function optimizeWavAudio(file) {
            const audioContext = new (window.AudioContext || window.webkitAudioContext)();
            const arrayBuffer = await file.arrayBuffer();
            const audioBuffer = await audioContext.decodeAudioData(arrayBuffer);

            // We'll create a new buffer: Mono, 22050Hz (or similar)
            const offlineContext = new OfflineAudioContext(1, audioBuffer.duration * 22050, 22050);
            const source = offlineContext.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(offlineContext.destination);
            source.start();

            const renderedBuffer = await offlineContext.startRendering();
            return bufferToWav(renderedBuffer);
        }

        function bufferToWav(buffer) {
            const length = buffer.length * 2;
            const view = new DataView(new ArrayBuffer(44 + length));
            const samples = buffer.getChannelData(0);

            // RIFF identifier
            writeString(view, 0, 'RIFF');
            view.setUint32(4, 36 + length, true);
            writeString(view, 8, 'WAVE');
            writeString(view, 12, 'fmt ');
            view.setUint32(16, 16, true);
            view.setUint16(20, 1, true); // PCM
            view.setUint16(22, 1, true); // Mono
            view.setUint32(24, 22050, true);
            view.setUint32(28, 22050 * 2, true);
            view.setUint16(32, 2, true);
            view.setUint16(34, 16, true);
            writeString(view, 36, 'data');
            view.setUint32(40, length, true);

            let offset = 44;
            for (let i = 0; i < samples.length; i++, offset += 2) {
                let s = Math.max(-1, Math.min(1, samples[i]));
                view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
            }

            return new Blob([view], { type: 'audio/wav' });
        }

        function writeString(view, offset, string) {
            for (let i = 0; i < string.length; i++) {
                view.setUint8(offset + i, string.charCodeAt(i));
            }
        }

        function compressImage(file, maxWidth, maxHeight, quality) {
            return new Promise((resolve, reject) => {
                const reader = new FileReader();
                reader.readAsDataURL(file);
                reader.onload = e => {
                    const img = new Image();
                    img.src = e.target.result;
                    img.onload = () => {
                        const canvas = document.createElement('canvas');
                        let width = img.width, height = img.height;
                        if (width > height) {
                            if (width > maxWidth) { height *= maxWidth / width; width = maxWidth; }
                        } else {
                            if (height > maxHeight) { width *= maxHeight / height; height = maxHeight; }
                        }
                        canvas.width = width; canvas.height = height;
                        const ctx = canvas.getContext('2d');
                        ctx.drawImage(img, 0, 0, width, height);
                        canvas.toBlob(blob => {
                            resolve(new File([blob], file.name, { type: 'image/jpeg', lastModified: Date.now() }));
                        }, 'image/jpeg', quality);
                    };
                    img.onerror = reject;
                };
                reader.onerror = reject;
            });
        }

        function loadLegacyMeetingsTable() {
            const fd = new FormData();
            fd.append('ajax_action', 'get_meetings');
            fetch(window.location.href, { method: 'POST', body: fd })
                .then(r => r.json())
                .then(res => {
                    if (res.status === 'success' && res.meetings) {
                        let html = '';
                        if (res.meetings.length === 0) {
                            html = '<tr><td colspan="6" style="text-align: center; padding: 30px;">មិនមានកិច្ចប្រជុំទេ</td></tr>';
                        } else {
                            res.meetings.forEach(m => {
                                let audioBtn = '';
                                if (m.audio_file_path) audioBtn = `<a href="${m.audio_file_path}" target="_blank" class="btn btn-sm btn-success" title="Play Audio" style="margin-right:5px;"><i class="fa-solid fa-play"></i> Audio</a> `;
                                if (m.external_url) audioBtn += `<a href="${m.external_url}" target="_blank" class="btn btn-sm btn-info" title="External Link"><i class="fa-solid fa-link"></i> Link</a>`;

                                let photosCount = 0;
                                try {
                                    const p = JSON.parse(m.related_photos);
                                    photosCount = p ? p.length : 0;
                                } catch (e) { }

                                html += `<tr>
                                            <td style="font-weight: bold;">${m.topic}</td>
                                            <td>${m.department}</td>
                                            <td>${m.meeting_date}</td>
                                            <td>${audioBtn}</td>
                                            <td><i class="fa-solid fa-image"></i> ${photosCount} Photos</td>
                                            <td>
                                                <div class="action-dropdown">
                                                    <button type="button" class="crud-dots-btn" onclick="toggleActionMenu(this, event)" title="Actions">
                                                        <i class="fa-solid fa-ellipsis-vertical"></i>
                                                    </button>
                                                    <div class="action-menu">
                                                        <button type="button" class="action-item text-danger" onclick="deleteLegacyMeeting(${m.id})">
                                                            <i class="fa-solid fa-trash"></i> Delete
                                                        </button>
                                                    </div>
                                                </div>
                                            </td>
                                        </tr>`;
                            });
                        }
                        $('#meetingsListBody').html(html);
                    }
                });
        }

