            function updateReporterDetails() {
                const selectedOption = reporterSelect.options[reporterSelect.selectedIndex];
                if (selectedOption && selectedOption.value) {
                    roleInput.value = selectedOption.getAttribute('data-position') || 'N/A';
                    groupInput.value = selectedOption.getAttribute('data-skill-group') || 'N/A';
                } else {
                    roleInput.value = '';
                    groupInput.value = '';
                }
            }

            if (reporterSelect) {
                reporterSelect?.addEventListener('change', updateReporterDetails);
                updateReporterDetails(); // Initial call
            }

            // Render initial destinations list
            renderTGDestinations();
        });

        if (typeof window.tgDestinations === 'undefined') {
            window.tgDestinations = [];
        }

        function renderTGDestinations() {
            const container = document.getElementById('tg_destinations_checklist');
            const jsonInput = document.getElementById('dr_destinations_json');
            if (!container || !jsonInput) return;

            try {
                window.tgDestinations = JSON.parse(jsonInput.value || '[]');
            } catch (e) { window.tgDestinations = []; }

            if (window.tgDestinations.length === 0) {
                container.innerHTML = '<div style="grid-column: 1/-1; text-align: center; color: #94a3b8; padding: 10px;">សូមចុច "បន្ថែមគោលដៅ" ដើម្បីបញ្ចូល Group/Topic</div>';
                return;
            }

            let html = '';
            window.tgDestinations.forEach((dest, idx) => {
                const isChecked = dest.active !== false; // Default active
                html += `
                                                <div style="background: #f8fafc; border: 1px solid #e2e8f0; padding: 8px 12px; border-radius: 6px; display: flex; align-items: center; gap: 10px;">
                                                    <input type="checkbox" ${isChecked ? 'checked' : ''} onchange="updateDestStatus(${idx}, this.checked)" style="width: 18px; height: 18px;">
                                                    <div style="flex: 1; overflow: hidden;">
                                                        <div style="font-size: 12px; font-weight: 600; color: #1e293b; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;">${dest.name || 'Group Topic'}</div>
                                                        <div style="font-size: 10px; color: #64748b;">ID: ${dest.chat_id} ${dest.thread_id ? '| Topic: ' + dest.thread_id : ''}</div>
                                                    </div>
                                                    <button type="button" class="btn btn-xs text-danger p-0" onclick="removeTGDest(${idx})"><i class="fa-solid fa-trash-can"></i></button>
                                                </div>
                                            `;
            });
            container.innerHTML = html;
        }

        function addTGDestionationField() {
            const chat_id = prompt("បញ្ជាក់លេខ Chat ID / Group ID (ឧ. -100xxxxxxxx):");
            if (!chat_id) return;
            const thread_id = prompt("បញ្ជាក់លេខ Thread ID (Topic ID) - បើគ្មានសូមទុកទទេ:", "");
            const name = prompt("ឈ្មោះចំណាំ (ឧ. IT Group):", "Group");

            window.tgDestinations.push({
                name: name,
                chat_id: chat_id.trim(),
                thread_id: thread_id ? thread_id.trim() : '',
                active: true
            });
            syncTGDest();
        }

        function removeTGDest(idx) {
            if (confirm('តើអ្នកពិតជាចង់លុបគោលដៅនេះទេ?')) {
                window.tgDestinations.splice(idx, 1);
                syncTGDest();
            }
        }

        function updateDestStatus(idx, checked) {
            window.tgDestinations[idx].active = checked;
            syncTGDest();
        }

        function syncTGDest() {
            const jsonInput = document.getElementById('dr_destinations_json');
            jsonInput.value = JSON.stringify(window.tgDestinations);
            renderTGDestinations();
        }

        function toggleTGPreview(prefix, textareaName, isDailyReport = false) {
            const previewEl = document.getElementById(prefix + '_preview');
            const textarea = document.querySelector('textarea[name="' + textareaName + '"]');
            if (!previewEl || !textarea) return;

            if (previewEl.style.display === 'block') {
                previewEl.style.display = 'none';
                return;
            }

            let content = textarea.value.trim();
            if (!content) {
                content = "--- (Empty Template - Will use system default) ---";
            } else {
                const samples = isDailyReport ? {
                    'name': 'សម្បត្តិ ភក្តី',
                    'employee_id': 'VVC001',
                    'position': 'IT Manager',
                    'content': 'របាយការណ៍ បូកសរុបប្រចាំថ្ងៃ៖ វត្តមានគ្រប់ចំនួន...',
                    'date': window.VVC_CURRENT_DATE,
                    'time': window.VVC_CURRENT_TIME
                } : {
                    'name': 'សៅរ៍ ពិសិដ្ឋ',
                    'employee_id': 'EMP123',
                    'action': 'CHECK-IN',
                    'status': 'Good',
                    'status_icon': '✅',
                    'time': window.VVC_CURRENT_DATETIME,
                    'location_name': 'Office Main Gate',
                    'distance_m': '15',
                    'allowed_distance': '100',
                    'late_reason': 'N/A',
                    'late_reason_section': '',
                    'map_url': 'https://maps.google.com/?q=11.55,104.91',
                    'request_type': 'ច្បាប់ឈប់សម្រាក',
                    'summary': 'សុំច្បាប់ឈប់សម្រាក ២ ថ្ងៃ',
                    'field_department': 'Human Resources',
                    'field_position': 'Manager'
                };

                for (let key in samples) {
                    const placeholder = isDailyReport ? '{' + key + '}' : '{{' + key + '}}';
                    content = content.split(placeholder).join(samples[key]);
                }
            }

            previewEl.textContent = content;
            previewEl.style.display = 'block';
        }

        // QR Designer logic
        var qrStylingInstance = null;
        var qrDesignData = { text: '', name: '' };

        function openQrDesigner(btnEl) {
            const data = btnEl.getAttribute('data-qr');
            const locName = btnEl.getAttribute('data-locname') || 'Location';
            qrDesignData.text = data || '';
            qrDesignData.name = locName;
            document.getElementById('qrDesignLocationName').value = locName;
            // Initialize if needed
            const preview = document.getElementById('qrPreview');
            preview.innerHTML = '';
            qrStylingInstance = new QRCodeStyling({
                width: 300,
                height: 300,
                type: 'canvas',
                data: qrDesignData.text,
                image: null,
                dotsOptions: { type: 'dots', color: '#000000' },
                cornersSquareOptions: { type: 'dot', color: '#000000' },
                cornersDotOptions: { type: 'dot', color: '#000000' },
                backgroundOptions: { color: '#ffffff' }
            });
            qrStylingInstance.append(preview);
            document.getElementById('qrDesignerModal').style.display = 'block';
        }

        function updateQrDesign() {
            if (!qrStylingInstance) return;
            const bodyType = document.getElementById('qrBodyShape').value || 'dots';
            const eyeOuter = document.getElementById('qrEyeOuter').value || 'dot';
            const eyeInner = document.getElementById('qrEyeInner').value || 'dot';
            qrStylingInstance.update({
                data: qrDesignData.text,
                dotsOptions: { type: bodyType, color: '#000000' },
                cornersSquareOptions: { type: eyeOuter, color: '#000000' },
                cornersDotOptions: { type: eyeInner, color: '#000000' }
            });
        }

        document.addEventListener('change', function (e) {
            if (e.target && (e.target.id === 'qrBodyShape' || e.target.id === 'qrEyeOuter' || e.target.id === 'qrEyeInner')) {
                updateQrDesign();
            }
        });

        document.getElementById('qrLogoInput')?.addEventListener('change', function (e) {
            const file = e.target.files && e.target.files[0];
            if (!file) { if (qrStylingInstance) qrStylingInstance.update({ image: null }); return; }
            const reader = new FileReader();
            reader.onload = function () {
                if (qrStylingInstance) {
                    qrStylingInstance.update({ image: reader.result });
                }
            };
            reader.readAsDataURL(file);
        });

        document.getElementById('qrDownloadPngBtn')?.addEventListener('click', function () {
            if (!qrStylingInstance) return;
            const filename = `QR_${qrDesignData.name.replace(/\s+/g, '_')}.png`;
            qrStylingInstance.download({ name: filename, extension: 'png' });
        });

        document.getElementById('qrDownloadSvgBtn')?.addEventListener('click', function () {
            if (!qrStylingInstance) return;
            const filename = `QR_${qrDesignData.name.replace(/\s+/g, '_')}.svg`;
            qrStylingInstance.download({ name: filename, extension: 'svg' });
        });

        (function () {
            const tableBody = document.getElementById('userFieldsList');
            if (!tableBody) return;

            let dragSrcRow = null;

            function onDragStart(e) {
                dragSrcRow = this;
                this.classList.add('dragging');
                e.dataTransfer.effectAllowed = 'move';
                try { e.dataTransfer.setData('text/plain', this.dataset.fieldId); } catch (err) { }
            }
            function onDragEnd() { this.classList.remove('dragging'); removePlaceholders(); }

            function removePlaceholders() {
                const ph = tableBody.querySelectorAll('.placeholder');
                ph.forEach(p => p.classList.remove('placeholder'));
            }

            function onDragOver(e) {
                e.preventDefault();
                e.dataTransfer.dropEffect = 'move';
                const row = getRowFromEvent(e);
                if (!row || row === dragSrcRow) return;
                // mark nearest
                removePlaceholders();
                row.classList.add('placeholder');
            }

            function onDrop(e) {
                e.stopPropagation();
                const row = getRowFromEvent(e);
                if (!row || !dragSrcRow) return;
                if (row === dragSrcRow) return;
                // insert before placeholder row
                tableBody.insertBefore(dragSrcRow, row);
                removePlaceholders();
                sendNewOrder();
            }

            function getRowFromEvent(e) {
                let el = e.target;
                while (el && el !== tableBody && el.nodeName !== 'TR') el = el.parentNode;
                return (el && el.nodeName === 'TR') ? el : null;
            }

            function sendNewOrder() {
                const ids = Array.from(tableBody.querySelectorAll('tr[data-field-id]')).map(r => r.dataset.fieldId);
                const fd = new FormData();
                fd.append('ajax_action', 'reorder_user_fields');
                ids.forEach(id => fd.append('ordered_field_ids[]', id));
                fetch(window.location.pathname + window.location.search, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(r => r.json())
                    .then(json => { if (json && json.status === 'success') { showAjaxMessage('success', json.message || 'Order saved'); } else { showAjaxMessage('error', json.message || 'Order save failed'); } })
                    .catch(err => { showAjaxMessage('error', 'Network error while saving order'); });
            }

            // Attach drag handlers
            tableBody.querySelectorAll('tr.draggable-field-row').forEach(row => {
                row?.addEventListener('dragstart', onDragStart);
                row?.addEventListener('dragend', onDragEnd);
                row?.addEventListener('dragover', onDragOver);
                row?.addEventListener('drop', onDrop);
            });

            // Inline label editing
            tableBody?.addEventListener('click', function (e) {
                const lbl = e.target.closest('.field-label-display');
                if (!lbl) return;
                const cell = lbl.parentNode;
                const input = cell.querySelector('.field-label-input');
                lbl.style.display = 'none'; input.style.display = '';
                input.focus(); input.select();
            });

            tableBody?.addEventListener('keydown', function (e) {
                if (e.target && e.target.classList && e.target.classList.contains('field-label-input')) {
                    if (e.key === 'Enter') { e.preventDefault(); e.target.blur(); }
                    if (e.key === 'Escape') { e.target.value = e.target.previousElementSibling.textContent; e.target.blur(); }
                }
            });

            tableBody?.addEventListener('blur', function (e) {
                if (!(e.target && e.target.classList && e.target.classList.contains('field-label-input'))) return;
                const input = e.target; const newLabel = input.value.trim();
                const row = input.closest('tr'); const fid = row && row.dataset.fieldId;
                const display = row.querySelector('.field-label-display');
                input.style.display = 'none'; display.style.display = '';
                if (!fid) return;
                if (newLabel === display.textContent) return; // nothing changed
                const fd = new FormData(); fd.append('ajax_action', 'update_user_field'); fd.append('field_id', fid); fd.append('field_label', newLabel);
                // include required state
                const req = row.querySelector('.field-required-checkbox'); if (req) fd.append('is_required', req.checked ? 1 : 0);
                fetch(window.location.pathname + window.location.search, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(r => r.json()).then(json => {
                        if (json && json.status === 'success') { display.textContent = newLabel; showAjaxMessage('success', json.message || 'Field updated'); }
                        else { showAjaxMessage('error', json.message || 'Update failed'); }
                    }).catch(() => showAjaxMessage('error', 'Network error while updating field'));
            }, true);

            // Toggle required checkbox
            tableBody?.addEventListener('change', function (e) {
                if (!(e.target && e.target.classList && e.target.classList.contains('field-required-checkbox'))) return;
                const chk = e.target; const row = chk.closest('tr'); const fid = row && row.dataset.fieldId;
                if (!fid) return;
                const fd = new FormData(); fd.append('ajax_action', 'update_user_field'); fd.append('field_id', fid); fd.append('field_label', row.querySelector('.field-label-input').value || row.querySelector('.field-label-display').textContent); fd.append('is_required', chk.checked ? 1 : 0);
                fetch(window.location.pathname + window.location.search, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(r => r.json()).then(json => {
                        if (json && json.status === 'success') { showAjaxMessage('success', json.message || 'Field updated'); }
                        else { showAjaxMessage('error', json.message || 'Update failed'); }
                    }).catch(() => showAjaxMessage('error', 'Network error while updating field'));
            });

        })();

        (function ($) {
            $(document).ready(function () {
                // 1. User Actions Dropdown Toggle
                $(document).on('click', '.user-actions-dropdown .dropdown-toggle', function (e) {
                    e.preventDefault();
                    e.stopPropagation();

                    var $dropdown = $(this).closest('.user-actions-dropdown');
                    var $menu = $dropdown.find('.dropdown-menu');

                    // Close other menus first
                    $('.dropdown-menu.open').not($menu).removeClass('open').hide();

                    // Toggle current
                    if ($menu.hasClass('open')) {
                        $menu.removeClass('open').hide();
                    } else {
                        $menu.addClass('open').show();
                    }
                });

                // 2. Action Toggle Buttons (Inline/Action icons)
                $(document).on('click', '.action-toggle-btn', function (e) {
                    e.preventDefault();
                    e.stopPropagation();

                    var $container = $(this).closest('.action-dropdown-container');
                    var $menu = $container.find('.action-dropdown-menu');
                    var $icon = $(this).find('i.fa-circle-chevron-down, i.fa-caret-down');

                    var isHidden = $menu.is(':hidden');

                    // Close others
                    $('.action-dropdown-menu:visible').not($menu).hide();
                    $('.action-toggle-btn i').css('transform', 'rotate(0deg)');

                    if (isHidden) {
                        $menu.show();
                        if ($icon.length) $icon.css('transform', 'rotate(180deg)');
                    } else {
                        $menu.hide();
                        if ($icon.length) $icon.css('transform', 'rotate(0deg)');
                    }
                });

                // 3. Global AJAX Delete Handler
                $(document).on('click', '.ajax-delete-link', function (e) {
                    e.preventDefault();
                    e.stopPropagation();

                    var btnEl = this;
                    var $btn = $(btnEl);
                    var ajaxAction = ($btn.data('ajax-action') || 'delete_user').toString().trim();
                    var confirmMsg = $btn.data('confirm') || 'Are you sure you want to delete this item?';

                    if (!confirm(confirmMsg)) return;

                    var payload = { ajax_action: ajaxAction };

                    Object.keys(btnEl.dataset || {}).forEach(function (key) {
                        if (key === 'ajaxAction' || key === 'confirm') return;
                        var value = btnEl.dataset[key];
                        if (value === undefined || value === null || value === '') return;
                        var snakeKey = key.replace(/([A-Z])/g, '_$1').toLowerCase();
                        payload[snakeKey] = value;
                    });

                    if (ajaxAction === 'delete_user' && !payload.user_id && $btn.data('user-id')) {
                        payload.user_id = $btn.data('user-id');
                    }

                    $.ajax({
                        url: 'admin_attendance.php',
                        type: 'POST',
                        data: payload,
                        dataType: 'json',
                        success: function (res) {
                            if (res && res.status === 'success') {
                                if (typeof showAjaxMessage === 'function') {
                                    showAjaxMessage('success', res.message || 'Deleted successfully');
                                }
                                setTimeout(function () { window.adminSoftReload(); }, 650);
                            } else {
                                if (typeof showAjaxMessage === 'function') {
                                    showAjaxMessage('error', (res && res.message) ? res.message : 'Delete failed');
                                } else {
                                    alert((res && res.message) ? res.message : 'Delete failed');
                                }
                            }
                        },
                        error: function () {
                            if (typeof showAjaxMessage === 'function') {
                                showAjaxMessage('error', 'Network error while deleting');
                            }
                        }
                    });
                });

                // 5. Outside Click
                $(document).on('click', function (e) {
                    if (!$(e.target).closest('.user-actions-dropdown, .action-dropdown-container, .action-dropdown').length) {
                        $('.dropdown-menu.open, .action-dropdown-menu:visible').removeClass('open').hide();
                        $('.action-toggle-btn i').css('transform', 'rotate(0deg)');
                    }
                });
                $(document).on('keydown', function (e) { if (e.key === 'Escape') { $('.dropdown-menu.open, .action-dropdown-menu:visible').hide(); } });
            });
        })(jQuery);

        // Column visibility functionality
        (function () {
            const COLUMN_VISIBILITY_KEY = 'attendance_report_column_visibility';

            // Default column visibility settings
            const defaultColumns = {
                'show_column_checkbox': true,
                'show_column_employee_id': true,
                'show_column_name': true,
                'show_column_action_type': true,
                'show_column_date': true,
                'show_column_time': true,
                'show_column_status': true,
                'show_column_late_reason': true,
                'show_column_actions': true
            };

            // Load column visibility preferences from localStorage
            function loadColumnVisibility() {
                try {
                    const saved = localStorage.getItem(COLUMN_VISIBILITY_KEY);
                    return saved ? JSON.parse(saved) : defaultColumns;
                } catch (e) {
                    console.warn('Failed to load column visibility settings:', e);
                    return defaultColumns;
                }
            }

            // Save column visibility preferences to localStorage
            function saveColumnVisibility(settings) {
                try {
                    localStorage.setItem(COLUMN_VISIBILITY_KEY, JSON.stringify(settings));
                } catch (e) {
                    console.warn('Failed to save column visibility settings:', e);
                }
            }

            // Apply column visibility to the table
            function applyColumnVisibility() {
                const settings = loadColumnVisibility();
                const table = document.getElementById('attendance-reports-table');

                if (!table) return;

                // Get all table headers
                const headers = table.querySelectorAll('thead th');
                const rows = table.querySelectorAll('tbody tr');

                // Column mapping (index to setting key)
                const columnMap = {
                    0: 'show_column_checkbox',      // Checkbox column
                    1: 'show_column_employee_id',   // Employee ID
                    2: 'show_column_name',          // Name
                    // Dynamic fields will be handled separately
                    // Action Type, Date, Time, Status, Late Reason, Actions
                };

                // Apply visibility to static columns
                headers.forEach((header, index) => {
                    const settingKey = columnMap[index];
                    if (settingKey) {
                        const isVisible = settings[settingKey] !== false;
                        header.style.display = isVisible ? '' : 'none';

                        // Apply to corresponding cells in all rows
                        rows.forEach(row => {
                            const cell = row.cells[index];
                            if (cell) {
                                cell.style.display = isVisible ? '' : 'none';
                            }
                        });
                    }
                });

                // Handle dynamic fields (custom user fields)
                const dynamicFieldHeaders = Array.from(headers).filter(header => header.classList.contains('dynamic-field-header'));
                dynamicFieldHeaders.forEach(header => {
                    const fieldId = header.dataset.fieldId;
                    const settingKey = `show_dynamic_field_${fieldId}`;
                    const isVisible = settings[settingKey] !== false;

                    header.style.display = isVisible ? '' : 'none';

                    // Find corresponding column index for this dynamic field
                    const headerIndex = Array.from(headers).indexOf(header);
                    rows.forEach(row => {
                        const cell = row.cells[headerIndex];
                        if (cell) {
                            cell.style.display = isVisible ? '' : 'none';
                        }
                    });
                });
            }

            // Initialize column visibility on page load
            function initColumnVisibility() {
                // ONLY overwrite checkboxes from localStorage if we are on the reports page.
                // On the settings page, the DB-rendered state should be the source of truth.
                const urlParams = new URLSearchParams(window.location.search);
                const isSettingsPage = (urlParams.get('page') === 'settings' && urlParams.get('action') === 'manage_app_scan');

                if (!isSettingsPage) {
                    const settings = loadColumnVisibility();
                    Object.keys(settings).forEach(key => {
                        const checkbox = document.querySelector(`input[name="${key}"]`);
                        if (checkbox && checkbox.getAttribute('data-not-from-storage') !== 'true') {
                            checkbox.checked = settings[key];
                        }
                    });
                }

                // Apply visibility to table
                applyColumnVisibility();
            }

            // Handle checkbox changes in settings
            document.addEventListener('change', function (e) {
                if (e.target.matches('input[name^="show_column_"], input[name^="show_dynamic_field_"]')) {
                    const checkbox = e.target;
                    const settingKey = checkbox.name;
                    const isChecked = checkbox.checked;

                    // Update localStorage
                    const settings = loadColumnVisibility();
                    settings[settingKey] = isChecked;
                    saveColumnVisibility(settings);

                    // Apply changes immediately
                    applyColumnVisibility();

                    // Show success message
                    showAjaxMessage('success', 'Column visibility updated');
                }
            });

            // Initialize when DOM is ready
            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', initColumnVisibility);
            } else {
                initColumnVisibility();
            }

            // Also initialize after AJAX table updates
            const originalFetch = window.fetch;
            window.fetch = function (...args) {
                return originalFetch.apply(this, args).then(response => {
                    response.clone().text().then(text => {
                        if (text.includes('attendance-reports-table')) {
                            setTimeout(applyColumnVisibility, 100);
                        }
                    });
                    return response;
                });
            };
        })();

        (function () {
            const searchBtn = document.getElementById('searchUserBtn');
            const idInput = document.getElementById('searchUserID');
            const nameInput = document.getElementById('searchUserName');

            if (!searchBtn || !idInput || !nameInput) return;

            function filterUsers() {
                const idQuery = idInput.value.toLowerCase().trim();
                const nameQuery = nameInput.value.toLowerCase().trim();
                const rows = document.querySelectorAll('#usersTableBody tr.user-row');

                rows.forEach(row => {
                    const idText = (row.cells[1] ? row.cells[1].textContent : '').toLowerCase();
                    const nameText = (row.cells[2] ? row.cells[2].textContent : '').toLowerCase();

                    const matchesId = idQuery === '' || idText.includes(idQuery);
                    const matchesName = nameQuery === '' || nameText.includes(nameQuery);

                    if (matchesId && matchesName) {
                        row.style.display = '';
                    } else {
                        row.style.display = 'none';
                    }
                });

                // Handle group headers (hide group header if all its rows are hidden)
                const allRows = document.querySelectorAll('#usersTableBody tr');
                let lastGroupHeader = null;
                let hasVisibleInGroup = false;

                allRows.forEach(row => {
                    if (row.classList.contains('group-header')) {
                        if (lastGroupHeader) {
                            lastGroupHeader.style.display = hasVisibleInGroup ? '' : 'none';
                        }
                        lastGroupHeader = row;
                        hasVisibleInGroup = false;
                    } else if (!row.classList.contains('group-header') && row.style.display !== 'none') {
                        hasVisibleInGroup = true;
                    }
                });
                if (lastGroupHeader) {
                    lastGroupHeader.style.display = hasVisibleInGroup ? '' : 'none';
                }
            }

            searchBtn?.addEventListener('click', filterUsers);
            idInput?.addEventListener('input', filterUsers);
            nameInput?.addEventListener('input', filterUsers);
        })();

        window.toggleVerification = function (userId) {
            const fd = new FormData();
            fd.append('ajax_action', 'toggle_verification');
            fd.append('user_id', userId);

            fetch(window.location.href, { method: 'POST', body: fd })
                .then(r => r.text())
                .then(text => {
                    let res;
                    try {
                        // Strip any PHP warnings/notices before the JSON
                        const jsonStart = text.indexOf('{');
                        res = JSON.parse(jsonStart >= 0 ? text.slice(jsonStart) : text);
                    } catch (e) {
                        console.error('JSON parse error:', text);
                        alert('Server response error');
                        return;
                    }
                    if (res.status === 'success') {
                        if (typeof window.showAjaxMessage === 'function') {
                            window.showAjaxMessage('success', res.message);
                        }
                        // Use authoritative new_verified from server
                        const isVerified = res.new_verified === 1;
                        const btn = document.querySelector(`.verify-toggle[data-user-id="${userId}"]`);
                        if (btn) {
                            if (isVerified) {
                                btn.classList.add('verified');
                                btn.innerHTML = '<i class="fa-solid fa-circle-check" style="color: #3b82f6; font-size: 0.9rem;"></i>';
                            } else {
                                btn.classList.remove('verified');
                                btn.innerHTML = '<i class="fa-regular fa-circle-check" style="color: #cbd5e1; font-size: 0.9rem;"></i>';
                            }
                        }
                    } else {
                        alert(res.message || 'Error toggling verification');
                    }
                })
                .catch(err => {
                    console.error('Verification toggle error:', err);
                    alert('Error communicating with server');
                });
        };

        // Sessions Search & Bulk Actions Logic
        (function () {
            const sBtn = document.getElementById('searchSessionBtn');
            const sId = document.getElementById('searchSessionID') || { value: '' }; // Check if exists
            const sName = document.getElementById('searchSessionName');
            const sCat = document.getElementById('filterSessionCategory');
            const revokeAllBtn = document.getElementById('revokeAllSessionsBtn');
            const bulkRevokeBtn = document.getElementById('bulkRevokeSessionsBtn');
            const selectAllBox = document.getElementById('selectAllSessions');
            const sessionCheckboxes = document.querySelectorAll('.session-checkbox');

            if (!sBtn || !sName) return;

            function filterSessions() {
                const qText = sName.value.toLowerCase().trim();
                const qCat = sCat ? sCat.value : '';
                const rows = document.querySelectorAll('#sessionsTable .session-row');

                rows.forEach(row => {
                    const idText = (row.querySelector('.user-info-cell small') || row.querySelector('td:nth-child(2) div:nth-child(2)') || { textContent: '' }).textContent.toLowerCase();
                    const nameText = (row.querySelector('.user-info-cell strong') || row.querySelector('td:nth-child(2) div:first-child') || { textContent: '' }).textContent.toLowerCase();
                    const rowCat = row.getAttribute('data-group-id') || '';

                    const mText = qText === '' || idText.includes(qText) || nameText.includes(qText);
                    const mCat = qCat === '' || rowCat === qCat;

                    row.style.display = (mText && mCat) ? '' : 'none';
                    if (row.style.display === 'none') {
                        const cb = row.querySelector('.session-checkbox');
                        if (cb) cb.checked = false;
                    }
                });
                updateBulkButtonState();
            }

            function updateBulkButtonState() {
                const selectedCount = document.querySelectorAll('.session-checkbox:checked').length;
                if (bulkRevokeBtn) {
                    bulkRevokeBtn.style.display = selectedCount > 0 ? 'inline-block' : 'none';
                    bulkRevokeBtn.innerHTML = `<i class="fa-solid fa-trash-sweep"></i> លុប Token ដែលបានជ្រើសរើស (${selectedCount})`;
                }
            }

            sBtn?.addEventListener('click', filterSessions);
            sName?.addEventListener('input', filterSessions);
            sCat?.addEventListener('change', filterSessions);

            if (selectAllBox) {
                selectAllBox.addEventListener('change', function () {
                    const visibleRows = document.querySelectorAll('#sessionsTable .session-row:not([style*="display: none"])');
                    visibleRows.forEach(row => {
                        const cb = row.querySelector('.session-checkbox');
                        if (cb) cb.checked = selectAllBox.checked;
                    });
                    updateBulkButtonState();
                });
            }

            document.querySelectorAll('.session-checkbox').forEach(cb => {
                cb.addEventListener('change', updateBulkButtonState);
            });

            if (bulkRevokeBtn) {
                bulkRevokeBtn.addEventListener('click', function () {
                    const selectedTokens = Array.from(document.querySelectorAll('.session-checkbox:checked')).map(cb => cb.value);
                    if (selectedTokens.length === 0) return;

                    if (confirm(`តើអ្នកពិតជាចង់លុប Token ចំនួន ${selectedTokens.length} ដែលបានជ្រើសរើសមែនទេ?`)) {
                        const fd = new FormData();
                        fd.append('ajax_action', 'revoke_bulk_tokens');
                        selectedTokens.forEach(t => fd.append('tokens[]', t));

                        fetch(window.location.href, { method: 'POST', body: fd })
                            .then(r => r.json())
                            .then(res => {
                                if (res.status === 'success') {
                                    if (typeof window.showAjaxMessage === 'function') window.showAjaxMessage('success', res.message);
                                    else alert(res.message);
                                    window.adminSoftReload();
                                } else {
                                    if (typeof window.showAjaxMessage === 'function') window.showAjaxMessage('error', res.message);
                                    else alert(res.message);
                                }
                            });
                    }
                });
            }

            if (revokeAllBtn) {
                revokeAllBtn?.addEventListener('click', function (e) {
                    e.preventDefault();
                    if (confirm('តើអ្នកពិតជាចង់លុបចោល Session របស់បុគ្គលិកទាំងអស់មែនទេ? ពួកគេនឹងត្រូវចូលគណនីម្តងទៀត។')) {
                        const fd = new FormData();
                        fd.append('ajax_action', 'revoke_all_my_users_tokens');

                        fetch(window.location.href, {
                            method: 'POST',
                            body: fd
                        })
                            .then(r => r.json())
                            .then(res => {
                                if (res.status === 'success') {
                                    showAjaxMessage('info', res.message);
                                    window.adminSoftReload();
                                } else {
                                    showAjaxMessage('error', res.message || 'Error occurred');
                                }
                            })
                            .catch(err => showAjaxMessage('error', 'Network error: ' + err));
                    }
                });
            }
        })();

        (function () {
            const toggleBtn = document.getElementById('toggleReportsFullscreen');
            if (toggleBtn) {
                // Create Exit button
                let exitBtn = document.createElement('button');
                exitBtn.id = 'fullscreenExitBtn';
                exitBtn.type = 'button';
                exitBtn.innerHTML = '<i class="fa-solid fa-compress"></i> ចាកចេញ (Exit)';
                document.body.appendChild(exitBtn);

                // Toggle On
                toggleBtn?.addEventListener('click', function () {
                    document.body.classList.add('fullscreen-mode');
                });

                // Toggle Off (Exit)
                exitBtn?.addEventListener('click', function () {
                    document.body.classList.remove('fullscreen-mode');
                });

                // Allow ESC key to exit
                document.addEventListener('keydown', function (e) {
                    if (e.key === 'Escape' && document.body.classList.contains('fullscreen-mode')) {
                        document.body.classList.remove('fullscreen-mode');
                    }
                });
            }
        })();

