        function exportTableToExcel(tableID, filename = '') {
            var downloadLink;
            var dataType = 'application/vnd.ms-excel';
            var tableSelect = document.getElementById(tableID);
            if (!tableSelect) return;

            var tableHTML = tableSelect.outerHTML.replace(/ /g, '%20');

            // Specify file name
            filename = filename ? filename + '.xls' : 'excel_data.xls';

            // Create download link element
            downloadLink = document.createElement("a");

            document.body.appendChild(downloadLink);

            if (navigator.msSaveOrOpenBlob) {
                var blob = new Blob(['\ufeff', tableHTML], {
                    type: dataType
                });
                navigator.msSaveOrOpenBlob(blob, filename);
            } else {
                // Create a link to the file
                downloadLink.href = 'data:' + dataType + ', ' + tableHTML;

                // Setting the file name
                downloadLink.download = filename;

                //triggering the function
                downloadLink.click();
            }
        }

        document.getElementById('exportExcelBtn')?.addEventListener('click', function () {
            exportTableToExcel('reportsTableExport', 'Attendance_Report');
        });

        // --- HRM INTEGRATION: JAVASCRIPT LOGIC ---

        // Checklist Functions
        window.loadChecklist = function () {
            const container = document.getElementById('checklist-container');
            if (!container) return;

            const fd = new FormData();
            fd.append('ajax_action', 'get_checklist');

            fetch(window.location.href, { method: 'POST', body: fd })
                .then(r => r.json())
                .then(res => {
                    if (res.status === 'success') {
                        let html = '';
                        if (res.data.length === 0) {
                            html = '<div class="text-center p-4 text-muted">No tasks found.</div>';
                        } else {
                            res.data.forEach(item => {
                                const isDone = item.status === 'completed';
                                html += `
                                <div class="checklist-item ${isDone ? 'completed' : ''}">
                                    <input type="checkbox" ${isDone ? 'checked' : ''} onchange="toggleChecklistStatus(${item.id}, this.checked)" style="margin-right: 15px; width: 20px; height: 20px;">
                                    <span style="flex: 1; font-size: 1rem;">${item.task}</span>
                                    <span class="badge" style="background: #f1f5f9; color: #64748b; margin-right: 15px;">${item.category}</span>
                                    <div class="action-dropdown">
                                        <button type="button" class="crud-dots-btn" onclick="toggleActionMenu(this, event)" title="Actions">
                                            <i class="fa-solid fa-ellipsis-vertical"></i>
                                        </button>
                                        <div class="action-menu">
                                            <button type="button" class="action-item text-danger" onclick="deleteChecklistItem(${item.id})">
                                                <i class="fa-solid fa-trash"></i> Delete
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            `;
                            });
                        }
                        container.innerHTML = html;
                    }
                })
                .catch(err => console.error('Checklist error:', err));
        };

        window.addChecklistItem = function () {
            const input = document.getElementById('checklist-task-input');
            const task = input.value.trim();
            if (!task) return;

            const fd = new FormData();
            fd.append('ajax_action', 'add_checklist_item');
            fd.append('task', task);

            fetch(window.location.href, { method: 'POST', body: fd })
                .then(r => r.json())
                .then(res => {
                    if (res.status === 'success') {
                        input.value = '';
                        loadChecklist();
                    }
                });
        };

        window.toggleChecklistStatus = function (id, checked) {
            const fd = new FormData();
            fd.append('ajax_action', 'toggle_checklist_status');
            fd.append('task_id', id);
            fd.append('status', checked ? 'completed' : 'pending');

            fetch(window.location.href, { method: 'POST', body: fd })
                .then(r => r.json())
                .then(res => {
                    if (res.status === 'success') loadChecklist();
                });
        };

        window.deleteChecklistItem = function (id) {
            if (!confirm('Are you sure you want to delete this task?')) return;
            const fd = new FormData();
            fd.append('ajax_action', 'delete_checklist_item');
            fd.append('task_id', id);

            fetch(window.location.href, { method: 'POST', body: fd })
                .then(r => r.json())
                .then(res => {
                    if (res.status === 'success') loadChecklist();
                });
        };

