                                    : `<button class="btn btn-sm btn-primary" style="padding:6px 15px; border-radius:8px;" onclick="paySalary('${row.employee_id}', ${row.base_salary}, ${row.present_days}, ${row.calculated_salary})"><i class="fa-solid fa-hand-holding-dollar"></i> បើកប្រាក់</button>`;

                                html += `
