                                    <td>$${row.base_salary}</td>
                                    <td class="text-center" style="font-weight:600;">${row.present_days}</td>
                                    <td style="color:#ef4444; font-weight:600;">-$${row.deductions}</td>
                                    <td style="color:#22c55e; font-weight:600;">+$${row.ot_bonus}</td>
                                    <td style="color:#f59e0b; font-weight:600;">-$${row.loan_deduct}</td>
