        // Reports: Click to jump to row
        $(document)
            .on('click', 'a.late-jump', function (e) {
                e.preventDefault();
                const id = parseInt($(this).data('log-id'), 10) || 0;
                let $row = null;
                if (id) { $row = $(`#reportsTable tr[data-log-pk="${id}"]`); }
                if (!$row || $row.length === 0) {
                    const emp = $(this).data('emp-id');
                    const dt = $(this).data('dt');
                    if (emp && dt) { $row = $(`#reportsTable tr[data-emp="${emp}"][data-dt="${dt}"]`); }
                }
                if ($row && $row.length) {
                    const $wrap = $('#reportsTableWrapper');
                    if ($wrap.length) {
                        const top = $row.position().top + $wrap.scrollTop();
                        $wrap.animate({ scrollTop: Math.max(top - 80, 0) }, 250);
                    } else {
                        $row[0].scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                    $row.addClass('row-pulse');
                    setTimeout(() => $row.removeClass('row-pulse'), 1600);
                }
            });

        // Reports fullscreen toggle
        (function () {
            const $btn = $('#toggleReportsFullscreen');
            if ($btn.length === 0) return;
            const $wrap = $('#reportsTableWrapper');
            function setIcon(isFull) {
                const i = $btn.find('i');
                i.toggleClass('fa-expand', !isFull);
                i.toggleClass('fa-compress', isFull);
                $btn.attr('title', isFull ? 'បិទ Fullscreen' : 'បង្ហាញពេញអេក្រង់');
            }
            function isNativeFs() { return !!(document.fullscreenElement || document.webkitFullscreenElement || document.msFullscreenElement); }
            function requestFs(el) {
                if (el.requestFullscreen) return el.requestFullscreen();
                if (el.webkitRequestFullscreen) return el.webkitRequestFullscreen();
                if (el.msRequestFullscreen) return el.msRequestFullscreen();
            }
            function exitFs() {
                if (document.exitFullscreen) return document.exitFullscreen();
                if (document.webkitExitFullscreen) return document.webkitExitFullscreen();
                if (document.msExitFullscreen) return document.msExitFullscreen();
            }
            function applyAllData() {
                if ($wrap.data('allDataApplied')) return;
                const $exportRows = $('#reportsTableExport tbody tr');
                if ($exportRows.length === 0) return;
                const $tbody = $('#reportsTable tbody');
                $wrap.data('originalPaginatedHtml', $tbody.html());
                let newHtml = '';
                const ths = Array.from(document.querySelectorAll('#reportsTable thead th[data-col]'));
                const headers = ths.map(t => ({ key: t.getAttribute('data-col') }));
                $exportRows.each(function () {
                    const $r = $(this);
                    const logPk = $r.data('log-pk') || 0;
                    const dt = $r.data('dt') || '';
                    newHtml += '<tr data-log-pk="' + logPk + '" data-dt="' + dt + '">';
                    headers.forEach(h => {
                        if (h.key === 'select') {
                            newHtml += '<td class="col-select" style="text-align:center;"><input type="checkbox" class="report-select" data-id="' + logPk + '"></td>';
                        } else {
                            const $cell = $r.find('.col-' + h.key).first();
                            const cls = 'col-' + h.key + ($cell.attr('class') ? ' ' + $cell.attr('class') : '');
                            newHtml += '<td class="' + cls + '">' + $cell.html() + '</td>';
                        }
                    });
                    newHtml += '</tr>';
                });
                $tbody.html(newHtml);
                $wrap.data('allDataApplied', true);
            }
            function revertPaginated() {
                if (!$wrap.data('allDataApplied')) return;
                const original = $wrap.data('originalPaginatedHtml');
                if (original) $('#reportsTable tbody').html(original);
                $wrap.removeData('allDataApplied').removeData('originalPaginatedHtml');
            }
            $btn.on('click', function () {
                const el = $wrap.get(0);
                if (!isNativeFs() && !$wrap.hasClass('fullscreen-fallback')) {
                    const p = requestFs(el);
                    if (p && p.catch) p.catch(() => { $wrap.addClass('fullscreen-fallback'); setIcon(true); $('body').addClass('no-scroll'); applyAllData(); });
                    else { $wrap.addClass('fullscreen-fallback'); setIcon(true); $('body').addClass('no-scroll'); applyAllData(); }
                } else {
                    if (isNativeFs()) exitFs();
                    $wrap.removeClass('fullscreen-fallback'); setIcon(false); $('body').removeClass('no-scroll'); revertPaginated();
                }
            });
            ['fullscreenchange', 'webkitfullscreenchange', 'MSFullscreenChange'].forEach(evt => {
                document.addEventListener(evt, function () {
                    if (isNativeFs()) { setIcon(true); $('body').addClass('no-scroll'); applyAllData(); }
                    else { $wrap.removeClass('fullscreen-fallback'); setIcon(false); $('body').removeClass('no-scroll'); revertPaginated(); }
                });
            });
        })();

        window.addTimeRule = function (type) {
            const container = document.getElementById(type + 'RulesContainer');
            if (!container) return;
            const div = document.createElement('div');
            div.className = 'time-rule-row';
            div.dataset.type = type;
            div.innerHTML = `
        <label><i class="fa-solid fa-play"></i> ចាប់ពី</label>
        <input type="time" class="form-control rule-start" value="08:00:00" step="1">
        <label><i class="fa-solid fa-stop"></i> ដល់</label>
        <input type="time" class="form-control rule-end" value="09:00:00" step="1">
        <label><i class="fa-solid fa-circle-info"></i> ស្ថានភាព</label>
        <select class="form-control rule-status">
            <option value="Good">✅ Good</option>
            <option value="Late">⚠️ Late</option>
            <option value="Absent">❌ Absent</option>
        </select>
        <button type="button" class="btn btn-danger remove-rule" onclick="this.parentNode.remove()"><i class="fa-solid fa-trash"></i></button>
    `;
            container.appendChild(div);
        };

        $(document).on('click', '#copyFromUserBtn', function () {
            const srcUserId = $('#copyFromUserSelect').val();
            if (!srcUserId) {
                if (typeof window.showAjaxMessage === 'function') {
                    window.showAjaxMessage('warning', 'សូមជ្រើសរើសបុគ្គលិកដើម្បីចម្លង!');
                }
                return;
            }
            if (!confirm('តើអ្នកពិតជាចង់ចម្លងច្បាប់ម៉ោងពីបុគ្គលិក ' + srcUserId + ' មែនទេ? វានឹងជំនួសច្បាប់បច្ចុប្បន្នរបស់អ្នក។')) return;

            $.ajax({
                url: 'admin_attendance.php',
                type: 'POST',
                data: { ajax_action: 'get_time_rules', user_id: srcUserId },
                dataType: 'json',
                success: function (res) {
                    if (res.status === 'success') {
                        $('#checkinRulesContainer').empty();
                        $('#checkoutRulesContainer').empty();
                        if (res.rules && res.rules.length > 0) {
                            res.rules.forEach(r => {
                                const type = r.type || 'checkin';
                                const container = document.getElementById(type + 'RulesContainer');
                                if (!container) return;
                                const div = document.createElement('div');
                                div.className = 'time-rule-row';
                                div.dataset.type = type;
                                div.innerHTML = `
                            <label><i class="fa-solid fa-play"></i> ចាប់ពី</label>
                            <input type="time" class="form-control rule-start" value="${r.start_time}" step="1">
                            <label><i class="fa-solid fa-stop"></i> ដល់</label>
                            <input type="time" class="form-control rule-end" value="${r.end_time}" step="1">
                            <label><i class="fa-solid fa-circle-info"></i> ស្ថានភាព</label>
                            <select class="form-control rule-status">
                                <option value="Good" ${r.status === 'Good' ? 'selected' : ''}>✅ Good</option>
                                <option value="Late" ${r.status === 'Late' ? 'selected' : ''}>⚠️ Late</option>
                                <option value="Absent" ${r.status === 'Absent' ? 'selected' : ''}>❌ Absent</option>
                            </select>
                            <button type="button" class="btn btn-danger remove-rule" onclick="this.parentNode.remove()"><i class="fa-solid fa-trash"></i></button>
                        `;
                                container.appendChild(div);
                            });
                        }
                        if (typeof window.showAjaxMessage === 'function') {
                            window.showAjaxMessage('success', 'ចម្លងបានជោគជ័យ!');
                        }
                    } else {
                        if (typeof window.showAjaxMessage === 'function') {
                            window.showAjaxMessage('error', 'Error: ' + (res.message || 'Unknown error'));
                        }
                    }
                },
                error: function () {
                    if (typeof window.showAjaxMessage === 'function') {
                        window.showAjaxMessage('error', 'មានកំហុសក្នុងការទាញយកច្បាប់ម៉ោង');
                    }
                }
            });
        });
    </script>

    <script>
        function resetActionMenuPosition(menu) {
            if (!menu) return;
            menu.style.position = '';
            menu.style.top = '';
            menu.style.left = '';
            menu.style.right = '';
            menu.style.bottom = '';
            menu.style.zIndex = '';
            menu.style.visibility = '';
            menu.dataset.floating = '0';
            const dropdown = menu.closest('.action-dropdown, .action-dropdown-container');
            if (dropdown) {
                dropdown.classList.remove('menu-open');
            }
            const host = menu.closest('.hrm-card, .stock-card, .card, .content-card, .checklist-item');
            if (host) {
                host.classList.remove('action-menu-open');
            }
            const trigger = dropdown ? dropdown.querySelector('.crud-dots-btn, .action-toggle-btn') : null;
            if (trigger) {
                trigger.classList.remove('menu-open');
                trigger.setAttribute('aria-expanded', 'false');
            }
        }

        function positionFloatingActionMenu(btn, menu) {
            if (!btn || !menu) return;

            menu.style.visibility = 'hidden';
            menu.style.position = 'fixed';
            menu.style.top = '0';
            menu.style.left = '0';
            menu.style.right = 'auto';
            menu.style.bottom = 'auto';
            menu.style.zIndex = '5000';
            menu.dataset.floating = '1';

            const btnRect = btn.getBoundingClientRect();
            const menuRect = menu.getBoundingClientRect();
            const viewportWidth = window.innerWidth || document.documentElement.clientWidth || 0;
            const viewportHeight = window.innerHeight || document.documentElement.clientHeight || 0;
            const margin = 12;
            const gap = 8;

            let left = btnRect.right - menuRect.width;
            if (left < margin) {
                left = margin;
            }
            if ((left + menuRect.width) > (viewportWidth - margin)) {
                left = Math.max(margin, viewportWidth - menuRect.width - margin);
            }

            let top = btnRect.bottom + gap;
            if ((top + menuRect.height) > (viewportHeight - margin)) {
                top = btnRect.top - menuRect.height - gap;
            }
            if (top < margin) {
                top = margin;
            }

            menu.style.left = `${left}px`;
            menu.style.top = `${top}px`;
            menu.style.visibility = 'visible';
        }

        function closeAllActionMenus(exceptMenu = null) {
            document.querySelectorAll('.action-menu.show, .action-dropdown-menu.show').forEach(menu => {
                if (menu !== exceptMenu) {
                    menu.classList.remove('show');
                    resetActionMenuPosition(menu);
                }
            });
        }

        function toggleActionMenu(btn, ev) {
            ev = ev || window.event;
            if (ev) {
                ev.preventDefault();
                ev.stopPropagation();
            }
            const menu = btn ? btn.nextElementSibling : null;
            if (!menu) return;
            const dropdown = btn.closest('.action-dropdown, .action-dropdown-container');
            const host = btn.closest('.hrm-card, .stock-card, .card, .content-card, .checklist-item');
            const willOpen = !menu.classList.contains('show');
            closeAllActionMenus(menu);
            menu.classList.toggle('show', willOpen);
            btn.setAttribute('aria-expanded', willOpen ? 'true' : 'false');
            if (willOpen) {
                if (dropdown) {
                    dropdown.classList.add('menu-open');
                }
                if (host) {
                    host.classList.add('action-menu-open');
                }
                btn.classList.add('menu-open');
                requestAnimationFrame(() => {
                    if (!menu.classList.contains('show')) return;
                    positionFloatingActionMenu(btn, menu);
                });
            } else {
                resetActionMenuPosition(menu);
            }
        }

        window.applyGroupFilter = function (groupId) {
            const url = new URL(window.location.href);
            if (groupId) {
                url.searchParams.set('group_id', groupId);
            } else {
                url.searchParams.delete('group_id');
            }
            window.adminSoftGo(url.toString());
        };

        // Close menus when clicking outside
        document.addEventListener('click', function (e) {
            if (!e.target.closest('.action-dropdown, .action-dropdown-container')) {
                closeAllActionMenus();
            }
        });
        document.addEventListener('keydown', function (e) {
            if (e.key === 'Escape') closeAllActionMenus();
        });
        window.addEventListener('resize', function () {
            closeAllActionMenus();
        });
        window.addEventListener('scroll', function () {
            closeAllActionMenus();
        }, true);

        // Handle row hovering effects for premium feel
        document.querySelectorAll('.user-row').forEach(row => {
            row.addEventListener('mouseenter', () => {
                row.style.zIndex = "10";
            });
            row.addEventListener('mouseleave', () => {
                row.style.zIndex = "1";
            });
        });
    </script>
    </div><!-- closes main-content -->
    </div><!-- closes content-wrapper -->
    </div><!-- closes admin-container -->
    </body>

</html>

